try:
    sys.modules.setdefault('adv_fast_select_runtime', sys.modules.get(__name__))
except Exception:
    pass




def _adv_safe_warning(msg):
    """Maya 2020 (Python 2.7) compatible warning that avoids garbled Chinese text."""
    try:
        if sys.version_info[0] < 3:
            try:
                text_type = unicode  # noqa: F821
            except NameError:
                text_type = str
            if isinstance(msg, text_type) and text_type is not str:
                try:
                    msg = msg.encode(sys.getfilesystemencoding() or 'mbcs', 'replace')
                except Exception:
                    try:
                        msg = msg.encode('gbk', 'replace')
                    except Exception:
                        msg = msg.encode('utf-8', 'replace')
    except Exception:
        pass
    try:
        cmds.warning(msg)
    except Exception:
        try:
            cmds.warning(str(msg))
        except Exception:
            pass


def _adv_safe_print(msg):
    """Maya 2020 (Python 2.7) compatible print for Chinese text."""
    try:
        if sys.version_info[0] < 3:
            try:
                text_type = unicode  # noqa: F821
            except NameError:
                text_type = str
            if isinstance(msg, text_type) and text_type is not str:
                try:
                    msg = msg.encode(sys.getfilesystemencoding() or 'mbcs', 'replace')
                except Exception:
                    try:
                        msg = msg.encode('gbk', 'replace')
                    except Exception:
                        msg = msg.encode('utf-8', 'replace')
    except Exception:
        pass
    print(msg)


def _adv_runtime_command_exists(name):
    """Quiet existence check for Maya runTimeCommand across versions."""
    if not name:
        return False
    try:
        name = str(name)
    except Exception:
        return False

    # Prefer command arrays to avoid noisy/unsupported -exists flags.
    for arr_flag in ('userCommandArray', 'commandArray'):
        try:
            arr = cmds.runTimeCommand(q=True, **{arr_flag: True}) or []
            for cmd_name in arr:
                try:
                    if str(cmd_name) == name:
                        return True
                except Exception:
                    pass
        except Exception:
            pass

    # Avoid direct query-by-name fallback because Maya may print noisy
    # "name is not unique" errors before raising.
    return False


def _adv_runtime_command_delete_all(name, max_iter=8):
    """Best-effort removal for duplicate runTimeCommand entries with same name."""
    if not name:
        return
    try:
        name = str(name)
    except Exception:
        return
    try:
        import maya.mel as _mel
    except Exception:
        _mel = None

    for _ in range(int(max_iter) if max_iter else 8):
        if not _adv_runtime_command_exists(name):
            break
        removed = False
        try:
            cmds.runTimeCommand(name, edit=True, delete=True)
            removed = True
        except Exception:
            try:
                cmds.runTimeCommand(name, e=True, delete=True)
                removed = True
            except Exception:
                pass
        if (not removed) and _mel:
            try:
                _mel.eval('catch(`runTimeCommand -e -delete "%s"`);' % name)
                removed = True
            except Exception:
                pass
        if not removed:
            break


def _adv_delete_command_ui_if_exists(name):
    """Delete a command UI object only when it exists (avoid noisy deleteUI errors)."""
    if not name:
        return
    try:
        exists = set(cmds.lsUI(type='command') or [])
    except Exception:
        exists = set()
    try:
        if str(name) in exists:
            cmds.deleteUI(str(name))
    except Exception:
        pass


def _adv_runtime_pkg_dir(local_scripts):
    """Return preferred local runtime package dir (new name first)."""
    try:
        import os
        if not local_scripts:
            return ''
        for pkg_name in ('adv_IKFKSwitch', 'switchRuntime'):
            pkg_dir = os.path.join(local_scripts, pkg_name).replace('\\', '/')
            if os.path.isdir(pkg_dir):
                return pkg_dir
        return os.path.join(local_scripts, 'switchRuntime').replace('\\', '/')
    except Exception:
        return ''


def _adv_is_switch_runtime_module_key(module_key):
    """Support both new and legacy runtime module names during reload cleanup."""
    try:
        k = str(module_key or '')
    except Exception:
        return False
    return (
        k == 'adv_IKFKSwitch' or k.startswith('adv_IKFKSwitch.') or
        k == 'switchRuntime' or k.startswith('switchRuntime.')
    )


def _adv_import_switch_runtime():
    """Prefer adv_IKFKSwitch and keep legacy switchRuntime aliases available."""
    import os
    import sys
    try:
        import importlib
    except Exception:
        importlib = None

    try:
        local_scripts = os.path.join(os.path.dirname(__file__), 'scripts').replace('\\', '/')
        if local_scripts and local_scripts not in sys.path:
            sys.path.insert(0, local_scripts)
    except Exception:
        pass

    last_err = None
    runtime_mod = None
    for pkg_name in ('adv_IKFKSwitch', 'switchRuntime'):
        try:
            if importlib:
                runtime_mod = importlib.import_module(pkg_name)
            else:
                runtime_mod = __import__(pkg_name)
            if runtime_mod is not None:
                break
        except Exception as exc:
            last_err = exc
            runtime_mod = None

    if runtime_mod is None:
        if last_err is not None:
            raise last_err
        raise ImportError('Cannot import adv_IKFKSwitch/switchRuntime')

    root_name = str(getattr(runtime_mod, '__name__', '') or '')
    for alias_root in ('adv_IKFKSwitch', 'switchRuntime'):
        try:
            sys.modules[alias_root] = runtime_mod
        except Exception:
            pass

    for sub_name in ('callback', 'ik_core', 'switch', 'tools', 'key_frame_post', 'key_frame_post_BACKUP'):
        sub_mod = None
        for cand in [
            (root_name + '.' + sub_name) if root_name else '',
            'adv_IKFKSwitch.' + sub_name,
            'switchRuntime.' + sub_name,
        ]:
            if not cand:
                continue
            try:
                if importlib:
                    sub_mod = importlib.import_module(cand)
                else:
                    sub_mod = __import__(cand, fromlist=['*'])
                if sub_mod is not None:
                    break
            except Exception:
                sub_mod = None
        if sub_mod is None:
            continue
        try:
            setattr(runtime_mod, sub_name, sub_mod)
        except Exception:
            pass
        for alias_root in ('adv_IKFKSwitch', 'switchRuntime'):
            try:
                sys.modules[alias_root + '.' + sub_name] = sub_mod
            except Exception:
                pass

    return runtime_mod


try:
    _adv_import_switch_runtime()
except Exception:
    pass

def get_controller_name_without_namespace(obj):
    """Get controller name without namespace prefix"""
    return obj.split(':')[-1].split('|')[-1]

def get_ikfk_blend_value(ctrl_name):
    """Get IKFK blend value from corresponding switch controller"""
    # Determine which switch controller to check
    if ctrl_name.endswith('_L'):
        switch_ctrl = 'FKIKArm_L'
    elif ctrl_name.endswith('_R'):
        switch_ctrl = 'FKIKArm_R'
    elif ctrl_name in ['FKNeck_M', 'IKSpine1_M', 'IKSpine2_M', 'IKSpine3_M', 'FKRoot_M', 'RootX_M']:
        # For spine-related controllers, check spine IKFK switch
        switch_ctrl = 'FKIKSpine_M'
    else:
        # For other controllers, default to left arm
        switch_ctrl = 'FKIKArm_L'
    
    # Find the switch controller in scene
    all_objects = cmds.ls(type='transform')
    for obj in all_objects:
        obj_name = get_controller_name_without_namespace(obj)
        if obj_name == switch_ctrl:
            # Check if FKIKBlend attribute exists
            if cmds.attributeQuery('FKIKBlend', node=obj, exists=True):
                blend_value = cmds.getAttr(obj + '.FKIKBlend')
                print("IKFK Blend value for %s: %s" % (switch_ctrl, blend_value))
                return blend_value
    
    print("FKIKBlend attribute not found for %s, defaulting to FK mode" % switch_ctrl)
    return 0  # Default to FK if not found

def find_adv_parent_controller(current_obj):
    """Find parent controller using ADV rig naming convention"""
    # NOTE: This function historically used a temporary mapping dict named
    # adv_child_map, but that dict was never defined, causing NameError.
    # Keep it local to avoid leaking globals.
    adv_child_map = {}
    ctrl_name = get_controller_name_without_namespace(current_obj)
    
    # Check spine IKFK state for neck controller
    if ctrl_name == 'FKNeck_M':
        spine_ikfk_value = get_ikfk_blend_value(ctrl_name)
        if spine_ikfk_value == 0:  # FK mode
            # FK: FKNeck_M -> FKChest_M
            target_name = 'FKChest_M'
        else:  # IK mode (value = 10)
            # IK: FKNeck_M -> IKSpine3_M
            target_name = 'IKSpine3_M'
        
        # Search for target controller in scene
        all_objects = cmds.ls(type='transform')
        for obj in all_objects:
            obj_name = get_controller_name_without_namespace(obj)
            if obj_name == target_name:
                if get_shape_type(obj):
                    print("Spine IKFK mode: %s, FKNeck_M -> %s" % ("FK" if spine_ikfk_value == 0 else "IK", target_name))
                    return obj

        cmds.warning("%s not found!" % target_name)
        return None
    if ctrl_name in ['FKScapula_L', 'FKScapula_R']:
        side = ctrl_name[-1]  # Get L or R
        ikfk_value = get_ikfk_blend_value(ctrl_name)
        
        if ikfk_value == 0:  # FK mode
            adv_child_map[ctrl_name] = 'FKShoulder_' + side
            print("FK mode detected for %s, targeting FKShoulder_%s" % (ctrl_name, side))
        else:  # IK mode (value = 10)
            adv_child_map[ctrl_name] = 'PoleArm_' + side
            print("IK mode detected for %s, targeting PoleArm_%s" % (ctrl_name, side))
    
    # FK chest parent should be the FK spine (not the neck).
    # Decide by spine IKFK mode.
    if ctrl_name == 'FKChest_M':
        spine_ikfk_value = get_ikfk_blend_value(ctrl_name)
        target_name = 'FKSpine2_M' if spine_ikfk_value == 0 else 'IKSpine3_M'

        all_objects = cmds.ls(type='transform')
        for obj in all_objects:
            obj_name = get_controller_name_without_namespace(obj)
            if obj_name == target_name:
                if get_shape_type(obj):
                    print("Spine IKFK mode: %s, FKChest_M -> %s" % ("FK" if spine_ikfk_value == 0 else "IK", target_name))
                    return obj

        cmds.warning("%s not found!" % target_name)
        return None

    # Other specific mappings (kept minimal here; more complex cases are handled in find_parent_controller)

    # Foot roll / toe controls: treat as direct children of IKLeg (independent),
    # so selecting parent from any of them goes back to IKLeg.
    if ctrl_name in ['IKToes_L', 'RollHeel_L', 'RollToes_L', 'RollToesEnd_L', 'IKToes_R', 'RollHeel_R', 'RollToes_R', 'RollToesEnd_R']:
        side = ctrl_name[-1]
        target_name = 'IKLeg_' + side
        try:
            all_objects = cmds.ls(type='transform')
        except Exception:
            all_objects = []
        for obj in all_objects:
            try:
                obj_name = get_controller_name_without_namespace(obj)
            except Exception:
                continue
            if obj_name == target_name:
                try:
                    if get_shape_type(obj):
                        return obj
                except Exception:
                    return obj
        # If not found, fall back to other logic.

    # IMPORTANT: parent selection should never map wrist -> finger.
    # Wrist's parent in FK chain is the elbow.
    if ctrl_name in ['FKWrist_L', 'FKWrist_R']:
        side = ctrl_name[-1]
        target_name = 'FKElbow_' + side
        all_objects = cmds.ls(type='transform')
        for obj in all_objects:
            obj_name = get_controller_name_without_namespace(obj)
            if obj_name == target_name:
                if get_shape_type(obj):
                    return obj
        # If not found, fall back to other logic.
    
    # Check if controller matches ADV naming convention
    if ctrl_name in adv_child_map:
        target_name = adv_child_map[ctrl_name]
        
        # Search for target controller in scene
        all_objects = cmds.ls(type='transform')
        for obj in all_objects:
            obj_name = get_controller_name_without_namespace(obj)
            if obj_name == target_name:
                # Verify it has a shape node (is a controller)
                if get_shape_type(obj):
                    return obj
        
        print("ADV child controller '%s' not found in scene" % target_name)
        return None
    
    return None


def find_adv_child_controller(current_obj):
    """Find a likely child controller using simple ADV naming conventions.

    This is a lightweight helper used by get_all_children_for_node(). It should
    never throw even if the rig doesn't match expected naming.
    """
    try:
        ctrl_name = get_controller_name_without_namespace(current_obj)
    except Exception:
        return None

    adv_map = {}

    # Spine chain (single step). Note: some of these are also handled earlier in get_all_children_for_node.
    adv_map.update({
        'FKRoot_M': 'FKSpine1_M',
        'IKSpine1_M': 'IKSpine2_M',
        'IKSpine2_M': 'IKSpine3_M',
        'IKSpine3_M': 'FKNeck_M',
        'FKChest_M': 'FKNeck_M',
    })

    # Arm basic chain (FK)
    for side in ('L', 'R'):
        adv_map['FKShoulder_' + side] = 'FKElbow_' + side
        adv_map['FKElbow_' + side] = 'FKWrist_' + side

        # Scapula child depends on arm IKFK state
        if ctrl_name == ('FKScapula_' + side):
            try:
                ikfk_value = get_ikfk_blend_value('FKScapula_' + side)
            except Exception:
                ikfk_value = 0
            adv_map['FKScapula_' + side] = ('FKShoulder_' + side) if ikfk_value == 0 else ('PoleArm_' + side)

    target_name = adv_map.get(ctrl_name)
    if not target_name:
        return None

    try:
        all_objects = cmds.ls(type='transform')
    except Exception:
        all_objects = []
    for obj in all_objects:
        try:
            if get_controller_name_without_namespace(obj) == target_name and get_shape_type(obj):
                return obj
        except Exception:
            continue
    return None

def get_shape_type(obj):
    """Get the shape node type of an object"""
    shapes = cmds.listRelatives(obj, shapes=True, fullPath=True)
    if shapes:
        return cmds.nodeType(shapes[0])
    return None

def find_parent_controller():
    """Find parent controller of the same type"""
    global USE_CUSTOM_MAPPING, CUSTOM_PARENT_MAP

    selection = cmds.ls(selection=True, long=True) or []
    if not selection:
        cmds.warning("Please select a controller first!")
        return

        def _adv_hotkey_python_call_code(func_name, args_src=None):
            """Return Python source to call a function from this tool.

            Important: this returned source must remain ASCII-only so it can be executed
            in Maya 2018 (Python 2.7) from MEL python("...") / runTimeCommand without an
            encoding cookie.
            """
            fn = str(func_name or '').strip()
            if not fn:
                return ''

            # Reduce risk of code injection if func_name ever becomes user-controlled.
            if not fn.replace('_', '').isalnum():
                return ''

            args_src = list(args_src or [])
            arg_tuple = '(%s%s)' % (', '.join(args_src), ',' if len(args_src) == 1 else '')

            return (
                "import maya.cmds as cmds\n"
                "import sys, os\n"
                "mn='adv_fast_select_runtime'\n"
                "fn=%r\n"
                "args=%s\n"
                "def _pick_main_py(d):\n"
                "    try:\n"
                "        preferred=[u'ADV\u5feb\u901f\u9009\u62e9\u7236\u5b50.py','ADV_fast_select.py']\n"
                "        for nm in preferred:\n"
                "            p=os.path.join(d,nm)\n"
                "            if os.path.isfile(p):\n"
                "                return p\n"
                "        files=[]\n"
                "        for f in os.listdir(d):\n"
                "            fl=f.lower()\n"
                "            if not fl.endswith('.py'):\n"
                "                continue\n"
                "            if (u'\u526f\u672c' in f) or ('backup' in fl) or ('.bak' in fl):\n"
                "                continue\n"
                "            p=os.path.join(d,f)\n"
                "            if os.path.isfile(p):\n"
                "                files.append(p)\n"
                "        if not files:\n"
                "            return ''\n"
                "        files.sort(key=lambda p: (os.path.getsize(p), p))\n"
                "        return files[-1]\n"
                "    except Exception:\n"
                "        return ''\n"
                "def _find_script_path():\n"
                "    p=''\n"
                "    try:\n"
                "        if cmds.optionVar(exists='ADV_FastSelectScriptPath'):\n"
                "            p=cmds.optionVar(q='ADV_FastSelectScriptPath') or ''\n"
                "    except Exception:\n"
                "        p=''\n"
                "    try:\n"
                "        if p and os.path.isfile(p):\n"
                "            return p\n"
                "    except Exception:\n"
                "        pass\n"
                "    d=''\n"
                "    try:\n"
                "        if p and os.path.isdir(p):\n"
                "            d=p\n"
                "        elif p and os.path.isfile(p):\n"
                "            d=os.path.dirname(p)\n"
                "    except Exception:\n"
                "        d=''\n"
                "    if not d:\n"
                "        try:\n"
                "            base=cmds.internalVar(userAppDir=True)\n"
                "            d=os.path.join(base,'scripts','ADV Fast select')\n"
                "        except Exception:\n"
                "            d=''\n"
                "    if d and os.path.isdir(d):\n"
                "        s=_pick_main_py(d)\n"
                "        if s:\n"
                "            return s\n"
                "    return p if (p and os.path.isfile(p)) else ''\n"
                "p=_find_script_path()\n"
                "m=sys.modules.get(mn)\n"
                "need_reload=False\n"
                "try:\n"
                "    need_reload = (not m) or (p and getattr(m,'__file__',None)!=p)\n"
                "except Exception:\n"
                "    need_reload=True\n"
                "if need_reload and p and os.path.isfile(p):\n"
                "    try:\n"
                "        import importlib.util as iu\n"
                "    except Exception:\n"
                "        iu=None\n"
                "    if iu is not None:\n"
                "        spec=iu.spec_from_file_location(mn,p)\n"
                "        m=iu.module_from_spec(spec)\n"
                "        spec.loader.exec_module(m)\n"
                "    else:\n"
                "        import imp\n"
                "        m=imp.load_source(mn,p)\n"
                "    sys.modules[mn]=m\n"
                "m=sys.modules.get(mn)\n"
                "if m and hasattr(m,fn):\n"
                "    getattr(m,fn)(*args)\n"
                "else:\n"
                "    try:\n"
                "        cmds.warning('ADV: runtime module not available')\n"
                "    except Exception:\n"
                "        pass\n"
            ) % (fn, arg_tuple)


    def _get_parent_for_node(current_obj):
        ctrl_name = get_controller_name_without_namespace(current_obj)

        # 0) Macro custom mapping override (used by Macro Menu presets)
        # When enabled, resolve parent by controller name (ignores namespaces/paths).
        try:
            if USE_CUSTOM_MAPPING and ctrl_name in CUSTOM_PARENT_MAP:
                target_name = str(CUSTOM_PARENT_MAP.get(ctrl_name) or '').strip()
                if target_name:
                    try:
                        all_objects = cmds.ls(type='transform')
                    except Exception:
                        all_objects = []
                    for obj in all_objects:
                        try:
                            obj_name = get_controller_name_without_namespace(obj)
                        except Exception:
                            continue
                        if obj_name == target_name:
                            try:
                                if get_shape_type(obj):
                                    return obj
                            except Exception:
                                return obj
        except Exception:
            pass

        # SPECIAL FORCE FIXES: Handle specific controllers before any other logic

        # FK澶ц噦鎺у埗鍣ㄥ線涓婄粰鍒拌偐鑶€
        if ctrl_name in ['FKShoulder_L', 'FKShoulder_R']:
            side = ctrl_name[-1]  # Get L or R
            target_name = 'FKScapula_' + side
            print("SPECIAL FIX: %s detected, forcing to %s" % (ctrl_name, target_name))

            all_objects = cmds.ls(type='transform')
            for obj in all_objects:
                obj_name = get_controller_name_without_namespace(obj)
                if obj_name == target_name:
                    if get_shape_type(obj):
                        print("FORCE SUCCESS: %s -> %s" % (ctrl_name, target_name))
                        return obj
            cmds.warning("%s not found!" % target_name)
            return None

        elif ctrl_name in ['IKArm_L', 'IKArm_R']:
            print("SPECIAL NOTE: %s has no specific child controller" % ctrl_name)
            cmds.warning("%s has no specific child controller" % ctrl_name)
            return None

        # 强制修复：手臂极向量向下给到IK手臂控制器控制器 - 修版本
        elif ctrl_name in ['PoleArm_L', 'PoleArm_R']:
            side = ctrl_name[-1]  # Get L or R
            target_name = 'IKArm_' + side
            print("SPECIAL FIX DOWN: %s detected, forcing to %s" % (ctrl_name, target_name))

            all_objects = cmds.ls(type='transform')
            for obj in all_objects:
                obj_name = get_controller_name_without_namespace(obj)
                if obj_name == target_name:
                    if get_shape_type(obj):
                        print("FORCE SUCCESS DOWN: %s -> %s" % (ctrl_name, target_name))
                        return obj
            cmds.warning("%s not found!" % target_name)
            return None

        # 鑵块儴鏋佸悜閲忓線涓婄粰鍒癛ootX_M
        elif ctrl_name in ['PoleLeg_L', 'PoleLeg_R']:
            target_name = 'RootX_M'
