def reload_functions():
    """Reload all functions to clear Maya's function cache"""
    import importlib
    import sys
    
    # Force reload by executing the function definitions again
    print("=== Reloading Controller Hierarchy Functions ===")
    
    # Re-execute the main functions (this is a simple approach)
    exec("""
# Re-define all core functions
def get_controller_name_without_namespace(obj):
    return obj.split(':')[-1].split('|')[-1]

def get_shape_type(obj):
    shapes = cmds.listRelatives(obj, shapes=True, fullPath=True)
    if shapes:
        return cmds.nodeType(shapes[0])
    return None

def get_ikfk_blend_value(ctrl_name):
    if ctrl_name.endswith('_L'):
        switch_ctrl = 'FKIKArm_L'
    elif ctrl_name.endswith('_R'):
        switch_ctrl = 'FKIKArm_R'
    elif ctrl_name in ['FKNeck_M', 'IKSpine1_M', 'IKSpine2_M', 'IKSpine3_M', 'FKRoot_M', 'RootX_M']:
        switch_ctrl = 'FKIKSpine_M'
    else:
        switch_ctrl = 'FKIKArm_L'
    
    all_objects = cmds.ls(type='transform')
    for obj in all_objects:
        obj_name = get_controller_name_without_namespace(obj)
        if obj_name == switch_ctrl:
            if cmds.attributeQuery('FKIKBlend', node=obj, exists=True):
                blend_value = cmds.getAttr(obj + '.FKIKBlend')
                return blend_value
    return 0
""", globals())
    
    # Force re-import of the module if it exists
    module_name = '__main__'
    if module_name in sys.modules:
        try:
            importlib.reload(sys.modules[module_name])
        except:
            pass
    
    print("鉁?Functions reloaded successfully")
    print("鉁?Function cache cleared")

    # Rebuild UI so layout/style changes take effect immediately
    try:
        if cmds.window(ADV_MAIN_WINDOW_NAME, exists=True):
            cmds.deleteUI(ADV_MAIN_WINDOW_NAME)
    except Exception:
        pass
    try:
        create_hierarchy_selection_ui()
    except Exception:
        pass

    try:
        msg = (u"函数已重载并重建UI，请测试控制器。"
               if LANGUAGE == 'CN'
               else "Functions reloaded and UI rebuilt. If anything looks off, test your controllers.")
        cmds.inViewMessage(amg=msg, pos='topCenter', fade=True)
    except Exception:
        try:
            print(msg)
        except Exception:
            pass

def create_hotkey(hotkey_name, key_combination, command_string):
    """Create Maya hotkey using MEL commands"""
    try:
        # Use MEL commands to avoid unicode issues
        import maya.mel as mel
        
        # Delete existing hotkey if it exists
        try:
            # NOTE: Older Maya requires flags before the key spec.
            mel.eval('hotkey -name "" -k "%s"' % key_combination)
        except:
            pass
        
        # Create named command using MEL
        mel_cmd = 'nameCommand -annotation "%s" -command "python(\\\"%s\\\")" %s' % (hotkey_name, command_string, hotkey_name)
        mel.eval(mel_cmd)
        
        # Assign hotkey using MEL
        hotkey_cmd = 'hotkey -name "%s" -k "%s"' % (hotkey_name, key_combination)
        mel.eval(hotkey_cmd)
        
        return True
    except Exception as e:
        print("Error creating hotkey: %s" % str(e))
        return False

