def _adv_sr_log(msg):
    try:
        import time
        line = "[%0.3f] %s" % (time.time(), str(msg))
    except Exception:
        line = str(msg)
    _ADV_SR_DIAG_LOG.append(line)
    # keep it bounded
    if len(_ADV_SR_DIAG_LOG) > 400:
        del _ADV_SR_DIAG_LOG[0:200]


def adv_sr_dump_diagnostics(*_):
    """Export diagnostics for ADV->switchRuntime realtime switch integration."""
    import os
    import sys
    import datetime

    def _get_adv_root_dir():
        """Return ADV Fast select root dir (folder containing this script)."""
        # Prefer persisted path (works even if loaded via exec)
        try:
            if cmds.optionVar(exists='ADV_FastSelectScriptPath'):
                p = cmds.optionVar(q='ADV_FastSelectScriptPath') or ''
                if p and os.path.isfile(p):
                    return os.path.dirname(os.path.abspath(p))
        except Exception:
            pass
        # Fallback to __file__
        try:
            p = os.path.abspath(__file__)
            if p and os.path.isfile(p):
                return os.path.dirname(p)
        except Exception:
            pass
        return None

    def _hotkey_query(key, alt=False, ctrl=False, shift=False):
        try:
            return cmds.hotkey(k=str(key), q=True, name=True, alt=alt, ctl=ctrl, sht=shift) or ''
        except Exception:
            return ''

    def _runtime_exists(name):
        return bool(_adv_runtime_command_exists(name))

    def _dump_legacy_setkey_state(lines_list):
        """Add legacy ADV SetKey interception diagnostics (source of spam warnings)."""
        lines_list.append("")
        lines_list.append("--- Legacy SetKey interception diagnostics ---")

        # userSetup.py marker presence (installed by ADV Fast Select installer)
        try:
            usd = cmds.internalVar(userScriptDir=True)
        except Exception:
            usd = ''
        try:
            user_setup_path = os.path.join(str(usd), 'userSetup.py') if usd else ''
        except Exception:
            user_setup_path = ''
        lines_list.append('userSetup.py path: %s' % (str(user_setup_path) if user_setup_path else '<UNKNOWN>'))
        try:
            has_marker = False
            if user_setup_path and os.path.isfile(user_setup_path):
                try:
                    with io.open(user_setup_path, 'r', encoding='utf-8') as f:
                        t = f.read()
                except Exception:
                    with open(user_setup_path, 'r') as f:
                        t = f.read()
                has_marker = ('# >>> ADV Fast Select Legacy SetKey Fix >>>' in str(t))
            lines_list.append('userSetup.py has ADV fix marker: %s' % str(bool(has_marker)))
        except Exception as e:
            lines_list.append('userSetup.py has ADV fix marker: <error> %s' % str(e))

        # Hotkey set + S bindings
        cur_set = None
        try:
            cur_set = cmds.hotkeySet(q=True, current=True)
        except Exception:
            cur_set = None
        lines_list.append("hotkeySet current: %s" % str(cur_set))

        # Maya version differences: some builds do not support flag 'hotkeySets'.
        # Prefer 'hotkeySetArray' when available.
        try:
            all_sets = cmds.hotkeySet(q=True, hotkeySetArray=True) or []
        except Exception:
            try:
                all_sets = cmds.hotkeySet(q=True, hotkeySets=True) or []
            except Exception:
                all_sets = []
        lines_list.append("hotkeySet count: %d" % int(len(all_sets) if all_sets else 0))

        keys = ('s', 'S')
        combos = (
            (False, False, False, 'none'),
            (True, False, False, 'alt'),
            (False, True, False, 'ctrl'),
            (False, False, True, 'shift'),
        )

        def _scan_current_set(tag):
            for k in keys:
                for alt, ctrl, shift, mod_name in combos:
                    bound = _hotkey_query(k, alt=alt, ctrl=ctrl, shift=shift)
                    # Always print; empty binding is useful for debugging too.
                    lines_list.append('hotkey %s %s (%s): %s' % (tag, k, mod_name, (str(bound) if bound else '<EMPTY>')))

        # Scan current set
        _scan_current_set('current')

        # Optionally scan other sets too
        scanned = set()
        for hs in all_sets:
            if not hs or hs in scanned:
                continue
            scanned.add(hs)
            try:
                mel.eval('hotkeySet -e -current "%s"' % str(hs))
            except Exception:
                try:
                    cmds.hotkeySet(e=True, current=hs)
                except Exception:
                    continue
            _scan_current_set('set=%s' % str(hs))

        # Restore hotkey set
        if cur_set:
            try:
                mel.eval('hotkeySet -e -current "%s"' % str(cur_set))
            except Exception:
                try:
                    cmds.hotkeySet(e=True, current=cur_set)
                except Exception:
                    pass

        # Legacy commands existence/details
        rt = ADV_SYNC_SETKEY_RUNTIME_COMMAND
        lines_list.append('runTimeCommand %s exists: %s' % (rt, str(_runtime_exists(rt))))
        if _runtime_exists(rt):
            try:
                lang = cmds.runTimeCommand(rt, q=True, commandLanguage=True)
            except Exception:
                lang = ''
            try:
                cmd = cmds.runTimeCommand(rt, q=True, command=True)
            except Exception:
                cmd = ''
            lines_list.append('runTimeCommand %s language: %s' % (rt, str(lang)))
            if cmd:
                lines_list.append('runTimeCommand %s command(head 200): %s' % (rt, str(cmd).replace('\n', '\\n')[:200]))

        # nameCommand details (if exists)
        try:
            nc_cmd = cmds.nameCommand('ADVSyncSetKeyCmd', q=True, command=True)
        except Exception:
            nc_cmd = ''
        lines_list.append('nameCommand ADVSyncSetKeyCmd command(head 200): %s' % (str(nc_cmd).replace('\n', '\\n')[:200] if nc_cmd else '<none>'))

        # Quick hint: if plain S is bound directly to the runtimeCommand name, it can be invoked and spam warnings.
        try:
            s_plain = _hotkey_query('s', alt=False, ctrl=False, shift=False) or ''
        except Exception:
            s_plain = ''
        lines_list.append('S plain boundToRuntimeCmd: %s' % str(str(s_plain) == str(rt)))

        # ScriptJobs that may be spamming warnings
        try:
            jobs = cmds.scriptJob(listJobs=True) or []
        except Exception:
            jobs = []
        sus = []
        for j in jobs:
            try:
                s = str(j)
            except Exception:
                continue
            sl = s.lower()
            if (
                ('advsyncsetkey' in sl)
                or ('setkey' in sl and 'adv' in sl)
                or ('adv_sync_autokey' in sl)
                or ('adv_sync_delete' in sl)
                or ('adv_sync' in sl and 'autokey' in sl)
                or ('adv_fast_select_runtime' in sl)
                or (u'关键帧同步模块未注册' in s)
            ):
                sus.append(s)
        lines_list.append('scriptJobs suspicious count: %d' % int(len(sus)))
        for j in sus[:80]:
            lines_list.append('  - %s' % j)

    now = datetime.datetime.now()
    lines = []
    lines.append("ADV switchRuntime Diagnose Report")
    lines.append("Time: %s" % now.strftime('%Y-%m-%d %H:%M:%S'))
    try:
        lines.append("ADV file: %s" % str(__file__))
    except Exception:
        pass
    try:
        lines.append("Maya: %s" % cmds.about(v=True))
    except Exception as e:
        lines.append("Maya: <error> %s" % str(e))
    lines.append("Python: %s" % sys.version.replace('\n', ' '))
    lines.append("Platform: %s" % str(sys.platform))
    lines.append("")

    # Paths
    try:
        user_dir = cmds.internalVar(userScriptDir=True)
        lines.append("userScriptDir: %s" % str(user_dir))
    except Exception as e:
        lines.append("userScriptDir: <error> %s" % str(e))
        user_dir = None
    lines.append("sys.path (first 40):")
    try:
        for p in (sys.path or [])[:40]:
            lines.append("  - %s" % str(p))
    except Exception:
        pass
    lines.append("")

    # Legacy SetKey interception diagnostics (source of repeated warnings)
    try:
        _dump_legacy_setkey_state(lines)
    except Exception as e:
        lines.append('legacy setkey diagnostics: <error> %s' % str(e))

    # UI state
    try:
        v = bool(cmds.checkBox(ADV_IKFK_LIVE_SYNC_CB, q=True, v=True)) if cmds.checkBox(ADV_IKFK_LIVE_SYNC_CB, exists=True) else None
        lines.append("UI realtime enabled (adv): %s" % str(v))
    except Exception as e:
        lines.append("UI realtime enabled (adv): <error> %s" % str(e))
    try:
        v = bool(cmds.checkBox(ADV_SR_LIVE_FOLLOW_CB, q=True, v=True)) if cmds.checkBox(ADV_SR_LIVE_FOLLOW_CB, exists=True) else None
        lines.append("UI follow during drag: %s" % str(v))
    except Exception as e:
        lines.append("UI follow during drag: <error> %s" % str(e))
    try:
        ov = bool(cmds.optionVar(q='switchRuntime_realtimeDuringDrag')) if cmds.optionVar(exists='switchRuntime_realtimeDuringDrag') else None
        lines.append("optionVar switchRuntime_realtimeDuringDrag: %s" % str(ov))
    except Exception as e:
        lines.append("optionVar switchRuntime_realtimeDuringDrag: <error> %s" % str(e))
    lines.append("")

    # Last errors/log
    lines.append("Last error: %s" % str(_ADV_SR_LAST_ERROR or ''))
    if _ADV_SR_LAST_TRACE:
        lines.append("Last traceback:\n%s" % str(_ADV_SR_LAST_TRACE))
    lines.append("")
    lines.append("Recent log (last 120):")
    for l in (_ADV_SR_DIAG_LOG[-120:] if _ADV_SR_DIAG_LOG else []):
        lines.append("  %s" % str(l))
    lines.append("")

    # Try import switchRuntime
    sr_tools = None
    try:
        try:
            import os
            import sys
            local_scripts = os.path.join(os.path.dirname(__file__), 'scripts')
            local_scripts = local_scripts.replace('\\', '/')
            if local_scripts and local_scripts not in sys.path:
                sys.path.insert(0, local_scripts)
        except Exception:
            pass
        switchRuntime = _adv_import_switch_runtime()
        lines.append("switchRuntime import: OK")
        try:
            lines.append("switchRuntime module file: %s" % str(getattr(switchRuntime, '__file__', '')))
        except Exception:
            pass
        try:
            # Maya 会缓存已 import 的模块；诊断时强制 reload tools 以拿到最新输出内容。
            try:
                import importlib
                importlib.reload(switchRuntime.tools)
            except Exception:
                pass
            sr_tools = switchRuntime.tools
            lines.append("switchRuntime.tools: OK")
        except Exception as e:
            lines.append("switchRuntime.tools: <error> %s" % str(e))
    except Exception as e:
        lines.append("switchRuntime import: FAILED (%s)" % str(e))
        # retry after appending user scripts dir
        try:
            if user_dir:
                if str(user_dir) not in sys.path:
                    sys.path.append(str(user_dir))
                switchRuntime = _adv_import_switch_runtime()
                lines.append("switchRuntime import (retry): OK")
                try:
                    lines.append("switchRuntime module file: %s" % str(getattr(switchRuntime, '__file__', '')))
                except Exception:
                    pass
                try:
                    sr_tools = switchRuntime.tools
                    lines.append("switchRuntime.tools (retry): OK")
                except Exception as e2:
                    lines.append("switchRuntime.tools (retry): <error> %s" % str(e2))
        except Exception as e2:
            lines.append("switchRuntime import (retry): FAILED (%s)" % str(e2))
    lines.append("")

    # If available, inline switchRuntime diagnose text WITHOUT writing its own file.
    if sr_tools:
        try:
            try:
                sr_text = sr_tools.diagnose_export(write_file=False)
            except TypeError:
                # Backward compatibility: older switchRuntime without the new arg.
                sr_text = None
            if sr_text:
                lines.append("")
                lines.append("--- switchRuntime diagnose_export content ---")
                c_lines = str(sr_text).splitlines()
                if len(c_lines) > 2500:
                    c_lines = c_lines[-2500:]
                for cl in c_lines:
                    try:
                        lines.append(cl)
                    except Exception:
                        pass
            else:
                lines.append("switchRuntime diagnose_export: <skipped/no-text>")
        except Exception as e:
            lines.append("switchRuntime diagnose_export: <error> %s" % str(e))

    # Inline key runtime info so this ADV report is self-contained.
    try:
        try:
            import os
            import sys
            local_scripts = os.path.join(os.path.dirname(__file__), 'scripts')
            local_scripts = local_scripts.replace('\\', '/')
            if local_scripts and local_scripts not in sys.path:
                sys.path.insert(0, local_scripts)
        except Exception:
            pass
        switchRuntime = _adv_import_switch_runtime()
        try:
            cb = switchRuntime.callback
            lines.append("")
            lines.append("switchRuntime.callback.CTRL: %s" % str(getattr(cb, 'CTRL', None)))
            lines.append("switchRuntime.callback.SWITCHES keys: %s" % str(len(getattr(cb, 'SWITCHES', {}) or {})))
            lines.append("switchRuntime.callback.SWITCH_INSTANCE: %s" % str(len(getattr(cb, 'SWITCH_INSTANCE', []) or [])))
            lines.append("switchRuntime.callback._CYCLECHECK_SUPPRESSED: %s" % str(getattr(cb, '_CYCLECHECK_SUPPRESSED', None)))
        except Exception as e:
            lines.append("")
            lines.append("switchRuntime callback globals: <error> %s" % str(e))

        try:
            lines.append("")
            jobs = cmds.scriptJob(listJobs=True) or []
            sr_jobs = [j for j in jobs if 'switchRuntime' in j]
            lines.append("scriptJobs containing 'switchRuntime': %d" % len(sr_jobs))
            for j in sr_jobs:
                lines.append("  - %s" % str(j))
        except Exception as e:
            lines.append("")
            lines.append("scriptJobs: <error> %s" % str(e))

        try:
            lines.append("")
            switch_sets = cmds.ls('switchRuntime*Set*', '*:switchRuntime*Set*', '*:*:switchRuntime*Set*', type='objectSet') or []
            lines.append("switchRuntime objectSets: %d" % len(switch_sets))
            for s in switch_sets:
                lines.append("\n[Set] %s" % str(s))
                try:
                    members = cmds.sets(s, q=True) or []
                    lines.append("members(%d):" % len(members))
                    for m in members:
                        lines.append("  - %s" % str(m))
                except Exception as e:
                    lines.append("members: <error> %s" % str(e))
                try:
                    attrs = cmds.listAttr(s, ud=True) or []
                    lines.append("udAttrs(%d): %s" % (len(attrs), ', '.join(attrs)))
                except Exception as e:
                    lines.append("udAttrs: <error> %s" % str(e))
        except Exception as e:
            lines.append("")
            lines.append("switchRuntime sets: <error> %s" % str(e))
    except Exception:
        pass

    # ----------------------------------------------------------------------
    # ADV IKFK live sync diagnostics (merge into the same report)
    # ----------------------------------------------------------------------
    try:
        lines.append("")
        lines.append("--- ADV IKFK Live Sync Diagnostics ---")
        try:
            lines.append("ikfk debug enabled: %s" % str(bool(cmds.optionVar(q=ADV_IKFK_DEBUG_OPTIONVAR)) if cmds.optionVar(exists=ADV_IKFK_DEBUG_OPTIONVAR) else False))
        except Exception:
            lines.append("ikfk debug enabled: <error>")
        try:
            lines.append("liveSyncEnabled: %s" % str(bool(_ADV_IKFK_LIVE_SYNC_ENABLED)))
            lines.append("liveSyncSuspend: %s" % str(bool(_ADV_IKFK_LIVE_SYNC_SUSPEND)))
        except Exception:
            pass
        try:
            lines.append("undo_state: %s" % str(bool(cmds.undoInfo(q=True, state=True))))
            lines.append("undo_stateWithoutFlush: %s" % str(bool(cmds.undoInfo(q=True, stateWithoutFlush=True))))
            lines.append("undo_queue_empty: %s" % str(bool(cmds.undoInfo(q=True, undoQueueEmpty=True))))
            lines.append("redo_queue_empty: %s" % str(bool(cmds.undoInfo(q=True, redoQueueEmpty=True))))
        except Exception:
            pass
        try:
            lines.append("selJobId: %s" % str(_ADV_IKFK_LIVE_SYNC_SEL_JOB_ID))
            lines.append("idleJobId: %s" % str(_ADV_IKFK_LIVE_SYNC_IDLE_JOB_ID))
            lines.append("undoJobId: %s" % str(_ADV_IKFK_LIVE_SYNC_UNDO_JOB_ID))
            lines.append("redoJobId: %s" % str(_ADV_IKFK_LIVE_SYNC_REDO_JOB_ID))
            lines.append("attrJobIds: %s" % str(len(_ADV_IKFK_LIVE_SYNC_ATTR_JOB_IDS or [])))
        except Exception:
            pass
        try:
            lines.append("last_error: %s" % str(_ADV_IKFK_DEBUG_LAST_ERROR or ''))
        except Exception:
            pass
        lines.append("--- ikfk debug log tail (last 160) ---")
        try:
            tail = _ADV_IKFK_DEBUG_LOG[-160:] if _ADV_IKFK_DEBUG_LOG else []
            for l in tail:
                lines.append(str(l))
        except Exception:
            pass
    except Exception:
        pass

    # ----------------------------------------------------------------------
    # Time Slider Drag diagnostics (Qt eventFilter based)
    # ----------------------------------------------------------------------
    try:
        lines.append("")
        lines.append("--- Time Slider Drag Diagnostics ---")
        try:
            p = cmds.optionVar(q='ADV_TimeSliderDragScriptPath') if cmds.optionVar(exists='ADV_TimeSliderDragScriptPath') else ''
        except Exception:
            p = ''
        lines.append("ADV_TimeSliderDragScriptPath: %s" % str(p or ''))

        try:
            import adv_time_slider_drag_runtime as _adv_ts_mod
        except Exception as e:
            _adv_ts_mod = None
            lines.append("adv_time_slider_drag_runtime import: FAILED (%s)" % str(e))

        try:
            if _adv_ts_mod is not None:
                lines.append("adv_time_slider_drag_runtime file: %s" % str(getattr(_adv_ts_mod, '__file__', '') or ''))
        except Exception:
            pass

        txt = None
        if _adv_ts_mod and hasattr(_adv_ts_mod, 'diagnose_export'):
            try:
                txt = _adv_ts_mod.diagnose_export(200)
            except Exception as e:
                lines.append("time slider diagnose_export(runtime): <error> %s" % str(e))
                txt = None
        else:
            # Fallback: load directly from the script path so diagnostics always match the enabled file.
            try:
                if p and os.path.isfile(p):
                    try:
                        import importlib.util as _iu
                        spec = _iu.spec_from_file_location('adv_time_slider_drag_diag', p)
                        mm = _iu.module_from_spec(spec)
                        spec.loader.exec_module(mm)
                        if hasattr(mm, 'diagnose_export'):
                            txt = mm.diagnose_export(200)
                    except Exception as e:
                        lines.append("time slider diagnose_export(file): <error> %s" % str(e))
            except Exception:
                pass

        if txt:
            lines.append("--- time slider diagnose_export content ---")
            c_lines = str(txt).splitlines()
            if len(c_lines) > 800:
                c_lines = c_lines[-800:]
            for cl in c_lines:
                lines.append(cl)
        else:
            lines.append("time slider diagnose_export: <missing>")
    except Exception:
        pass

    # ----------------------------------------------------------------------
    # ADV Key Sync diagnostics (SetKey intercept + AutoKey watcher)
    # ----------------------------------------------------------------------
    try:
        lines.append("")
        lines.append("--- ADV Key Sync Diagnostics ---")

        # optionVars / UI state
        try:
            if 'ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR' in globals() and cmds.optionVar(exists=ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR):
                lines.append("keySync enabled(optionVar): %s" % str(bool(cmds.optionVar(q=ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR))))
            else:
                lines.append("keySync enabled(optionVar): <missing>")
        except Exception as e:
            lines.append("keySync enabled(optionVar): <error> %s" % str(e))
        try:
            if 'ADV_SYNC_GROUPS_OPTIONVAR' in globals() and cmds.optionVar(exists=ADV_SYNC_GROUPS_OPTIONVAR):
                v = cmds.optionVar(q=ADV_SYNC_GROUPS_OPTIONVAR) or ''
                lines.append("keySync groups(optionVar) chars: %d" % int(len(str(v))))
            else:
                lines.append("keySync groups(optionVar): <missing>")
        except Exception as e:
            lines.append("keySync groups(optionVar): <error> %s" % str(e))
        try:
            if 'ADV_SYNC_UI_ENABLE_CB' in globals() and cmds.checkBox(ADV_SYNC_UI_ENABLE_CB, exists=True):
                lines.append("keySync UI checkbox: %s" % str(bool(cmds.checkBox(ADV_SYNC_UI_ENABLE_CB, q=True, v=True))))
        except Exception:
            pass

        lines.append("")
        lines.append("--- Tangent Debug Diagnostics ---")
        try:
            lines.append("tangentDebug enabled(optionVar): %s" % str(bool(cmds.optionVar(q=ADV_SYNC_TANGENT_DEBUG_OPTIONVAR)) if cmds.optionVar(exists=ADV_SYNC_TANGENT_DEBUG_OPTIONVAR) else False))
        except Exception:
            lines.append("tangentDebug enabled(optionVar): <error>")
        try:
            lines.append("tangentDebug log path: %s" % str(_adv_sync_tangent_debug_get_log_path()))
        except Exception as e:
            lines.append("tangentDebug log path: <error> %s" % str(e))
        try:
            lines.append("tangentDebug last_error: %s" % str(_ADV_SYNC_TANGENT_DEBUG_LAST_ERROR or ''))
        except Exception:
            pass
        lines.append("--- tangent debug log tail (last 160) ---")
        try:
            tail = _ADV_SYNC_TANGENT_DEBUG_LOG[-160:] if _ADV_SYNC_TANGENT_DEBUG_LOG else []
            for l in tail:
                lines.append(str(l))
            if (not tail):
                p = _adv_sync_tangent_debug_get_log_path()
                if p:
                    try:
                        with io.open(p, 'r', encoding='utf-8') as f:
                            ll = f.read().splitlines()
                    except Exception:
                        with open(p, 'r') as f:
                            ll = f.read().splitlines()
                    for l in (ll[-160:] if ll else []):
                        lines.append(str(l))
        except Exception:
            pass

        # Runtime module info
        try:
            import sys
            m = sys.modules.get('adv_fast_select_runtime')
            if m:
                lines.append("runtime module: adv_fast_select_runtime")
                try:
                    lines.append("runtime __file__: %s" % str(getattr(m, '__file__', '')))
                except Exception:
                    pass
            else:
                lines.append("runtime module: <none>")
        except Exception as e:
            lines.append("runtime module: <error> %s" % str(e))

        # AutoKey status / commandEcho
        try:
            lines.append("commandEcho(state): %s" % str(bool(cmds.commandEcho(q=True, state=True))))
        except Exception as e:
            lines.append("commandEcho(state): <error> %s" % str(e))
        try:
            # Use cached query (should not spam Script Editor)
            lines.append("AutoKey(_adv_sync_is_autokey_on): %s" % str(bool(_adv_sync_is_autokey_on())))
        except Exception as e:
            lines.append("AutoKey(_adv_sync_is_autokey_on): <error> %s" % str(e))

        # Watcher states
        try:
            lines.append("sync suspend: %s" % str(bool(globals().get('_ADV_SYNC_SUSPEND', False))))
        except Exception:
            pass
        try:
            lines.append("deleteWatch idleJobId: %s" % str(globals().get('_ADV_SYNC_DELETE_WATCH_IDLE_JOB_ID', None)))
        except Exception:
            pass
        try:
            lines.append("autokeyWatch selJobId: %s" % str(globals().get('_ADV_SYNC_AUTOKEY_WATCH_SEL_JOB_ID', None)))
            lines.append("autokeyWatch idleJobId: %s" % str(globals().get('_ADV_SYNC_AUTOKEY_WATCH_IDLE_JOB_ID', None)))
            lines.append("autokeyWatch attrJobs: %s" % str(len(globals().get('_ADV_SYNC_AUTOKEY_WATCH_ATTR_JOB_IDS', []) or [])))
            lines.append("autokey pending: %s" % str(bool(globals().get('_ADV_SYNC_AUTOKEY_PENDING', False))))
            lines.append("autokey pending nodes: %s" % str(len(globals().get('_ADV_SYNC_AUTOKEY_PENDING_NODES', []) or [])))
        except Exception:
            pass
        try:
            lines.append("undoJobId: %s" % str(globals().get('_ADV_SYNC_UNDO_JOB_ID', None)))
            lines.append("redoJobId: %s" % str(globals().get('_ADV_SYNC_REDO_JOB_ID', None)))
        except Exception:
            pass

        # Scan scriptJobs for stale/duplicate callbacks
        try:
            jobs = cmds.scriptJob(listJobs=True) or []
        except Exception:
            jobs = []
        keys = ['adv_sync', 'advsync', 'adv_fast_select_runtime', 'adv sync', 'key sync', 'autokey']
        sus = []
        for j in jobs:
            try:
                s = str(j)
            except Exception:
                continue
            sl = s.lower()
            if any(k in sl for k in keys):
                sus.append(s)
        lines.append("scriptJobs match(keySync/autokey) count: %d" % int(len(sus)))
        for j in sus[:120]:
            lines.append("  - %s" % j)
        if len(sus) > 120:
            lines.append("  ... (%d more)" % int(len(sus) - 120))
    except Exception:
        pass

    # ----------------------------------------------------------------------
    # Camera diagnostics (seamless switch / saved view cameras)
    # ----------------------------------------------------------------------
    try:
        lines.append("")
        lines.append("--- Camera Diagnostics ---")
        panel = None
        try:
            panel = _adv_get_hover_or_active_model_panel() or _adv_get_active_model_panel()
        except Exception:
            panel = None
        lines.append("active_panel: %s" % str(panel or "<none>"))
        panel_cam = None
        if panel:
            try:
                panel_cam = cmds.modelPanel(panel, q=True, camera=True) or ''
            except Exception:
                panel_cam = ''
        lines.append("active_camera: %s" % str(panel_cam or "<none>"))
        if panel_cam:
            try:
                cam_tr = panel_cam
                if cmds.nodeType(cam_tr) == 'camera':
                    p = cmds.listRelatives(cam_tr, parent=True, fullPath=True) or []
                    cam_tr = p[0] if p else cam_tr
                cam_shape = _adv_get_camera_shape(cam_tr)
                lines.append("active_camera_transform: %s" % str(cam_tr))
                lines.append("active_camera_shape: %s" % str(cam_shape or "<none>"))
                try:
                    t = cmds.xform(cam_tr, q=True, ws=True, t=True) or [0.0, 0.0, 0.0]
                    r = cmds.xform(cam_tr, q=True, ws=True, ro=True) or [0.0, 0.0, 0.0]
                    lines.append("active_camera_ws_t: %.6f, %.6f, %.6f" % (float(t[0]), float(t[1]), float(t[2])))
                    lines.append("active_camera_ws_r: %.6f, %.6f, %.6f" % (float(r[0]), float(r[1]), float(r[2])))
                except Exception as e:
                    lines.append("active_camera_xform: <error> %s" % str(e))
                if cam_shape:
                    try:
                        lines.append("active_camera_ortho: %s" % str(bool(cmds.getAttr(cam_shape + '.orthographic'))))
                    except Exception as e:
                        lines.append("active_camera_ortho: <error> %s" % str(e))
                    try:
                        if cmds.attributeQuery('orthographicWidth', node=cam_shape, exists=True):
                            lines.append("active_camera_orthographicWidth: %s" % str(cmds.getAttr(cam_shape + '.orthographicWidth')))
                    except Exception as e:
                        lines.append("active_camera_orthographicWidth: <error> %s" % str(e))
                    try:
                        if cmds.attributeQuery('centerOfInterest', node=cam_shape, exists=True):
                            lines.append("active_camera_centerOfInterest: %s" % str(cmds.getAttr(cam_shape + '.centerOfInterest')))
                    except Exception as e:
                        lines.append("active_camera_centerOfInterest: <error> %s" % str(e))
            except Exception as e:
                lines.append("active_camera_details: <error> %s" % str(e))

        # Saved ADV view camera optionVars
        try:
            ov_keys = [
                'ADV_ViewCam_ADV_View_Front',
                'ADV_ViewCam_ADV_View_Back',
                'ADV_ViewCam_ADV_View_Left',
                'ADV_ViewCam_ADV_View_Right',
                'ADV_ViewCam_ADV_View_Top',
                'ADV_ViewCam_ADV_View_Bottom',
            ]
            lines.append("saved_view_optionVars:")
            for k in ov_keys:
                try:
                    v = cmds.optionVar(q=k) if cmds.optionVar(exists=k) else ''
                except Exception:
                    v = '<error>'
                lines.append("  %s = %s" % (k, str(v)))
        except Exception:
            pass

        # Existing ADV view cameras in scene
        try:
            cams = cmds.ls('ADV_View_*', '*:ADV_View_*', type='transform', long=True) or []
            uniq = []
            seen = set()
            for c in cams:
                sc = str(c)
                if sc not in seen:
                    seen.add(sc)
                    uniq.append(sc)
            lines.append("scene_adv_view_cameras: %d" % int(len(uniq)))
            for c in uniq[:40]:
                lines.append("  [%s]" % c)
                try:
                    shp = _adv_get_camera_shape(c)
                    lines.append("    shape=%s" % str(shp or "<none>"))
                    t = cmds.xform(c, q=True, ws=True, t=True) or [0.0, 0.0, 0.0]
                    r = cmds.xform(c, q=True, ws=True, ro=True) or [0.0, 0.0, 0.0]
                    lines.append("    ws_t=%.6f, %.6f, %.6f" % (float(t[0]), float(t[1]), float(t[2])))
                    lines.append("    ws_r=%.6f, %.6f, %.6f" % (float(r[0]), float(r[1]), float(r[2])))
                    if shp:
                        try:
                            lines.append("    ortho=%s" % str(bool(cmds.getAttr(shp + '.orthographic'))))
                        except Exception:
                            lines.append("    ortho=<error>")
                        try:
                            if cmds.attributeQuery('orthographicWidth', node=shp, exists=True):
                                lines.append("    orthographicWidth=%s" % str(cmds.getAttr(shp + '.orthographicWidth')))
                        except Exception:
                            lines.append("    orthographicWidth=<error>")
                        try:
                            if cmds.attributeQuery('centerOfInterest', node=shp, exists=True):
                                lines.append("    centerOfInterest=%s" % str(cmds.getAttr(shp + '.centerOfInterest')))
                        except Exception:
                            lines.append("    centerOfInterest=<error>")
                        # Derived distance from ortho width + camera FOV.
                        try:
                            if cmds.attributeQuery('orthographicWidth', node=shp, exists=True):
                                import math
                                ow_v = float(cmds.getAttr(shp + '.orthographicWidth'))
                                focal_v = float(cmds.getAttr(shp + '.focalLength')) if cmds.attributeQuery('focalLength', node=shp, exists=True) else 35.0
                                hfa_in_v = float(cmds.getAttr(shp + '.horizontalFilmAperture')) if cmds.attributeQuery('horizontalFilmAperture', node=shp, exists=True) else 1.417
                                vfa_in_v = float(cmds.getAttr(shp + '.verticalFilmAperture')) if cmds.attributeQuery('verticalFilmAperture', node=shp, exists=True) else 0.945
                                fit_v = int(cmds.getAttr(shp + '.filmFit')) if cmds.attributeQuery('filmFit', node=shp, exists=True) else 1
                                ap_mm_v = max(1e-6, float(hfa_in_v) * 25.4)
                                fov_v = 2.0 * math.atan((ap_mm_v * 0.5) / max(1e-6, float(focal_v)))
                                dist_x_v = (float(ow_v) * 0.5) / max(1e-6, math.tan(fov_v * 0.5))
                                dist_v = dist_x_v
                                vap_mm_v = max(1e-6, float(vfa_in_v) * 25.4)
                                vfov_v = 2.0 * math.atan((vap_mm_v * 0.5) / max(1e-6, float(focal_v)))
                                cam_aspect_v = max(1e-6, ap_mm_v / max(1e-6, vap_mm_v))
                                ortho_h_v = float(ow_v) / cam_aspect_v
                                dist_y_v = (float(ortho_h_v) * 0.5) / max(1e-6, math.tan(vfov_v * 0.5))
                                if fit_v == 2:
                                    dist_v = dist_y_v
                                elif fit_v == 0:
                                    dist_v = max(dist_x_v, dist_y_v)
                                elif fit_v == 3:
                                    dist_v = min(dist_x_v, dist_y_v)
                                else:
                                    dist_v = dist_x_v
                                lines.append("    estimatedDist=%s" % str(float(dist_v)))
                                if cmds.attributeQuery('centerOfInterest', node=shp, exists=True):
                                    coi_v = float(cmds.getAttr(shp + '.centerOfInterest'))
                                    ratio_v = float(coi_v) / max(1e-6, float(dist_v))
                                    lines.append("    coiDistRatio=%s" % str(float(ratio_v)))
                        except Exception:
                            lines.append("    distDerived=<error>")
                except Exception as e:
                    lines.append("    <error> %s" % str(e))
            if len(uniq) > 40:
                lines.append("  ... (%d more)" % int(len(uniq) - 40))
        except Exception as e:
            lines.append("scene_adv_view_cameras: <error> %s" % str(e))

        # Seamless switch runtime diagnostics
        try:
            lines.append("")
            lines.append("--- Seamless View Diagnostics ---")
            try:
                lines.append("seamless_enabled: %s" % str(bool(_adv_seamless_view_switch_is_enabled(default=True))))
            except Exception as e:
                lines.append("seamless_enabled: <error> %s" % str(e))
            try:
                lines.append("seamless_debug: %s" % str(bool(_adv_sv_debug_enabled())))
            except Exception as e:
                lines.append("seamless_debug: <error> %s" % str(e))
            try:
                tail = _ADV_SV_DIAG_LOG[-120:] if _ADV_SV_DIAG_LOG else []
                lines.append("seamless_log_tail_count: %d" % int(len(tail)))
                for l in tail:
                    lines.append("  %s" % str(l))
            except Exception as e:
                lines.append("seamless_log_tail: <error> %s" % str(e))
        except Exception:
            pass
    except Exception:
        pass

    # Write file (overwrite) to ADV Fast select root dir
    out_dir = _get_adv_root_dir() or None
    if not out_dir:
        # fallback to user scripts dir
        out_dir = None
        try:
            out_dir = str(user_dir) if user_dir else None
        except Exception:
            out_dir = None
    if not out_dir:
        out_dir = os.path.join(os.path.expanduser('~'), 'Documents', 'maya', 'scripts')
    try:
        if not os.path.isdir(out_dir):
            os.makedirs(out_dir)
    except Exception:
        pass
    out_path = os.path.join(out_dir, 'ADV_All_Diagnostics.txt')
    try:
        with io.open(out_path, 'w', encoding='utf-8') as f:
            f.write('\n'.join(lines) + '\n')
    except TypeError:
        with io.open(out_path, 'w', encoding='utf-8') as f:
            f.write('\n'.join(lines) + '\n')

    try:
        cmds.inViewMessage(amg=u"诊断已导出：<hl>%s</hl>" % out_path.replace('\\', '/'), pos='midCenterTop', fade=True)
    except Exception:
        pass
    print('[ADV] diagnostics exported: %s' % out_path)
    return out_path


def _adv_ikfk_debug_undo_snapshot(tag=""):
    """Collect a best-effort snapshot of Maya Undo state for IKFK debugging."""
    snap = {
        'tag': str(tag or ''),
        'time': None,
        'ctx': None,
        'undo_state': None,
        'undo_stateWithoutFlush': None,
        'undo_infinity': None,
        'undo_queue_empty': None,
        'redo_queue_empty': None,
        'selection': None,
        'active': None,
        'liveSyncEnabled': None,
        'liveSyncSuspend': None,
    }
    try:
        snap['time'] = cmds.currentTime(q=True)
    except Exception:
        pass
    try:
        snap['ctx'] = cmds.currentCtx()
    except Exception:
        pass
    try:
        snap['undo_state'] = bool(cmds.undoInfo(q=True, state=True))
    except Exception:
        pass
    try:
        snap['undo_stateWithoutFlush'] = bool(cmds.undoInfo(q=True, stateWithoutFlush=True))
    except Exception:
        pass
    try:
        snap['undo_infinity'] = bool(cmds.undoInfo(q=True, infinity=True))
    except Exception:
        pass
    try:
        snap['undo_queue_empty'] = bool(cmds.undoInfo(q=True, undoQueueEmpty=True))
    except Exception:
        pass
    try:
        snap['redo_queue_empty'] = bool(cmds.undoInfo(q=True, redoQueueEmpty=True))
    except Exception:
        pass
    try:
        sel = cmds.ls(orderedSelection=True, long=True) or []
    except Exception:
        try:
            sel = cmds.ls(sl=True, long=True) or []
        except Exception:
            sel = []
    try:
        snap['selection'] = sel
        snap['active'] = sel[-1] if sel else None
    except Exception:
        pass
    try:
        snap['liveSyncEnabled'] = bool(_ADV_IKFK_LIVE_SYNC_ENABLED)
        snap['liveSyncSuspend'] = bool(_ADV_IKFK_LIVE_SYNC_SUSPEND)
    except Exception:
        pass
    return snap

