# Keep this short to avoid Maya showing "Undo temporarily unavailable" when the user
# hits Ctrl+Z while a custom chunk is still open.
_ADV_SYNC_ANIMBOT_FINALIZE_MAX_CHUNK_SECONDS = 0.45

# With evalDeferred(lowestPriority=True) finalize, we still keep a few passes to
# catch late animBot deferred feedback and avoid an extra "noChange" undo step.
_ADV_SYNC_ANIMBOT_FINALIZE_DEFER_PASSES = 4


def _adv_sync_animbot_finalize_tick():
    """Finalize pending animBot apply when ready (called from idle)."""
    # Safety: never keep Undo disabled for user interactions.
    # If something went wrong and Undo got stuck OFF, restore it immediately.
    try:
        # Prefer the shared helper if already defined.
        try:
            _adv_ensure_undo_enabled()
        except Exception:
            if not bool(cmds.undoInfo(q=True, state=True)):
                cmds.undoInfo(state=True)
    except Exception:
        pass
    try:
        import time
        now = time.time()
    except Exception:
        now = 0.0

    # Safety: if our outer undo chunk got stuck open, close it.
    # IMPORTANT: run this even when finalize is NOT pending (record_undo might be gated off).
    try:
        if _ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN and now and _ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN_TIME:
            if (now - float(_ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN_TIME)) > float(_ADV_SYNC_ANIMBOT_FINALIZE_MAX_CHUNK_SECONDS or 2.5):
                try:
                    cmds.undoInfo(closeChunk=True)
                except Exception:
                    pass
                _ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN = False
                _ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN_TIME = 0.0
    except Exception:
        pass

    try:
        if not _ADV_SYNC_ANIMBOT_FINALIZE_PENDING:
            return
    except Exception:
        return
    try:
        if _ADV_SYNC_ANIMBOT_FINALIZE_READY_TIME and now and (now < float(_ADV_SYNC_ANIMBOT_FINALIZE_READY_TIME)):
            return
    except Exception:
        pass
    try:
        import maya.OpenMaya as _adv_om
        if _adv_om.MGlobal.isUndoing() or _adv_om.MGlobal.isRedoing():
            return
    except Exception:
        pass
    try:
        tok = int(_ADV_SYNC_ANIMBOT_FINALIZE_TOKEN or 0)
    except Exception:
        tok = 0
    if not tok:
        return
    try:
        _adv_sync_animbot_finalize_deferred(tok)
    except Exception:
        pass


def _adv_sync_animbot_finalize_deferred(token):
    """Finalize animBot apply: capture AFTER snapshot and create marker."""
    global _ADV_SYNC_ANIMBOT_FINALIZE_PENDING
    global _ADV_SYNC_ANIMBOT_FINALIZE_TOKEN
    global _ADV_SYNC_ANIMBOT_FINALIZE_MODE, _ADV_SYNC_ANIMBOT_FINALIZE_NODES, _ADV_SYNC_ANIMBOT_FINALIZE_TIME
    global _ADV_SYNC_ANIMBOT_FINALIZE_BEFORE_SNAP
    global _ADV_SYNC_ANIMBOT_FINALIZE_PREV_UNDO_STATE, _ADV_SYNC_ANIMBOT_FINALIZE_UNDO_SUSPENDED
    global _ADV_SYNC_ANIMBOT_APPLYING
    global _ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN, _ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN_TIME
    try:
        if (not _ADV_SYNC_ANIMBOT_FINALIZE_PENDING) or (int(token) != int(_ADV_SYNC_ANIMBOT_FINALIZE_TOKEN)):
            return
    except Exception:
        return

    mode = str(_ADV_SYNC_ANIMBOT_FINALIZE_MODE or '').strip().lower()
    nodes = list(_ADV_SYNC_ANIMBOT_FINALIZE_NODES or [])
    t = _ADV_SYNC_ANIMBOT_FINALIZE_TIME
    before_snap = list(_ADV_SYNC_ANIMBOT_FINALIZE_BEFORE_SNAP or [])

    after_snap = []
    try:
        if t is not None and nodes:
            after_snap = _adv_animbot_capture_tangent_snapshot(nodes, t)
    except Exception:
        after_snap = []

    # Ensure Undo is enabled (we should not keep it disabled across frames).
    try:
        _adv_ensure_undo_enabled()
    except Exception:
        pass

    try:
        old_marker = _adv_animbot_undo_get_marker()
        if old_marker is None:
            old_marker = 0
        new_marker = int(old_marker) + 1
    except Exception:
        old_marker = 0
        new_marker = 1

    # Push entry so Undo/Redo callbacks can restore.
    try:
        global _ADV_ANIMBOT_UNDO_STACK, _ADV_ANIMBOT_UNDO_MARKER_CACHED
        _ADV_ANIMBOT_UNDO_STACK.append({
            'before_marker': int(old_marker),
            'after_marker': int(new_marker),
            'before_snap': before_snap,
            'after_snap': after_snap,
            'time': float(t) if t is not None else None,
            'mode': str(mode),
        })
        if len(_ADV_ANIMBOT_UNDO_STACK) > 40:
            del _ADV_ANIMBOT_UNDO_STACK[0:10]
    except Exception:
        pass

    # Write marker. If we have an outer chunk open, keep everything in ONE undo step.
    try:
        _adv_animbot_undo_set_marker(new_marker)
        try:
            _ADV_ANIMBOT_UNDO_MARKER_CACHED = int(new_marker)
        except Exception:
            pass
    except Exception:
        pass

    # Close our outer chunk (if any) to finalize the single undo step.
    try:
        if _ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN:
            try:
                cmds.undoInfo(closeChunk=True)
            except Exception:
                pass
            _ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN = False
            _ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN_TIME = 0.0
    except Exception:
        pass

    try:
        _adv_sync_tangent_debug_log('apply_tangent animBot undoMarker %s->%s curvesBefore=%d curvesAfter=%d' % (
            str(old_marker), str(new_marker), len(before_snap or []), len(after_snap or [])
        ))
    except Exception:
        pass

    # Clear finalize state
    _ADV_SYNC_ANIMBOT_FINALIZE_PENDING = False
    _ADV_SYNC_ANIMBOT_FINALIZE_MODE = ""
    _ADV_SYNC_ANIMBOT_FINALIZE_NODES = []
    _ADV_SYNC_ANIMBOT_FINALIZE_TIME = None
    _ADV_SYNC_ANIMBOT_FINALIZE_BEFORE_SNAP = []
    _ADV_SYNC_ANIMBOT_FINALIZE_PREV_UNDO_STATE = None
    _ADV_SYNC_ANIMBOT_FINALIZE_UNDO_SUSPENDED = False
    _ADV_SYNC_ANIMBOT_FINALIZE_READY_TIME = 0.0

    # Release applying guards
    try:
        _ADV_SYNC_ANIMBOT_APPLYING = False
    except Exception:
        pass
    try:
        globals()['_ADV_SYNC_TANGENT_WATCH_SUSPEND'] = False
    except Exception:
        pass

# animBot Undo/Redo restore can trigger attributeChange callbacks which would
# immediately queue a new animBot tangent apply and overwrite the restored tangents.
# Use a short post-undo cooldown to ignore watcher events.
_ADV_SYNC_ANIMBOT_SUSPEND_UNTIL = 0.0
_ADV_SYNC_ANIMBOT_POST_UNDO_COOLDOWN = 0.55

# animBot tangent + manipulation Undo chunk support
_ADV_SYNC_ANIMBOT_DRAGPRESS_JOB_ID = None
_ADV_SYNC_ANIMBOT_DRAGRELEASE_JOB_ID = None
_ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN = False
_ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN_TIME = 0.0
_ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME = 0.0
_ADV_SYNC_ANIMBOT_IN_DRAG = False
_ADV_SYNC_ANIMBOT_DRAG_DIRTY = False
_ADV_SYNC_ANIMBOT_DRAG_CACHED_MODE = ""
_ADV_SYNC_ANIMBOT_DRAG_CACHED_NODES = []
_ADV_SYNC_ANIMBOT_BLOCK_UNTIL_USER = False
_ADV_SYNC_ANIMBOT_IN_UNDO = False
_ADV_SYNC_ANIMBOT_UNDO_BLOCK_UNTIL = 0.0

# animBot tangent Undo/Redo support
_ADV_ANIMBOT_UNDO_MARKER_NODE = 'ADV_Sync_AnimbotUndo'
_ADV_ANIMBOT_UNDO_MARKER_ATTR = 'marker'
_ADV_ANIMBOT_UNDO_JOB_UNDO_ID = None
_ADV_ANIMBOT_UNDO_JOB_REDO_ID = None
_ADV_ANIMBOT_UNDO_STACK = []  # list of {before_marker, after_marker, before_snap, after_snap, time, mode}
_ADV_ANIMBOT_UNDO_MARKER_CACHED = None
_ADV_ANIMBOT_UNDO_APPLY_GUARD = False


def _adv_animbot_undo_ensure_node():
    """Ensure a lightweight marker node exists in-scene for animBot tangent undo."""
    try:
        prev_sel = []
        try:
            prev_sel = cmds.ls(sl=True, long=True) or []
        except Exception:
            prev_sel = []
        if cmds.objExists(_ADV_ANIMBOT_UNDO_MARKER_NODE):
            node = _ADV_ANIMBOT_UNDO_MARKER_NODE
        else:
            try:
                node = cmds.createNode('network', name=_ADV_ANIMBOT_UNDO_MARKER_NODE, skipSelect=True)
            except Exception:
                node = cmds.createNode('network', name=_ADV_ANIMBOT_UNDO_MARKER_NODE)
            try:
                if prev_sel:
                    cmds.select(prev_sel, r=True)
            except Exception:
                pass
        plug = '%s.%s' % (node, _ADV_ANIMBOT_UNDO_MARKER_ATTR)
        if not cmds.attributeQuery(_ADV_ANIMBOT_UNDO_MARKER_ATTR, node=node, exists=True):
            try:
                cmds.addAttr(node, ln=_ADV_ANIMBOT_UNDO_MARKER_ATTR, at='long')
                cmds.setAttr(plug, e=True, keyable=False, channelBox=False)
            except Exception:
                pass
        # Initialize
        try:
            if cmds.getAttr(plug) is None:
                cmds.setAttr(plug, 0)
        except Exception:
            try:
                cmds.setAttr(plug, 0)
            except Exception:
                pass
        return node
    except Exception:
        return None


def _adv_animbot_undo_get_marker():
    node = _adv_animbot_undo_ensure_node()
    if not node:
        return None
    plug = '%s.%s' % (node, _ADV_ANIMBOT_UNDO_MARKER_ATTR)
    try:
        return int(cmds.getAttr(plug))
    except Exception:
        return None


def _adv_animbot_undo_set_marker(v):
    node = _adv_animbot_undo_ensure_node()
    if not node:
        return False
    plug = '%s.%s' % (node, _ADV_ANIMBOT_UNDO_MARKER_ATTR)
    try:
        cmds.setAttr(plug, int(v))
        return True
    except Exception:
        return False


def _adv_animbot_capture_tangent_snapshot(nodes, t):
    """Capture tangent data for keys at time t on animCurves connected to nodes."""
    if not nodes or t is None:
        return []

    curves = []
    seen = set()
    for n in (nodes or []):
        if not n or (not cmds.objExists(n)):
            continue
        try:
            cs = cmds.listConnections(n, s=True, d=False, type='animCurve') or []
        except Exception:
            cs = []
        for c in cs:
            if c and c not in seen and cmds.objExists(c):
                curves.append(c)
                seen.add(c)

    snap = []
    for c in curves:
        try:
            try:
                idxs = cmds.keyframe(c, q=True, time=(t, t), indexValue=True) or []
            except Exception:
                idxs = cmds.keyframe(c, q=True, time=(t, t), iv=True) or []
        except Exception:
            idxs = []
        if not idxs:
            continue

        # curve-level weighted tangents state (best effort)
        weighted = None
        try:
            wt = cmds.keyTangent(c, q=True, weightedTangents=True)
            if isinstance(wt, (list, tuple)) and wt:
                weighted = bool(wt[0])
            elif wt is not None:
                weighted = bool(wt)
        except Exception:
            weighted = None

        keys = []
        for i in idxs:
            try:
                ii = int(i)
            except Exception:
                continue

            def _q(flag):
                try:
                    v = cmds.keyTangent(c, q=True, index=(ii, ii), **{flag: True})
                    if isinstance(v, (list, tuple)):
                        return v[0] if v else None
                    return v
                except Exception:
                    return None

            keys.append({
                'index': ii,
                'inType': _q('inTangentType'),
                'outType': _q('outTangentType'),
                'inAngle': _q('inAngle'),
                'outAngle': _q('outAngle'),
                'inWeight': _q('inWeight'),
                'outWeight': _q('outWeight'),
                'lock': _q('lock'),
                'weightLock': _q('weightLock'),
            })

        if keys:
            snap.append({'curve': c, 'weighted': weighted, 'keys': keys})
    return snap


def _adv_animbot_apply_tangent_snapshot(snapshot):
    """Restore previously captured tangent snapshot (no Undo pollution)."""
    if not snapshot:
        return
    global _ADV_SYNC_TANGENT_WATCH_SUSPEND
    _ADV_SYNC_TANGENT_WATCH_SUSPEND = True
    prev_state, suspended = _adv_undo_suspend_without_flush_begin()
    try:
        for cinfo in (snapshot or []):
            c = cinfo.get('curve')
            if not c or (not cmds.objExists(c)):
                continue

            weighted = cinfo.get('weighted', None)
            if weighted is not None:
                try:
                    cmds.keyTangent(c, e=True, weightedTangents=bool(weighted))
                except Exception:
                    pass

            for k in (cinfo.get('keys', []) or []):
                try:
                    idx = int(k.get('index'))
                except Exception:
                    continue

                # Unlock first so we can restore values.
                try:
                    cmds.keyTangent(c, e=True, index=(idx, idx), lock=False)
                except Exception:
                    pass
                try:
                    cmds.keyTangent(c, e=True, index=(idx, idx), weightLock=False)
                except Exception:
                    pass

                try:
                    in_type = k.get('inType', None)
                    out_type = k.get('outType', None)
                    if in_type is not None:
                        cmds.keyTangent(c, e=True, index=(idx, idx), inTangentType=str(in_type))
                    if out_type is not None:
                        cmds.keyTangent(c, e=True, index=(idx, idx), outTangentType=str(out_type))
                except Exception:
                    pass

                try:
                    if k.get('inAngle', None) is not None:
                        cmds.keyTangent(c, e=True, index=(idx, idx), inAngle=float(k.get('inAngle')))
                    if k.get('outAngle', None) is not None:
                        cmds.keyTangent(c, e=True, index=(idx, idx), outAngle=float(k.get('outAngle')))
                except Exception:
                    pass
                try:
                    if k.get('inWeight', None) is not None:
                        cmds.keyTangent(c, e=True, index=(idx, idx), inWeight=float(k.get('inWeight')))
                    if k.get('outWeight', None) is not None:
                        cmds.keyTangent(c, e=True, index=(idx, idx), outWeight=float(k.get('outWeight')))
                except Exception:
                    pass

                # Restore locks last.
                try:
                    if k.get('weightLock', None) is not None:
                        cmds.keyTangent(c, e=True, index=(idx, idx), weightLock=bool(k.get('weightLock')))
                except Exception:
                    pass
                try:
                    if k.get('lock', None) is not None:
                        cmds.keyTangent(c, e=True, index=(idx, idx), lock=bool(k.get('lock')))
                except Exception:
                    pass
    finally:
        _adv_undo_suspend_without_flush_end(prev_state, suspended)
        _ADV_SYNC_TANGENT_WATCH_SUSPEND = False


def _adv_animbot_undo_ensure_jobs():
    """Ensure Undo/Redo scriptJobs exist to restore animBot tangents."""
    global _ADV_ANIMBOT_UNDO_JOB_UNDO_ID, _ADV_ANIMBOT_UNDO_JOB_REDO_ID, _ADV_ANIMBOT_UNDO_MARKER_CACHED
    # Ensure marker exists + cache current marker.
    try:
        cur = _adv_animbot_undo_get_marker()
        if cur is not None:
            _ADV_ANIMBOT_UNDO_MARKER_CACHED = int(cur)
    except Exception:
        pass

    if not _ADV_ANIMBOT_UNDO_JOB_UNDO_ID:
        try:
            _ADV_ANIMBOT_UNDO_JOB_UNDO_ID = cmds.scriptJob(event=['Undo', _adv_animbot_undo_on_undo_event], protected=True)
        except Exception:
            _ADV_ANIMBOT_UNDO_JOB_UNDO_ID = None
    if not _ADV_ANIMBOT_UNDO_JOB_REDO_ID:
        try:
            _ADV_ANIMBOT_UNDO_JOB_REDO_ID = cmds.scriptJob(event=['Redo', _adv_animbot_undo_on_redo_event], protected=True)
        except Exception:
            _ADV_ANIMBOT_UNDO_JOB_REDO_ID = None


def _adv_animbot_undo_on_undo_event(*_):
    global _ADV_ANIMBOT_UNDO_MARKER_CACHED, _ADV_ANIMBOT_UNDO_APPLY_GUARD
    # Synchronously block watchers to prevent Undo-driven attribute changes from triggering logic
    try:
        import time
        g = globals()
        g['_ADV_SYNC_ANIMBOT_IN_UNDO'] = True
        g['_ADV_SYNC_ANIMBOT_BLOCK_UNTIL_USER'] = True
        now_u = time.time()
        g['_ADV_SYNC_ANIMBOT_UNDO_BLOCK_UNTIL'] = now_u + 2.0
        # Also set the master suspend flag
        g['_ADV_SYNC_ANIMBOT_SUSPEND_UNTIL'] = now_u + 2.0
        
        # [CRITICAL] Synchronously clear any pending "idle" applications.
        # If we don't clear this, a pending tangent update from BEFORE the undo
        # might execute right AFTER variables are restored, effectively undoing the Undo.
        g['_ADV_SYNC_ANIMBOT_PENDING'] = False
        g['_ADV_SYNC_TANGENT_PENDING'] = False
        g['_ADV_SYNC_ANIMBOT_PENDING_NODES'] = []
    except Exception:
        pass

    if _ADV_ANIMBOT_UNDO_APPLY_GUARD:
        return

    prev_cached = _ADV_ANIMBOT_UNDO_MARKER_CACHED

    def _adv__after_undo():
        global _ADV_ANIMBOT_UNDO_MARKER_CACHED, _ADV_ANIMBOT_UNDO_APPLY_GUARD

        if _ADV_ANIMBOT_UNDO_APPLY_GUARD:
            return

        try:
            cur = _adv_animbot_undo_get_marker()
        except Exception:
            cur = None
        if cur is None:
            return
        cur = int(cur)

        # Always suppress debounce/pending logic right after Undo.
        # Even if we don't have a matching snapshot entry, watcher/idle could
        # immediately re-queue animBot tangents and overwrite the undo result.
        try:
            g = globals()
            g['_ADV_SYNC_ANIMBOT_BLOCK_UNTIL_USER'] = True
            g['_ADV_SYNC_ANIMBOT_IN_UNDO'] = True
            g['_ADV_SYNC_TANGENT_PENDING'] = False
            g['_ADV_SYNC_TANGENT_PENDING_MODE'] = ""
            g['_ADV_SYNC_TANGENT_PENDING_NODES'] = []
            g['_ADV_SYNC_TANGENT_PENDING_TRIES'] = 0
            g['_ADV_SYNC_ANIMBOT_PENDING_TRIES'] = 0
            g['_ADV_SYNC_ANIMBOT_PENDING'] = False
            g['_ADV_SYNC_ANIMBOT_PENDING_MODE'] = ""
            g['_ADV_SYNC_ANIMBOT_PENDING_NODES'] = []
            import time
            now_u = time.time()
            post_undo = float(g.get('_ADV_SYNC_ANIMBOT_POST_UNDO_COOLDOWN', 0.0) or 0.0)
            g['_ADV_SYNC_ANIMBOT_SUSPEND_UNTIL'] = now_u + max(post_undo, 0.8)
            g['_ADV_SYNC_ANIMBOT_UNDO_BLOCK_UNTIL'] = now_u + 0.4
            g['_ADV_SYNC_TANGENT_WATCH_SELECTION_COOLDOWN_UNTIL'] = now_u + 0.8
            try:
                g['_ADV_SYNC_TANGENT_WATCH_SUSPEND'] = True
            except Exception:
                pass
            try:
                import maya.utils as _adv_maya_utils

                def _restore_watch():
                    try:
                        globals()['_ADV_SYNC_TANGENT_WATCH_SUSPEND'] = False
                    except Exception:
                        pass

                _adv_maya_utils.executeDeferred(lambda: _adv_maya_utils.executeDeferred(_restore_watch))
            except Exception:
                try:
                    g['_ADV_SYNC_TANGENT_WATCH_SUSPEND'] = False
                except Exception:
                    pass
        except Exception:
            pass

        if prev_cached is None:
            _ADV_ANIMBOT_UNDO_MARKER_CACHED = int(cur)
            try:
                _adv_sync_tangent_debug_log('animbot undo event initCache cur=%s' % str(cur))
            except Exception:
                pass
            return

        prev = int(prev_cached)
        if cur == prev:
            _ADV_ANIMBOT_UNDO_MARKER_CACHED = int(cur)
            try:
                _adv_sync_tangent_debug_log('animbot undo event noChange cur=%s' % str(cur))
            except Exception:
                pass
            return

        # If marker moved from prev -> cur, check if it matches an animBot tangent undo transition.
        entry = None
        for e in reversed(_ADV_ANIMBOT_UNDO_STACK or []):
            try:
                if int(e.get('before_marker')) == cur and int(e.get('after_marker')) == prev:
                    entry = e
                    break
            except Exception:
                continue

        _ADV_ANIMBOT_UNDO_MARKER_CACHED = int(cur)
        if not entry:
            try:
                _adv_sync_tangent_debug_log('animbot undo MISS prev=%s cur=%s stack=%d' % (str(prev), str(cur), len(_ADV_ANIMBOT_UNDO_STACK or [])))
            except Exception:
                pass
            return

        snap = entry.get('before_snap') or []
        try:
            _adv_sync_tangent_debug_log('animbot undo HIT prev=%s cur=%s mode=%s snapCurves=%d' % (str(prev), str(cur), str(entry.get('mode')), len(snap)))
        except Exception:
            pass

        try:
            _adv_sync_set_suspend(True)
        except Exception:
            pass

        # Prevent debounce/pending logic from re-applying tangents right after we restore.
        try:
            global _ADV_SYNC_TANGENT_PENDING, _ADV_SYNC_TANGENT_PENDING_MODE, _ADV_SYNC_TANGENT_PENDING_NODES
            global _ADV_SYNC_TANGENT_PENDING_TRIES, _ADV_SYNC_ANIMBOT_PENDING_TRIES
            global _ADV_SYNC_ANIMBOT_PENDING, _ADV_SYNC_ANIMBOT_PENDING_MODE, _ADV_SYNC_ANIMBOT_PENDING_NODES
            global _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL, _ADV_SYNC_ANIMBOT_POST_UNDO_COOLDOWN
            global _ADV_SYNC_TANGENT_WATCH_SUSPEND, _ADV_SYNC_TANGENT_WATCH_SELECTION_COOLDOWN_UNTIL
            global _ADV_SYNC_ANIMBOT_LAST_APPLIED_FRAME, _ADV_SYNC_ANIMBOT_LAST_APPLIED
            _ADV_SYNC_TANGENT_PENDING = False
            _ADV_SYNC_TANGENT_PENDING_MODE = ""
            _ADV_SYNC_TANGENT_PENDING_NODES = []
            _ADV_SYNC_TANGENT_PENDING_TRIES = 0
            _ADV_SYNC_ANIMBOT_PENDING_TRIES = 0
            _ADV_SYNC_ANIMBOT_PENDING = False
            _ADV_SYNC_ANIMBOT_PENDING_MODE = ""
            _ADV_SYNC_ANIMBOT_PENDING_NODES = []
            try:
                import time
                now_u = time.time()
                _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL = now_u + max(float(_ADV_SYNC_ANIMBOT_POST_UNDO_COOLDOWN), 0.8)
                _ADV_SYNC_TANGENT_WATCH_SELECTION_COOLDOWN_UNTIL = now_u + 0.8
                try:
                    _ADV_SYNC_TANGENT_WATCH_SUSPEND = True
                except Exception:
                    pass
                try:
                    mode_u = str(entry.get('mode') or '')
                    _ADV_SYNC_ANIMBOT_LAST_APPLIED[mode_u] = now_u
                    try:
                        tcur = cmds.currentTime(q=True)
                        _ADV_SYNC_ANIMBOT_LAST_APPLIED_FRAME[mode_u] = float(tcur)
                    except Exception:
                        pass
                except Exception:
                    pass
            except Exception:
                _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL = 0.0
            try:
                import maya.utils as _adv_maya_utils
                def _restore_watch():
                    try:
                        _ADV_SYNC_TANGENT_WATCH_SUSPEND = False
                    except Exception:
                        pass
                _adv_maya_utils.executeDeferred(lambda: _adv_maya_utils.executeDeferred(_restore_watch))
            except Exception:
                try:
                    _ADV_SYNC_TANGENT_WATCH_SUSPEND = False
                except Exception:
                    pass
        except Exception:
            pass

        try:
            _ADV_ANIMBOT_UNDO_APPLY_GUARD = True
            # CRITICAL: restoring tangents during Undo must NOT create a new undo step.
            # Otherwise Ctrl+Z becomes: (1) undo marker, (2) undo our restore, (3) undo move.
            prev_state_u, suspended_u = (None, False)
            try:
                prev_state_u, suspended_u = _adv_undo_suspend_without_flush_begin()
            except Exception:
                prev_state_u, suspended_u = (None, False)
            try:
                _adv_animbot_apply_tangent_snapshot(snap)
            finally:
                try:
                    _adv_undo_suspend_without_flush_end(prev_state_u, suspended_u)
                except Exception:
                    pass
            try:
                _adv_sync_tangent_debug_log('animbot undo APPLY ok curves=%d' % len(snap))
            except Exception:
                pass
        finally:
            _ADV_ANIMBOT_UNDO_APPLY_GUARD = False
            try:
                _adv_sync_set_suspend(False)
            except Exception:
                pass

    # Defer marker read + restore until after Maya finishes Undo evaluation.
    try:
        import maya.utils as _adv_maya_utils
        _adv_maya_utils.executeDeferred(_adv__after_undo)
    except Exception:
        _adv__after_undo()


def _adv_animbot_undo_on_redo_event(*_):
    global _ADV_ANIMBOT_UNDO_MARKER_CACHED, _ADV_ANIMBOT_UNDO_APPLY_GUARD
    # Synchronously block watchers
    try:
        import time
        g = globals()
        g['_ADV_SYNC_ANIMBOT_IN_UNDO'] = True
        g['_ADV_SYNC_ANIMBOT_BLOCK_UNTIL_USER'] = True
        now_u = time.time()
        g['_ADV_SYNC_ANIMBOT_UNDO_BLOCK_UNTIL'] = now_u + 2.0
        g['_ADV_SYNC_ANIMBOT_SUSPEND_UNTIL'] = now_u + 2.0
        
        # [CRITICAL] Synchronously clear pending
        g['_ADV_SYNC_ANIMBOT_PENDING'] = False
        g['_ADV_SYNC_TANGENT_PENDING'] = False
        g['_ADV_SYNC_ANIMBOT_PENDING_NODES'] = []
    except Exception:
        pass

    if _ADV_ANIMBOT_UNDO_APPLY_GUARD:
        return

    prev_cached = _ADV_ANIMBOT_UNDO_MARKER_CACHED

    def _adv__after_redo():
        global _ADV_ANIMBOT_UNDO_MARKER_CACHED, _ADV_ANIMBOT_UNDO_APPLY_GUARD

        if _ADV_ANIMBOT_UNDO_APPLY_GUARD:
            return

        try:
            cur = _adv_animbot_undo_get_marker()
        except Exception:
            cur = None
        if cur is None:
            return
        cur = int(cur)

        # Always suppress debounce/pending logic right after Redo.
        try:
            g = globals()
            g['_ADV_SYNC_ANIMBOT_BLOCK_UNTIL_USER'] = True
            g['_ADV_SYNC_ANIMBOT_IN_UNDO'] = True
            g['_ADV_SYNC_TANGENT_PENDING'] = False
            g['_ADV_SYNC_TANGENT_PENDING_MODE'] = ""
            g['_ADV_SYNC_TANGENT_PENDING_NODES'] = []
            g['_ADV_SYNC_TANGENT_PENDING_TRIES'] = 0
            g['_ADV_SYNC_ANIMBOT_PENDING_TRIES'] = 0
            g['_ADV_SYNC_ANIMBOT_PENDING'] = False
            g['_ADV_SYNC_ANIMBOT_PENDING_MODE'] = ""
            g['_ADV_SYNC_ANIMBOT_PENDING_NODES'] = []
            import time
            now_u = time.time()
            post_undo = float(g.get('_ADV_SYNC_ANIMBOT_POST_UNDO_COOLDOWN', 0.0) or 0.0)
            g['_ADV_SYNC_ANIMBOT_SUSPEND_UNTIL'] = now_u + max(post_undo, 0.8)
            g['_ADV_SYNC_ANIMBOT_UNDO_BLOCK_UNTIL'] = now_u + 0.4
            g['_ADV_SYNC_TANGENT_WATCH_SELECTION_COOLDOWN_UNTIL'] = now_u + 0.8
            try:
                g['_ADV_SYNC_TANGENT_WATCH_SUSPEND'] = True
            except Exception:
                pass
            try:
                import maya.utils as _adv_maya_utils

                def _restore_watch():
                    try:
                        globals()['_ADV_SYNC_TANGENT_WATCH_SUSPEND'] = False
                    except Exception:
                        pass

                _adv_maya_utils.executeDeferred(lambda: _adv_maya_utils.executeDeferred(_restore_watch))
            except Exception:
                try:
                    g['_ADV_SYNC_TANGENT_WATCH_SUSPEND'] = False
                except Exception:
                    pass
        except Exception:
            pass

        if prev_cached is None:
            _ADV_ANIMBOT_UNDO_MARKER_CACHED = int(cur)
            try:
                _adv_sync_tangent_debug_log('animbot redo event initCache cur=%s' % str(cur))
            except Exception:
                pass
            return

        prev = int(prev_cached)
        if cur == prev:
            _ADV_ANIMBOT_UNDO_MARKER_CACHED = int(cur)
            try:
                _adv_sync_tangent_debug_log('animbot redo event noChange cur=%s' % str(cur))
            except Exception:
                pass
            return

        entry = None
        for e in reversed(_ADV_ANIMBOT_UNDO_STACK or []):
            try:
                if int(e.get('before_marker')) == prev and int(e.get('after_marker')) == cur:
                    entry = e
                    break
            except Exception:
                continue

        _ADV_ANIMBOT_UNDO_MARKER_CACHED = int(cur)
        if not entry:
            try:
                _adv_sync_tangent_debug_log('animbot redo MISS prev=%s cur=%s stack=%d' % (str(prev), str(cur), len(_ADV_ANIMBOT_UNDO_STACK or [])))
            except Exception:
                pass
            return

        snap = entry.get('after_snap') or []
        try:
            _adv_sync_tangent_debug_log('animbot redo HIT prev=%s cur=%s mode=%s snapCurves=%d' % (str(prev), str(cur), str(entry.get('mode')), len(snap)))
        except Exception:
            pass

        try:
            _adv_sync_set_suspend(True)
        except Exception:
            pass

        try:
            global _ADV_SYNC_TANGENT_PENDING, _ADV_SYNC_TANGENT_PENDING_MODE, _ADV_SYNC_TANGENT_PENDING_NODES
            global _ADV_SYNC_TANGENT_PENDING_TRIES, _ADV_SYNC_ANIMBOT_PENDING_TRIES
            global _ADV_SYNC_ANIMBOT_PENDING, _ADV_SYNC_ANIMBOT_PENDING_MODE, _ADV_SYNC_ANIMBOT_PENDING_NODES
            global _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL, _ADV_SYNC_ANIMBOT_POST_UNDO_COOLDOWN
            global _ADV_SYNC_TANGENT_WATCH_SUSPEND, _ADV_SYNC_TANGENT_WATCH_SELECTION_COOLDOWN_UNTIL
            global _ADV_SYNC_ANIMBOT_LAST_APPLIED_FRAME, _ADV_SYNC_ANIMBOT_LAST_APPLIED
            _ADV_SYNC_TANGENT_PENDING = False
            _ADV_SYNC_TANGENT_PENDING_MODE = ""
            _ADV_SYNC_TANGENT_PENDING_NODES = []
            _ADV_SYNC_TANGENT_PENDING_TRIES = 0
            _ADV_SYNC_ANIMBOT_PENDING_TRIES = 0
            _ADV_SYNC_ANIMBOT_PENDING = False
            _ADV_SYNC_ANIMBOT_PENDING_MODE = ""
            _ADV_SYNC_ANIMBOT_PENDING_NODES = []
            try:
                import time
                now_u = time.time()
                _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL = now_u + max(float(_ADV_SYNC_ANIMBOT_POST_UNDO_COOLDOWN), 0.8)
                _ADV_SYNC_TANGENT_WATCH_SELECTION_COOLDOWN_UNTIL = now_u + 0.8
                try:
                    _ADV_SYNC_TANGENT_WATCH_SUSPEND = True
                except Exception:
                    pass
                try:
                    mode_u = str(entry.get('mode') or '')
                    _ADV_SYNC_ANIMBOT_LAST_APPLIED[mode_u] = now_u
                    try:
                        tcur = cmds.currentTime(q=True)
                        _ADV_SYNC_ANIMBOT_LAST_APPLIED_FRAME[mode_u] = float(tcur)
                    except Exception:
                        pass
                except Exception:
                    pass
            except Exception:
                _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL = 0.0
            try:
                import maya.utils as _adv_maya_utils
                def _restore_watch():
                    try:
                        _ADV_SYNC_TANGENT_WATCH_SUSPEND = False
                    except Exception:
                        pass
                _adv_maya_utils.executeDeferred(lambda: _adv_maya_utils.executeDeferred(_restore_watch))
            except Exception:
                try:
                    _ADV_SYNC_TANGENT_WATCH_SUSPEND = False
                except Exception:
                    pass
        except Exception:
            pass

        try:
            _ADV_ANIMBOT_UNDO_APPLY_GUARD = True
            # CRITICAL: restoring tangents during Redo must NOT create a new undo step.
            prev_state_u, suspended_u = (None, False)
            try:
                prev_state_u, suspended_u = _adv_undo_suspend_without_flush_begin()
            except Exception:
                prev_state_u, suspended_u = (None, False)
            try:
                _adv_animbot_apply_tangent_snapshot(snap)
            finally:
                try:
                    _adv_undo_suspend_without_flush_end(prev_state_u, suspended_u)
                except Exception:
                    pass
            try:
                _adv_sync_tangent_debug_log('animbot redo APPLY ok curves=%d' % len(snap))
            except Exception:
                pass
        finally:
            _ADV_ANIMBOT_UNDO_APPLY_GUARD = False
            try:
                _adv_sync_set_suspend(False)
            except Exception:
                pass

    try:
        import maya.utils as _adv_maya_utils
        _adv_maya_utils.executeDeferred(_adv__after_redo)
    except Exception:
        _adv__after_redo()

# Retry counters for cases where AutoKey writes keys slightly later than our idle tick.
_ADV_SYNC_TANGENT_PENDING_TRIES = 0
_ADV_SYNC_ANIMBOT_PENDING_TRIES = 0

# Non-animbot tangent debounce: apply once after manipulation settles
_ADV_SYNC_TANGENT_PENDING = False
_ADV_SYNC_TANGENT_PENDING_MODE = ""
_ADV_SYNC_TANGENT_PENDING_NODES = []
_ADV_SYNC_TANGENT_LAST_CHANGE_TIME = 0.0
# Keep this reasonably high so we don't run heavy key/tangent ops mid-drag.
_ADV_SYNC_TANGENT_DEBOUNCE_SECONDS = 0.22
_ADV_SYNC_TANGENT_LAST_APPLIED = {}  # mode -> last time (frame)


def _adv_sync_has_keys_at_time(nodes, t):
    """Return True if any of the given nodes has a key at time t.

    IMPORTANT: This must NOT change object/key selection, otherwise it can
    interfere with viewport manipulation.
    """
    if not nodes or t is None:
        return False
    try:
        kc = cmds.keyframe(nodes, q=True, time=(t, t), kc=True)
        if kc is None:
            return False
        if isinstance(kc, (list, tuple)):
            for x in kc:
                try:
                    if int(x or 0) > 0:
                        return True
                except Exception:
                    continue
            return False
        try:
            return int(kc or 0) > 0
        except Exception:
            return bool(kc)
    except Exception:
        # Fallback per node
        for n in (nodes or []):
            try:
                kc2 = cmds.keyframe(n, q=True, time=(t, t), kc=True)
                if kc2 is None:
                    continue
                if isinstance(kc2, (list, tuple)):
                    for x in kc2:
                        try:
                            if int(x or 0) > 0:
                                return True
                        except Exception:
                            continue
                else:
                    try:
                        if int(kc2 or 0) > 0:
                            return True
                    except Exception:
                        if kc2:
                            return True
            except Exception:
                continue
        return False


def _adv_ui_popup_animbot_missing(mode=""):
    msg_cn = u"未检测到 animBot 插件，无法使用该切线：%s" % (str(mode) or "")
    msg_en = "animBot not found; tangent unavailable: %s" % (str(mode) or "")
    try:
        cmds.confirmDialog(
            title=(u"提示" if LANGUAGE == 'CN' else "Notice"),
            message=(msg_cn if LANGUAGE == 'CN' else msg_en),
            button=[u"确定" if LANGUAGE == 'CN' else "OK"],
            defaultButton=(u"确定" if LANGUAGE == 'CN' else "OK"),
        )
    except Exception:
        try:
            cmds.warning(msg_cn if LANGUAGE == 'CN' else msg_en)
        except Exception:
            pass


def _adv_ikfk_debug_enabled():
    # Unified diagnostics switch: controlled by IKFK Sync "Record Diag" checkbox.
    try:
        return bool(_adv_sync_tangent_debug_enabled())
    except Exception:
        pass
    # Fallback for legacy behavior.
    try:
        return bool(cmds.optionVar(q=ADV_IKFK_DEBUG_OPTIONVAR)) if cmds.optionVar(exists=ADV_IKFK_DEBUG_OPTIONVAR) else False
    except Exception:
        return False


def _adv_ikfk_debug_log(msg):
    if not _adv_ikfk_debug_enabled():
        return
    try:
        import time
        ts = time.strftime('%Y-%m-%d %H:%M:%S')
    except Exception:
        ts = ""
    line = "[%s] %s" % (ts, msg)
    _ADV_IKFK_DEBUG_LOG.append(line)
    if len(_ADV_IKFK_DEBUG_LOG) > 400:
        del _ADV_IKFK_DEBUG_LOG[0:150]


def _adv_ikfk_ws_ro(node):
    """Return rounded world-space Euler rotation tuple for logging."""
    if not node or (not cmds.objExists(node)):
        return None
    try:
        ro = cmds.xform(node, q=True, ws=True, ro=True)
        if ro and len(ro) >= 3:
            return (round(float(ro[0]), 4), round(float(ro[1]), 4), round(float(ro[2]), 4))
    except Exception:
        return None
    return None


def _adv_ikfk_debug_probe(namespace, limb_type, side, active_node=None, reason=""):
    """Log whether IKX/FK pairs are changing during manipulation.

    This helps diagnose cases where IK controls move but IKX joints don't update until mouse release.
    """
    if not _adv_ikfk_debug_enabled():
        return
    ns = str(namespace or "")
    limb_type = str(limb_type or "")
    side = str(side or "")
    if limb_type not in ('arm', 'leg') or side not in ('L', 'R'):
        return

    # Throttle to avoid log spam
    global _ADV_IKFK_DEBUG_PROBE_LAST_TIME
    try:
        import time
        now = time.time()
    except Exception:
        now = 0.0
    try:
        if now and (now - float(_ADV_IKFK_DEBUG_PROBE_LAST_TIME)) < 0.12:
            return
        _ADV_IKFK_DEBUG_PROBE_LAST_TIME = now
    except Exception:
        pass

    ik_token = 'Arm' if limb_type == 'arm' else 'Leg'
    control_curve = ns + 'FKIK' + ik_token + '_' + side
    start_joint = middle_joint = end_joint = ''
    if cmds.objExists(control_curve):
        try:
            start_joint = cmds.getAttr(control_curve + '.startJoint') or ''
            middle_joint = cmds.getAttr(control_curve + '.middleJoint') or ''
            end_joint = cmds.getAttr(control_curve + '.endJoint') or ''
        except Exception:
            start_joint = middle_joint = end_joint = ''

    # If meta isn't available, still attempt legacy probes.
    suf = '_' + side
    joints = []
    if start_joint and middle_joint and end_joint:
        joints = [start_joint, middle_joint, end_joint]
    else:
        joints = ['Hip', 'Knee', 'Ankle'] if limb_type == 'leg' else ['Shoulder', 'Elbow', 'Wrist']

    pairs = []
    for j in joints:
        pairs.append((ns + 'IKX' + j + suf, ns + 'FK' + j + suf))

    try:
        ctx = cmds.currentCtx()
    except Exception:
        ctx = None

    active_short = None
    if active_node:
        try:
            active_short = str(active_node).split('|')[-1]
        except Exception:
            active_short = str(active_node)

    # Collect rotations and detect changes vs last probe
    global _ADV_IKFK_DEBUG_PROBE_LAST
    changed_any = False
    parts = []
    for src, dst in pairs:
        src_ro = _adv_ikfk_ws_ro(src)
        dst_ro = _adv_ikfk_ws_ro(dst)
        key = (src, dst)
        prev = _ADV_IKFK_DEBUG_PROBE_LAST.get(key)
        cur = (src_ro, dst_ro)
        if prev != cur:
            changed_any = True
        _ADV_IKFK_DEBUG_PROBE_LAST[key] = cur
        parts.append('%s->%s src_ro=%s dst_ro=%s' % (src.split('|')[-1], dst.split('|')[-1], str(src_ro), str(dst_ro)))

    # Only log when something changes, or when explicitly requested by reason.
    if (not changed_any) and (not reason):
        return
    _adv_ikfk_debug_log('probe %s limb=%s side=%s ns=%s active=%s ctx=%s changed=%s | %s' % (
        (reason or 'tick'), limb_type, side, ns, str(active_short), str(ctx), int(bool(changed_any)), ' ; '.join(parts)
    ))


