def _adv_ikfk_node_info(node):
    """Return a compact dict of node status for diagnostics."""
    info = {
        'node': node,
        'exists': False,
        'rotateLocked': None,
        'translateLocked': None,
        'rotateIncoming': [],
        'translateIncoming': [],
        'rotateOrder': None,
    }
    if not node:
        return info
    try:
        info['exists'] = bool(cmds.objExists(node))
    except Exception:
        info['exists'] = False
    if not info['exists']:
        return info
    try:
        info['rotateOrder'] = cmds.getAttr(node + '.rotateOrder')
    except Exception:
        pass
    try:
        info['rotateLocked'] = bool(cmds.getAttr(node + '.rotateX', l=True)) or bool(cmds.getAttr(node + '.rotateY', l=True)) or bool(cmds.getAttr(node + '.rotateZ', l=True))
    except Exception:
        pass
    try:
        info['translateLocked'] = bool(cmds.getAttr(node + '.translateX', l=True)) or bool(cmds.getAttr(node + '.translateY', l=True)) or bool(cmds.getAttr(node + '.translateZ', l=True))
    except Exception:
        pass
    try:
        info['rotateIncoming'] = cmds.listConnections(node + '.rotate', s=True, d=False, p=True) or []
    except Exception:
        pass
    try:
        info['translateIncoming'] = cmds.listConnections(node + '.translate', s=True, d=False, p=True) or []
    except Exception:
        pass
    return info


def _adv_ikfk_meta_info(namespace, limb_type, side):
    """Collect FKIK meta (asAlignFKIK-style) for a limb for diagnostics/logging."""
    ns = str(namespace or "")
    limb_type = str(limb_type or "")
    side = str(side or "")
    ik_token = 'Arm' if limb_type == 'arm' else 'Leg'
    control_curve = ns + 'FKIK' + ik_token + '_' + side
    pole_curve = ns + 'Pole' + ik_token + '_' + side
    out = {
        'control_curve': control_curve,
        'control_curve_exists': False,
        'pole_curve': pole_curve,
        'pole_curve_exists': False,
        'startJoint': '',
        'middleJoint': '',
        'endJoint': '',
        'align_pairs': [],
    }

    try:
        out['control_curve_exists'] = bool(cmds.objExists(control_curve))
    except Exception:
        out['control_curve_exists'] = False
    try:
        out['pole_curve_exists'] = bool(cmds.objExists(pole_curve))
    except Exception:
        out['pole_curve_exists'] = False

    if out['control_curve_exists']:
        try:
            out['startJoint'] = cmds.getAttr(control_curve + '.startJoint') or ''
        except Exception:
            pass
        try:
            out['middleJoint'] = cmds.getAttr(control_curve + '.middleJoint') or ''
        except Exception:
            pass
        try:
            out['endJoint'] = cmds.getAttr(control_curve + '.endJoint') or ''
        except Exception:
            pass

    if out['startJoint'] and out['middleJoint'] and out['endJoint']:
        suf = '_' + side
        pairs = []
        for j in (out['startJoint'], out['middleJoint'], out['endJoint']):
            src = ns + 'IKX' + j + suf
            dst = ns + 'FK' + j + suf
            try:
                src_exists = bool(cmds.objExists(src))
            except Exception:
                src_exists = False
            try:
                dst_exists = bool(cmds.objExists(dst))
            except Exception:
                dst_exists = False
            pairs.append({'src': src, 'dst': dst, 'src_exists': src_exists, 'dst_exists': dst_exists})
        out['align_pairs'] = pairs

    return out


