def _adv_sync_set_switchruntime_perf_diag(enabled):
    """Enable/disable switchRuntime realtime perf diagnostics (Script Editor stats)."""
    v = bool(enabled)
    try:
        switchRuntime = _adv_import_switch_runtime()
        tools = getattr(switchRuntime, 'tools', None)
        if tools and hasattr(tools, 'set_perf_diag_enabled'):
            tools.set_perf_diag_enabled(v)
            if v and hasattr(tools, 'reset_perf_diag'):
                try:
                    tools.reset_perf_diag()
                except Exception:
                    pass
            return True
    except Exception:
        pass
    try:
        cmds.optionVar(intValue=('switchRuntime_perfDiag', 1 if v else 0))
    except Exception:
        pass
    return False


def _adv_sync_select_keys_at_time(nodes, t):
    """Select keys (Graph Editor key selection) on node attrs at a given time.

    Returns approximate count of plugs that had keys at time t (not exact key count).
    """
    if not nodes:
        return 0

    # Some Maya setups will emit "select -cl" as a side-effect of selectKey(clear=True).
    # To avoid clearing object selection, we DO NOT call selectKey(clear=True) here.
    # Instead, we use replace=True on the first selection and add=True afterwards.
    # Preserve object selection to avoid breaking manipulation workflows.
    prev_obj_sel = []
    try:
        prev_obj_sel = cmds.ls(sl=True, long=True) or []
    except Exception:
        prev_obj_sel = []

    # Prefer selecting by connected animCurves.
    # Reason: many rigs lock/hide channels, so listAttr(k/cb) may not include
    # keyed attributes even though keys exist; animBot then sees no selected keys.
    try:
        plugs_to_select = []
        seen_plugs = set()
        for node in (nodes or []):
            if not node or (not cmds.objExists(node)):
                continue
            try:
                curves = cmds.listConnections(node, s=True, d=False, type='animCurve') or []
            except Exception:
                curves = []
            if not curves:
                continue
            for c in curves:
                if not c or (not cmds.objExists(c)):
                    continue
                # Skip conversion nodes so we reach the real animated plug.
                try:
                    dst_plugs = cmds.listConnections(c, s=False, d=True, plugs=True, skipConversionNodes=True) or []
                except Exception:
                    try:
                        dst_plugs = cmds.listConnections(c, s=False, d=True, p=True) or []
                    except Exception:
                        dst_plugs = []
                for p in dst_plugs:
                    if not p or ('.' not in str(p)):
                        continue
                    # Keep only plugs on this node when possible.
                    if not str(p).startswith(str(node) + '.'):
                        continue
                    if p in seen_plugs:
                        continue
                    seen_plugs.add(p)
                    plugs_to_select.append(p)

        if plugs_to_select:
            plugs_with_keys = 0
            first = True
            for plug in plugs_to_select:
                try:
                    kc = cmds.keyframe(plug, q=True, time=(t, t), kc=True)
                except Exception:
                    kc = 0
                if not kc:
                    continue
                try:
                    if first:
                        cmds.selectKey(plug, r=True, keyframe=True, time=(t, t))
                        first = False
                    else:
                        cmds.selectKey(plug, add=True, keyframe=True, time=(t, t))
                    plugs_with_keys += 1
                except Exception:
                    try:
                        if first:
                            mel.eval('selectKey -r -k -t %s %s;' % (str(t), plug))
                            first = False
                        else:
                            mel.eval('selectKey -add -k -t %s %s;' % (str(t), plug))
                        plugs_with_keys += 1
                    except Exception:
                        pass

            if plugs_with_keys > 0:
                try:
                    if prev_obj_sel:
                        cmds.select(prev_obj_sel, r=True)
                except Exception:
                    pass
                return plugs_with_keys
    except Exception:
        pass

    plugs_with_keys = 0
    first = True
    for node in nodes:
        if not node or not cmds.objExists(node):
            continue
        try:
            keyable = cmds.listAttr(node, k=True) or []
        except Exception:
            keyable = []
        try:
            cb = cmds.listAttr(node, cb=True) or []
        except Exception:
            cb = []
        attrs = list(set(keyable + cb))
        for attr in attrs:
            plug = '%s.%s' % (node, attr)
            try:
                kc = cmds.keyframe(plug, q=True, time=(t, t), kc=True)
            except Exception:
                kc = 0
            if not kc:
                continue
            try:
                if first:
                    cmds.selectKey(plug, r=True, keyframe=True, time=(t, t))
                    first = False
                else:
                    cmds.selectKey(plug, add=True, keyframe=True, time=(t, t))
                plugs_with_keys += 1
            except Exception:
                # Fallback to MEL-style selection if needed
                try:
                    if first:
                        mel.eval('selectKey -r -k -t %s %s;' % (str(t), plug))
                        first = False
                    else:
                        mel.eval('selectKey -add -k -t %s %s;' % (str(t), plug))
                    plugs_with_keys += 1
                except Exception:
                    pass
    try:
        if prev_obj_sel:
            cmds.select(prev_obj_sel, r=True)
    except Exception:
        pass
    return plugs_with_keys


