def adv_sync_set_tangent_debug_enabled(enabled, *_):
    try:
        v = 1 if bool(enabled) else 0
        try:
            cmds.optionVar(intValue=(ADV_SYNC_TANGENT_DEBUG_OPTIONVAR, int(v)))
        except Exception:
            pass
        # Keep diagnostics switches unified with the same UI checkbox.
        try:
            cmds.optionVar(intValue=(ADV_IKFK_DEBUG_OPTIONVAR, int(v)))
        except Exception:
            pass
        try:
            cmds.optionVar(intValue=(_ADV_SEAMLESS_VIEW_SWITCH_DEBUG_OPTIONVAR, int(v)))
        except Exception:
            pass

        if cmds.checkBox(ADV_TANGENT_DEBUG_CB, exists=True):
            try:
                cmds.checkBox(ADV_TANGENT_DEBUG_CB, e=True, v=bool(v))
            except Exception:
                pass

        try:
            _adv_sync_set_switchruntime_perf_diag(bool(v))
        except Exception:
            pass

        if bool(v):
            try:
                del _ADV_SYNC_TANGENT_DEBUG_LOG[:]
            except Exception:
                pass
            try:
                del _ADV_IKFK_DEBUG_LOG[:]
            except Exception:
                pass
            try:
                del _ADV_SV_DIAG_LOG[:]
            except Exception:
                pass
            try:
                p = _adv_sync_tangent_debug_get_log_path()
                if p:
                    with io.open(p, 'w', encoding='utf-8') as f:
                        f.write("ADV Tangent Debug Log\n")
            except Exception as e:
                try:
                    globals()['_ADV_SYNC_TANGENT_DEBUG_LAST_ERROR'] = str(e)
                except Exception:
                    pass
            try:
                _adv_sync_tangent_debug_log("debug enabled")
            except Exception:
                pass
            try:
                _adv_ikfk_debug_log("debug enabled")
            except Exception:
                pass
        else:
            try:
                _adv_sync_tangent_debug_log("debug disabled")
            except Exception:
                pass
    except Exception:
        pass
    return

_ADV_IKFK_LIVE_SYNC_ENABLED = False
_ADV_IKFK_LIVE_SYNC_SEL_JOB_ID = None
_ADV_IKFK_LIVE_SYNC_ATTR_JOB_IDS = []
_ADV_IKFK_LIVE_SYNC_GUARD = False
_ADV_IKFK_LIVE_SYNC_SUSPEND = False
_ADV_IKFK_LIVE_SYNC_UNDO_JOB_ID = None
_ADV_IKFK_LIVE_SYNC_REDO_JOB_ID = None
_ADV_IKFK_ALIGN_GUARD = False
_ADV_IKFK_LIVE_SYNC_IDLE_JOB_ID = None
_ADV_IKFK_LIVE_SYNC_IDLE_LAST = {}
_ADV_IKFK_LIVE_SYNC_IDLE_LAST_CALL = 0.0
_ADV_IKFK_LIVE_SYNC_IDLE_MIN_INTERVAL = 0.05
_ADV_IKFK_LIVE_SYNC_GLOBAL_DIRTY = False
_ADV_IKFK_LIVE_SYNC_GLOBAL_NS = ""
_ADV_IKFK_LIVE_SYNC_GLOBAL_LAST_ALIGN_TIME = 0.0
_ADV_IKFK_LIVE_SYNC_WATCH_NODES = []
_ADV_IKFK_LIVE_SYNC_PERIODIC_LAST_ALIGN = {}
_ADV_IKFK_LIVE_SYNC_PERIODIC_MIN_INTERVAL = 0.08
_ADV_IKFK_LIVE_SYNC_LAST_ACTIVE = None

# Treat "SuperContext" as only *actively dragging* when we saw recent movement.
_ADV_IKFK_LIVE_SYNC_LAST_ACTIVITY_TIME = 0.0
_ADV_IKFK_LIVE_SYNC_ACTIVITY_WINDOW = 0.25

# Extra guard for Undo/Redo so live sync doesn't immediately re-apply alignment.
_ADV_IKFK_LIVE_SYNC_SUSPEND_UNTIL = 0.0

# Post-Undo/Redo write-block window. Even after suspend ends, we may still see
# delayed DG/eval updates that would trigger live-sync alignment and overwrite Undo.
_ADV_IKFK_LIVE_SYNC_BLOCK_UNTIL = 0.0

# Flag to indicate we need to re-prime threshold baselines after block expires.
_ADV_IKFK_LIVE_SYNC_REPRIME_PENDING = False

# Flag to track if we were in SuperContext and need to align on release.
_ADV_IKFK_LIVE_SYNC_WAS_IN_SUPERCONTEXT = False
_ADV_IKFK_LIVE_SYNC_SUPERCONTEXT_PENDING_ALIGN = {}  # {(ns, limb_type, side, driver): True}
_ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_SCHEDULED = False
_ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_COUNT = 0
_ADV_IKFK_LIVE_SYNC_DRAG_UNDO_CHUNK_OPEN = False  # Track if we opened an Undo chunk for dragging

# Undo chunk coalescing for live-sync align writes.
_ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_OPEN = False
_ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_LAST_TOUCH = 0.0

# Prevent stacking multiple executeDeferred resume loops.
_ADV_IKFK_LIVE_SYNC_RESUME_DEFERRED = False


def _adv_live_sync_schedule_release_check():
    """Schedule a fast check for SuperContext release using executeDeferred."""
    global _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_SCHEDULED, _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_COUNT
    if _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_SCHEDULED:
        return
    # Reset counter each time a new drag session schedules a check.
    _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_COUNT = 0
    _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_SCHEDULED = True
    try:
        import maya.utils as _adv_maya_utils
        _adv_maya_utils.executeDeferred(_adv_live_sync_check_release)
    except Exception:
        _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_SCHEDULED = False


def _adv_live_sync_check_release(*_):
    """Check if SuperContext has ended and execute pending alignments."""
    global _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_SCHEDULED
    global _ADV_IKFK_LIVE_SYNC_WAS_IN_SUPERCONTEXT, _ADV_IKFK_LIVE_SYNC_SUPERCONTEXT_PENDING_ALIGN
    global _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_COUNT

    _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_SCHEDULED = False

    if not _ADV_IKFK_LIVE_SYNC_SUPERCONTEXT_PENDING_ALIGN:
        _ADV_IKFK_LIVE_SYNC_WAS_IN_SUPERCONTEXT = False
        _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_COUNT = 0
        return

    # Check if still in SuperContext.
    still_in_super = False
    try:
        cur_ctx = cmds.currentCtx()
        if cur_ctx and ('SuperContext' in str(cur_ctx)):
            still_in_super = True
    except Exception:
        pass

    # Increment counter each check.
    _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_COUNT += 1

    # If still in SuperContext and haven't waited too long, keep waiting.
    # Add a timeout (20 checks) to prevent infinite waiting if SuperContext detection is unreliable.
    if still_in_super and _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_COUNT < 20:
        _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_SCHEDULED = True
        try:
            import maya.utils as _adv_maya_utils
            _adv_maya_utils.executeDeferred(_adv_live_sync_check_release)
        except Exception:
            _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_SCHEDULED = False
        return

    # Not in SuperContext anymore (or timeout) - user released. Execute alignment.
    _ADV_IKFK_LIVE_SYNC_WAS_IN_SUPERCONTEXT = False
    _ADV_IKFK_LIVE_SYNC_RELEASE_CHECK_COUNT = 0
    pending = dict(_ADV_IKFK_LIVE_SYNC_SUPERCONTEXT_PENDING_ALIGN)
    _ADV_IKFK_LIVE_SYNC_SUPERCONTEXT_PENDING_ALIGN.clear()

    if pending:
        if _adv_ikfk_debug_enabled():
            try:
                _adv_ikfk_debug_log('release_align count=%d' % len(pending))
            except Exception:
                pass
        
        # Execute alignment with Undo DISABLED so it doesn't create extra Undo steps.
        # User only needs to undo their drag - alignment will re-sync automatically.
        undo_was_on = True
        try:
            undo_was_on = cmds.undoInfo(q=True, state=True)
        except Exception:
            pass
        
        try:
            for (pns, plimb, pside, pdriver) in pending.keys():
                try:
                    # In FK mode, fk_to_ik_align doesn't need mode switch (FK bones are already valid).
                    # In IK mode, ik_to_fk_align doesn't need mode switch (IK solver is already valid).
                    # Only need temp switch when:
                    #   - driver='ik' but mode=FK (need IK solver to be valid to read IK positions)
                    #   - driver='fk' but mode=IK (need FK bones to be valid to read FK positions)
                    sw = pns + ("FKIKArm_" if plimb == 'arm' else "FKIKLeg_") + pside
                    prev_blend = None
                    need_target = None
                    
                    if cmds.objExists(sw) and cmds.attributeQuery('FKIKBlend', node=sw, exists=True):
                        prev_blend = float(cmds.getAttr(sw + '.FKIKBlend'))
                        # Only need to switch when driver doesn't match current mode
                        if pdriver == 'ik' and prev_blend <= 0.5:
                            # IK drives but we're in FK mode - need to temp switch to IK for valid IK positions
                            need_target = 10.0
                        # Note: When pdriver='fk' and mode=IK, FK bones might not be in valid positions,
                        # but we're aligning IK TO FK, so we read FK rotations (which are always readable).
                        # The IK controls will be set, which works regardless of mode.
                    
                    if need_target is not None:
                        cmds.setAttr(sw + '.FKIKBlend', need_target)
                    
                    try:
                        if pdriver == 'ik':
                            ik_to_fk_align(pns, plimb, pside)
                        elif pdriver == 'fk':
                            fk_to_ik_align(pns, plimb, pside)
                    finally:
                        if need_target is not None and prev_blend is not None:
                            try:
                                cmds.setAttr(sw + '.FKIKBlend', prev_blend)
                            except Exception:
                                pass
                except Exception:
                    pass
        finally:
            # Restore Undo state.
            if undo_was_on:
                try:
                    try:
                        cmds.undoInfo(stateWithoutFlush=True)
                    except Exception:
                        pass
                    cmds.undoInfo(state=True)
                except Exception:
                    pass


def _adv_live_sync_undo_chunk_touch(close_delay=0.20):
    """Open (if needed) an undo chunk to coalesce live-sync writes.

    The goal is to reduce the number of Undo presses needed by grouping repeated
    align operations into a single undoable step when they occur outside Maya's
    native manipulation chunk.
    """
    global _ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_OPEN, _ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_LAST_TOUCH
    try:
        import time
        now = time.time()
    except Exception:
        now = 0.0

    # If a transform SuperContext is active, Maya typically wraps manipulations
    # in its own undo chunk. Opening our own chunk there can create extra Undo steps.
    try:
        cur_ctx = cmds.currentCtx()
        if cur_ctx and ('SuperContext' in str(cur_ctx)):
            return
    except Exception:
        pass

    if not _ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_OPEN:
        try:
            cmds.undoInfo(openChunk=True)
            _ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_OPEN = True
            if _adv_ikfk_debug_enabled():
                try:
                    _adv_ikfk_debug_log('undo_chunk open')
                except Exception:
                    pass
        except Exception:
            _ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_OPEN = False

    try:
        _ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_LAST_TOUCH = float(now or 0.0)
    except Exception:
        _ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_LAST_TOUCH = 0.0

    def _try_close():
        global _ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_OPEN, _ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_LAST_TOUCH
        if not _ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_OPEN:
            return
        try:
            import time
            now2 = time.time()
        except Exception:
            now2 = 0.0
        try:
            last = float(_ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_LAST_TOUCH or 0.0)
        except Exception:
            last = 0.0
        try:
            if now2 and last and (now2 - last) < float(close_delay or 0.0):
                import maya.utils as _adv_maya_utils
                _adv_maya_utils.executeDeferred(_try_close)
                return
        except Exception:
            pass
        _adv_live_sync_undo_chunk_force_close(reason='deferred')

    try:
        import maya.utils as _adv_maya_utils
        _adv_maya_utils.executeDeferred(_try_close)
    except Exception:
        try:
            _try_close()
        except Exception:
            pass


def _adv_live_sync_undo_chunk_force_close(reason=''):
    global _ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_OPEN
    if not _ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_OPEN:
        return
    try:
        cmds.undoInfo(closeChunk=True)
    except Exception:
        pass
    _ADV_IKFK_LIVE_SYNC_UNDO_CHUNK_OPEN = False
    if _adv_ikfk_debug_enabled():
        try:
            _adv_ikfk_debug_log('undo_chunk close reason=%s' % str(reason or ''))
        except Exception:
            pass


def _adv_live_sync_suspend_for(seconds=0.45, reason=""):
    """Suspend IKFK live sync for a short time window (used for Undo/Redo safety)."""
    global _ADV_IKFK_LIVE_SYNC_SUSPEND_UNTIL, _ADV_IKFK_LIVE_SYNC_LAST_ACTIVITY_TIME, _ADV_IKFK_LIVE_SYNC_BLOCK_UNTIL, _ADV_IKFK_LIVE_SYNC_REPRIME_PENDING
    try:
        import time
        now = time.time()
    except Exception:
        now = 0.0
    try:
        _ADV_IKFK_LIVE_SYNC_SUSPEND_UNTIL = float(now) + float(seconds or 0.0)
    except Exception:
        _ADV_IKFK_LIVE_SYNC_SUSPEND_UNTIL = 0.0

    # Extend a bit beyond suspend to avoid "resume -> immediate align" from late updates.
    try:
        extra = 0.80
        _ADV_IKFK_LIVE_SYNC_BLOCK_UNTIL = max(float(_ADV_IKFK_LIVE_SYNC_BLOCK_UNTIL or 0.0), float(now) + float(seconds or 0.0) + float(extra))
    except Exception:
        try:
            _ADV_IKFK_LIVE_SYNC_BLOCK_UNTIL = 0.0
        except Exception:
            pass

    # Mark that we need to re-prime threshold baselines after block expires.
    _ADV_IKFK_LIVE_SYNC_REPRIME_PENDING = True

    # Close any pending undo chunk before suspending.
    try:
        _adv_live_sync_undo_chunk_force_close(reason='suspend')
    except Exception:
        pass

    _ADV_IKFK_LIVE_SYNC_LAST_ACTIVITY_TIME = 0.0
    _adv_live_sync_set_suspend(True)
    try:
        if _adv_ikfk_debug_enabled():
            _adv_ikfk_debug_log('live_sync_suspend_for %.3fs reason=%s' % (float(seconds or 0.0), str(reason or '')))
            try:
                _adv_ikfk_debug_log('live_sync_block_until %.3f (+%.2fs)' % (float(_ADV_IKFK_LIVE_SYNC_BLOCK_UNTIL or 0.0), float(extra)))
            except Exception:
                pass
    except Exception:
        pass


def _adv_live_sync_try_resume_after_suspend(*_):
    """Deferred resume that waits until the suspend window expires."""
    global _ADV_IKFK_LIVE_SYNC_SUSPEND_UNTIL, _ADV_IKFK_LIVE_SYNC_RESUME_DEFERRED
    try:
        import time
        now = time.time()
    except Exception:
        now = 0.0
    try:
        until = float(_ADV_IKFK_LIVE_SYNC_SUSPEND_UNTIL or 0.0)
    except Exception:
        until = 0.0
    if now and until and now < until:
        try:
            import maya.utils as _adv_maya_utils
            _adv_maya_utils.executeDeferred(_adv_live_sync_try_resume_after_suspend)
        except Exception:
            pass
        return
    _ADV_IKFK_LIVE_SYNC_SUSPEND_UNTIL = 0.0
    _ADV_IKFK_LIVE_SYNC_RESUME_DEFERRED = False
    _adv_live_sync_resume_and_rebuild()

# Threshold-driven live sync (SuperContext only)
# Some rigs don't expose continuously-changing IKX transforms during drag.
# We can instead trigger alignment based on the user's controller movement.
_ADV_IKFK_LIVE_SYNC_THRESHOLD_T_OPTIONVAR = 'ADV_IKFK_LIVE_SYNC_thresholdTranslate'
_ADV_IKFK_LIVE_SYNC_THRESHOLD_R_OPTIONVAR = 'ADV_IKFK_LIVE_SYNC_thresholdRotate'
_ADV_IKFK_LIVE_SYNC_THRESHOLD_MIN_INTERVAL_OPTIONVAR = 'ADV_IKFK_LIVE_SYNC_thresholdMinInterval'

_ADV_IKFK_LIVE_SYNC_THRESHOLD_LAST_SAMPLE = {}
_ADV_IKFK_LIVE_SYNC_THRESHOLD_LAST_FIRE = {}

# Anti-jitter: record time of last successful align to impose a cooldown
# This prevents align -> position change -> re-detect -> re-align loop
_ADV_IKFK_LIVE_SYNC_LAST_ALIGN_TIME = {}
_ADV_IKFK_LIVE_SYNC_ALIGN_COOLDOWN = 0.10  # 100ms cooldown to prevent jitter during drag

# Evaluation Manager override (SuperContext only)
_ADV_IKFK_EM_OVERRIDE_ACTIVE = False
_ADV_IKFK_EM_OVERRIDE_PREV_MODE = None
_ADV_IKFK_EM_OVERRIDE_LAST_MANIP_TIME = 0.0
_ADV_IKFK_EM_OVERRIDE_RESTORE_DELAY = 0.6
_ADV_IKFK_EM_OVERRIDE_TARGET_MODE = 'off'  # 'off' ~= DG (often more interactive-stable)


def _adv_em_get_mode():
    try:
        m = cmds.evaluationManager(q=True, mode=True)
        if isinstance(m, (list, tuple)) and m:
            return str(m[0])
        return str(m) if m is not None else None
    except Exception:
        return None


def _adv_em_set_mode(mode):
    if not mode:
        return False
    try:
        cmds.evaluationManager(mode=str(mode))
        return True
    except Exception:
        try:
            mel.eval('evaluationManager -mode "%s";' % str(mode))
            return True
        except Exception:
            return False


def _adv_em_override_update(is_manipulating, now_time):
    """If user is manipulating, switch EM mode to DG/off; restore after manipulation ends."""
    global _ADV_IKFK_EM_OVERRIDE_ACTIVE, _ADV_IKFK_EM_OVERRIDE_PREV_MODE, _ADV_IKFK_EM_OVERRIDE_LAST_MANIP_TIME

    try:
        now_time = float(now_time or 0.0)
    except Exception:
        now_time = 0.0

    if is_manipulating and now_time:
        _ADV_IKFK_EM_OVERRIDE_LAST_MANIP_TIME = now_time

    # Begin override once per manipulation session.
    if is_manipulating and (not _ADV_IKFK_EM_OVERRIDE_ACTIVE):
        prev = _adv_em_get_mode()
        # Only override when in parallel/serial (leave already-off mode as-is).
        if prev and str(prev).lower() != str(_ADV_IKFK_EM_OVERRIDE_TARGET_MODE).lower():
            ok = _adv_em_set_mode(_ADV_IKFK_EM_OVERRIDE_TARGET_MODE)
            if ok:
                _ADV_IKFK_EM_OVERRIDE_PREV_MODE = prev
                _ADV_IKFK_EM_OVERRIDE_ACTIVE = True
                if _adv_ikfk_debug_enabled():
                    _adv_ikfk_debug_log('em_override_begin prev=%s new=%s' % (str(prev), str(_ADV_IKFK_EM_OVERRIDE_TARGET_MODE)))

    # Restore after a small delay once manipulation ends.
    if (not is_manipulating) and _ADV_IKFK_EM_OVERRIDE_ACTIVE and now_time:
        try:
            dt = now_time - float(_ADV_IKFK_EM_OVERRIDE_LAST_MANIP_TIME or 0.0)
        except Exception:
            dt = 0.0
        if dt >= float(_ADV_IKFK_EM_OVERRIDE_RESTORE_DELAY):
            prev_mode = _ADV_IKFK_EM_OVERRIDE_PREV_MODE
            if prev_mode:
                ok2 = _adv_em_set_mode(prev_mode)
                if _adv_ikfk_debug_enabled():
                    _adv_ikfk_debug_log('em_override_restore prev=%s ok=%s' % (str(prev_mode), int(bool(ok2))))
            _ADV_IKFK_EM_OVERRIDE_ACTIVE = False
            _ADV_IKFK_EM_OVERRIDE_PREV_MODE = None


def _adv_live_sync_force_evaluate(namespace, limb_type, side, active=None, watch_nodes=None):
    """Try to force graph evaluation during interactive manipulation.

    Some rigs (especially in EM parallel) can return stale IKX transforms during SuperContext
    until mouse release. We try a lightweight pulse:
    - invalidate evaluation cache (if supported)
    - touch IKX worldMatrix to request an eval
    - optionally force a refresh
    All wrapped in try/except to avoid breaking user sessions.
    """
    ns = str(namespace or "")
    limb_type = str(limb_type or "")
    side = str(side or "")

    # 1) Invalidate evaluation cache if Maya supports it.
    try:
        cmds.evaluationManager(invalidate=True)
    except Exception:
        try:
            mel.eval('evaluationManager -invalidate;')
        except Exception:
            pass

    # 2) Touch a few matrices to encourage evaluation.
    try:
        meta = _adv_ikfk_meta_info(ns, limb_type, side)
        pairs = meta.get('align_pairs') or []
        for p in pairs:
            try:
                src = p.get('src')
            except Exception:
                src = None
            if not src or (not cmds.objExists(src)):
                continue
            try:
                cmds.getAttr(src + '.worldMatrix[0]')
            except Exception:
                pass
    except Exception:
        pass

    # Touch active / watch nodes too (can help on some rigs).
    for n in (watch_nodes or []):
        try:
            if n and cmds.objExists(n):
                cmds.getAttr(n + '.worldMatrix[0]')
        except Exception:
            pass
    try:
        if active and cmds.objExists(active):
            cmds.getAttr(active + '.worldMatrix[0]')
    except Exception:
        pass

    # 3) Force refresh (throttled by caller) to push updates to viewport/eval.
    try:
        cmds.refresh(force=True)
    except Exception:
        pass


def _adv_live_sync_get_watch_nodes(active, limb_type, side, max_parents=3):
    """Return a small list of nodes to watch for changes while manipulating.

    Problem this solves:
    Some rigs drive IK via offset/extra parent groups. User selects IKLeg_L, but
    the actual animated transform during drag can be IKExtraLeg_L/IKOffsetLeg_L.
    Watching only the selected leaf misses real-time changes.
    """
    nodes = []
    if not active:
        return nodes
    try:
        if cmds.objExists(active):
            nodes.append(active)
    except Exception:
        return nodes

    # Walk up a few parents and include likely offset/extra groups.
    side_token = '_' + str(side or '') if side else ''
    # NOTE: Do NOT require names to contain 'Arm'/'Leg'.
    # Many ADV rigs use FKOffsetWrist_L / FKExtraWrist_L etc which don't include the limb token.
    cur = active
    for _ in range(int(max_parents) if max_parents is not None else 0):
        try:
            parent = (cmds.listRelatives(cur, parent=True, fullPath=True) or [None])[0]
        except Exception:
            parent = None
        if not parent or (not cmds.objExists(parent)):
            break
        cur = parent
        short = parent.split('|')[-1]

        # Heuristics: include common ADV offset/extra groups above FK/IK controls.
        s = short
        if side_token and (side_token not in s):
            continue

        # Match both IK and FK offset/extra patterns.
        if ('Offset' in s) or ('Extra' in s) or ('IKHandle' in s) or ('FKSystem' in s) or ('IKSystem' in s):
            nodes.append(parent)
        else:
            # Keep climbing a bit, but don't add unrelated parents.
            continue

    # de-dup, preserve order
    out = []
    seen = set()
    for n in nodes:
        if not n or (n in seen):
            continue
        seen.add(n)
        out.append(n)
    return out


def _adv_live_sync_world_sig(node):
    """Return a comparable signature for a node's world transform."""
    if not node or not cmds.objExists(node):
        return None
    try:
        m = cmds.xform(node, q=True, ws=True, m=True)
        if m and len(m) == 16:
            return tuple([round(float(v), 6) for v in m])
    except Exception:
        pass
    # Fallback to TR
    try:
        t = cmds.getAttr(node + '.translate')[0]
    except Exception:
        t = (0.0, 0.0, 0.0)
    try:
        r = cmds.getAttr(node + '.rotate')[0]
    except Exception:
        r = (0.0, 0.0, 0.0)
    return (round(float(t[0]), 6), round(float(t[1]), 6), round(float(t[2]), 6), round(float(r[0]), 6), round(float(r[1]), 6), round(float(r[2]), 6))


def _adv_live_sync_get_thresholds():
    """Return (translate_threshold, rotate_threshold, min_interval).

    Defaults are chosen to balance responsiveness with stability:
    - translate: 0.3 scene unit (responsive but not jittery)
    - rotate: 0.8 degree
    - min_interval: 0.04s (25Hz max)
    """
    t_th = 0.3
    r_th = 0.8
    min_int = 0.04
    try:
        if cmds.optionVar(exists=_ADV_IKFK_LIVE_SYNC_THRESHOLD_T_OPTIONVAR):
            t_th = float(cmds.optionVar(q=_ADV_IKFK_LIVE_SYNC_THRESHOLD_T_OPTIONVAR))
    except Exception:
        pass
    try:
        if cmds.optionVar(exists=_ADV_IKFK_LIVE_SYNC_THRESHOLD_R_OPTIONVAR):
            r_th = float(cmds.optionVar(q=_ADV_IKFK_LIVE_SYNC_THRESHOLD_R_OPTIONVAR))
    except Exception:
        pass
    try:
        if cmds.optionVar(exists=_ADV_IKFK_LIVE_SYNC_THRESHOLD_MIN_INTERVAL_OPTIONVAR):
            min_int = float(cmds.optionVar(q=_ADV_IKFK_LIVE_SYNC_THRESHOLD_MIN_INTERVAL_OPTIONVAR))
    except Exception:
        pass

    # Safety clamps
    try:
        t_th = max(0.0, float(t_th))
    except Exception:
        t_th = 1.0
    try:
        r_th = max(0.0, float(r_th))
    except Exception:
        r_th = 1.0
    try:
        min_int = max(0.0, float(min_int))
    except Exception:
        min_int = 0.02
    return t_th, r_th, min_int


def _adv_live_sync_angle_delta_deg(a, b):
    """Smallest angular delta in degrees between two Euler component values."""
    try:
        d = float(a) - float(b)
    except Exception:
        return 0.0
    # wrap into [-180, 180]
    try:
        d = (d + 180.0) % 360.0 - 180.0
    except Exception:
        pass
    return abs(float(d))


def _adv_live_sync_vec_len3(v):
    try:
        x, y, z = float(v[0]), float(v[1]), float(v[2])
    except Exception:
        return 0.0
    return (x * x + y * y + z * z) ** 0.5


def _adv_live_sync_get_world_tr(node):
    if not node or (not cmds.objExists(node)):
        return None, None
    try:
        t = cmds.xform(node, q=True, ws=True, t=True)
    except Exception:
        t = None
    try:
        r = cmds.xform(node, q=True, ws=True, ro=True)
    except Exception:
        r = None
    if not t or len(t) < 3:
        t = None
    else:
        t = (float(t[0]), float(t[1]), float(t[2]))
    if not r or len(r) < 3:
        r = None
    else:
        r = (float(r[0]), float(r[1]), float(r[2]))
    return t, r


def _adv_live_sync_threshold_fire_key(namespace, limb_type, side, driver, active_short):
    return (str(namespace or ''), str(limb_type or ''), str(side or ''), str(driver or ''), str(active_short or ''))


def _adv_live_sync_set_suspend(v):
    global _ADV_IKFK_LIVE_SYNC_SUSPEND
    _ADV_IKFK_LIVE_SYNC_SUSPEND = bool(v)


def _adv_live_sync_resume_and_rebuild(*_):
    """Resume live sync and rebuild attribute jobs (safe to call deferred)."""
    _adv_live_sync_set_suspend(False)
    try:
        _adv_live_sync_rebuild_jobs()

        # IMPORTANT:
        # After Undo/Redo we may have cleared movement caches. If caches are empty,
        # the next idle tick will treat "prev_sig is None" as a change and align immediately,
        # which can overwrite the freshly-undone pose.
        # Prime caches from the current active selection so idle sees a stable baseline.
        try:
            _adv_live_sync_prime_caches_from_active(reason='resume')
        except Exception:
            pass

        # IMPORTANT: do not force-align right after Undo/Redo.
        # It can re-apply transforms and make Undo appear broken.
        try:
            if _adv_ikfk_debug_enabled():
                _adv_ikfk_debug_log('resume_and_rebuild (no force-align)')
        except Exception:
            pass
    except Exception:
        pass


def _adv_live_sync_prime_caches_for_limb(namespace, limb_type, side):
    """Refresh all threshold/idle caches for a specific limb after alignment.
    
    This prevents alignment-caused position changes from being detected as new movement,
    which would cause jitter (FK->IK align changes IK pos -> detected as IK movement -> IK->FK align -> jitter).
    """
    if not limb_type or not side:
        return
    
    ns = str(namespace or '')
    
    # Get all controllers for this limb and update their caches.
    ik_ctrls = []
    fk_ctrls = []
    
    try:
        if limb_type == 'arm':
            ik_ctrls = [
                ns + 'IKArm_' + side,
                ns + 'PoleArm_' + side,
            ]
            fk_ctrls = [
                ns + 'FKShoulder_' + side,
                ns + 'FKElbow_' + side,
                ns + 'FKWrist_' + side,
            ]
        else:  # leg
            ik_ctrls = [
                ns + 'IKLeg_' + side,
                ns + 'PoleLeg_' + side,
            ]
            fk_ctrls = [
                ns + 'FKHip_' + side,
                ns + 'FKKnee_' + side,
                ns + 'FKAnkle_' + side,
            ]
    except Exception:
        pass
    
    all_ctrls = ik_ctrls + fk_ctrls
    
    # Update world signature cache.
    for ctrl in all_ctrls:
        try:
            if cmds.objExists(ctrl):
                sig = _adv_live_sync_world_sig(ctrl)
                if sig is not None:
                    _ADV_IKFK_LIVE_SYNC_IDLE_LAST[ctrl] = sig
        except Exception:
            pass
    
    # Update threshold sample cache for both IK and FK.
    try:
        import time
        now = time.time()
    except Exception:
        now = 0.0
    
    for driver in ('ik', 'fk'):
        ctrls = ik_ctrls if driver == 'ik' else fk_ctrls
        for ctrl in ctrls:
            try:
                if cmds.objExists(ctrl):
                    ctrl_short = ctrl.split('|')[-1]
                    t_cur, r_cur = _adv_live_sync_get_world_tr(ctrl)
                    key_thr = _adv_live_sync_threshold_fire_key(ns, limb_type, side, driver, ctrl_short)
                    _ADV_IKFK_LIVE_SYNC_THRESHOLD_LAST_SAMPLE[key_thr] = (t_cur, r_cur)
                    if now:
                        _ADV_IKFK_LIVE_SYNC_THRESHOLD_LAST_FIRE[key_thr] = now
            except Exception:
                pass
    
    # Update periodic last align time.
    if now:
        try:
            for d in ('ik', 'fk'):
                key = (ns, str(limb_type), str(side), d)
                _ADV_IKFK_LIVE_SYNC_PERIODIC_LAST_ALIGN[key] = now
        except Exception:
            pass


def _adv_live_sync_prime_caches_from_active(reason=''):
    """Prime idle/threshold/periodic caches based on current active selection.

    This is used after Undo/Redo suspend windows so live-sync doesn't immediately
    treat empty caches as "movement" and write transforms back.
    """
    global _ADV_IKFK_LIVE_SYNC_LAST_ACTIVITY_TIME
    if not _ADV_IKFK_LIVE_SYNC_ENABLED:
        return
    if _ADV_IKFK_LIVE_SYNC_SUSPEND:
        return

    try:
        sel = cmds.ls(orderedSelection=True, long=True) or []
    except Exception:
        sel = cmds.ls(sl=True, long=True) or []
    if not sel:
        return
    active = sel[-1]
    if not active or (not cmds.objExists(active)):
        return

    active_short = active.split('|')[-1]
    short_name = get_controller_name_without_namespace(active)
    limb_type, side = _adv_parse_limb_from_ctrl(short_name)
    if not limb_type or not side:
        return
    ns = _adv_get_namespace_from_node(active)

    # Determine a reasonable driver baseline (not in active dragging mode).
    driver_from_mode = None
    try:
        switch_ctrl = ns + ("FKIKArm_" if limb_type == 'arm' else "FKIKLeg_") + side
        if cmds.objExists(switch_ctrl) and cmds.attributeQuery('FKIKBlend', node=switch_ctrl, exists=True):
            st, _bv, _mx = _adv_fkik_state_from_ctrl_robust(switch_ctrl)
            if st in ('FK', 'IK'):
                driver_from_mode = 'ik' if st == 'IK' else 'fk'
    except Exception:
        driver_from_mode = None

    driver = driver_from_mode

    # Prime world-signature cache for watch nodes.
    try:
        watch_nodes = _adv_live_sync_get_watch_nodes(active, limb_type, side, max_parents=3)
    except Exception:
        watch_nodes = None
    if not watch_nodes:
        watch_nodes = [active]
    if active not in watch_nodes:
        watch_nodes = list(watch_nodes) + [active]

    for n in watch_nodes:
        try:
            sig = _adv_live_sync_world_sig(n)
            if sig is not None:
                _ADV_IKFK_LIVE_SYNC_IDLE_LAST[n] = sig
        except Exception:
            pass

    # Prevent immediate periodic/threshold fires after resume.
    try:
        import time
        now = time.time()
    except Exception:
        now = 0.0

    try:
        _ADV_IKFK_LIVE_SYNC_LAST_ACTIVITY_TIME = 0.0
    except Exception:
        pass

    if now:
        try:
            for d in ('ik', 'fk'):
                key = (str(ns or ""), str(limb_type or ""), str(side or ""), str(d))
                _ADV_IKFK_LIVE_SYNC_PERIODIC_LAST_ALIGN[key] = now
        except Exception:
            pass

        if driver in ('ik', 'fk'):
            try:
                t_cur, r_cur = _adv_live_sync_get_world_tr(active)
                key_thr = _adv_live_sync_threshold_fire_key(ns, limb_type, side, driver, active_short)
                _ADV_IKFK_LIVE_SYNC_THRESHOLD_LAST_SAMPLE[key_thr] = (t_cur, r_cur)
                _ADV_IKFK_LIVE_SYNC_THRESHOLD_LAST_FIRE[key_thr] = now
            except Exception:
                pass

    if _adv_ikfk_debug_enabled():
        try:
            _adv_ikfk_debug_log('prime_caches reason=%s active=%s limb=%s side=%s ns=%s driver=%s watch=%s' % (
                str(reason or ''), str(active_short), str(limb_type), str(side), str(ns or ''), str(driver or ''),
                str([w.split('|')[-1] for w in (watch_nodes or [])])
            ))
        except Exception:
            pass


def _adv_live_sync_force_align_active():
    """Force a one-shot align based on current active selection.

    Used after Undo/Redo where we temporarily suspend live sync.
    """
    if not _ADV_IKFK_LIVE_SYNC_ENABLED:
        return
    if _ADV_IKFK_LIVE_SYNC_SUSPEND:
        return
    try:
        sel = cmds.ls(orderedSelection=True, long=True) or []
    except Exception:
        sel = cmds.ls(sl=True, long=True) or []
    if not sel:
        return
    active = sel[-1]
    active_short = active.split('|')[-1]
    short_name = get_controller_name_without_namespace(active)
    limb_type, side = _adv_parse_limb_from_ctrl(short_name)
    if not limb_type or not side:
        return
    ns = _adv_get_namespace_from_node(active)
    _, fk_nodes, ik_nodes = _adv_get_nodes_for_limb(ns, limb_type, side)
    fk_set = set([n.split('|')[-1] for n in fk_nodes])
    ik_set = set([n.split('|')[-1] for n in ik_nodes])
    driver = None
    if active_short in ik_set:
        driver = 'ik'
    elif active_short in fk_set:
        driver = 'fk'
    else:
        # Fallback: check if control name matches known IK/FK patterns.
        sn = short_name
        if any(p in sn for p in ('IK', 'Pole', 'Roll', 'IKToes')):
            driver = 'ik'
        elif any(p in sn for p in ('FK',)):
            driver = 'fk'
    if not driver:
        return
    _adv_live_sync_on_change(ns, limb_type, side, driver)


def _adv_is_global_mover_ctrl(ctrl_name):
    """Return True if the controller name looks like a global mover (COG/body/pelvis/root).

    These controls can move the whole character without directly moving limb IK/FK controls.
    We treat them as triggers to refresh IKFK alignment for arms/legs.
    """
    n = str(ctrl_name or "").lower()
    if not n:
        return False
    keys = (
        'cog', 'center', 'main', 'root', 'global',
        'body', 'pelvis', 'hip', 'hips', 'spine', 'chest',
    )
    return any(k in n for k in keys)


def _adv_live_sync_mark_global_dirty(namespace, *_):
    """Mark that a global mover changed; alignment will run once in idle tick."""
    global _ADV_IKFK_LIVE_SYNC_GLOBAL_DIRTY, _ADV_IKFK_LIVE_SYNC_GLOBAL_NS
    if not _ADV_IKFK_LIVE_SYNC_ENABLED:
        return
    if _ADV_IKFK_LIVE_SYNC_SUSPEND:
        return
    _ADV_IKFK_LIVE_SYNC_GLOBAL_DIRTY = True
    _ADV_IKFK_LIVE_SYNC_GLOBAL_NS = str(namespace or "")


def _adv_live_sync_force_align_all(namespace):
    """Align all limbs (arm/leg L/R) based on FKIKBlend.

    Used when moving global controls (COG/body/pelvis) so hands/feet keep following.
    """
    if not _ADV_IKFK_LIVE_SYNC_ENABLED:
        return
    if _ADV_IKFK_LIVE_SYNC_SUSPEND:
        return
    # Namespace can be empty for many rigs; treat '' as valid.
    ns = str(namespace or "")

    # Avoid recursion: this may move IK/FK controls which can fire attributeChange.
    global _ADV_IKFK_LIVE_SYNC_GUARD
    if _ADV_IKFK_LIVE_SYNC_GUARD:
        return
    _ADV_IKFK_LIVE_SYNC_GUARD = True
    try:
        # NOTE: Do NOT disable Undo here. Disabling Undo inside an attributeChange/idle callback
        # can prevent the animator's transform edits from being recorded, making Undo stop working.
        for limb_type in ('arm', 'leg'):
            for side in ('L', 'R'):
                switch_ctrl = ns + ("FKIKArm_" if limb_type == 'arm' else "FKIKLeg_") + side
                if not cmds.objExists(switch_ctrl):
                    continue
                st, blend_value, _mx = _adv_fkik_state_from_ctrl_robust(switch_ctrl)
                if st not in ('FK', 'IK'):
                    continue
                driver = 'ik' if st == 'IK' else 'fk'

                try:
                    if driver == 'ik':
                        ok = ik_to_fk_align(ns, limb_type, side)
                    else:
                        ok = fk_to_ik_align(ns, limb_type, side)
                except Exception:
                    ok = None
                if _adv_ikfk_debug_enabled():
                    _adv_ikfk_debug_log('global_align limb=%s side=%s ns=%s driver=%s blend=%s ok=%s' % (limb_type, side, ns, driver, str(blend_value), str(ok)))
                    if ok in (False, None):
                        try:
                            _adv_ikfk_debug_log('global_align_meta limb=%s side=%s meta=%s' % (limb_type, side, str(_adv_ikfk_meta_info(ns, limb_type, side))))
                        except Exception:
                            pass
    finally:
        _ADV_IKFK_LIVE_SYNC_GUARD = False


def _adv_live_sync_suspend_briefly(*_):
    """Suspend live sync briefly (used for Undo/Redo events)."""
    try:
        if _adv_ikfk_debug_enabled():
            global _ADV_IKFK_DEBUG_LAST_UNDO_SNAPSHOT
            _ADV_IKFK_DEBUG_LAST_UNDO_SNAPSHOT = _adv_ikfk_debug_undo_snapshot('UndoRedoEvent')
            _adv_ikfk_debug_log('undo_redo_event snapshot=%s' % str(_ADV_IKFK_DEBUG_LAST_UNDO_SNAPSHOT))
    except Exception:
        pass
    _adv_live_sync_suspend_for(0.45, reason='UndoRedo')

    # Clear movement caches so we don't treat post-Undo state changes as active dragging.
    try:
        _ADV_IKFK_LIVE_SYNC_IDLE_LAST.clear()
    except Exception:
        pass
    try:
        _ADV_IKFK_LIVE_SYNC_THRESHOLD_LAST_SAMPLE.clear()
        _ADV_IKFK_LIVE_SYNC_THRESHOLD_LAST_FIRE.clear()
    except Exception:
        pass
    try:
        _ADV_IKFK_LIVE_SYNC_PERIODIC_LAST_ALIGN.clear()
    except Exception:
        pass
    # Clear align cooldown cache so post-Undo align is not blocked.
    try:
        _ADV_IKFK_LIVE_SYNC_LAST_ALIGN_TIME.clear()
    except Exception:
        pass

    global _ADV_IKFK_LIVE_SYNC_RESUME_DEFERRED
    if not _ADV_IKFK_LIVE_SYNC_RESUME_DEFERRED:
        _ADV_IKFK_LIVE_SYNC_RESUME_DEFERRED = True
        try:
            import maya.utils as _adv_maya_utils
            _adv_maya_utils.executeDeferred(_adv_live_sync_try_resume_after_suspend)
        except Exception:
            _adv_live_sync_try_resume_after_suspend()


def _adv_live_sync_on_undo_event(*_):
    try:
        if _adv_ikfk_debug_enabled():
            global _ADV_IKFK_DEBUG_LAST_UNDO_SNAPSHOT
            _ADV_IKFK_DEBUG_LAST_UNDO_SNAPSHOT = _adv_ikfk_debug_undo_snapshot('Undo')
            _adv_ikfk_debug_log('undo_event snapshot=%s' % str(_ADV_IKFK_DEBUG_LAST_UNDO_SNAPSHOT))
    except Exception:
        pass
    _adv_live_sync_suspend_briefly()


def _adv_live_sync_on_redo_event(*_):
    try:
        if _adv_ikfk_debug_enabled():
            global _ADV_IKFK_DEBUG_LAST_REDO_SNAPSHOT
            _ADV_IKFK_DEBUG_LAST_REDO_SNAPSHOT = _adv_ikfk_debug_undo_snapshot('Redo')
            _adv_ikfk_debug_log('redo_event snapshot=%s' % str(_ADV_IKFK_DEBUG_LAST_REDO_SNAPSHOT))
    except Exception:
        pass
    _adv_live_sync_suspend_briefly()


def _adv_live_sync_clear_attr_jobs():
    global _ADV_IKFK_LIVE_SYNC_ATTR_JOB_IDS
    if not _ADV_IKFK_LIVE_SYNC_ATTR_JOB_IDS:
        return
    for jid in list(_ADV_IKFK_LIVE_SYNC_ATTR_JOB_IDS):
        try:
            if cmds.scriptJob(exists=jid):
                cmds.scriptJob(kill=jid, force=True)
        except Exception:
            pass
    _ADV_IKFK_LIVE_SYNC_ATTR_JOB_IDS = []


def _adv_live_sync_clear_jobs():
    """Kill all live-sync jobs."""
    global _ADV_IKFK_LIVE_SYNC_SEL_JOB_ID, _ADV_IKFK_LIVE_SYNC_UNDO_JOB_ID, _ADV_IKFK_LIVE_SYNC_REDO_JOB_ID, _ADV_IKFK_LIVE_SYNC_IDLE_JOB_ID
    _adv_live_sync_clear_attr_jobs()
    try:
        if _ADV_IKFK_LIVE_SYNC_SEL_JOB_ID and cmds.scriptJob(exists=_ADV_IKFK_LIVE_SYNC_SEL_JOB_ID):
            cmds.scriptJob(kill=_ADV_IKFK_LIVE_SYNC_SEL_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_IKFK_LIVE_SYNC_SEL_JOB_ID = None

    try:
        if _ADV_IKFK_LIVE_SYNC_UNDO_JOB_ID and cmds.scriptJob(exists=_ADV_IKFK_LIVE_SYNC_UNDO_JOB_ID):
            cmds.scriptJob(kill=_ADV_IKFK_LIVE_SYNC_UNDO_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_IKFK_LIVE_SYNC_UNDO_JOB_ID = None

    try:
        if _ADV_IKFK_LIVE_SYNC_REDO_JOB_ID and cmds.scriptJob(exists=_ADV_IKFK_LIVE_SYNC_REDO_JOB_ID):
            cmds.scriptJob(kill=_ADV_IKFK_LIVE_SYNC_REDO_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_IKFK_LIVE_SYNC_REDO_JOB_ID = None

    try:
        if _ADV_IKFK_LIVE_SYNC_IDLE_JOB_ID and cmds.scriptJob(exists=_ADV_IKFK_LIVE_SYNC_IDLE_JOB_ID):
            cmds.scriptJob(kill=_ADV_IKFK_LIVE_SYNC_IDLE_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_IKFK_LIVE_SYNC_IDLE_JOB_ID = None

    try:
        _ADV_IKFK_LIVE_SYNC_IDLE_LAST.clear()
    except Exception:
        pass

    _adv_live_sync_set_suspend(False)


def _adv_live_sync_on_change(namespace, limb_type, side, driver, source_node=None):
    """Callback for attributeChange: match the opposite side."""
    global _ADV_IKFK_LIVE_SYNC_GUARD, _ADV_IKFK_LIVE_SYNC_LAST_ALIGN_TIME
    if _ADV_IKFK_LIVE_SYNC_SUSPEND:
        return

    # In SuperContext (dragging), do NOT execute alignment to avoid jitter.
    # Record pending align and schedule release detection.
    global _ADV_IKFK_LIVE_SYNC_WAS_IN_SUPERCONTEXT, _ADV_IKFK_LIVE_SYNC_SUPERCONTEXT_PENDING_ALIGN
    in_super_context = False
    try:
        cur_ctx_chk = cmds.currentCtx()
        if cur_ctx_chk and ('SuperContext' in str(cur_ctx_chk)):
            in_super_context = True
    except Exception:
        pass
    
    if in_super_context:
        # Just record pending align, don't execute now.
        _ADV_IKFK_LIVE_SYNC_WAS_IN_SUPERCONTEXT = True
        pending_key = (str(namespace or ''), str(limb_type or ''), str(side or ''), str(driver or ''))
        _ADV_IKFK_LIVE_SYNC_SUPERCONTEXT_PENDING_ALIGN[pending_key] = True
        
        # Schedule fast release detection.
        try:
            _adv_live_sync_schedule_release_check()
        except Exception:
            pass
        return

    # Anti-jitter cooldown: skip if we just aligned this limb recently.
    # This prevents align -> position change -> re-detect -> re-align loops.
    cooldown_key = (str(namespace or ''), str(limb_type or ''), str(side or ''))
    try:
        import time
        now_cd = time.time()
        last_align = float(_ADV_IKFK_LIVE_SYNC_LAST_ALIGN_TIME.get(cooldown_key) or 0.0)
        if last_align and (now_cd - last_align) < float(_ADV_IKFK_LIVE_SYNC_ALIGN_COOLDOWN):
            if _adv_ikfk_debug_enabled():
                try:
                    _adv_ikfk_debug_log('on_change cooldown skip src=%s dt=%.3f' % (str(source_node or ''), now_cd - last_align))
                except Exception:
                    pass
            return
    except Exception:
        pass

    # Post-Undo/Redo safety: block *all* alignment writes for a short window.
    global _ADV_IKFK_LIVE_SYNC_BLOCK_UNTIL
    try:
        import time
        now_blk = time.time()
    except Exception:
        now_blk = 0.0
    try:
        if now_blk and float(_ADV_IKFK_LIVE_SYNC_BLOCK_UNTIL or 0.0) and now_blk < float(_ADV_IKFK_LIVE_SYNC_BLOCK_UNTIL or 0.0):
            if _adv_ikfk_debug_enabled():
                try:
                    _adv_ikfk_debug_log('on_change blocked src=%s until=%.3f now=%.3f' % (str(source_node or ''), float(_ADV_IKFK_LIVE_SYNC_BLOCK_UNTIL or 0.0), float(now_blk)))
                except Exception:
                    pass
            return
    except Exception:
        pass

    # Mark activity (but not for periodic source).
    src = str(source_node or '')
    if src.lower() != 'periodic':
        global _ADV_IKFK_LIVE_SYNC_LAST_ACTIVITY_TIME
        try:
            import time
            _ADV_IKFK_LIVE_SYNC_LAST_ACTIVITY_TIME = time.time()
        except Exception:
            pass

    # Coalesce live-sync writes into fewer undo steps.
    try:
        _adv_live_sync_undo_chunk_touch(close_delay=0.20)
    except Exception:
        pass

    if _ADV_IKFK_LIVE_SYNC_GUARD:
        return
    _ADV_IKFK_LIVE_SYNC_GUARD = True

    try:
        def _get_blend_info():
            try:
                sw, _, _ = _adv_get_nodes_for_limb(str(namespace or ''), str(limb_type or ''), str(side or ''))
            except Exception:
                sw = None
            if not sw or (not cmds.objExists(sw)):
                return None, None
            try:
                if not cmds.attributeQuery('FKIKBlend', node=sw, exists=True):
                    return sw, None
            except Exception:
                return sw, None
            try:
                return sw, float(cmds.getAttr(sw + '.FKIKBlend'))
            except Exception:
                return sw, None

        def _maybe_temp_switch_and_run():
            """During live sync, temporarily switch FKIKBlend to ensure the driver side actually evaluates."""
            sw, prev_blend = _get_blend_info()
            if not sw or prev_blend is None:
                # No switch control; just run.
                if driver == 'ik':
                    return ik_to_fk_align(namespace, limb_type, side)
                if driver == 'fk':
                    return fk_to_ik_align(namespace, limb_type, side)
                return None

            # Determine required mode for evaluation.
            # If we want IK->FK (driver=='ik') but rig is currently FK, IK solution may not update.
            # If we want FK->IK (driver=='fk') but rig is currently IK, FK solution may not update.
            need_target = None
            try:
                if driver == 'ik' and float(prev_blend) <= 0.5:
                    need_target = 10.0
                elif driver == 'fk' and float(prev_blend) >= 9.5:
                    need_target = 0.0
            except Exception:
                need_target = None

            if need_target is None:
                if driver == 'ik':
                    return ik_to_fk_align(namespace, limb_type, side)
                if driver == 'fk':
                    return fk_to_ik_align(namespace, limb_type, side)
                return None

            # Only do temporary switching when live sync is enabled (avoid surprising behavior in manual calls).
            if not _ADV_IKFK_LIVE_SYNC_ENABLED:
                if driver == 'ik':
                    return ik_to_fk_align(namespace, limb_type, side)
                if driver == 'fk':
                    return fk_to_ik_align(namespace, limb_type, side)
                return None

            # Temp switch, run, restore.
            try:
                cmds.setAttr(sw + '.FKIKBlend', float(need_target))
            except Exception:
                pass
            try:
                if _adv_ikfk_debug_enabled():
                    _adv_ikfk_debug_log('temp_mode_switch sw=%s prev=%s tmp=%s driver=%s src=%s' % (str(sw), str(prev_blend), str(need_target), str(driver), str(source_node or '')))

                if driver == 'ik':
                    return ik_to_fk_align(namespace, limb_type, side)
                if driver == 'fk':
                    return fk_to_ik_align(namespace, limb_type, side)
                return None
            finally:
                try:
                    cmds.setAttr(sw + '.FKIKBlend', float(prev_blend))
                except Exception:
                    pass

        ok = None
        ok = _maybe_temp_switch_and_run()
        
        # Record successful align time for anti-jitter cooldown.
        if ok:
            try:
                import time
                _ADV_IKFK_LIVE_SYNC_LAST_ALIGN_TIME[cooldown_key] = time.time()
            except Exception:
                pass
        
        if _adv_ikfk_debug_enabled():
            _adv_ikfk_debug_log("on_change driver=%s limb=%s side=%s ns=%s src=%s ok=%s" % (driver, limb_type, side, namespace, (source_node or ''), ok))
            try:
                _adv_ikfk_debug_probe(namespace, limb_type, side, active_node=None, reason=('on_change_' + str(driver)))
            except Exception:
                pass
    except Exception:
        if _adv_ikfk_debug_enabled():
            import traceback
            _ADV_IKFK_DEBUG_LAST_ERROR = traceback.format_exc()
            _adv_ikfk_debug_log("on_change exception")
        else:
            pass
    finally:
        _ADV_IKFK_LIVE_SYNC_GUARD = False


def _adv_live_sync_idle_tick():
    """Idle fallback: detect transform changes and align.

    Some Maya tool settings only update attributes on mouse release; in that case
    attributeChange may not fire during drag. Idle tick ensures live sync still works.
    """
    global _ADV_IKFK_LIVE_SYNC_IDLE_LAST_CALL
    global _ADV_IKFK_LIVE_SYNC_LAST_ACTIVITY_TIME
    if not _ADV_IKFK_LIVE_SYNC_ENABLED:
        return
    if _ADV_IKFK_LIVE_SYNC_SUSPEND:
        return

    # Post-Undo/Redo safety: do not drive alignment while Maya may still be settling.
    global _ADV_IKFK_LIVE_SYNC_BLOCK_UNTIL, _ADV_IKFK_LIVE_SYNC_REPRIME_PENDING
    try:
        import time
        now_blk = time.time()
        until_blk = float(_ADV_IKFK_LIVE_SYNC_BLOCK_UNTIL or 0.0)
        if now_blk and until_blk and now_blk < until_blk:
            return
    except Exception:
        pass

    # If block just expired and reprime is pending, re-prime threshold baselines now.
    if _ADV_IKFK_LIVE_SYNC_REPRIME_PENDING:
        _ADV_IKFK_LIVE_SYNC_REPRIME_PENDING = False
        try:
            _adv_live_sync_prime_caches_from_active(reason='post_block')
        except Exception:
            pass

    try:
        import time
        now = time.time()
        if (now - float(_ADV_IKFK_LIVE_SYNC_IDLE_LAST_CALL)) < float(_ADV_IKFK_LIVE_SYNC_IDLE_MIN_INTERVAL):
            return
        _ADV_IKFK_LIVE_SYNC_IDLE_LAST_CALL = now
    except Exception:
        pass

    # If a global mover changed (COG/body/pelvis), refresh all limbs once.
    global _ADV_IKFK_LIVE_SYNC_GLOBAL_DIRTY, _ADV_IKFK_LIVE_SYNC_GLOBAL_NS
    if _ADV_IKFK_LIVE_SYNC_GLOBAL_DIRTY:
        _ADV_IKFK_LIVE_SYNC_GLOBAL_DIRTY = False
        try:
            _adv_live_sync_force_align_all(_ADV_IKFK_LIVE_SYNC_GLOBAL_NS)
        except Exception:
            pass

    try:
        sel = cmds.ls(orderedSelection=True, long=True) or []
    except Exception:
        sel = cmds.ls(sl=True, long=True) or []

    global _ADV_IKFK_LIVE_SYNC_LAST_ACTIVE
    active = None
    if sel:
        active = sel[-1]
        _ADV_IKFK_LIVE_SYNC_LAST_ACTIVE = active
    else:
        # Some Maya contexts can transiently clear selection during manipulation.
        # Keep syncing based on last known active control.
        if _ADV_IKFK_LIVE_SYNC_LAST_ACTIVE and cmds.objExists(_ADV_IKFK_LIVE_SYNC_LAST_ACTIVE):
            active = _ADV_IKFK_LIVE_SYNC_LAST_ACTIVE
        else:
            return
    active_short = active.split('|')[-1]
    short_name = get_controller_name_without_namespace(active)

    # Detect whether user is actively manipulating with Maya transform tools.
    # This is used for a periodic-align fallback when Maya doesn't continuously update matrices during drag.
    try:
        cur_ctx = cmds.currentCtx()
    except Exception:
        cur_ctx = ""
    is_super_context = False
    try:
        sctx = str(cur_ctx or "")
        is_super_context = ('SuperContext' in sctx)
    except Exception:
        is_super_context = False

    # Check if we just exited SuperContext and have pending alignments to execute.
    # Note: The fast release check (_adv_live_sync_check_release) usually handles this,
    # but idle_tick serves as a fallback in case it misses.
    global _ADV_IKFK_LIVE_SYNC_WAS_IN_SUPERCONTEXT, _ADV_IKFK_LIVE_SYNC_SUPERCONTEXT_PENDING_ALIGN
    if (not is_super_context) and _ADV_IKFK_LIVE_SYNC_SUPERCONTEXT_PENDING_ALIGN:
        # User has released - execute pending alignments.
        _ADV_IKFK_LIVE_SYNC_WAS_IN_SUPERCONTEXT = False
        pending = dict(_ADV_IKFK_LIVE_SYNC_SUPERCONTEXT_PENDING_ALIGN)
        _ADV_IKFK_LIVE_SYNC_SUPERCONTEXT_PENDING_ALIGN.clear()
        
        if pending:
            # Execute alignment with Undo DISABLED.
            undo_was_on = True
            try:
                undo_was_on = cmds.undoInfo(q=True, state=True)
            except Exception:
                pass
            
            try:
                for (pns, plimb, pside, pdriver) in pending.keys():
                    try:
                        sw = pns + ("FKIKArm_" if plimb == 'arm' else "FKIKLeg_") + pside
                        prev_blend = None
                        need_target = None
                        
                        if cmds.objExists(sw) and cmds.attributeQuery('FKIKBlend', node=sw, exists=True):
                            prev_blend = float(cmds.getAttr(sw + '.FKIKBlend'))
                            if pdriver == 'ik' and prev_blend <= 0.5:
                                need_target = 10.0
                        
                        if need_target is not None:
                            cmds.setAttr(sw + '.FKIKBlend', need_target)
                        
                        try:
                            if pdriver == 'ik':
                                ik_to_fk_align(pns, plimb, pside)
                            elif pdriver == 'fk':
                                fk_to_ik_align(pns, plimb, pside)
                        finally:
                            if need_target is not None and prev_blend is not None:
                                try:
                                    cmds.setAttr(sw + '.FKIKBlend', prev_blend)
                                except Exception:
                                    pass
                    except Exception:
                        pass
            finally:
                if undo_was_on:
                    try:
                        try:
                            cmds.undoInfo(stateWithoutFlush=True)
                        except Exception:
                            pass
                        cmds.undoInfo(state=True)
                    except Exception:
                        pass
            
            # Return after fallback align to avoid double-triggering.
            return

    # SuperContext can remain active even when the user is NOT dragging.
    # Only consider it "active dragging" if we observed recent changes.
    active_dragging = False
    try:
        import time
        now_act = time.time()
    except Exception:
        now_act = 0.0
    try:
        last_act = float(_ADV_IKFK_LIVE_SYNC_LAST_ACTIVITY_TIME or 0.0)
    except Exception:
        last_act = 0.0
    try:
        win = float(_ADV_IKFK_LIVE_SYNC_ACTIVITY_WINDOW or 0.25)
    except Exception:
        win = 0.25
    # If we detect the active controller's world transform changed, treat it as activity.
    try:
        sig_a = _adv_live_sync_world_sig(active)
        prev_a = _ADV_IKFK_LIVE_SYNC_IDLE_LAST.get(active)
        if (prev_a is not None) and (sig_a is not None) and (prev_a != sig_a):
            _ADV_IKFK_LIVE_SYNC_IDLE_LAST[active] = sig_a
            _ADV_IKFK_LIVE_SYNC_LAST_ACTIVITY_TIME = float(now_act or 0.0)
        elif sig_a is not None and prev_a is None:
            # Prime baseline so the first drag delta isn't missed.
            _ADV_IKFK_LIVE_SYNC_IDLE_LAST[active] = sig_a
    except Exception:
        pass

    try:
        active_dragging = bool(is_super_context and now_act and last_act and ((now_act - last_act) < win))
    except Exception:
        active_dragging = False

    # SuperContext-only Evaluation Manager override (forces continuous eval for some rigs).
    try:
        import time
        _adv_em_override_update(active_dragging, time.time())
    except Exception:
        pass

    # Global mover support: some tools only update attributes on release, so
    # attributeChange may not fire during drag. Use idle sampling.
    if _adv_is_global_mover_ctrl(short_name):
        ns = _adv_get_namespace_from_node(active)

        sig = _adv_live_sync_world_sig(active)
        prev = _ADV_IKFK_LIVE_SYNC_IDLE_LAST.get(active)
        changed = (prev != sig)
        _ADV_IKFK_LIVE_SYNC_IDLE_LAST[active] = sig

        # If change detection misses (some tools), still refresh periodically while a global mover is active.
        global _ADV_IKFK_LIVE_SYNC_GLOBAL_LAST_ALIGN_TIME
        try:
            import time
            now = time.time()
        except Exception:
            now = 0.0
        periodic = False
        try:
            periodic = (now and (now - float(_ADV_IKFK_LIVE_SYNC_GLOBAL_LAST_ALIGN_TIME)) > 0.20)
        except Exception:
            periodic = True

        if _adv_ikfk_debug_enabled():
            _adv_ikfk_debug_log('global_idle active=%s ns=%s changed=%s periodic=%s' % (active_short, ns, int(bool(changed)), int(bool(periodic))))

        if not changed and not periodic:
            return

        _ADV_IKFK_LIVE_SYNC_GLOBAL_LAST_ALIGN_TIME = now
        try:
            _adv_live_sync_force_align_all(ns)
        except Exception:
            pass
        return

    limb_type, side = _adv_parse_limb_from_ctrl(short_name)
    if not limb_type or not side:
        return

    ns = _adv_get_namespace_from_node(active)
    _, fk_nodes, ik_nodes = _adv_get_nodes_for_limb(ns, limb_type, side)
    fk_set = set([n.split('|')[-1] for n in fk_nodes])
    ik_set = set([n.split('|')[-1] for n in ik_nodes])

    # Decide driver direction.
    # - While manipulating: follow the control being moved (IK ctrl drives FK; FK ctrl drives IK)
    #   so the manipulated control does NOT snap back.
    # - Otherwise: prefer FKIKBlend (keeps the "inactive" side ready to switch).
    driver_from_active = None
    if active_short in ik_set:
        driver_from_active = 'ik'
    elif active_short in fk_set:
        driver_from_active = 'fk'
    else:
        # Fallback: check if control name matches known IK/FK patterns.
        # This handles cases where _collect_ik_children might miss some controls.
        sn = short_name  # short_name is already without namespace
        if any(p in sn for p in ('IK', 'Pole', 'Roll', 'IKToes')):
            driver_from_active = 'ik'
        elif any(p in sn for p in ('FK',)):
            driver_from_active = 'fk'

    driver_from_mode = None
    try:
        switch_ctrl = ns + ("FKIKArm_" if limb_type == 'arm' else "FKIKLeg_") + side
        if cmds.objExists(switch_ctrl) and cmds.attributeQuery('FKIKBlend', node=switch_ctrl, exists=True):
            st, _bv, _mx = _adv_fkik_state_from_ctrl_robust(switch_ctrl)
            if st in ('FK', 'IK'):
                driver_from_mode = 'ik' if st == 'IK' else 'fk'
    except Exception:
        driver_from_mode = None

    driver = None
    # Always prefer driver_from_active (based on which control is selected).
    # This ensures when user moves IK, FK aligns to IK, regardless of FKIKBlend value.
    # Only fall back to driver_from_mode when we can't determine from the selected control.
    if driver_from_active:
        driver = driver_from_active
    elif driver_from_mode:
        driver = driver_from_mode
    if not driver:
        return

    if _adv_ikfk_debug_enabled():
        try:
            _adv_ikfk_debug_log('idle active=%s short=%s limb=%s side=%s ns=%s driver=%s' % (active_short, short_name, limb_type, side, ns, driver))
        except Exception:
            pass

    # Threshold-based trigger during active manipulation:
    # When the controller moves/rotates by more than the threshold, run align immediately.
    # This makes live sync feel responsive even if attributeChange/worldSig doesn't update.

    # Check if we are still within a post-Undo/Redo block window - skip threshold entirely.
    threshold_blocked = False
    try:
        import time
        now_blk2 = time.time()
        until_blk2 = float(_ADV_IKFK_LIVE_SYNC_BLOCK_UNTIL or 0.0)
        if now_blk2 and until_blk2 and now_blk2 < until_blk2:
            threshold_blocked = True
    except Exception:
        pass

    if is_super_context and not threshold_blocked:
        # In SuperContext (user is dragging) - do NOT execute alignment.
        # Just record that we were in SuperContext, alignment will happen on release.
        _ADV_IKFK_LIVE_SYNC_WAS_IN_SUPERCONTEXT = True
        pending_key = (str(ns or ''), str(limb_type or ''), str(side or ''), str(driver or ''))
        _ADV_IKFK_LIVE_SYNC_SUPERCONTEXT_PENDING_ALIGN[pending_key] = True
        
        # Schedule release check.
        try:
            _adv_live_sync_schedule_release_check()
        except Exception:
            pass
        
        # Don't execute alignment during drag.
        return

    # Periodic align fallback while actively manipulating.
    # This helps for rigs where the selected control (or its watched parents) don't reliably expose
    # continuously-changing matrices during drag, but the IK solution does update.
    periodic_fire = False
    try:
        import time
        now2 = time.time()
    except Exception:
        now2 = 0.0

    # Skip periodic if still within block window.
    if threshold_blocked:
        active_dragging = False

    if active_dragging and now2:
        try:
            key = (str(ns or ""), str(limb_type or ""), str(side or ""), str(driver or ""))
            last = float(_ADV_IKFK_LIVE_SYNC_PERIODIC_LAST_ALIGN.get(key) or 0.0)
            if (now2 - last) >= float(_ADV_IKFK_LIVE_SYNC_PERIODIC_MIN_INTERVAL):
                _ADV_IKFK_LIVE_SYNC_PERIODIC_LAST_ALIGN[key] = now2
                periodic_fire = True
        except Exception:
            periodic_fire = False

    # Sample WORLD transform signature for multiple watch nodes.
    # Some rigs animate parent offset groups rather than the selected leaf.
    watch_nodes = _adv_live_sync_get_watch_nodes(active, limb_type, side, max_parents=3)
    if not watch_nodes:
        watch_nodes = [active]

    changed_node = None
    if not is_super_context:
        for n in watch_nodes:
            cur_sig = _adv_live_sync_world_sig(n)
            if cur_sig is None:
                continue
            prev_sig = _ADV_IKFK_LIVE_SYNC_IDLE_LAST.get(n)
            if prev_sig is None or prev_sig != cur_sig:
                _ADV_IKFK_LIVE_SYNC_IDLE_LAST[n] = cur_sig
                changed_node = n
                break

    if not changed_node:
        if _adv_ikfk_debug_enabled():
            try:
                _adv_ikfk_debug_probe(ns, limb_type, side, active_node=active, reason='idle_no_active_delta')
            except Exception:
                pass
        # If no detectable change but we are actively dragging, still run periodic align.
        if periodic_fire and active_dragging:
            # Try forcing evaluation so IKX nodes update during drag (some rigs cache until release).
            try:
                _adv_live_sync_force_evaluate(ns, limb_type, side, active=active, watch_nodes=watch_nodes)
                if _adv_ikfk_debug_enabled():
                    _adv_ikfk_debug_log('idle_force_eval ok=1 ctx=%s' % str(cur_ctx))
            except Exception:
                if _adv_ikfk_debug_enabled():
                    _adv_ikfk_debug_log('idle_force_eval ok=0 ctx=%s' % str(cur_ctx))
            if _adv_ikfk_debug_enabled():
                try:
                    _adv_ikfk_debug_log('idle_periodic_align ctx=%s' % str(cur_ctx))
                except Exception:
                    pass
            _adv_live_sync_on_change(ns, limb_type, side, driver, source_node='periodic')
        return

    if _adv_ikfk_debug_enabled():
        try:
            _adv_ikfk_debug_log('idle_watch_changed node=%s' % (str(changed_node).split('|')[-1]))
        except Exception:
            pass
        try:
            _adv_ikfk_debug_probe(ns, limb_type, side, active_node=active, reason='idle_active_delta')
        except Exception:
            pass

    _adv_live_sync_on_change(ns, limb_type, side, driver, source_node=str(changed_node).split('|')[-1])

    # Mark activity when we detect a watched transform change.
    try:
        import time
        _ADV_IKFK_LIVE_SYNC_LAST_ACTIVITY_TIME = time.time()
    except Exception:
        pass


def _adv_live_sync_rebuild_jobs():
    """Rebuild attributeChange jobs based on current active selection."""
    global _ADV_IKFK_LIVE_SYNC_ATTR_JOB_IDS
    if not _ADV_IKFK_LIVE_SYNC_ENABLED:
        _adv_live_sync_clear_attr_jobs()
        return

    try:
        sel = cmds.ls(orderedSelection=True, long=True) or []
    except Exception:
        sel = cmds.ls(sl=True, long=True) or []

    if not sel:
        # Don't clear existing jobs if selection is temporarily empty.
        return

    # We have a valid selection; rebuild jobs for the new active.
    _adv_live_sync_clear_attr_jobs()

    active = sel[-1]
    active_short = active.split('|')[-1]
    short_name = get_controller_name_without_namespace(active)
    ns = _adv_get_namespace_from_node(active)
    limb_type, side = _adv_parse_limb_from_ctrl(short_name)
    is_global_mover = _adv_is_global_mover_ctrl(short_name)
    driver = None
    fk_nodes = []
    ik_nodes = []

    if limb_type and side:
        _, fk_nodes, ik_nodes = _adv_get_nodes_for_limb(ns, limb_type, side)
        fk_set = set([n.split('|')[-1] for n in fk_nodes])
        ik_set = set([n.split('|')[-1] for n in ik_nodes])

        # For attributeChange jobs, always follow the selected control.
        # This avoids snapping the actively manipulated control back.
        if active_short in ik_set:
            driver = 'ik'
        elif active_short in fk_set:
            driver = 'fk'
        else:
            # Fallback: check if control name matches known IK/FK patterns.
            sn = short_name
            if any(p in sn for p in ('IK', 'Pole', 'Roll', 'IKToes')):
                driver = 'ik'
            elif any(p in sn for p in ('FK',)):
                driver = 'fk'
            else:
                limb_type, side = None, None

    if _adv_ikfk_debug_enabled():
        _adv_ikfk_debug_log(
            "rebuild_jobs active=%s short=%s limb=%s side=%s ns=%s driver=%s global=%s fk=%s ik=%s" %
            (active_short, short_name, limb_type, side, ns, driver, int(bool(is_global_mover)), [n.split('|')[-1] for n in fk_nodes], [n.split('|')[-1] for n in ik_nodes])
        )

    # If selecting a global mover, force one refresh on next idle.
    if is_global_mover:
        try:
            _adv_live_sync_mark_global_dirty(ns)
        except Exception:
            pass

    from functools import partial

    # 监听常见变换属性（拖动时会频繁触发，若 Maya 被设成 Release 才更新则会延后）
    attrs = (
        "translateX", "translateY", "translateZ",
        "rotateX", "rotateY", "rotateZ",
    )

    # Build a small list of nodes to watch (active + likely parent offset groups)
    global _ADV_IKFK_LIVE_SYNC_WATCH_NODES
    if limb_type and side:
        _ADV_IKFK_LIVE_SYNC_WATCH_NODES = _adv_live_sync_get_watch_nodes(active, limb_type, side, max_parents=3)
    else:
        _ADV_IKFK_LIVE_SYNC_WATCH_NODES = [active]

    parent = ADV_MAIN_WINDOW_NAME if cmds.window(ADV_MAIN_WINDOW_NAME, exists=True) else None

    watch_targets = list(_ADV_IKFK_LIVE_SYNC_WATCH_NODES or [])
    if not watch_targets:
        watch_targets = [active]

    for node in watch_targets:
        node_short = node.split('|')[-1] if node else ''
        for a in attrs:
            plug = "{}.{}".format(node, a)
            try:
                if limb_type and side and driver:
                    cb = partial(_adv_live_sync_on_change, ns, limb_type, side, driver, node_short)
                elif is_global_mover:
                    cb = partial(_adv_live_sync_mark_global_dirty, ns)
                else:
                    continue

                jid = cmds.scriptJob(attributeChange=[plug, cb], protected=True, parent=parent)
                _ADV_IKFK_LIVE_SYNC_ATTR_JOB_IDS.append(jid)
            except Exception:
                # 某些 Maya 版本/节点名情况下 longName plug 可能失败，fallback 用短名
                try:
                    plug2 = "{}.{}".format(node_short, a)
                    if limb_type and side and driver:
                        cb2 = partial(_adv_live_sync_on_change, ns, limb_type, side, driver, node_short)
                    elif is_global_mover:
                        cb2 = partial(_adv_live_sync_mark_global_dirty, ns)
                    else:
                        continue
                    jid2 = cmds.scriptJob(attributeChange=[plug2, cb2], protected=True, parent=parent)
                    _ADV_IKFK_LIVE_SYNC_ATTR_JOB_IDS.append(jid2)
                except Exception:
                    pass


def _adv_sr_is_running():
    """Return whether switchRuntime auto-switch appears to be running.

    Used to keep UI state consistent even after script reloads.
    """
    try:
        import os
        import sys
        local_scripts = os.path.join(os.path.dirname(__file__), 'scripts')
        local_scripts = local_scripts.replace('\\', '/')
        if local_scripts and local_scripts not in sys.path:
            sys.path.insert(0, local_scripts)
    except Exception:
        pass
    try:
        switchRuntime = _adv_import_switch_runtime()
        cb = getattr(switchRuntime, 'callback', None)
        inst = getattr(cb, 'SWITCH_INSTANCE', None) if cb else None
        try:
            return bool(inst) and (len(inst) > 0)
        except Exception:
            return bool(inst)
    except Exception:
        return False


def adv_set_ikfk_live_sync_enabled(enabled):
    """Enable/disable IKFK realtime sync using switchRuntime.

    ADV's original IKFK live sync implementation is intentionally disabled in favor
    of switchRuntime (better rig-agnostic solve + undo stability work).
    """
    global _ADV_IKFK_LIVE_SYNC_ENABLED

    enabled = bool(enabled)
    # UI/global flag can desync after reloads; check actual runtime before early-return.
    sr_running = False
    try:
        sr_running = bool(_adv_sr_is_running())
    except Exception:
        sr_running = False
    if enabled == _ADV_IKFK_LIVE_SYNC_ENABLED:
        if (enabled and sr_running) or ((not enabled) and (not sr_running)):
            return

    def _sr_tools():
        # Prefer local vendored scripts under this tool folder.
        try:
            import os
            import sys
            local_scripts = os.path.join(os.path.dirname(__file__), 'scripts')
            local_scripts = local_scripts.replace('\\', '/')
            if local_scripts and local_scripts not in sys.path:
                sys.path.insert(0, local_scripts)

            # Remove competing Download/backup paths so import resolves to our vendored scripts.
            try:
                for p in list(sys.path):
                    if not p:
                        continue
                    pp = str(p).replace('\\', '/').lower()
                    if 'downloads' in pp and 'adv fast select' in pp:
                        try:
                            sys.path.remove(p)
                        except Exception:
                            pass
            except Exception:
                pass

            # If a switchRuntime was already imported from elsewhere, but we have a local copy,
            # prefer the local one by clearing cached modules.
            local_pkg = _adv_runtime_pkg_dir(local_scripts)
            if os.path.isdir(local_pkg) and 'switchRuntime' in sys.modules:
                try:
                    loaded = getattr(sys.modules.get('switchRuntime'), '__file__', '') or ''
                except Exception:
                    loaded = ''
                if loaded and (local_pkg.replace('\\', '/') not in loaded.replace('\\', '/')):
                    for k in list(sys.modules.keys()):
                        if _adv_is_switch_runtime_module_key(k):
                            sys.modules.pop(k, None)
        except Exception:
            pass

        # Try import directly
        try:
            switchRuntime = _adv_import_switch_runtime()
            # Check if callback module has the latest version marker
            expected_ver = "2026.01.14.v14"
            cur_ver = getattr(switchRuntime.callback, '_CALLBACK_VERSION', None)
            if cur_ver != expected_ver:
                # Force reload all switchRuntime modules
                for k in list(sys.modules.keys()):
                    if _adv_is_switch_runtime_module_key(k):
                        sys.modules.pop(k, None)
                switchRuntime = _adv_import_switch_runtime()
            return switchRuntime.tools
        except Exception:
            pass

        # Retry after ensuring Maya user scripts dir is on sys.path
        try:
            import sys
            try:
                user_dir = cmds.internalVar(userScriptDir=True)
            except Exception:
                user_dir = None
            if user_dir:
                user_dir = str(user_dir)
                if user_dir not in sys.path:
                    sys.path.append(user_dir)
            switchRuntime = _adv_import_switch_runtime()
            return switchRuntime.tools
        except Exception as e:
            try:
                msg = u"[ADV] 未找到 switchRuntime（请先拖拽安装 Install.mel）。\n\n错误：%s" % str(e)
                cmds.warning(msg)
            except Exception:
                pass
            return None

    tools = _sr_tools()
    if not tools:
        _ADV_IKFK_LIVE_SYNC_ENABLED = False
        try:
            if cmds.checkBox(ADV_IKFK_LIVE_SYNC_CB, exists=True):
                cmds.checkBox(ADV_IKFK_LIVE_SYNC_CB, e=True, v=False)
        except Exception:
            pass
        return

    _ADV_IKFK_LIVE_SYNC_ENABLED = enabled

    # Safety: if ADV legacy live-sync was enabled earlier in this session,
    # clear its scriptJobs to avoid double-driving/jitter.
    try:
        _adv_live_sync_clear_jobs()
    except Exception:
        pass

    def _sr_find_ctrl(short_name):
        try:
            hits = cmds.ls([short_name, '*:' + short_name, '*:*:' + short_name], type='transform', l=True) or []
            return hits[0] if hits else None
        except Exception:
            return None

    def _sr_has_sets():
        try:
            s = cmds.ls('switchRuntime*Set*', '*:switchRuntime*Set*', '*:*:switchRuntime*Set*', type='objectSet') or []
            return len(s) > 0
        except Exception:
            return False

    def _sr_try_apply_saved_groups():
        """Try to apply saved IKFK groups (2-bone by default) when enabling realtime.

        Returns True if at least one set was created.
        """
        global _ADV_SR_ACTIVE_GROUP_NAME, _ADV_SR_ACTIVE_GROUP_HORSE3
        try:
            groups = _adv_sr_groups_load()
        except Exception:
            groups = {}

        if not groups:
            return False

        try:
            switchRuntime = _adv_import_switch_runtime()
            sr_switch = switchRuntime.switch
        except Exception as e:
            _adv_sr_log('apply_saved_groups import failed: %s' % str(e))
            return False

        # Prefer 2-bone groups first, then 3-bone
        sorted_names = sorted(groups.keys(), key=lambda n: (1 if groups[n].get('horse3', False) else 0, n.lower()))

        ns = _adv_sr_ui_namespace_hint()
        created_any = False

        def _resolve_saved(name_or_path):
            try:
                node = _adv_sr_resolve_transform(name_or_path)
                if node:
                    return node
            except Exception:
                node = None
            try:
                leaf = (name_or_path or '').split('|')[-1]
            except Exception:
                leaf = name_or_path or ''
            if not leaf:
                return None
            try:
                node = _adv_sr_resolve_transform(leaf)
                if node:
                    return node
            except Exception:
                pass
            try:
                if ':' in leaf:
                    leaf_no_ns = leaf.rsplit(':', 1)[-1]
                else:
                    leaf_no_ns = leaf
                if leaf_no_ns and leaf_no_ns != leaf:
                    node = _adv_sr_resolve_transform(leaf_no_ns)
                    if node:
                        return node
            except Exception:
                pass
            return None

        for name in sorted_names:
            g = groups[name]
            items = g.get('items') or {}
            horse3 = bool(g.get('horse3', False))
            mode = g.get('mode', 'relative')

            # Resolve control names
            def _resolve(key):
                raw = (items.get(key) or '').strip()
                if not raw:
                    return None
                if mode == 'relative':
                    raw = ns + raw
                node = _resolve_saved(raw)
                if node:
                    return node
                # fallback: try original raw (in case stored with namespace/path)
                return _resolve_saved((items.get(key) or '').strip())

            ctrls = []
            if horse3:
                for k in ['FK1', 'FK2', 'FK3', 'FK4', 'Pole', 'IK']:
                    c = _resolve(k)
                    if c:
                        ctrls.append(c)
                blend = _resolve('Blend')
                if blend:
                    ctrls.append(blend)
                if len(ctrls) not in (6, 7):
                    continue
            else:
                for k in ['FK1', 'FK2', 'FK3', 'Pole', 'IK']:
                    c = _resolve(k)
                    if c:
                        ctrls.append(c)
                blend = _resolve('Blend')
                if blend:
                    ctrls.append(blend)
                if len(ctrls) not in (5, 6):
                    continue

            try:
                # Delete related sets only for these controls (avoid nuking all sets)
                try:
                    to_delete = set()
                    for c in ctrls:
                        try:
                            for s in (cmds.listSets(object=c) or []):
                                if 'switchRuntime' in s and 'Set' in s and cmds.nodeType(s) == 'objectSet':
                                    to_delete.add(s)
                        except Exception:
                            pass
                    if to_delete:
                        try:
                            cmds.delete(list(to_delete))
                        except Exception:
                            pass
                except Exception:
                    pass

                cmds.select(ctrls, r=True)
                if horse3:
                    created = bool(sr_switch.Leg3.create_set()) if hasattr(sr_switch, 'Leg3') else False
                else:
                    created = bool(sr_switch.Arm.create_set())

                if created:
                    if not _ADV_SR_ACTIVE_GROUP_NAME:
                        _ADV_SR_ACTIVE_GROUP_NAME = name
                        _ADV_SR_ACTIVE_GROUP_HORSE3 = horse3
                    created_any = True
                    _adv_sr_log('apply_saved_groups created set for group: %s (horse3=%s)' % (name, horse3))
            except Exception as e:
                _adv_sr_log('apply_saved_groups failed for %s: %s' % (name, str(e)))
                continue

        return created_any

    def _sr_try_autocreate_adv_biped_sets():
        """Try to create switchRuntime sets for standard ADV biped control names.

        This is a best-effort fallback when user enables realtime but scene has no
        switchRuntime data sets yet.
        """
        try:
            switchRuntime = _adv_import_switch_runtime()
            sr_switch = switchRuntime.switch
        except Exception as e:
            _adv_sr_log('autoCreate import switchRuntime.switch failed: %s' % str(e))
            return False

        def _make_one(names, label):
            ctrls = []
            missing = []
            for n in names:
                hit = _sr_find_ctrl(n)
                if hit:
                    ctrls.append(hit)
                else:
                    missing.append(n)
            # allow 5-ctrl version (no FKIKBlend ctrl)
            if len(ctrls) not in (5, 6):
                _adv_sr_log('autoCreate skip %s (found=%d missing=%s)' % (label, len(ctrls), ','.join(missing)))
                return False
            try:
                # delete any existing related sets that already contain these ctrls
                to_delete = set()
                for c in ctrls:
                    try:
                        for s in (cmds.listSets(object=c) or []):
                            if 'switchRuntime' in s and 'Set' in s and cmds.nodeType(s) == 'objectSet':
                                to_delete.add(s)
                    except Exception:
                        pass
                if to_delete:
                    try:
                        cmds.delete(list(to_delete))
                    except Exception:
                        pass
            except Exception:
                pass

            try:
                cmds.select(ctrls, r=True)
                created = sr_switch.Arm.create_set()
                _adv_sr_log('autoCreate %s created=%s' % (label, str(bool(created))))
                return bool(created)
            except Exception as e:
                _adv_sr_log('autoCreate %s failed: %s' % (label, str(e)))
                return False

        ok = False
        ok = _make_one([u'FKShoulder_L', u'FKElbow_L', u'FKWrist_L', u'PoleArm_L', u'IKArm_L', u'FKIKArm_L'], 'Arm_L') or ok
        ok = _make_one([u'FKShoulder_R', u'FKElbow_R', u'FKWrist_R', u'PoleArm_R', u'IKArm_R', u'FKIKArm_R'], 'Arm_R') or ok
        ok = _make_one([u'FKHip_L', u'FKKnee_L', u'FKAnkle_L', u'PoleLeg_L', u'IKLeg_L', u'FKIKLeg_L'], 'Leg_L') or ok
        ok = _make_one([u'FKHip_R', u'FKKnee_R', u'FKAnkle_R', u'PoleLeg_R', u'IKLeg_R', u'FKIKLeg_R'], 'Leg_R') or ok
        return ok

    if enabled:
        # Ensure Undo is enabled so animator can undo transforms.
        try:
            _adv_ensure_undo_enabled()
        except Exception:
            pass

        # Force switchRuntime debug prints OFF (prevents Script Editor spam).
        try:
            cmds.optionVar(iv=('switchRuntime_debug', 0))
        except Exception:
            pass

        # Enable follow checkbox only when realtime switch is ON.
        try:
            if cmds.checkBox(ADV_SR_LIVE_FOLLOW_CB, exists=True):
                cmds.checkBox(ADV_SR_LIVE_FOLLOW_CB, e=True, enable=True)
        except Exception:
            pass

        # Apply follow mode from UI.
        follow = False
        try:
            follow = bool(cmds.checkBox(ADV_SR_LIVE_FOLLOW_CB, q=True, v=True))
        except Exception:
            follow = False
        try:
            tools.set_realtime_during_drag(bool(follow))
        except Exception:
            pass

        try:
            _adv_sr_log('enable: follow=%s' % str(bool(follow)))
        except Exception:
            pass

        # If scene has no switchRuntime sets, try to apply saved groups first,
        # then fall back to auto-create for standard ADV biped.
        try:
            if not _sr_has_sets():
                _adv_sr_log('enable: no switchRuntime sets found; trying saved groups first')
                if not _sr_try_apply_saved_groups():
                    _adv_sr_log('enable: no saved groups applied; trying autoCreate biped')
                    _sr_try_autocreate_adv_biped_sets()
        except Exception:
            pass

        try:
            _adv_sr_log('enable: calling tools.open_auto_switch()')
            tools.open_auto_switch()
            try:
                # report basic runtime state
                switchRuntime = _adv_import_switch_runtime()
                inst_n = len(getattr(switchRuntime.callback, 'SWITCH_INSTANCE', []) or [])
                sets_n = len(cmds.ls('switchRuntime*Set*', '*:switchRuntime*Set*', '*:*:switchRuntime*Set*', type='objectSet') or [])
                _adv_sr_log('enable: open_auto_switch OK (sets=%d instances=%d)' % (sets_n, inst_n))
                if inst_n <= 0:
                    try:
                        _adv_safe_warning(u"[ADV] 实时切换已启动，但没有构建到任何 switchRuntime 实例（通常是场景里没有有效的 switchRuntime*Set* 数据）。")
                    except Exception:
                        pass
            except Exception:
                pass
        except Exception as e:
            _ADV_IKFK_LIVE_SYNC_ENABLED = False
            try:
                _adv_safe_warning(u"[ADV] switchRuntime 启动失败：%s" % str(e))
            except Exception:
                pass
            try:
                if cmds.checkBox(ADV_IKFK_LIVE_SYNC_CB, exists=True):
                    cmds.checkBox(ADV_IKFK_LIVE_SYNC_CB, e=True, v=False)
            except Exception:
                pass
            return
        try:
            cmds.inViewMessage(amg=u"<hl>实时切换: ON</hl>", pos='midCenter', fade=True)
        except Exception:
            pass
        return

    # Disable
    try:
        tools.close_auto_switch()
    except Exception:
        pass
    _ADV_IKFK_LIVE_SYNC_ENABLED = False

    # When realtime switch is OFF, follow must be OFF and disabled.
    try:
        try:
            tools.set_realtime_during_drag(False)
        except Exception:
            pass
        if cmds.checkBox(ADV_SR_LIVE_FOLLOW_CB, exists=True):
            cmds.checkBox(ADV_SR_LIVE_FOLLOW_CB, e=True, v=False, enable=False)
    except Exception:
        pass
    try:
        cmds.inViewMessage(amg=u"<hl>实时切换: OFF</hl>", pos='midCenter', fade=True)
    except Exception:
        pass

    try:
        _adv_sr_log('disable: tools.close_auto_switch() called')
    except Exception:
        pass


def adv_toggle_ikfk_live_sync_from_ui(*_):
    """UI callback for the live sync checkbox."""
    try:
        v = bool(cmds.checkBox(ADV_IKFK_LIVE_SYNC_CB, q=True, value=True))
    except Exception:
        v = False
    try:
        _adv_sr_log("UI click realtime=%s" % str(v))
    except Exception:
        pass
    try:
        adv_set_ikfk_live_sync_enabled(v)
    except Exception as e:
        try:
            import traceback
            tb = traceback.format_exc()
        except Exception:
            tb = "traceback unavailable"
        try:
            global _ADV_SR_LAST_ERROR, _ADV_SR_LAST_TRACE
            _ADV_SR_LAST_ERROR = str(e)
            _ADV_SR_LAST_TRACE = str(tb)
        except Exception:
            pass
        try:
            _adv_safe_warning(u"[ADV] 开启实时切换失败：%s\n%s" % (str(e), tb))
        except Exception:
            pass
        try:
            if cmds.checkBox(ADV_IKFK_LIVE_SYNC_CB, exists=True):
                cmds.checkBox(ADV_IKFK_LIVE_SYNC_CB, e=True, v=False)
        except Exception:
            pass


def _adv_sr_set_follow_from_ui(enabled):
    """UI callback for '实时跟随' checkbox (switchRuntime optionVar)."""
    try:
        enabled = bool(enabled)
    except Exception:
        enabled = False

    try:
        _adv_sr_log("UI click follow=%s" % str(enabled))
    except Exception:
        pass

    # Follow-during-drag must be subordinate to realtime switch.
    # If realtime switch is OFF, force follow OFF and disable the checkbox.
    try:
        if not bool(globals().get('_ADV_IKFK_LIVE_SYNC_ENABLED', False)):
            try:
                if cmds.checkBox(ADV_SR_LIVE_FOLLOW_CB, exists=True):
                    cmds.checkBox(ADV_SR_LIVE_FOLLOW_CB, e=True, v=False, enable=False)
            except Exception:
                pass
            return
    except Exception:
        pass

    def _sr_tools():
        try:
            import os
            import sys
            local_scripts = os.path.join(os.path.dirname(__file__), 'scripts')
            local_scripts = local_scripts.replace('\\', '/')
            if local_scripts and local_scripts not in sys.path:
                sys.path.insert(0, local_scripts)
        except Exception:
            pass
        try:
            switchRuntime = _adv_import_switch_runtime()
            return switchRuntime.tools
        except Exception:
            return None

    tools = _sr_tools()

    if not tools:
        try:
            _adv_safe_warning(u"[ADV] 未找到 switchRuntime（请先拖拽安装 Install.mel）")
        except Exception:
            pass
        # Roll back UI to unchecked to avoid misleading state.
        try:
            if cmds.checkBox(ADV_SR_LIVE_FOLLOW_CB, exists=True):
                cmds.checkBox(ADV_SR_LIVE_FOLLOW_CB, e=True, v=False)
        except Exception:
            pass
        return

    try:
        tools.set_realtime_during_drag(bool(enabled))
    except Exception:
        pass


