def _adv_sr_resolve_transform(name_or_path):
    """Resolve a transform from user input.

    Accepts long path, namespaced name, or short name.
    Returns a long transform path (preferred) or None.
    """
    try:
        s = (name_or_path or '').strip()
    except Exception:
        s = ''
    if not s:
        return None

    # Direct exists
    try:
        if cmds.objExists(s) and cmds.nodeType(s) == 'transform':
            hits = cmds.ls(s, l=True) or []
            return hits[0] if hits else s
    except Exception:
        pass

    # Try as short name patterns
    try:
        hits = cmds.ls([s, '*:' + s, '*:*:' + s], type='transform', l=True) or []
        return hits[0] if hits else None
    except Exception:
        return None


def _adv_sr_ui_set_field_from_selection(field, index=-1):
    try:
        sel = cmds.ls(sl=True, long=True, type='transform') or []
    except Exception:
        sel = cmds.ls(sl=True, long=True) or []
    if not sel:
        _adv_safe_warning(u"请先选择一个控制器")
        return
    try:
        value = sel[index]
    except Exception:
        value = sel[-1]
    try:
        if cmds.control(field, exists=True):
            cmds.textField(field, e=True, text=value)
    except Exception:
        pass


def _adv_sr_ui_fill_from_selection():
    """Fill FK1/FK2/FK3/Pole/IK/(Blend) from current ordered selection."""
    try:
        sel = cmds.ls(orderedSelection=True, long=True, type='transform') or []
    except Exception:
        sel = cmds.ls(sl=True, long=True) or []

    if len(sel) not in (5, 6):
        _adv_safe_warning(u"请选择 5 或 6 个控制器（顺序：FK1, FK2, FK3, Pole, IK, (Blend)）")
        return

    fields = [ADV_SR_SET_FK1_TF, ADV_SR_SET_FK2_TF, ADV_SR_SET_FK3_TF, ADV_SR_SET_POLE_TF, ADV_SR_SET_IK_TF]
    if len(sel) == 6:
        fields.append(ADV_SR_SET_BLEND_TF)

    for f, v in zip(fields, sel):
        try:
            if cmds.control(f, exists=True):
                cmds.textField(f, e=True, text=v)
        except Exception:
            pass


def _adv_sr_ui_get_set_nodes():
    """Read UI text fields and return list of transforms for create_set (5 or 6)."""
    vals = []
    for f in (ADV_SR_SET_FK1_TF, ADV_SR_SET_FK2_TF, ADV_SR_SET_FK3_TF, ADV_SR_SET_POLE_TF, ADV_SR_SET_IK_TF):
        try:
            t = cmds.textField(f, q=True, text=True) if cmds.control(f, exists=True) else ''
        except Exception:
            t = ''
        vals.append(t)

    # optional blend
    try:
        bt = cmds.textField(ADV_SR_SET_BLEND_TF, q=True, text=True) if cmds.control(ADV_SR_SET_BLEND_TF, exists=True) else ''
    except Exception:
        bt = ''
    if bt.strip():
        vals.append(bt)

    out = []
    missing = []
    for raw in vals:
        node = _adv_sr_resolve_transform(raw)
        if node:
            out.append(node)
        else:
            missing.append(raw)

    if len(out) not in (5, 6):
        _adv_safe_warning(u"控制器数量不正确：需要 5 或 6 个（当前解析到 %d 个）。" % len(out))
        return None
    if missing:
        _adv_safe_warning(u"以下控制器未找到/不可用：%s" % (', '.join([m for m in missing if m.strip()]) or u"(空)"))
        return None
    return out


def _adv_sr_ui_import_switch_runtime():
    """Import local vendored switchRuntime and return module (or None)."""
    local_scripts = ''
    try:
        import os
        import sys
        local_scripts = os.path.join(os.path.dirname(__file__), 'scripts').replace('\\', '/')
        if local_scripts and local_scripts not in sys.path:
            sys.path.insert(0, local_scripts)

        # Remove competing Download/backup paths so import resolves to our vendored scripts.
        try:
            for p in list(sys.path):
                if not p:
                    continue
                pp = str(p).replace('\\', '/').lower()
                if 'downloads' in pp and 'adv fast select' in pp:
                    try:
                        sys.path.remove(p)
                    except Exception:
                        pass
        except Exception:
            pass
    except Exception:
        pass
    try:
        import os
        import sys
        import importlib

        expected_pkg = _adv_runtime_pkg_dir(local_scripts) if local_scripts else ''

        def _is_expected(mod):
            try:
                p = (getattr(mod, '__file__', '') or '').replace('\\', '/')
                if expected_pkg and p:
                    return p.startswith(expected_pkg)
            except Exception:
                pass
            return False

        # First import (may resolve to an external same-named package)
        _sr = _adv_import_switch_runtime()
        # If it's not our local vendored one, purge and re-import.
        if expected_pkg and not _is_expected(_sr):
            try:
                for k in list(sys.modules.keys()):
                    if _adv_is_switch_runtime_module_key(k):
                        try:
                            del sys.modules[k]
                        except Exception:
                            pass
            except Exception:
                pass
            _sr = _adv_import_switch_runtime()

        # Ensure submodules are loaded from the same place
        try:
            runtime_root = str(getattr(_sr, '__name__', 'switchRuntime') or 'switchRuntime')
            # Also reload callback first to ensure SWITCH_CLASS is fresh
            cb_mod = importlib.import_module(runtime_root + '.callback')
            try:
                importlib.reload(cb_mod)
            except Exception:
                pass
            
            sw_mod = importlib.import_module(runtime_root + '.switch')
            # Hot-reload solver code so updates apply without restarting Maya.
            try:
                importlib.reload(sw_mod)
            except Exception:
                pass
            
            # Debug: check SWITCH_CLASS after reload
            _adv_sr_log("[DEBUG] After reload - SWITCH_CLASS: %s" % list(cb_mod.SWITCH_CLASS.keys()))
            _adv_sr_log("[DEBUG] switch.SWITCH_VERSION: %s" % getattr(sw_mod, 'SWITCH_VERSION', 'unknown'))
        except Exception as e:
            _adv_sr_log("[DEBUG] reload exception: %s" % str(e))

        return _sr
    except Exception as e:
        _adv_safe_warning(u"未找到 switchRuntime：%s" % str(e))
        return None


def _adv_sr_ui_create_set_and_rebuild():
    nodes = _adv_sr_ui_get_set_nodes()
    if not nodes:
        return

    sr = _adv_sr_ui_import_switch_runtime()
    if not sr:
        return

    try:
        cmds.select(nodes, r=True)
    except Exception:
        pass

    created = False
    try:
        created = bool(sr.switch.Arm.create_set())
    except Exception as e:
        _adv_safe_warning(u"创建 switchRuntime set 失败：%s" % str(e))
        return

    if not created:
        _adv_safe_warning(u"创建 switchRuntime set 失败：请确认选择顺序/数量是否为 5 或 6")
        return

    # Rebuild runtime if realtime is enabled; otherwise just build instances.
    try:
        if bool(globals().get('_ADV_IKFK_LIVE_SYNC_ENABLED', False)):
            # Keep follow-during-drag option consistent
            try:
                follow = bool(cmds.checkBox(ADV_SR_LIVE_FOLLOW_CB, q=True, v=True)) if cmds.checkBox(ADV_SR_LIVE_FOLLOW_CB, exists=True) else False
            except Exception:
                follow = False
            try:
                sr.tools.set_realtime_during_drag(bool(follow))
            except Exception:
                pass

            try:
                sr.tools.open_auto_switch()
            except Exception:
                sr.tools.open_switch()
        else:
            sr.tools.open_switch()
    except Exception:
        pass

    try:
        inst_n = 0
        try:
            inst_n = len(getattr(sr.callback, 'SWITCH_INSTANCE', []) or [])
        except Exception:
            inst_n = 0
        cmds.inViewMessage(amg=u"<hl>switchRuntime set 已创建</hl>（instances=%d）" % inst_n, pos='midCenter', fade=True)
    except Exception:
        pass


def _adv_sr_ui_rebuild_runtime_only():
    sr = _adv_sr_ui_import_switch_runtime()
    if not sr:
        return
    try:
        if bool(globals().get('_ADV_IKFK_LIVE_SYNC_ENABLED', False)):
            sr.tools.open_auto_switch()
        else:
            sr.tools.open_switch()
        try:
            inst_n = len(getattr(sr.callback, 'SWITCH_INSTANCE', []) or [])
        except Exception:
            inst_n = 0
        cmds.inViewMessage(amg=u"<hl>switchRuntime 已重建</hl>（instances=%d）" % inst_n, pos='midCenter', fade=True)
    except Exception as e:
        _adv_safe_warning(u"重建 switchRuntime 失败：%s" % str(e))


def _adv_parse_limb_from_ctrl(ctrl_name):
    """根据控制器名推断肢体类型与侧面。

    Returns:
        tuple[str|None, str|None]: ("arm"|"leg", "L"|"R")
    """
    if not ctrl_name:
        return None, None

    name = str(ctrl_name)
    side = None
    if "_L" in name:
        side = "L"
    elif "_R" in name:
        side = "R"

    # 允许直接选 FKIK / IK / Pole / FK 等控制器
    is_arm = (
        ("Arm" in name)
        or ("Shoulder" in name)
        or ("Elbow" in name)
        or ("Wrist" in name)
        or ("Scapula" in name)
        or ("FKIKArm" in name)
        or ("PoleArm" in name)
    )
    is_leg = (
        ("Leg" in name)
        or ("Hip" in name)
        or ("Knee" in name)
        or ("Ankle" in name)
        or ("Heel" in name)
        or ("Toes" in name)
        or ("RollHeel" in name)
        or ("RollToes" in name)
        or ("RollToesEnd" in name)
        or ("IKToes" in name)
        or ("FKToes" in name)
        or ("FKIKLeg" in name)
        or ("PoleLeg" in name)
    )

    if is_arm and side:
        return "arm", side
    if is_leg and side:
        return "leg", side
    return None, None


def _adv_get_namespace_from_node(node):
    """Extract Maya namespace from a node.

    Works for both short names (ns:ctrl) and long DAG paths (|grp|ns:ctrl).
    """
    if not node:
        return ""
    try:
        short = str(node).split('|')[-1]
    except Exception:
        short = str(node)
    if ":" in short:
        return short.rsplit(":", 1)[0] + ":"
    return ""


def _adv_get_nodes_for_limb(namespace, limb_type, side):
    """返回 (switch_ctrl, key_nodes)"""
    def _in_control_set(n):
        try:
            cs = namespace + 'ControlSet'
            if cmds.objExists(cs):
                return bool(cmds.sets(n, isMember=cs))
        except Exception:
            pass
        return False

    def _collect_ik_children(root):
        """Collect transform children under IK root that belong to ControlSet."""
        out = []
        if not root or (not cmds.objExists(root)):
            return out
        try:
            kids = cmds.listRelatives(root, ad=True, type='transform', fullPath=False) or []
        except Exception:
            kids = []
        for k in kids:
            if not k or (k in out):
                continue
            if _in_control_set(k):
                # Ensure namespace prefix is included for consistency.
                if namespace and (':' not in k):
                    out.append(namespace + k)
                else:
                    out.append(k)
        return out

    if limb_type == "arm":
        switch_ctrl = namespace + "FKIKArm_" + side
        fk_nodes = [
            namespace + "FKShoulder_" + side,
            namespace + "FKElbow_" + side,
            namespace + "FKWrist_" + side,
        ]
        ik_nodes = [
            namespace + "IKArm_" + side,
            namespace + "PoleArm_" + side,
        ]
        # Include common IK child controls (e.g. roll/offset controls) so moving them triggers live sync.
        ik_nodes += _collect_ik_children(namespace + "IKArm_" + side)
    else:
        switch_ctrl = namespace + "FKIKLeg_" + side
        fk_nodes = [
            namespace + "FKHip_" + side,
            namespace + "FKKnee_" + side,
            namespace + "FKAnkle_" + side,
        ]
        ik_nodes = [
            namespace + "IKLeg_" + side,
            namespace + "PoleLeg_" + side,
        ]

        # Common leg roll/toes controls (names vary; include if exist)
        ik_nodes += [
            namespace + "RollHeel_" + side,
            namespace + "RollToes_" + side,
            namespace + "RollToesEnd_" + side,
            namespace + "IKToes_" + side,
        ]
        # Also include children under IKLeg that are in ControlSet
        ik_nodes += _collect_ik_children(namespace + "IKLeg_" + side)

    fk_nodes = [n for n in fk_nodes if cmds.objExists(n)]
    # de-dup + exists
    _seen = set()
    _ik = []
    for n in ik_nodes:
        if not n or (n in _seen):
            continue
        _seen.add(n)
        if cmds.objExists(n):
            _ik.append(n)
    ik_nodes = _ik
    return switch_ctrl, fk_nodes, ik_nodes


def _adv_collect_selected_limbs():
    """从当前选择收集需要烘焙的肢体集合。

    Returns:
        list[dict]: [{"namespace": ns, "limb_type": "arm"|"leg", "side": "L"|"R"}, ...]
    """
    selection = cmds.ls(sl=True, long=True) or []
    if not selection:
        return []

    seen = set()
    limbs = []
    for node in selection:
        short_name = get_controller_name_without_namespace(node)
        limb_type, side = _adv_parse_limb_from_ctrl(short_name)
        if not limb_type or not side:
            continue
        ns = _adv_get_namespace_from_node(node)
        key = (ns, limb_type, side)
        if key in seen:
            continue
        seen.add(key)
        limbs.append({"namespace": ns, "limb_type": limb_type, "side": side})

    return limbs


def _adv_get_time_slider_selection_range():
    """Return (start, end) from Maya time slider selection.

    Returns:
        tuple[int,int] | None: (start, end) inclusive, or None if no selection.
    """
    try:
        aTimeSlider = mel.eval('$tmpVar=$gPlayBackSlider')
        if cmds.timeControl(aTimeSlider, q=True, rangeVisible=True):
            time_range = cmds.timeControl(aTimeSlider, q=True, rangeArray=True)
            start = int(time_range[0])
            end = int(time_range[1]) - 1  # rangeArray is [start, end+1]
            return start, end
    except Exception:
        return None
    return None


def _adv_ikfk_bake_update_custom_fields_enabled():
    """Enable start/end inputs only when Custom range is selected."""
    try:
        is_custom = False
        if cmds.control(ADV_IKFK_BAKE_RANGE_CUSTOM_RB, exists=True):
            is_custom = bool(cmds.radioButton(ADV_IKFK_BAKE_RANGE_CUSTOM_RB, q=True, select=True))

        if cmds.control(ADV_IKFK_BAKE_RANGE_START_IF, exists=True):
            cmds.intField(ADV_IKFK_BAKE_RANGE_START_IF, e=True, enable=is_custom)
        if cmds.control(ADV_IKFK_BAKE_RANGE_END_IF, exists=True):
            cmds.intField(ADV_IKFK_BAKE_RANGE_END_IF, e=True, enable=is_custom)
    except Exception:
        pass


def _adv_get_ikfk_bake_settings_from_window():
    """Read bake settings from the ADV IKFK bake window (x8 Quick style)."""
    # 默认：时间轴范围 + 所有帧
    start = int(cmds.playbackOptions(q=True, min=True))
    end = int(cmds.playbackOptions(q=True, max=True))
    keyframes_only = True
    direction = "ik_to_fk"

    if cmds.window(ADV_IKFK_BAKE_WINDOW, exists=True):
        # 方向
        try:
            if cmds.control(ADV_IKFK_BAKE_DIR_FK_TO_IK_RB, exists=True) and cmds.radioButton(
                ADV_IKFK_BAKE_DIR_FK_TO_IK_RB, q=True, select=True
            ):
                direction = "fk_to_ik"
            else:
                direction = "ik_to_fk"
        except Exception:
            pass

        try:
            if cmds.control(ADV_IKFK_BAKE_RANGE_SELECTION_RB, exists=True) and cmds.radioButton(
                ADV_IKFK_BAKE_RANGE_SELECTION_RB, q=True, select=True
            ):
                sel = _adv_get_time_slider_selection_range()
                if sel:
                    start, end = sel

            elif cmds.control(ADV_IKFK_BAKE_RANGE_CUSTOM_RB, exists=True) and cmds.radioButton(
                ADV_IKFK_BAKE_RANGE_CUSTOM_RB, q=True, select=True
            ):
                if cmds.control(ADV_IKFK_BAKE_RANGE_START_IF, exists=True):
                    start = int(cmds.intField(ADV_IKFK_BAKE_RANGE_START_IF, q=True, value=True))
                if cmds.control(ADV_IKFK_BAKE_RANGE_END_IF, exists=True):
                    end = int(cmds.intField(ADV_IKFK_BAKE_RANGE_END_IF, q=True, value=True))
        except Exception:
            pass

        try:
            if cmds.control(ADV_IKFK_BAKE_KEYFRAMES_ONLY_CB, exists=True):
                keyframes_only = bool(cmds.checkBox(ADV_IKFK_BAKE_KEYFRAMES_ONLY_CB, q=True, value=True))
        except Exception:
            pass

    if start > end:
        start, end = end, start
    return {"direction": direction, "start": start, "end": end, "keyframes_only": keyframes_only}


def adv_bake_ikfk(direction=None, start=None, end=None, keyframes_only=True):
    """ADV IKFK 烘焙。

    Args:
        direction (str): "fk_to_ik" or "ik_to_fk"
    """
    if direction is None:
        settings = _adv_get_ikfk_bake_settings_from_window()
        direction = settings.get("direction")
        start = settings.get("start")
        end = settings.get("end")
        keyframes_only = settings.get("keyframes_only", True)

    if direction not in ("fk_to_ik", "ik_to_fk"):
        _adv_safe_warning(u"未知烘焙方向: %s" % direction)
        return

    limbs = _adv_collect_selected_limbs()
    if not limbs:
        _adv_safe_warning(u"Cannot find FKIK controller (select FK/IK/Pole control or load AdvancedSkeleton)")
        return

    if start is None or end is None:
        settings = _adv_get_ikfk_bake_settings_from_window()
        start = settings["start"]
        end = settings["end"]
        keyframes_only = settings.get("keyframes_only", True)

    start = int(start)
    end = int(end)
    if start > end:
        start, end = end, start

    if keyframes_only:
        # 与 x8 Quick 一致：只烘焙所涉及控制器在范围内出现的关键帧（去重排序）
        frames_set = set()
        for item in limbs:
            ns = item["namespace"]
            limb_type = item["limb_type"]
            side = item["side"]
            switch_ctrl, fk_nodes, ik_nodes = _adv_get_nodes_for_limb(ns, limb_type, side)

            nodes = []
            if cmds.objExists(switch_ctrl):
                nodes.append(switch_ctrl)
            nodes.extend([n for n in fk_nodes if cmds.objExists(n)])
            nodes.extend([n for n in ik_nodes if cmds.objExists(n)])

            for ctrl in nodes:
                try:
                    k = cmds.keyframe(ctrl, q=True, time=(start, end), timeChange=True) or []
                    for t in k:
                        frames_set.add(int(round(float(t))))
                except Exception:
                    pass
        frames = sorted([f for f in frames_set if start <= f <= end])
    else:
        frames = list(range(start, end + 1))

    if not frames:
        _adv_safe_warning(u"时间范围无效")
        return

    def _adv_try_align_via_asAlignFKIK(ns, limb_type, side, want_direction):
        """Try AdvancedSkeleton official align first.

        Returns:
            bool: True if asAlignFKIK succeeded.
        """
        try:
            ns = str(ns or "")
            limb_type = str(limb_type or "")
            side = str(side or "")
        except Exception:
            pass

        try:
            # Typical biped FKIK switch controls
            fkik_ctrl = ns + ("FKIKArm_" if limb_type == 'arm' else "FKIKLeg_") + side
            if not cmds.objExists(fkik_ctrl):
                return False
            ik_token, side_us = _adv_parse_fkik_name_parts(fkik_ctrl)
            if not ik_token or not side_us:
                return False
            w2k = 'FK2IK' if want_direction == 'fk_to_ik' else 'IK2FK'
            return bool(_adv_mel_call_asAlignFKIK(ns, ik_token, side_us, w2k))
        except Exception:
            return False


    # 性能/稳定性设置：与 AutoIKFKAlign 的 bake 思路一致
    current_time = cmds.currentTime(q=True)
    autokey_state = cmds.autoKeyframe(q=True, state=True)
    undo_state = cmds.undoInfo(q=True, state=True)
    suppress_results = cmds.scriptEditorInfo(q=True, suppressResults=True)
    suppress_info = cmds.scriptEditorInfo(q=True, suppressInfo=True)
    try:
        refresh_suspended = cmds.refresh(q=True, suspend=True)
    except Exception:
        refresh_suspended = False

    if autokey_state:
        cmds.autoKeyframe(state=False)

    if not refresh_suspended:
        cmds.refresh(suspend=True)
    if undo_state:
        pass
    cmds.scriptEditorInfo(suppressResults=True, suppressInfo=True)

    try:
        cmds.undoInfo(openChunk=True)

        # 首帧：把 FKIKBlend 设到“源状态”并 key 一下。
        # 说明：fk_to_ik_align 依赖 FKX（需要 FK 状态）；ik_to_fk_align 依赖 IKX/Joint（需要 IK 状态）。
        pre_frame = frames[0] - 1
        cmds.currentTime(pre_frame, edit=True, update=True)
        for item in limbs:
            ns = item["namespace"]
            limb_type = item["limb_type"]
            side = item["side"]
            switch_ctrl, _, _ = _adv_get_nodes_for_limb(ns, limb_type, side)
            if cmds.objExists(switch_ctrl) and cmds.attributeQuery("FKIKBlend", node=switch_ctrl, exists=True):
                try:
                    # Ensure source state at pre_frame to avoid mis-alignment when the rig is currently in the opposite mode.
                    if direction == "fk_to_ik":
                        _adv_set_fkik_state_endpoint(switch_ctrl, 'FK')
                    else:
                        _adv_set_fkik_state_endpoint(switch_ctrl, 'IK')
                    cmds.setKeyframe(switch_ctrl, attribute="FKIKBlend", time=pre_frame)
                except Exception:
                    pass

        # 烘焙
        for i, frame in enumerate(frames):
            cmds.currentTime(frame, edit=True, update=True)

            for item in limbs:
                ns = item["namespace"]
                limb_type = item["limb_type"]
                side = item["side"]

                switch_ctrl, fk_nodes, ik_nodes = _adv_get_nodes_for_limb(ns, limb_type, side)
                if not cmds.objExists(switch_ctrl) or not cmds.attributeQuery("FKIKBlend", node=switch_ctrl, exists=True):
                    continue

                # 对齐 + 设 blend（顺序参考 AutoIKFKAlign：源状态 -> 对齐 -> 目标状态 -> 打 key）
                if direction == "fk_to_ik":
                    # 先保证 FK 解算有效，再对齐 IK。
                    _adv_set_fkik_state_endpoint(switch_ctrl, 'FK')

                    # Prefer ADV official align (more robust on constrained/connected controllers)
                    ok = _adv_try_align_via_asAlignFKIK(ns, limb_type, side, 'fk_to_ik')
                    if not ok:
                        ok = fk_to_ik_align(ns, limb_type, side)
                    if ok:
                        _adv_set_fkik_state_endpoint(switch_ctrl, 'IK')
                        cmds.setKeyframe(switch_ctrl, attribute="FKIKBlend", time=frame)
                        for n in ik_nodes:
                            cmds.setKeyframe(n, time=frame)
                else:
                    # 先保证 IK 解算有效，再对齐 FK。
                    _adv_set_fkik_state_endpoint(switch_ctrl, 'IK')

                    ok = _adv_try_align_via_asAlignFKIK(ns, limb_type, side, 'ik_to_fk')
                    if not ok:
                        ok = ik_to_fk_align(ns, limb_type, side)
                    if ok:
                        _adv_set_fkik_state_endpoint(switch_ctrl, 'FK')
                        cmds.setKeyframe(switch_ctrl, attribute="FKIKBlend", time=frame)
                        for n in fk_nodes:
                            cmds.setKeyframe(n, time=frame)

            # 简单进度输出（避免刷屏）
            if (i + 1) % 50 == 0 or i == len(frames) - 1:
                try:
                    _adv_safe_print(u"IKFK烘焙进度: %d/%d" % (i + 1, len(frames)))
                except Exception:
                    pass

        cmds.inViewMessage(amg=u"<hl>IKFK烘焙完成</hl>", pos='midCenter', fade=True)

    except Exception as e:
        _adv_safe_warning(u"IKFK烘焙失败: %s" % str(e))
        import traceback
        traceback.print_exc()

    finally:
        try:
            cmds.undoInfo(closeChunk=True)
        except Exception:
            pass
        cmds.scriptEditorInfo(suppressResults=suppress_results, suppressInfo=suppress_info)
        if undo_state:
            try:
                try:
                    cmds.undoInfo(stateWithoutFlush=True)
                except Exception:
                    pass
                cmds.undoInfo(state=True)
            except Exception:
                pass
        if not refresh_suspended:
            cmds.refresh(suspend=False)
        cmds.currentTime(current_time)
        if autokey_state:
            cmds.autoKeyframe(state=True)


def open_adv_ikfk_bake_window():
    """打开 IKFK 烘焙弹窗（UI 参考 x8 IKFK Quick 的“烘焙设置”面板）。"""
    if cmds.window(ADV_IKFK_BAKE_WINDOW, exists=True):
        cmds.deleteUI(ADV_IKFK_BAKE_WINDOW)

    # NOTE:
    # - Old UI was tiny (180x220) and not resizable.
    # - Make it sizeable so users can enlarge it on high-DPI displays.
    # - Avoid resizeToFitChildren=True, which effectively locks the window size.
    w = cmds.window(
        ADV_IKFK_BAKE_WINDOW,
        title=(u"IKFK Quick" if LANGUAGE == "CN" else "IKFK Quick"),
        widthHeight=(280, 320),
        sizeable=True,
        resizeToFitChildren=False,
    )
    cmds.columnLayout(adjustableColumn=True, columnAttach=('both', 6), rowSpacing=5)

    # ===== 方向（Quick: IK→FK / FK→IK） =====
    cmds.rowLayout(numberOfColumns=2, columnWidth2=(85, 85), adjustableColumn=2, columnAlign=(1, 'left'), columnAttach=[(1, 'both', 0), (2, 'both', 0)])
    cmds.radioCollection("advIkfkBakeDirRC")
    cmds.radioButton(ADV_IKFK_BAKE_DIR_IK_TO_FK_RB, label=u"IK→FK", select=True)
    cmds.radioButton(ADV_IKFK_BAKE_DIR_FK_TO_IK_RB, label=u"FK→IK")
    cmds.setParent('..')

    # ===== 时间范围（Quick: label + 3 radios + 起止） =====
    cmds.text(label=(u"时间范围:" if LANGUAGE == "CN" else "Time Range:"), align='left')

    cmds.radioCollection("advIkfkBakeRangeRC")
    cmds.radioButton(
        ADV_IKFK_BAKE_RANGE_TIMELINE_RB,
        label=(u"时间轴范围" if LANGUAGE == "CN" else "Timeline Range"),
        select=True,
        changeCommand=lambda *_: _adv_ikfk_bake_update_custom_fields_enabled(),
    )
    cmds.radioButton(
        ADV_IKFK_BAKE_RANGE_SELECTION_RB,
        label=(u"选择范围" if LANGUAGE == "CN" else "Selection Range"),
        changeCommand=lambda *_: _adv_ikfk_bake_update_custom_fields_enabled(),
    )
    cmds.radioButton(
        ADV_IKFK_BAKE_RANGE_CUSTOM_RB,
        label=(u"自定义" if LANGUAGE == "CN" else "Custom"),
        changeCommand=lambda *_: _adv_ikfk_bake_update_custom_fields_enabled(),
    )

    start_default = int(cmds.playbackOptions(q=True, min=True))
    end_default = int(cmds.playbackOptions(q=True, max=True))
    # Use reasonable widths so the values are readable (the old width=5 was too tiny).
    cmds.rowLayout(
        numberOfColumns=4,
        columnWidth4=(30, 90, 30, 90),
        adjustableColumn=2,
        columnAlign=(1, 'left'),
        columnAttach=[(1, 'both', 0), (2, 'both', 0), (3, 'both', 0), (4, 'both', 0)],
    )
    cmds.text(label=(u"起:" if LANGUAGE == "CN" else "S:"), align='left')
    cmds.intField(ADV_IKFK_BAKE_RANGE_START_IF, value=start_default, width=90)
    cmds.text(label=(u"止:" if LANGUAGE == "CN" else "E:"), align='left')
    cmds.intField(ADV_IKFK_BAKE_RANGE_END_IF, value=end_default, width=90)
    cmds.setParent('..')

    # 初始：未选自定义时禁用输入框
    _adv_ikfk_bake_update_custom_fields_enabled()

    # ===== 仅关键帧（Quick: checkbox 默认 True） =====
    cmds.checkBox(
        ADV_IKFK_BAKE_KEYFRAMES_ONLY_CB,
        label=(u"仅关键帧" if LANGUAGE == "CN" else "Keyframes Only"),
        value=True,
        annotation=(u"只在有关键帧的帧上进行转换（更快）" if LANGUAGE == "CN" else "Convert only on keyed frames (faster)")
    )

    cmds.separator(height=6)

    # ===== 执行按钮（Quick: 单按钮） =====
    cmds.button(
        label=(u"执行烘焙" if LANGUAGE == "CN" else "Bake"),
        height=28,
        backgroundColor=(0.42, 0.56, 0.36),
        command=lambda *_: adv_bake_ikfk()
    )

    cmds.showWindow(w)


