def _adv_sync_normalize_groups_data(data):
    """Normalize a groups payload to our [{name, controllers}] format."""
    if not isinstance(data, list):
        return []
    norm = []
    for g in data:
        if not isinstance(g, dict):
            continue
        name = g.get("name")
        ctrls = g.get("controllers", [])
        if not name:
            continue
        if not isinstance(ctrls, list):
            ctrls = []
        ctrls = [c for c in ctrls if isinstance(c, str) and c]
        norm.append({"name": str(name), "controllers": ctrls})
    return norm


