def _adv_sync_presets_load():
    """Load presets dict: {presetName: groupsList}."""
    if not cmds.optionVar(exists=ADV_SYNC_GROUP_PRESETS_OPTIONVAR):
        return {}
    try:
        raw = cmds.optionVar(q=ADV_SYNC_GROUP_PRESETS_OPTIONVAR)
        if not raw:
            return {}
        data = json.loads(raw)
        if not isinstance(data, dict):
            return {}
        out = {}
        for k, v in data.items():
            if not k:
                continue
            out[str(k)] = _adv_sync_normalize_groups_data(v)
        return out
    except Exception:
        return {}


def _adv_sync_presets_save(presets):
    try:
        cmds.optionVar(stringValue=(ADV_SYNC_GROUP_PRESETS_OPTIONVAR, json.dumps(presets, ensure_ascii=False)))
    except Exception:
        cmds.optionVar(stringValue=(ADV_SYNC_GROUP_PRESETS_OPTIONVAR, json.dumps(presets)))


def _adv_sync_presets_get_active():
    try:
        if cmds.optionVar(exists=ADV_SYNC_GROUP_ACTIVE_PRESET_OPTIONVAR):
            v = cmds.optionVar(q=ADV_SYNC_GROUP_ACTIVE_PRESET_OPTIONVAR)
            if v:
                return str(v)
    except Exception:
        pass
    return "ADV"


def _adv_sync_presets_set_active(name):
    try:
        cmds.optionVar(stringValue=(ADV_SYNC_GROUP_ACTIVE_PRESET_OPTIONVAR, str(name)))
    except Exception:
        pass


def adv_sync_presets_ensure_defaults():
    presets = _adv_sync_presets_load()
    defaults = _adv_sync_default_groups_data()
    if "ADV" not in presets or not presets.get("ADV"):
        presets["ADV"] = defaults
    else:
        # Conservative merge: keep user edits but add new default controllers (e.g. Fingers_L/R)
        try:
            existing = _adv_sync_normalize_groups_data(presets.get("ADV") or [])
        except Exception:
            existing = []
        by_name = {str(g.get("name")): g for g in existing if isinstance(g, dict) and g.get("name")}
        changed = False
        for d in defaults:
            name = str(d.get("name"))
            if name not in by_name:
                continue
            g = by_name[name]
            cur_ctrls = g.get("controllers", []) or []
            if not isinstance(cur_ctrls, list):
                cur_ctrls = []
            cur_set = set(str(c) for c in cur_ctrls if isinstance(c, str) and c)
            for c in (d.get("controllers", []) or []):
                if c and str(c) not in cur_set:
                    cur_ctrls.append(c)
                    cur_set.add(str(c))
                    changed = True
            g["controllers"] = cur_ctrls
        if changed:
            presets["ADV"] = existing
    _adv_sync_presets_save(presets)
    # Ensure active exists
    active = _adv_sync_presets_get_active()
    if active not in presets:
        _adv_sync_presets_set_active("ADV")


def adv_sync_presets_apply(preset_name):
    presets = _adv_sync_presets_load()
    preset_name = str(preset_name or "")
    if preset_name not in presets:
        return
    _adv_sync_groups_save(presets[preset_name])
    _adv_sync_presets_set_active(preset_name)
    # Refresh any visible UIs
    try:
        _adv_sync_groups_window_refresh()
    except Exception:
        pass
    try:
        _adv_sync_ui_rebuild_groups()
    except Exception:
        pass


def adv_sync_presets_save_current_as(preset_name):
    preset_name = str(preset_name or "").strip()
    if not preset_name:
        return False
    presets = _adv_sync_presets_load()
    if preset_name in presets:
        cmds.warning(get_text("sync_key_preset_exists") % preset_name)
        return False
    presets[preset_name] = _adv_sync_groups_load()
    _adv_sync_presets_save(presets)
    _adv_sync_presets_set_active(preset_name)
    return True


def adv_sync_presets_overwrite(preset_name):
    """Overwrite an existing preset with current groups (ADV preset is protected)."""
    preset_name = str(preset_name or "").strip()
    if not preset_name:
        return False
    if preset_name == "ADV":
        cmds.warning(get_text("sync_key_preset_protect_adv"))
        return False
    presets = _adv_sync_presets_load()
    if preset_name not in presets:
        return False
    presets[preset_name] = _adv_sync_groups_load()
    _adv_sync_presets_save(presets)
    _adv_sync_presets_set_active(preset_name)
    return True


def adv_sync_presets_delete(preset_name):
    """Delete a preset (ADV preset is protected)."""
    preset_name = str(preset_name or "").strip()
    if not preset_name:
        return False
    if preset_name == "ADV":
        cmds.warning(get_text("sync_key_preset_protect_adv"))
        return False
    presets = _adv_sync_presets_load()
    if preset_name not in presets:
        return False
    try:
        del presets[preset_name]
    except Exception:
        return False
    # Ensure ADV exists
    if "ADV" not in presets or not presets.get("ADV"):
        presets["ADV"] = _adv_sync_default_groups_data()
    _adv_sync_presets_save(presets)
    # Adjust active preset
    active = _adv_sync_presets_get_active()
    if active == preset_name:
        _adv_sync_presets_set_active("ADV")
    return True


def _adv_sync_groups_load():
    """Load sync groups from optionVar as JSON."""
    if not cmds.optionVar(exists=ADV_SYNC_GROUPS_OPTIONVAR):
        return []
    try:
        raw = cmds.optionVar(q=ADV_SYNC_GROUPS_OPTIONVAR)
        if not raw:
            return []
        data = json.loads(raw)
        if isinstance(data, list):
            return _adv_sync_normalize_groups_data(data)
    except Exception:
        return []
    return []


def _adv_sync_strip_name(node_name):
    """Strip DAG path and namespace: '|ns:Foo' -> 'Foo'."""
    try:
        s = str(node_name)
    except Exception:
        return ""
    if not s:
        return ""
    s = s.split('|')[-1]
    s = s.split(':')[-1]
    return s


def adv_sync_ensure_default_groups(force=False):
    """Ensure 6 default ADV controller groups exist.

    Defaults requested:
      - L Hand, R Hand
      - L Hip, R Hip
      - Spine
      - Head

    Stored controller names are namespace-free so namespaced rigs still match.
    """
    try:
        existing = _adv_sync_groups_load()
    except Exception:
        existing = []

    def _get_version():
        try:
            if cmds.optionVar(exists=ADV_SYNC_DEFAULT_GROUPS_VERSION_OPTIONVAR):
                return int(cmds.optionVar(q=ADV_SYNC_DEFAULT_GROUPS_VERSION_OPTIONVAR))
        except Exception:
            pass
        return 0

    def _set_version(v):
        try:
            cmds.optionVar(intValue=(ADV_SYNC_DEFAULT_GROUPS_VERSION_OPTIONVAR, int(v)))
        except Exception:
            pass

    # If groups already exist and not forcing, do not overwrite user config.
    # But still allow a conservative migration when our default version increases.
    if not force and existing:
        if _get_version() >= ADV_SYNC_DEFAULT_GROUPS_VERSION:
            return

    # If groups are empty, always (re)create defaults even if a previous version flag exists.
    # This avoids a state where the version optionVar is set but the groups were cleared.

    defaults = _adv_sync_default_groups_data()

    # Case A: empty groups -> always create defaults
    if not existing or force:
        _adv_sync_groups_save(defaults)
        _set_version(ADV_SYNC_DEFAULT_GROUPS_VERSION)
        return

    # Case B: try a conservative migration for older defaults
    cur_v = _get_version()
    if cur_v >= ADV_SYNC_DEFAULT_GROUPS_VERSION:
        return

    # v3 migration strategy: non-destructive merge for known default group names.
    # This fixes cases like FKSpine2_M not being part of Spine group in older defaults.
    changed = False
    by_name = {str(g.get("name")): g for g in existing if isinstance(g, dict) and g.get("name")}
    for d in defaults:
        name = d["name"]
        if name not in by_name:
            continue
        g = by_name[name]
        cur_ctrls = g.get("controllers", []) or []
        if not isinstance(cur_ctrls, list):
            cur_ctrls = []
        cur_set = set(str(c) for c in cur_ctrls if isinstance(c, str) and c)
        for c in (d.get("controllers", []) or []):
            if c and str(c) not in cur_set:
                cur_ctrls.append(c)
                cur_set.add(str(c))
                changed = True
        g["controllers"] = cur_ctrls

    if changed:
        _adv_sync_groups_save(existing)
    _set_version(ADV_SYNC_DEFAULT_GROUPS_VERSION)


def _adv_sync_resolve_targets(name_or_pattern):
    """Resolve a stored controller name (or wildcard pattern) to actual scene nodes.

    Supports:
      - exact node name
      - namespace-free name (matches any transform with same stripped name)
      - wildcard patterns with '*' / '?' against stripped names (namespace-free)
    """
    out = []
    if not name_or_pattern:
        return out

    # Exact match first
    try:
        if cmds.objExists(name_or_pattern):
            return [name_or_pattern]
    except Exception:
        pass

    pat = _adv_sync_strip_name(name_or_pattern)
    if not pat:
        return out

    def _scene_transforms_cache(ttl=1.0):
        """Cached list of scene transforms and stripped-name mapping.

        This resolver is called frequently during sync key operations; caching avoids
        repeated `cmds.ls(type='transform')` scans inside the same second.
        """
        global _ADV_SYNC_SCENE_XFORMS_CACHE, _ADV_SYNC_SCENE_XFORMS_CACHE_TIME
        try:
            import time
            now = time.time()
        except Exception:
            now = 0.0

        try:
            if (
                _ADV_SYNC_SCENE_XFORMS_CACHE is not None
                and _ADV_SYNC_SCENE_XFORMS_CACHE_TIME
                and now
                and ttl > 0.0
                and (now - float(_ADV_SYNC_SCENE_XFORMS_CACHE_TIME)) < float(ttl)
            ):
                return _ADV_SYNC_SCENE_XFORMS_CACHE
        except Exception:
            pass

        xforms = []
        by_strip = {}
        try:
            xforms = cmds.ls(type='transform') or []
        except Exception:
            xforms = []
        for n in xforms:
            sn = _adv_sync_strip_name(n)
            if not sn:
                continue
            by_strip.setdefault(sn, []).append(n)
        _ADV_SYNC_SCENE_XFORMS_CACHE = (xforms, by_strip)
        _ADV_SYNC_SCENE_XFORMS_CACHE_TIME = now
        return _ADV_SYNC_SCENE_XFORMS_CACHE

    def _is_curve_controller(xform):
        """Best-effort: controllers are typically transforms with nurbsCurve shapes."""
        try:
            shapes = cmds.listRelatives(xform, s=True, ni=True, type='nurbsCurve') or []
            return bool(shapes)
        except Exception:
            return False

    use_glob = ('*' in pat) or ('?' in pat)
    try:
        xforms, by_strip = _scene_transforms_cache(ttl=1.0)
    except Exception:
        xforms, by_strip = ([], {})

    if use_glob:
        try:
            for n in xforms:
                sn = _adv_sync_strip_name(n)
                if sn and fnmatch.fnmatch(sn, pat):
                    out.append(n)
        except Exception:
            pass
        return out

    # Exact stripped-name match
    try:
        direct = by_strip.get(pat) or []
        if direct:
            return list(direct)
    except Exception:
        pass

    # Fuzzy match for common naming variants (e.g. "PoleArm_L" -> "PoleArm_L_CTRL").
    # Conservative: only used when there is no direct match.
    try:
        cands = []
        for n in xforms:
            sn = _adv_sync_strip_name(n)
            if not sn or sn == pat:
                continue
            if sn.startswith(pat):
                if len(sn) == len(pat) or sn[len(pat)] in ('_', '-'):  # delimiter boundary
                    cands.append(n)
                    continue
            if sn.endswith(pat):
                if len(sn) == len(pat) or sn[-len(pat)-1] in ('_', '-'):  # delimiter boundary
                    cands.append(n)
                    continue

        if not cands:
            return []

        # Prefer curve controllers to avoid grabbing offset/groups.
        curve = [n for n in cands if _is_curve_controller(n)]
        if curve:
            return curve
        return cands
    except Exception:
        return []


# Cached scene transforms for sync group resolving
_ADV_SYNC_SCENE_XFORMS_CACHE = None
_ADV_SYNC_SCENE_XFORMS_CACHE_TIME = 0.0


def adv_sync_select_group_controllers(group_name):
    """Select all controllers resolved for a group."""
    groups = _adv_sync_groups_load()
    ctrls = []
    for g in groups:
        if str(g.get("name", "")) == str(group_name):
            ctrls = g.get("controllers", []) or []
            break
    resolved = []
    seen = set()
    for c in ctrls:
        for n in _adv_sync_resolve_targets(c):
            if n and n not in seen:
                resolved.append(n)
                seen.add(n)
    if resolved:
        try:
            cmds.select(resolved, r=True)
        except Exception:
            pass


def _adv_sync_groups_save(groups):
    """Save sync groups to optionVar as JSON."""
    try:
        cmds.optionVar(stringValue=(ADV_SYNC_GROUPS_OPTIONVAR, json.dumps(groups, ensure_ascii=False)))
    except Exception:
        # Fallback to ASCII if needed
        cmds.optionVar(stringValue=(ADV_SYNC_GROUPS_OPTIONVAR, json.dumps(groups)))


def _adv_sync_group_name_exists(groups, name):
    name_l = str(name).strip().lower()
    return any(str(g.get("name", "")).strip().lower() == name_l for g in groups)


def _adv_sync_default_group_name(groups):
    base = u"组" if LANGUAGE == "CN" else "Group"
    i = 1
    while True:
        n = "%s%d" % (base, i)
        if not _adv_sync_group_name_exists(groups, n):
            return n
        i += 1


def _adv_sync_channelbox_selected_attrs():
    """Return selected attrs in main channel box (best-effort)."""
    try:
        cb = 'mainChannelBox'
        if not cmds.channelBox(cb, exists=True):
            return []
        attrs = []
        for flag in ('sma', 'ssa', 'sha', 'soa'):
            try:
                part = cmds.channelBox(cb, q=True, **{flag: True}) or []
            except Exception:
                part = []
            if part:
                try:
                    attrs.extend([str(a) for a in part if a])
                except Exception:
                    pass
        out = []
        seen = set()
        for a in attrs:
            if a and a not in seen:
                out.append(a)
                seen.add(a)
        return out
    except Exception:
        return []


def _adv_sync_is_safe_anim_connection(src_plug, max_hops=8):
    """Return True if src_plug is part of a normal animation network.

    We want KeySync's safe-SetKey to still work on already-animated channels
    (animCurves / animBlend nodes), but NOT on constraints/driven connections
    that would trigger Maya's "attribute is connected" warnings.
    """
    try:
        if not src_plug:
            return False
        plug = str(src_plug)
    except Exception:
        return False

    # Traverse upstream a few hops to allow common pass-through nodes.
    hop = 0
    seen = set()
    while plug and hop < int(max_hops):
        hop += 1
        try:
            node = plug.split('.', 1)[0]
        except Exception:
            node = ''
        if not node or node in seen:
            return False
        seen.add(node)

        try:
            nt = cmds.nodeType(node) or ''
        except Exception:
            nt = ''
        nt = str(nt)

        # Safe roots.
        if nt.startswith('animCurve'):
            return True
        if nt.startswith('animBlendNode'):
            return True
        if nt == 'pairBlend':
            return True

        # Pass-through nodes that often sit between animCurves and attrs.
        if nt in ('unitConversion',):
            try:
                ups = cmds.listConnections(node, s=True, d=False, p=True) or []
            except Exception:
                ups = []
            plug = str(ups[0]) if ups else ''
            continue

        # Anything else is treated as unsafe (constraints, expressions, etc.).
        return False

    return False


def _adv_sync_keyable_unconnected_attrs(node, preferred_attrs=None):
    """Return keyable attrs that are settable, unlocked, and have no incoming connection.

    preferred_attrs: if provided, only consider these attrs (e.g. channelBox selection).
    """
    if not node:
        return []
    if preferred_attrs:
        try:
            cand = [str(a) for a in preferred_attrs if a]
        except Exception:
            cand = []
    else:
        try:
            cand = cmds.listAttr(node, k=True) or []
        except Exception:
            cand = []

    out = []
    for a in cand:
        if not a:
            continue
        plug = '%s.%s' % (node, a)
        try:
            if not cmds.objExists(plug):
                continue
        except Exception:
            pass
        try:
            if cmds.getAttr(plug, lock=True):
                continue
        except Exception:
            pass
        try:
            if not cmds.getAttr(plug, settable=True):
                continue
        except Exception:
            pass
        # Skip incoming connection unless it is a normal animation network.
        try:
            src = ''
            if cmds.connectionInfo(plug, isDestination=True):
                src = cmds.connectionInfo(plug, sourceFromDestination=True) or ''
            if src and (not _adv_sync_is_safe_anim_connection(src)):
                continue
        except Exception:
            pass
        try:
            inc = cmds.listConnections(plug, s=True, d=False, p=True) or []
            if inc:
                # listConnections may return unitConversion etc; allow if any source is safe.
                safe_any = False
                for s in inc:
                    try:
                        if _adv_sync_is_safe_anim_connection(s):
                            safe_any = True
                            break
                    except Exception:
                        continue
                if not safe_any:
                    continue
        except Exception:
            pass
        out.append(a)
    return out


def _adv_sync_diag_enabled():
    """Key Sync diagnostics piggy-backs on Tangent Debug so users export ONE txt."""
    try:
        return bool(_adv_sync_tangent_debug_enabled())
    except Exception:
        return False


def _adv_sync_diag(msg):
    try:
        if not _adv_sync_diag_enabled():
            return
        _adv_sync_tangent_debug_log("[KeySync] %s" % str(msg))
    except Exception:
        pass


def _adv_sync_diag_short_list(items, max_items=10):
    try:
        items = list(items or [])
    except Exception:
        items = []
    if not items:
        return "[]"
    head = items[:max_items]
    more = len(items) - len(head)
    if more > 0:
        return "[%s, ... +%d]" % (", ".join([str(x) for x in head]), int(more))
    return "[%s]" % ", ".join([str(x) for x in head])


def _adv_sync_diag_attr_reasons(node, preferred_attrs=None):
    """Return (ok_attrs, reasons_dict) for why attrs may be skipped.

    reasons keys: missing/locked/unsettable/connected/error
    """
    reasons = {'missing': 0, 'locked': 0, 'unsettable': 0, 'connected': 0, 'error': 0}
    ok = []
    if not node:
        return ok, reasons
    try:
        if preferred_attrs:
            cand = [str(a) for a in (preferred_attrs or []) if a]
        else:
            cand = cmds.listAttr(node, k=True) or []
    except Exception:
        cand = []

    for a in (cand or []):
        if not a:
            continue
        plug = '%s.%s' % (node, a)
        try:
            if not cmds.objExists(plug):
                reasons['missing'] += 1
                continue
        except Exception:
            # If objExists fails, treat as error but keep going.
            reasons['error'] += 1
            continue
        try:
            if cmds.getAttr(plug, lock=True):
                reasons['locked'] += 1
                continue
        except Exception:
            reasons['error'] += 1
            continue
        try:
            if not cmds.getAttr(plug, settable=True):
                reasons['unsettable'] += 1
                continue
        except Exception:
            reasons['error'] += 1
            continue
        # incoming connections
        try:
            if cmds.connectionInfo(plug, isDestination=True):
                src = cmds.connectionInfo(plug, sourceFromDestination=True)
                if src:
                    reasons['connected'] += 1
                    continue
        except Exception:
            pass
        try:
            inc = cmds.listConnections(plug, s=True, d=False, p=True) or []
            if inc:
                reasons['connected'] += 1
                continue
        except Exception:
            pass
        ok.append(a)
    return ok, reasons


def _adv_sync_diag_snapshot(selection, groups=None):
    """Return (matched_group_names, target_patterns, resolve_map, resolved_nodes)."""
    sel = list(selection or [])
    if not sel:
        return [], [], {}, []
    try:
        groups = groups if groups is not None else _adv_sync_groups_load()
    except Exception:
        groups = []
    if not groups:
        return [], [], {}, []

    sel_set = set(sel)
    sel_stripped = set(_adv_sync_strip_name(s) for s in sel)
    matched = []
    for g in groups:
        ctrls = g.get('controllers', []) or []
        hit = False
        for c in ctrls:
            if not c:
                continue
            if c in sel_set:
                hit = True
                break
            cs = _adv_sync_strip_name(c)
            if not cs:
                continue
            if ('*' in cs) or ('?' in cs):
                for ss in sel_stripped:
                    if ss and fnmatch.fnmatch(ss, cs):
                        hit = True
                        break
                if hit:
                    break
            else:
                if cs in sel_stripped:
                    hit = True
                    break
        if hit:
            matched.append(g)

    if not matched:
        return [], [], {}, []

    patterns = []
    seen = set()
    names = []
    for g in matched:
        try:
            names.append(str(g.get('name', '')))
        except Exception:
            pass
        for c in (g.get('controllers', []) or []):
            if c and c not in seen:
                patterns.append(c)
                seen.add(c)

    resolve_map = {}
    resolved = []
    seen_nodes = set()
    for p in patterns:
        try:
            nodes = _adv_sync_resolve_targets(p) or []
        except Exception:
            nodes = []
        resolve_map[p] = list(nodes)
        for n in nodes:
            if n and n not in seen_nodes:
                resolved.append(n)
                seen_nodes.add(n)
    return names, patterns, resolve_map, resolved


def adv_sync_set_key(warn=True, selection=None):
    """Set key on all controllers in the matched sync group(s).

    Matching rule: If any currently selected node belongs to a group, that group is triggered.
    """
    # Make sure default groups/migrations are applied even if UI was never opened.
    try:
        adv_sync_ensure_default_groups(force=False)
    except Exception:
        pass
    groups = _adv_sync_groups_load()
    if not groups:
        if warn:
            cmds.warning(get_text("sync_key_empty_groups"))
        return

    sel = selection if selection is not None else (cmds.ls(sl=True) or [])
    if not sel:
        if warn:
            cmds.warning(get_text("sync_key_select_object"))
        return

    sel_set = set(sel)
    sel_stripped = set(_adv_sync_strip_name(s) for s in sel)
    matched_groups = []
    for g in groups:
        ctrls = g.get("controllers", []) or []
        # Match by exact name OR stripped name (namespace-free matching)
        hit = False
        for c in ctrls:
            if not c:
                continue
            if c in sel_set:
                hit = True
                break
            cs = _adv_sync_strip_name(c)
            if not cs:
                continue
            if ('*' in cs) or ('?' in cs):
                # Wildcard match against selected stripped names (e.g. FKThumbFinger*_L)
                for ss in sel_stripped:
                    if ss and fnmatch.fnmatch(ss, cs):
                        hit = True
                        break
                if hit:
                    break
            else:
                if cs in sel_stripped:
                    hit = True
                    break
        if hit:
            matched_groups.append(g)

    if not matched_groups:
        if warn:
            cmds.warning(get_text("sync_key_no_match"))
        return

    # Collect unique controllers from matched groups
    targets = []
    seen = set()
    for g in matched_groups:
        for c in (g.get("controllers", []) or []):
            if c and c not in seen:
                targets.append(c)
                seen.add(c)

    
    if _adv_sync_diag_enabled():
        try:
            gnames = [str(g.get('name', '')) for g in matched_groups]
        except Exception:
            gnames = []
        _adv_sync_diag('set_key begin sel=%s frame=%s groups=%s' % (
            _adv_sync_diag_short_list(sel, 6),
            str(int(round(float(cmds.currentTime(q=True))))),
            _adv_sync_diag_short_list(gnames, 6),
        ))

    # Key them
    cmds.undoInfo(openChunk=True)
    try:
        # Resolve namespace-free defaults to actual nodes
        resolved = []
        seen_nodes = set()
        resolve_map = {}
        for t in targets:
            try:
                rn = _adv_sync_resolve_targets(t) or []
            except Exception:
                rn = []
            resolve_map[t] = list(rn)
            for n in rn:
                if n and n not in seen_nodes:
                    resolved.append(n)
                    seen_nodes.add(n)

        if _adv_sync_diag_enabled():
            try:
                unresolved = [p for p, ns in resolve_map.items() if not (ns or [])]
            except Exception:
                unresolved = []
            _adv_sync_diag('set_key resolve patterns=%d resolvedNodes=%d unresolved=%s' % (
                int(len(targets)),
                int(len(resolved)),
                _adv_sync_diag_short_list(unresolved, 16),
            ))

        # Store + select the controllers we are about to key (for tangent tools)
        global _ADV_SYNC_LAST_KEYED_NODES, _ADV_SYNC_LAST_KEYED_TIME
        _ADV_SYNC_LAST_KEYED_NODES = list(resolved)
        try:
            _ADV_SYNC_LAST_KEYED_TIME = cmds.currentTime(q=True)
        except Exception:
            _ADV_SYNC_LAST_KEYED_TIME = None

        preferred = _adv_sync_channelbox_selected_attrs()

        if _adv_sync_diag_enabled():
            _adv_sync_diag('set_key channelBox preferredAttrs=%s' % _adv_sync_diag_short_list(preferred, 16))

        keyed_nodes = 0
        skipped_nodes = 0
        for node in resolved:
            try:
                attrs = _adv_sync_keyable_unconnected_attrs(node, preferred_attrs=preferred)
                # If user has channelBox attrs selected but this node doesn't have them,
                # fall back to keying all safe keyable attrs so group sync stays complete.
                if (not attrs) and preferred:
                    attrs = _adv_sync_keyable_unconnected_attrs(node, preferred_attrs=None)
                if attrs:
                    cmds.setKeyframe(node, attribute=attrs)
                    keyed_nodes += 1
                    if _adv_sync_diag_enabled() and keyed_nodes <= 6:
                        _adv_sync_diag('set_key keyed node=%s attrs=%s' % (str(node), _adv_sync_diag_short_list(attrs, 12)))
                else:
                    skipped_nodes += 1
                    if _adv_sync_diag_enabled():
                        # Explain skip reasons (preferred first, then fallback)
                        ok1, r1 = _adv_sync_diag_attr_reasons(node, preferred_attrs=preferred)
                        ok2, r2 = _adv_sync_diag_attr_reasons(node, preferred_attrs=None)
                        _adv_sync_diag('set_key SKIP node=%s preferredOk=%d reasons=%s fallbackOk=%d reasons=%s' % (
                            str(node),
                            int(len(ok1 or [])),
                            str(r1),
                            int(len(ok2 or [])),
                            str(r2),
                        ))
            except Exception:
                pass

        if _adv_sync_diag_enabled():
            _adv_sync_diag('set_key end keyedNodes=%d skippedNodes=%d' % (int(keyed_nodes), int(skipped_nodes)))

        # NOTE: (Removed) Tangent/curve debug feature was buggy and is intentionally disabled.
    finally:
        cmds.undoInfo(closeChunk=True)


