def _adv_sync_collect_group_nodes_for_selection(selection):
    """Resolve the matched sync group's controllers to scene nodes (namespace/wildcard supported)."""
    # Keep groups up-to-date for callers that don't go through the UI.
    try:
        adv_sync_ensure_default_groups(force=False)
    except Exception:
        pass
    try:
        groups = _adv_sync_groups_load()
    except Exception:
        groups = []

    sel = selection or []
    if not sel or not groups:
        return []

    sel_set = set(sel)
    sel_stripped = set(_adv_sync_strip_name(s) for s in sel)
    matched_groups = []
    for g in groups:
        ctrls = g.get("controllers", []) or []
        hit = False
        for c in ctrls:
            if not c:
                continue
            if c in sel_set:
                hit = True
                break
            cs = _adv_sync_strip_name(c)
            if not cs:
                continue
            if ('*' in cs) or ('?' in cs):
                for ss in sel_stripped:
                    if ss and fnmatch.fnmatch(ss, cs):
                        hit = True
                        break
                if hit:
                    break
            else:
                if cs in sel_stripped:
                    hit = True
                    break
        if hit:
            matched_groups.append(g)

    if not matched_groups:
        return []

    targets = []
    seen = set()
    for g in matched_groups:
        for c in (g.get("controllers", []) or []):
            if c and c not in seen:
                targets.append(c)
                seen.add(c)

    resolved = []
    seen_nodes = set()
    for t in targets:
        for n in _adv_sync_resolve_targets(t):
            if n and n not in seen_nodes:
                resolved.append(n)
                seen_nodes.add(n)
    return resolved


def _adv_sync_is_autokey_on():
    """Return AutoKey state.

    Note: Many studios enable Script Editor "Command Echo" which prints MEL-level
    commands like `autoKeyframe;` and their results. This function can be called
    extremely frequently (attributeChange/idle), so we cache with a small TTL to
    avoid spamming the Script Editor.
    """
    global _ADV_SYNC_AUTOKEY_CACHE_STATE, _ADV_SYNC_AUTOKEY_CACHE_TIME
    try:
        import time
        now = time.time()
    except Exception:
        now = 0.0

    try:
        ttl = float(_ADV_SYNC_AUTOKEY_CACHE_TTL)
    except Exception:
        ttl = 0.5

    if (
        _ADV_SYNC_AUTOKEY_CACHE_STATE is not None
        and _ADV_SYNC_AUTOKEY_CACHE_TIME
        and now
        and ttl > 0.0
        and (now - float(_ADV_SYNC_AUTOKEY_CACHE_TIME)) < ttl
    ):
        return bool(_ADV_SYNC_AUTOKEY_CACHE_STATE)

    prev_se = None
    prev_echo = None
    try:
        # Suppress Script Editor spam when Command Echo is ON.
        try:
            prev_se = _adv_script_editor_suppress_begin()
        except Exception:
            prev_se = None
        try:
            prev_echo = cmds.commandEcho(q=True, state=True)
            cmds.commandEcho(state=False)
        except Exception:
            prev_echo = None

        try:
            state = bool(cmds.autoKeyframe(q=True, state=True))
        except Exception:
            try:
                state = bool(cmds.autoKeyframe(q=True, st=True))
            except Exception:
                state = False
    finally:
        try:
            if prev_echo is not None:
                cmds.commandEcho(state=bool(prev_echo))
        except Exception:
            pass
        try:
            if prev_se is not None:
                _adv_script_editor_suppress_end(prev_se)
        except Exception:
            pass

    _ADV_SYNC_AUTOKEY_CACHE_STATE = bool(state)
    _ADV_SYNC_AUTOKEY_CACHE_TIME = now
    return bool(state)


def _adv_sync_apply_tangent_to_nodes(nodes):
    """Apply selected tangent mode to provided nodes at current frame."""
    if not _adv_sync_tangent_tools_enabled():
        return
    mode = _adv_sync_get_tangent_mode().strip().lower()
    if mode not in (ADV_SYNC_TANGENT_MODE_AUTO, ADV_SYNC_TANGENT_MODE_SPLINE, ADV_SYNC_TANGENT_MODE_STEP, ADV_SYNC_TANGENT_MODE_LINEAR, ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
        return

    # IMPORTANT:
    # Do NOT set _ADV_SYNC_ANIMBOT_DRAG_DIRTY here.
    # This function runs during idle/apply; marking "drag dirty" at apply time causes
    # unrelated future DragRelease events (timeline scrub/graph editor pan/etc) to
    # re-arm another animBot apply -> heavy lag + repeated animBot calls.
    if not nodes:
        return
    # Use the same MEL command user validated works in their Graph Editor context.
    # Key tangent in Maya is most reliable when operating on SELECTED KEYS.
    # So we select keys at current time for these nodes, then run keyTangent (no graphEditor target).
    try:
        t = cmds.currentTime(q=True)
    except Exception:
        t = None

    plugs_selected = 0
    has_keys = False
    try:
        if t is not None:
            has_keys = bool(_adv_sync_has_keys_at_time(nodes, t))
    except Exception:
        has_keys = False

    if mode in (ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
        global _ADV_SYNC_ANIMBOT_APPLYING, _ADV_SYNC_ANIMBOT_LAST_APPLY_TIME
        global _ADV_SYNC_ANIMBOT_UNDO_ARMED, _ADV_SYNC_ANIMBOT_LAST_RECORD_TIME
        global _ADV_SYNC_TANGENT_WATCH_SUSPEND
        _ADV_SYNC_ANIMBOT_APPLYING = True
        record_undo = False
        try:
            # Use snapshot undo if enabled, regardless of _ADV_ANIMBOT_FORCE_NO_UNDO
            if _ADV_ANIMBOT_USE_SNAPSHOT_UNDO:
                record_undo = True
            else:
                record_undo = bool(_adv_animbot_tangent_record_undo())
        except Exception:
            record_undo = False
        # Allow only ONE undo marker per user-change burst.
        # This prevents animBot deferred sub-steps from creating many undo steps.
        try:
            if record_undo:
                import time
                now_r = time.time()
                if not _ADV_SYNC_ANIMBOT_UNDO_ARMED:
                    record_undo = False
                elif _ADV_SYNC_ANIMBOT_LAST_RECORD_TIME and (now_r - float(_ADV_SYNC_ANIMBOT_LAST_RECORD_TIME)) < 0.25:
                    record_undo = False
                else:
                    _ADV_SYNC_ANIMBOT_LAST_RECORD_TIME = now_r
                    _ADV_SYNC_ANIMBOT_UNDO_ARMED = False
        except Exception:
            pass
        prev_undo_state = None
        undo_suspended = False
        # animBot generally operates on selected keys.
        # Only run if keys exist at this time; otherwise selection-based call is wasted.
        if not has_keys:
            _adv_sync_tangent_debug_log("apply_tangent animBot(%s) skipped (no keys at time)" % mode)
            try:
                _adv_sync_animbot_drag_chunk_close()
            except Exception:
                pass
            _ADV_SYNC_ANIMBOT_APPLYING = False
            return
        # Always ensure Undo/Redo jobs exist: even when not recording snapshots,
        # we still need post-undo suppression to avoid auto re-apply loops.
        try:
            _adv_animbot_undo_ensure_jobs()
        except Exception:
            pass

        # Capture tangents BEFORE applying animBot only when recording undo.
        before_snap = []
        if record_undo:
            try:
                before_snap = _adv_animbot_capture_tangent_snapshot(nodes, t)
            except Exception:
                before_snap = []
        try:
            try:
                _ADV_SYNC_TANGENT_WATCH_SUSPEND = True
            except Exception:
                pass

            try:
                plugs_selected = _adv_sync_select_keys_at_time(nodes, t) if (t is not None) else 0
            except Exception:
                plugs_selected = 0
            if not plugs_selected:
                _adv_sync_tangent_debug_log("apply_tangent animBot(%s) skipped (no selectable keys)" % mode)
                try:
                    _adv_sync_animbot_drag_chunk_close()
                except Exception:
                    pass
                _ADV_SYNC_ANIMBOT_APPLYING = False
                _ADV_SYNC_TANGENT_WATCH_SUSPEND = False
                return
            _adv_sync_tangent_debug_log("apply_tangent animBot(%s) plugsSelected=%d nodes=%d" % (mode, int(plugs_selected), len(nodes)))

            if mode == ADV_SYNC_TANGENT_MODE_FLOW:
                _adv_animbot_flow_tangent_trigger_deferred()
            elif mode == ADV_SYNC_TANGENT_MODE_BESTGUESS:
                _adv_animbot_bestguess_tangent_trigger_deferred()
            elif mode == ADV_SYNC_TANGENT_MODE_CYCLEMATCH:
                _adv_animbot_cyclematch_tangent_trigger_deferred()
            else:
                _adv_animbot_polished_tangent_trigger_deferred()

            # If recording undo, finalize (after-snapshot + marker) on deferred ticks.
            if record_undo:
                try:
                    global _ADV_SYNC_ANIMBOT_FINALIZE_PENDING, _ADV_SYNC_ANIMBOT_FINALIZE_TOKEN
                    global _ADV_SYNC_ANIMBOT_FINALIZE_MODE, _ADV_SYNC_ANIMBOT_FINALIZE_NODES, _ADV_SYNC_ANIMBOT_FINALIZE_TIME
                    global _ADV_SYNC_ANIMBOT_FINALIZE_BEFORE_SNAP
                    global _ADV_SYNC_ANIMBOT_FINALIZE_PREV_UNDO_STATE, _ADV_SYNC_ANIMBOT_FINALIZE_UNDO_SUSPENDED
                    global _ADV_SYNC_ANIMBOT_FINALIZE_READY_TIME, _ADV_SYNC_ANIMBOT_FINALIZE_DELAY_SECONDS
                    _ADV_SYNC_ANIMBOT_FINALIZE_PENDING = True
                    try:
                        _ADV_SYNC_ANIMBOT_FINALIZE_TOKEN = int(_ADV_SYNC_ANIMBOT_FINALIZE_TOKEN) + 1
                    except Exception:
                        _ADV_SYNC_ANIMBOT_FINALIZE_TOKEN = 1
                    _ADV_SYNC_ANIMBOT_FINALIZE_MODE = str(mode)
                    _ADV_SYNC_ANIMBOT_FINALIZE_NODES = list(nodes)
                    _ADV_SYNC_ANIMBOT_FINALIZE_TIME = t
                    _ADV_SYNC_ANIMBOT_FINALIZE_BEFORE_SNAP = list(before_snap or [])
                    # Keep these only for legacy safety; Undo is restored immediately above.
                    _ADV_SYNC_ANIMBOT_FINALIZE_PREV_UNDO_STATE = None
                    _ADV_SYNC_ANIMBOT_FINALIZE_UNDO_SUSPENDED = False

                    # Deferred finalize: keep the outer undo chunk open across several deferred ticks
                    # so animBot's own deferred feedback ends up in the SAME undo step.
                    _ADV_SYNC_ANIMBOT_FINALIZE_READY_TIME = 0.0
                    try:
                        tok2 = int(_ADV_SYNC_ANIMBOT_FINALIZE_TOKEN)
                        try:
                            passes = int(globals().get('_ADV_SYNC_ANIMBOT_FINALIZE_DEFER_PASSES', 4) or 4)
                        except Exception:
                            passes = 4
                        if passes < 2:
                            passes = 2

                        # Use evalDeferred(lowestPriority=True) so finalize runs AFTER animBot's
                        # own deferred feedback. This helps collapse the extra undo step that
                        # shows up as "undo event noChange cur=<marker>" before our marker HIT.
                        def _defer_lowest(callable_obj):
                            try:
                                cmds.evalDeferred(callable_obj, lp=True)
                            except Exception:
                                try:
                                    cmds.evalDeferred(callable_obj)
                                except Exception:
                                    callable_obj()

                        def _finalize_step(remaining):
                            try:
                                if int(remaining) <= 0:
                                    _adv_sync_animbot_finalize_deferred(tok2)
                                    return
                            except Exception:
                                try:
                                    _adv_sync_animbot_finalize_deferred(tok2)
                                except Exception:
                                    pass
                                return
                            _defer_lowest(lambda: _finalize_step(int(remaining) - 1))

                        _defer_lowest(lambda: _finalize_step(passes - 1))
                    except Exception:
                        try:
                            _adv_sync_animbot_finalize_deferred(int(_ADV_SYNC_ANIMBOT_FINALIZE_TOKEN))
                        except Exception:
                            pass
                except Exception as e_undo:
                    try:
                        _adv_sync_tangent_debug_log('apply_tangent animBot finalize schedule ERROR: %s' % str(e_undo))
                    except Exception:
                        pass
                    try:
                        _adv_undo_suspend_without_flush_end(prev_undo_state, undo_suspended)
                    except Exception:
                        pass
                    try:
                        _ADV_SYNC_ANIMBOT_APPLYING = False
                    except Exception:
                        pass
                    try:
                        _ADV_SYNC_TANGENT_WATCH_SUSPEND = False
                    except Exception:
                        pass
            else:
                # Not recording undo: restore undo immediately.
                try:
                    _adv_undo_suspend_without_flush_end(prev_undo_state, undo_suspended)
                except Exception:
                    pass
                try:
                    _ADV_SYNC_ANIMBOT_APPLYING = False
                except Exception:
                    pass
                try:
                    _ADV_SYNC_TANGENT_WATCH_SUSPEND = False
                except Exception:
                    pass
            return
        finally:
            try:
                _adv_sync_animbot_drag_chunk_close()
            except Exception:
                pass
            # Safety: ensure stale drag state doesn't re-arm on unrelated DragRelease.
            try:
                global _ADV_SYNC_ANIMBOT_DRAG_DIRTY, _ADV_SYNC_ANIMBOT_DRAG_CACHED_MODE, _ADV_SYNC_ANIMBOT_DRAG_CACHED_NODES
                _ADV_SYNC_ANIMBOT_DRAG_DIRTY = False
                _ADV_SYNC_ANIMBOT_DRAG_CACHED_MODE = ""
                _ADV_SYNC_ANIMBOT_DRAG_CACHED_NODES = []
            except Exception:
                pass
            try:
                import time
                _ADV_SYNC_ANIMBOT_LAST_APPLY_TIME = time.time()
                try:
                    global _ADV_SYNC_ANIMBOT_POST_APPLY_GUARD_UNTIL
                    _ADV_SYNC_ANIMBOT_POST_APPLY_GUARD_UNTIL = float(_ADV_SYNC_ANIMBOT_LAST_APPLY_TIME) + float(_ADV_SYNC_ANIMBOT_POST_APPLY_GUARD_SECONDS)
                except Exception:
                    _ADV_SYNC_ANIMBOT_POST_APPLY_GUARD_UNTIL = float(_ADV_SYNC_ANIMBOT_LAST_APPLY_TIME) + 8.0
            except Exception:
                _ADV_SYNC_ANIMBOT_LAST_APPLY_TIME = 0.0
            try:
                if t is not None:
                    _ADV_SYNC_ANIMBOT_LAST_APPLIED_FRAME[str(mode)] = float(t)
            except Exception:
                pass
            try:
                import time
                _ADV_SYNC_TANGENT_WATCH_SELECTION_COOLDOWN_UNTIL = time.time() + 0.45
            except Exception:
                _ADV_SYNC_TANGENT_WATCH_SELECTION_COOLDOWN_UNTIL = 0.0
            # If we scheduled a deferred finalize, it will clear these flags.
            try:
                if not bool(globals().get('_ADV_SYNC_ANIMBOT_FINALIZE_PENDING', False)):
                    _ADV_SYNC_ANIMBOT_APPLYING = False
                    _ADV_SYNC_TANGENT_WATCH_SUSPEND = False
            except Exception:
                _ADV_SYNC_ANIMBOT_APPLYING = False
                _ADV_SYNC_TANGENT_WATCH_SUSPEND = False

    # Tangent auto-apply is a helper; it should not spam the user's Undo queue.
    # IMPORTANT: Never use `undoInfo(state=False)` as a fallback because it may FLUSH
    # the user's undo queue in some environments, making their freshly keyed frame
    # impossible to undo. If we can't safely suspend Undo without flushing, we simply
    # leave Undo enabled (safe but may add an extra undo step).
    prev_undo_state, undo_suspended = _adv_undo_suspend_without_flush_begin()
    try:
        if _adv_sync_tangent_debug_enabled():
            _adv_sync_tangent_debug_log("apply_tangent undo_suspended=%s" % str(bool(undo_suspended)))

        # Prefer cmds.keyTangent first: it does NOT require selecting keys and is much
        # less likely to interfere with viewport manipulation.
        try:
            if t is None:
                t = cmds.currentTime(q=True)
            if mode == ADV_SYNC_TANGENT_MODE_AUTO:
                cmds.keyTangent(nodes, e=True, time=(t, t), itt='auto', ott='auto')
            elif mode == ADV_SYNC_TANGENT_MODE_SPLINE:
                cmds.keyTangent(nodes, e=True, time=(t, t), itt='spline', ott='spline')
            elif mode == ADV_SYNC_TANGENT_MODE_STEP:
                cmds.keyTangent(nodes, e=True, time=(t, t), ott='step')
            else:
                cmds.keyTangent(nodes, e=True, time=(t, t), itt='linear', ott='linear')
            _adv_sync_tangent_debug_log("apply_tangent cmds.keyTangent ok mode=%s nodes=%d" % (mode, len(nodes)))
            return
        except Exception as e2:
            global _ADV_SYNC_TANGENT_DEBUG_LAST_ERROR
            _ADV_SYNC_TANGENT_DEBUG_LAST_ERROR = str(e2)
            _adv_sync_tangent_debug_log("apply_tangent cmds.keyTangent ERROR: %s" % str(e2))

        # Last resort: MEL on selected keys (can affect selection; only used if needed).
        try:
            if t is not None:
                _adv_sync_select_keys_at_time(nodes, t)
            if mode == ADV_SYNC_TANGENT_MODE_AUTO:
                r = mel.eval('keyTangent -e -itt auto -ott auto;')
            elif mode == ADV_SYNC_TANGENT_MODE_SPLINE:
                r = mel.eval('keyTangent -e -itt spline -ott spline;')
            elif mode == ADV_SYNC_TANGENT_MODE_STEP:
                r = mel.eval('keyTangent -e -ott step;')
            else:
                r = mel.eval('keyTangent -e -itt linear -ott linear;')
            _adv_sync_tangent_debug_log("apply_tangent MEL ok mode=%s result=%s nodes=%d" % (mode, str(r), len(nodes)))
            return
        except Exception as e3:
            _ADV_SYNC_TANGENT_DEBUG_LAST_ERROR = str(e3)
            _adv_sync_tangent_debug_log("apply_tangent MEL ERROR: %s" % str(e3))
    finally:
        _adv_undo_suspend_without_flush_end(prev_undo_state, undo_suspended)
        if _adv_sync_tangent_debug_enabled() and undo_suspended and (prev_undo_state is True):
            _adv_sync_tangent_debug_log("apply_tangent undo_restored=True")


def _adv_sync_animbot_drag_chunk_open():
    """Open a long-lived undo chunk used to group drag + animBot tangent marker."""
    global _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN, _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN_TIME
    if _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN:
        return
    try:
        cmds.undoInfo(openChunk=True, chunkName="ADV_AnimbotTangent")
        _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN = True
        try:
            import time
            _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN_TIME = time.time()
        except Exception:
            _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN_TIME = 0.0
    except Exception:
        _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN = False
        _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN_TIME = 0.0


def _adv_sync_animbot_drag_chunk_close():
    """Close the long-lived undo chunk (safe no-op if not open)."""
    global _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN, _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN_TIME
    if not _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN:
        return
    try:
        cmds.undoInfo(closeChunk=True)
    except Exception:
        pass
    _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN = False
    _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN_TIME = 0.0


def adv_tangent_emergency_stop():
    try:
        _adv_sync_set_tangent_tools_enabled(False)
    except Exception:
        try:
            _adv_sync_tangent_watch_set_enabled(False)
        except Exception:
            pass

    g = globals()
    try:
        g['_ADV_SYNC_TANGENT_PENDING'] = False
        g['_ADV_SYNC_TANGENT_PENDING_MODE'] = ""
        g['_ADV_SYNC_TANGENT_PENDING_NODES'] = []
        g['_ADV_SYNC_TANGENT_PENDING_TRIES'] = 0
    except Exception:
        pass

    try:
        g['_ADV_SYNC_ANIMBOT_PENDING'] = False
        g['_ADV_SYNC_ANIMBOT_PENDING_MODE'] = ""
        g['_ADV_SYNC_ANIMBOT_PENDING_NODES'] = []
        g['_ADV_SYNC_ANIMBOT_PENDING_TRIES'] = 0
        g['_ADV_SYNC_ANIMBOT_FORCE_APPLY_ON_NEXT_IDLE'] = False
        g['_ADV_SYNC_ANIMBOT_PENDING_TOKEN'] = 0
    except Exception:
        pass

    try:
        _adv_sync_animbot_drag_chunk_close()
    except Exception:
        pass
    try:
        global _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN
        if _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN:
            try:
                cmds.undoInfo(closeChunk=True)
            except Exception:
                pass
            _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN = False
    except Exception:
        pass
    try:
        if g.get('_ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN', False):
            try:
                cmds.undoInfo(closeChunk=True)
            except Exception:
                pass
            g['_ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN'] = False
            g['_ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN_TIME'] = 0.0
    except Exception:
        pass


def _adv_sync_animbot_undoname_watch_tick():
    try:
        if not bool(globals().get('_ADV_SYNC_ANIMBOT_USE_UNDONAME_WATCH', False)):
            return
    except Exception:
        return
    try:
        if _ADV_SYNC_SUSPEND:
            return
    except Exception:
        pass
    if not _adv_sync_tangent_tools_enabled():
        return
    try:
        if bool(globals().get('_ADV_SYNC_ANIMBOT_APPLYING', False)):
            return
    except Exception:
        pass
    try:
        mode = _adv_sync_get_tangent_mode().strip().lower()
    except Exception:
        mode = ""
    if mode not in (ADV_SYNC_TANGENT_MODE_AUTO, ADV_SYNC_TANGENT_MODE_SPLINE, ADV_SYNC_TANGENT_MODE_STEP, ADV_SYNC_TANGENT_MODE_LINEAR, ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
        return
    try:
        if not _adv_sync_is_autokey_on():
            return
    except Exception:
        return
    try:
        undo_name = cmds.undoInfo(q=True, undoName=True)
    except Exception:
        return
    if not undo_name:
        return
    is_transform = False
    try:
        ctx = str(cmds.currentCtx() or "")
        if "SuperContext" in ctx:
            is_transform = True
        else:
            lower_ctx = ctx.lower()
            is_transform = ("move" in lower_ctx) or ("rotate" in lower_ctx) or ("scale" in lower_ctx)
    except Exception:
        is_transform = False
    if not is_transform:
        lower = str(undo_name).lower()
        is_transform = ("move" in lower) or ("rotate" in lower) or ("scale" in lower)
    global _ADV_SYNC_ANIMBOT_UNDONAME_PENDING, _ADV_SYNC_ANIMBOT_UNDONAME_SINCE
    global _ADV_SYNC_ANIMBOT_UNDONAME_LAST_SEEN, _ADV_SYNC_ANIMBOT_UNDONAME_LAST_FIRED
    global _ADV_SYNC_ANIMBOT_UNDONAME_APPLY_SCHEDULED, _ADV_SYNC_ANIMBOT_UNDONAME_DEBOUNCE_SECONDS
    global _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN, _ADV_SYNC_TANGENT_OUTER_CHUNK_NAME
    try:
        import time
        now = time.time()
    except Exception:
        now = 0.0

    if is_transform:
        if str(undo_name) != str(_ADV_SYNC_ANIMBOT_UNDONAME_LAST_SEEN or ""):
            _ADV_SYNC_ANIMBOT_UNDONAME_LAST_SEEN = str(undo_name)
            if not _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN:
                try:
                    cmds.undoInfo(openChunk=True, chunkName=str(_ADV_SYNC_TANGENT_OUTER_CHUNK_NAME))
                    _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN = True
                except Exception:
                    _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN = False
            _ADV_SYNC_ANIMBOT_UNDONAME_PENDING = True
            _ADV_SYNC_ANIMBOT_UNDONAME_SINCE = float(now or 0.0)
            return
        if _ADV_SYNC_ANIMBOT_UNDONAME_PENDING:
            try:
                if now and (now - float(_ADV_SYNC_ANIMBOT_UNDONAME_SINCE or 0.0)) >= float(_ADV_SYNC_ANIMBOT_UNDONAME_DEBOUNCE_SECONDS or 0.25):
                    _ADV_SYNC_ANIMBOT_UNDONAME_PENDING = False
                    if _ADV_SYNC_ANIMBOT_UNDONAME_LAST_SEEN and (_ADV_SYNC_ANIMBOT_UNDONAME_LAST_SEEN != _ADV_SYNC_ANIMBOT_UNDONAME_LAST_FIRED):
                        _ADV_SYNC_ANIMBOT_UNDONAME_LAST_FIRED = _ADV_SYNC_ANIMBOT_UNDONAME_LAST_SEEN
                        _adv_sync_animbot_undoname_schedule_apply()
            except Exception:
                pass
        return

    if _ADV_SYNC_ANIMBOT_UNDONAME_PENDING:
        try:
            if now and (now - float(_ADV_SYNC_ANIMBOT_UNDONAME_SINCE or 0.0)) >= float(_ADV_SYNC_ANIMBOT_UNDONAME_DEBOUNCE_SECONDS or 0.25):
                _ADV_SYNC_ANIMBOT_UNDONAME_PENDING = False
                if _ADV_SYNC_ANIMBOT_UNDONAME_LAST_SEEN and (_ADV_SYNC_ANIMBOT_UNDONAME_LAST_SEEN != _ADV_SYNC_ANIMBOT_UNDONAME_LAST_FIRED):
                    _ADV_SYNC_ANIMBOT_UNDONAME_LAST_FIRED = _ADV_SYNC_ANIMBOT_UNDONAME_LAST_SEEN
                    _adv_sync_animbot_undoname_schedule_apply()
        except Exception:
            pass


def _adv_sync_animbot_undoname_schedule_apply():
    global _ADV_SYNC_ANIMBOT_UNDONAME_APPLY_SCHEDULED
    try:
        if _ADV_SYNC_ANIMBOT_UNDONAME_APPLY_SCHEDULED:
            return
    except Exception:
        pass
    _ADV_SYNC_ANIMBOT_UNDONAME_APPLY_SCHEDULED = True
    try:
        import maya.utils as _adv_maya_utils
        _adv_maya_utils.executeDeferred(_adv_sync_animbot_undoname_apply_deferred)
    except Exception:
        _ADV_SYNC_ANIMBOT_UNDONAME_APPLY_SCHEDULED = False


def _adv_sync_animbot_undoname_apply_deferred():
    global _ADV_SYNC_ANIMBOT_UNDONAME_APPLY_SCHEDULED
    _ADV_SYNC_ANIMBOT_UNDONAME_APPLY_SCHEDULED = False
    try:
        if not _adv_sync_tangent_tools_enabled():
            return
    except Exception:
        return
    try:
        mode = _adv_sync_get_tangent_mode().strip().lower()
    except Exception:
        mode = ""
    if mode not in (ADV_SYNC_TANGENT_MODE_AUTO, ADV_SYNC_TANGENT_MODE_SPLINE, ADV_SYNC_TANGENT_MODE_STEP, ADV_SYNC_TANGENT_MODE_LINEAR, ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
        return
    try:
        if not _adv_sync_is_autokey_on():
            return
    except Exception:
        return
    try:
        nodes = list(_ADV_SYNC_TANGENT_WATCH_TARGET_NODES or [])
    except Exception:
        nodes = []
    if not nodes:
        try:
            _adv_sync_tangent_watch_rebuild_from_selection()
        except Exception:
            pass
        try:
            nodes = list(_ADV_SYNC_TANGENT_WATCH_TARGET_NODES or [])
        except Exception:
            nodes = []
    if not nodes:
        return
    try:
        t = cmds.currentTime(q=True)
    except Exception:
        t = None
    if t is None:
        return
    try:
        if not bool(_adv_sync_has_keys_at_time(nodes, t)):
            return
    except Exception:
        return

    sel_before = []
    try:
        sel_before = cmds.ls(sl=True, long=True) or []
    except Exception:
        sel_before = []

    opened_local_chunk = False
    global _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN
    try:
        plugs_selected = 0
        try:
            plugs_selected = int(_adv_sync_select_keys_at_time(nodes, t) or 0)
        except Exception:
            plugs_selected = 0
        if plugs_selected <= 0:
            return

        if not _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN:
            try:
                cmds.undoInfo(openChunk=True, chunkName="ADV_TangentDebug")
                opened_local_chunk = True
            except Exception:
                opened_local_chunk = False

        if mode in (ADV_SYNC_TANGENT_MODE_AUTO, ADV_SYNC_TANGENT_MODE_SPLINE, ADV_SYNC_TANGENT_MODE_STEP, ADV_SYNC_TANGENT_MODE_LINEAR):
            try:
                cmds.keyTangent(e=True, itt=str(mode), ott=str(mode))
            except Exception:
                pass
            return

        core = _adv_animbot_get_core()
        if not core:
            return
        if mode == ADV_SYNC_TANGENT_MODE_FLOW:
            core.trigger.tangents_flowTangent()
        elif mode == ADV_SYNC_TANGENT_MODE_BESTGUESS:
            core.trigger.tangents_bestGuessTangent()
        elif mode == ADV_SYNC_TANGENT_MODE_CYCLEMATCH:
            core.trigger.tangents_cycleMatchTangent()
        else:
            core.trigger.tangents_polishedTangent()
    finally:
        if opened_local_chunk:
            try:
                cmds.undoInfo(closeChunk=True)
            except Exception:
                pass
        try:
            if _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN:
                cmds.undoInfo(closeChunk=True)
                _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN = False
        except Exception:
            _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN = False
        try:
            cmds.selectKey(clear=True)
        except Exception:
            pass
        try:
            if sel_before:
                cmds.select(sel_before, r=True)
        except Exception:
            pass
        try:
            _adv_ensure_undo_enabled()
        except Exception:
            pass


def _adv_sync_animbot_drag_chunk_maybe_close_when_idle():
    """Safety: if a drag finished but we never applied tangents, close the chunk."""
    if not _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN:
        return
    try:
        import time
        now = time.time()
        # Hard safety: never allow a custom undo chunk to stay open for long.
        # Missing DragRelease (or stuck IN_DRAG) can otherwise leave Undo unusable.
        try:
            if _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN_TIME and (now - float(_ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN_TIME)) > 2.0:
                try:
                    globals()['_ADV_SYNC_ANIMBOT_IN_DRAG'] = False
                except Exception:
                    pass
                _adv_sync_animbot_drag_chunk_close()
                return
        except Exception:
            pass
        # Normal case: DragRelease recorded.
        if _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME and (now - float(_ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME)) > 0.6:
            _adv_sync_animbot_drag_chunk_close()
            return
        # Fallback: DragRelease scriptJob can fail/miss; never let the chunk stay open.
        try:
            if (not bool(globals().get('_ADV_SYNC_ANIMBOT_IN_DRAG', False))):
                if _ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN_TIME and (now - float(_ADV_SYNC_ANIMBOT_DRAG_CHUNK_OPEN_TIME)) > 1.2:
                    _adv_sync_animbot_drag_chunk_close()
                    return
        except Exception:
            pass
    except Exception:
        pass


def _adv_sync_animbot_on_drag_press(*_):
    """DragPress: mark start of manipulation."""
    try:
        if bool(globals().get('_ADV_SYNC_ANIMBOT_USE_UNDONAME_WATCH', False)):
            return
    except Exception:
        pass
    global _ADV_SYNC_ANIMBOT_IN_DRAG, _ADV_SYNC_ANIMBOT_BLOCK_UNTIL_USER, _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL
    global _ADV_SYNC_ANIMBOT_PENDING
    global _ADV_SYNC_ANIMBOT_DRAG_DIRTY, _ADV_SYNC_ANIMBOT_DRAG_CACHED_MODE, _ADV_SYNC_ANIMBOT_DRAG_CACHED_NODES
    global _ADV_SYNC_ANIMBOT_DRAG_CHANGE_SERIAL, _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_SERIAL
    _ADV_SYNC_ANIMBOT_IN_DRAG = True
    _ADV_SYNC_ANIMBOT_DRAG_DIRTY = False
    _ADV_SYNC_ANIMBOT_DRAG_CACHED_MODE = ""
    _ADV_SYNC_ANIMBOT_DRAG_CACHED_NODES = []
    _ADV_SYNC_ANIMBOT_DRAG_CHANGE_SERIAL = 0
    _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_SERIAL = 0
    _ADV_SYNC_ANIMBOT_BLOCK_UNTIL_USER = False
    _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL = 0
    # Clear any pending from previous manipulation
    _ADV_SYNC_ANIMBOT_PENDING = False
    if not _adv_sync_tangent_tools_enabled():
        return
    mode = _adv_sync_get_tangent_mode().strip().lower()
    if mode not in (ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
        return
    try:
        if not _adv_sync_is_autokey_on():
            return
    except Exception:
        return
    _adv_sync_animbot_drag_chunk_open()


def _adv_sync_animbot_on_drag_release(*_):
    """DragRelease: mark pending for immediate apply (bypass debounce)."""
    try:
        if bool(globals().get('_ADV_SYNC_ANIMBOT_USE_UNDONAME_WATCH', False)):
            return
    except Exception:
        pass
    global _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME, _ADV_SYNC_ANIMBOT_IN_DRAG
    global _ADV_SYNC_ANIMBOT_FORCE_APPLY_ON_NEXT_IDLE
    global _ADV_SYNC_ANIMBOT_RELEASE_TOKEN, _ADV_SYNC_ANIMBOT_PENDING_TOKEN
    global _ADV_SYNC_ANIMBOT_UNDO_ARMED
    global _ADV_SYNC_ANIMBOT_PENDING
    global _ADV_SYNC_ANIMBOT_DRAG_DIRTY, _ADV_SYNC_ANIMBOT_DRAG_CACHED_MODE, _ADV_SYNC_ANIMBOT_DRAG_CACHED_NODES
    global _ADV_SYNC_ANIMBOT_PENDING_MODE, _ADV_SYNC_ANIMBOT_PENDING_NODES, _ADV_SYNC_ANIMBOT_LAST_CHANGE_TIME
    global _ADV_SYNC_ANIMBOT_DRAG_CHANGE_SERIAL, _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_SERIAL
    _ADV_SYNC_ANIMBOT_IN_DRAG = False
    # Some Maya setups can emit DragRelease multiple times in rapid succession.
    # Guard against duplicates to avoid arming multiple apply/undo-marker sequences.
    try:
        prev_release = float(_ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME or 0.0)
    except Exception:
        prev_release = 0.0
    try:
        import time
        now_release = time.time()
        _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME = now_release
    except Exception:
        now_release = 0.0
        _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME = 0.0

    try:
        if prev_release and now_release and (now_release - prev_release) < 0.08:
            return
    except Exception:
        pass

    # If Maya fired a DragRelease but we have not seen any new user-driven transform
    # changes since the last processed release, ignore it to prevent duplicate applies.
    # Only apply this filter when we don't already have a pending/dirty request.
    try:
        if (not _ADV_SYNC_ANIMBOT_PENDING) and (not _ADV_SYNC_ANIMBOT_DRAG_DIRTY):
            if int(_ADV_SYNC_ANIMBOT_DRAG_CHANGE_SERIAL or 0) == int(_ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_SERIAL or 0):
                return
    except Exception:
        pass
    
    # If there's a pending animBot request, mark it for immediate processing.
    # This bypasses the debounce timer on the next idle tick.
    #
    # IMPORTANT: Some setups intermittently miss DragPress (job creation can fail) or
    # the watcher may be gated, so _ADV_SYNC_ANIMBOT_PENDING might be False even
    # though the user DID change values during the drag.
    # We keep a lightweight "drag_dirty" flag (set by attributeChange callbacks) and
    # use it as a fallback to arm a single apply on release.
    if (not _ADV_SYNC_ANIMBOT_PENDING) and _ADV_SYNC_ANIMBOT_DRAG_DIRTY:
        try:
            mode_now = _adv_sync_get_tangent_mode().strip().lower()
        except Exception:
            mode_now = ""
        if mode_now in (ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
            try:
                nodes_fallback = list(_ADV_SYNC_ANIMBOT_DRAG_CACHED_NODES or [])
            except Exception:
                nodes_fallback = []
            if not nodes_fallback:
                try:
                    nodes_fallback = list(_ADV_SYNC_TANGENT_WATCH_TARGET_NODES or [])
                except Exception:
                    nodes_fallback = []
            if nodes_fallback:
                _ADV_SYNC_ANIMBOT_PENDING = True
                try:
                    _ADV_SYNC_ANIMBOT_PENDING_MODE = str(_ADV_SYNC_ANIMBOT_DRAG_CACHED_MODE or mode_now).strip().lower()
                except Exception:
                    _ADV_SYNC_ANIMBOT_PENDING_MODE = str(mode_now)
                _ADV_SYNC_ANIMBOT_PENDING_NODES = list(nodes_fallback)
                try:
                    import time
                    _ADV_SYNC_ANIMBOT_LAST_CHANGE_TIME = time.time()
                except Exception:
                    _ADV_SYNC_ANIMBOT_LAST_CHANGE_TIME = 0.0
                _adv_sync_tangent_debug_log("drag release fallback armed pending mode=%s nodes=%d" % (str(_ADV_SYNC_ANIMBOT_PENDING_MODE), len(_ADV_SYNC_ANIMBOT_PENDING_NODES or [])))

    if _ADV_SYNC_ANIMBOT_PENDING:
        try:
            _ADV_SYNC_ANIMBOT_RELEASE_TOKEN = int(_ADV_SYNC_ANIMBOT_RELEASE_TOKEN) + 1
        except Exception:
            _ADV_SYNC_ANIMBOT_RELEASE_TOKEN = 1
        _ADV_SYNC_ANIMBOT_PENDING_TOKEN = int(_ADV_SYNC_ANIMBOT_RELEASE_TOKEN)
        _ADV_SYNC_ANIMBOT_UNDO_ARMED = True
        _ADV_SYNC_ANIMBOT_FORCE_APPLY_ON_NEXT_IDLE = True
        try:
            _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_SERIAL = int(_ADV_SYNC_ANIMBOT_DRAG_CHANGE_SERIAL or 0)
        except Exception:
            _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_SERIAL = 0
        _adv_sync_tangent_debug_log("drag release - force apply on next idle")

    # Consume dirty state for this release so we don't arm repeatedly.
    _ADV_SYNC_ANIMBOT_DRAG_DIRTY = False
    _ADV_SYNC_ANIMBOT_DRAG_CACHED_MODE = ""
    _ADV_SYNC_ANIMBOT_DRAG_CACHED_NODES = []
    
    # IMPORTANT:
    # Do not keep a custom Undo chunk open after the user releases the manipulator.
    # If this chunk stays open while we wait for the idle tick to apply tangents,
    # Maya can show "Undo temporarily unavailable" and Ctrl+Z will appear to do nothing
    # on the first manipulation at a new keyed frame.
    try:
        _adv_sync_animbot_drag_chunk_close()
    except Exception:
        pass
    try:
        _adv_ensure_undo_enabled()
    except Exception:
        pass
    try:
        g = globals()
        if g.get('_ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN', False):
            try:
                cmds.undoInfo(closeChunk=True)
            except Exception:
                pass
            g['_ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN'] = False
            g['_ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN_TIME'] = 0.0
    except Exception:
        pass


def _adv_sync_tangent_watch_clear_jobs():
    global _ADV_SYNC_TANGENT_WATCH_SEL_JOB_ID, _ADV_SYNC_TANGENT_WATCH_ATTR_JOB_IDS, _ADV_SYNC_TANGENT_WATCH_IDLE_JOB_ID
    global _ADV_SYNC_TANGENT_WATCH_TIME_JOB_ID
    try:
        if _ADV_SYNC_TANGENT_WATCH_SEL_JOB_ID and cmds.scriptJob(exists=_ADV_SYNC_TANGENT_WATCH_SEL_JOB_ID):
            cmds.scriptJob(kill=_ADV_SYNC_TANGENT_WATCH_SEL_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_SYNC_TANGENT_WATCH_SEL_JOB_ID = None

    for jid in list(_ADV_SYNC_TANGENT_WATCH_ATTR_JOB_IDS or []):
        try:
            if cmds.scriptJob(exists=jid):
                cmds.scriptJob(kill=jid, force=True)
        except Exception:
            pass
    _ADV_SYNC_TANGENT_WATCH_ATTR_JOB_IDS = []

    try:
        if _ADV_SYNC_TANGENT_WATCH_IDLE_JOB_ID and cmds.scriptJob(exists=_ADV_SYNC_TANGENT_WATCH_IDLE_JOB_ID):
            cmds.scriptJob(kill=_ADV_SYNC_TANGENT_WATCH_IDLE_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_SYNC_TANGENT_WATCH_IDLE_JOB_ID = None
    
    try:
        if _ADV_SYNC_TANGENT_WATCH_TIME_JOB_ID and cmds.scriptJob(exists=_ADV_SYNC_TANGENT_WATCH_TIME_JOB_ID):
            cmds.scriptJob(kill=_ADV_SYNC_TANGENT_WATCH_TIME_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_SYNC_TANGENT_WATCH_TIME_JOB_ID = None

    # clear animBot drag jobs + close any open drag undo chunk
    global _ADV_SYNC_ANIMBOT_DRAGPRESS_JOB_ID, _ADV_SYNC_ANIMBOT_DRAGRELEASE_JOB_ID
    try:
        if _ADV_SYNC_ANIMBOT_DRAGPRESS_JOB_ID and cmds.scriptJob(exists=_ADV_SYNC_ANIMBOT_DRAGPRESS_JOB_ID):
            cmds.scriptJob(kill=_ADV_SYNC_ANIMBOT_DRAGPRESS_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_SYNC_ANIMBOT_DRAGPRESS_JOB_ID = None
    try:
        if _ADV_SYNC_ANIMBOT_DRAGRELEASE_JOB_ID and cmds.scriptJob(exists=_ADV_SYNC_ANIMBOT_DRAGRELEASE_JOB_ID):
            cmds.scriptJob(kill=_ADV_SYNC_ANIMBOT_DRAGRELEASE_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_SYNC_ANIMBOT_DRAGRELEASE_JOB_ID = None
    try:
        _adv_sync_animbot_drag_chunk_close()
    except Exception:
        pass

    # clear animBot pending
    global _ADV_SYNC_ANIMBOT_PENDING, _ADV_SYNC_ANIMBOT_PENDING_MODE, _ADV_SYNC_ANIMBOT_PENDING_NODES
    _ADV_SYNC_ANIMBOT_PENDING = False
    _ADV_SYNC_ANIMBOT_PENDING_MODE = ""
    _ADV_SYNC_ANIMBOT_PENDING_NODES = []

    # clear animBot undo jobs
    global _ADV_ANIMBOT_UNDO_JOB_UNDO_ID, _ADV_ANIMBOT_UNDO_JOB_REDO_ID
    try:
        if _ADV_ANIMBOT_UNDO_JOB_UNDO_ID and cmds.scriptJob(exists=_ADV_ANIMBOT_UNDO_JOB_UNDO_ID):
            cmds.scriptJob(kill=_ADV_ANIMBOT_UNDO_JOB_UNDO_ID, force=True)
    except Exception:
        pass
    _ADV_ANIMBOT_UNDO_JOB_UNDO_ID = None
    try:
        if _ADV_ANIMBOT_UNDO_JOB_REDO_ID and cmds.scriptJob(exists=_ADV_ANIMBOT_UNDO_JOB_REDO_ID):
            cmds.scriptJob(kill=_ADV_ANIMBOT_UNDO_JOB_REDO_ID, force=True)
    except Exception:
        pass
    _ADV_ANIMBOT_UNDO_JOB_REDO_ID = None


def _adv_sync_tangent_watch_on_time_changed(*_):
    try:
        _adv_ensure_undo_enabled()
    except Exception:
        pass
    try:
        _adv_sync_animbot_drag_chunk_close()
    except Exception:
        pass
    try:
        g = globals()
        if g.get('_ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN', False):
            try:
                cmds.undoInfo(closeChunk=True)
            except Exception:
                pass
            g['_ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN'] = False
            g['_ADV_SYNC_ANIMBOT_FINALIZE_CHUNK_OPEN_TIME'] = 0.0
    except Exception:
        pass

    try:
        global _ADV_SYNC_ANIMBOT_PENDING, _ADV_SYNC_ANIMBOT_PENDING_MODE, _ADV_SYNC_ANIMBOT_PENDING_NODES
        global _ADV_SYNC_ANIMBOT_PENDING_TRIES, _ADV_SYNC_ANIMBOT_FORCE_APPLY_ON_NEXT_IDLE
        global _ADV_SYNC_ANIMBOT_PENDING_TOKEN, _ADV_SYNC_ANIMBOT_RELEASE_TOKEN
        global _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME, _ADV_SYNC_ANIMBOT_IN_DRAG
        global _ADV_SYNC_ANIMBOT_DRAG_DIRTY, _ADV_SYNC_ANIMBOT_DRAG_CACHED_MODE, _ADV_SYNC_ANIMBOT_DRAG_CACHED_NODES
        global _ADV_SYNC_ANIMBOT_DRAG_CHANGE_SERIAL, _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_SERIAL

        _ADV_SYNC_ANIMBOT_PENDING = False
        _ADV_SYNC_ANIMBOT_PENDING_MODE = ""
        _ADV_SYNC_ANIMBOT_PENDING_NODES = []
        _ADV_SYNC_ANIMBOT_PENDING_TRIES = 0
        _ADV_SYNC_ANIMBOT_FORCE_APPLY_ON_NEXT_IDLE = False
        _ADV_SYNC_ANIMBOT_PENDING_TOKEN = 0
        _ADV_SYNC_ANIMBOT_RELEASE_TOKEN = 0
        _ADV_SYNC_ANIMBOT_IN_DRAG = False
        _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME = 0.0
        _ADV_SYNC_ANIMBOT_DRAG_DIRTY = False
        _ADV_SYNC_ANIMBOT_DRAG_CACHED_MODE = ""
        _ADV_SYNC_ANIMBOT_DRAG_CACHED_NODES = []
        _ADV_SYNC_ANIMBOT_DRAG_CHANGE_SERIAL = 0
        _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_SERIAL = 0
    except Exception:
        pass

    try:
        global _ADV_SYNC_TANGENT_PENDING, _ADV_SYNC_TANGENT_PENDING_MODE, _ADV_SYNC_TANGENT_PENDING_NODES, _ADV_SYNC_TANGENT_PENDING_TRIES
        _ADV_SYNC_TANGENT_PENDING = False
        _ADV_SYNC_TANGENT_PENDING_MODE = ""
        _ADV_SYNC_TANGENT_PENDING_NODES = []
        _ADV_SYNC_TANGENT_PENDING_TRIES = 0
    except Exception:
        pass
    
    try:
        global _ADV_SYNC_ANIMBOT_UNDONAME_PENDING, _ADV_SYNC_ANIMBOT_UNDONAME_SINCE, _ADV_SYNC_ANIMBOT_UNDONAME_LAST_SEEN
        _ADV_SYNC_ANIMBOT_UNDONAME_PENDING = False
        _ADV_SYNC_ANIMBOT_UNDONAME_SINCE = 0.0
        _ADV_SYNC_ANIMBOT_UNDONAME_LAST_SEEN = ""
    except Exception:
        pass
    
    try:
        global _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN
        if _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN:
            try:
                cmds.undoInfo(closeChunk=True)
            except Exception:
                pass
            _ADV_SYNC_TANGENT_OUTER_CHUNK_OPEN = False
    except Exception:
        pass

    try:
        if _adv_sync_tangent_debug_enabled():
            _adv_sync_tangent_debug_log("timeChanged: cleared pending + closed chunks + ensured undo")
    except Exception:
        pass


def _adv_sync_tangent_watch_rebuild_from_selection():
    """Watch active selected controller's transform attrs; cache its group's nodes for tangent apply."""
    try:
        if _ADV_SYNC_TANGENT_WATCH_SUSPEND:
            return
    except Exception:
        pass
    try:
        import time
        if _ADV_SYNC_TANGENT_WATCH_SELECTION_COOLDOWN_UNTIL and time.time() < float(_ADV_SYNC_TANGENT_WATCH_SELECTION_COOLDOWN_UNTIL):
            return
    except Exception:
        pass
    global _ADV_SYNC_TANGENT_WATCH_ATTR_JOB_IDS
    global _ADV_SYNC_TANGENT_WATCH_TARGET_NODES, _ADV_SYNC_TANGENT_WATCH_ACTIVE_NODE

    # clear attr jobs
    for jid in list(_ADV_SYNC_TANGENT_WATCH_ATTR_JOB_IDS or []):
        try:
            if cmds.scriptJob(exists=jid):
                cmds.scriptJob(kill=jid, force=True)
        except Exception:
            pass
    _ADV_SYNC_TANGENT_WATCH_ATTR_JOB_IDS = []

    _ADV_SYNC_TANGENT_WATCH_TARGET_NODES = []
    _ADV_SYNC_TANGENT_WATCH_ACTIVE_NODE = None

    mode = _adv_sync_get_tangent_mode().strip().lower()
    if mode not in (ADV_SYNC_TANGENT_MODE_AUTO, ADV_SYNC_TANGENT_MODE_SPLINE, ADV_SYNC_TANGENT_MODE_STEP, ADV_SYNC_TANGENT_MODE_LINEAR, ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
        return

    try:
        sel = cmds.ls(orderedSelection=True, long=True) or []
    except Exception:
        sel = cmds.ls(sl=True, long=True) or []

    active = None
    try:
        if sel:
            active = sel[-1]
    except Exception:
        active = None

    if not active or (not cmds.objExists(active)):
        return
    _ADV_SYNC_TANGENT_WATCH_ACTIVE_NODE = active
    _adv_sync_tangent_debug_log("rebuild selection active=%s" % str(active))

    # Cache resolved nodes for this sync group (so we don't recompute each change)
    try:
        _ADV_SYNC_TANGENT_WATCH_TARGET_NODES = _adv_sync_collect_group_nodes_for_selection([active])
    except Exception:
        _ADV_SYNC_TANGENT_WATCH_TARGET_NODES = []


def _adv_sync_tangent_watch_on_change(*_):
    """On transform change, apply tangents to cached group nodes (key-aware)."""
    global _ADV_SYNC_TANGENT_WATCH_GUARD, _ADV_SYNC_TANGENT_WATCH_LAST_TICK
    global _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL, _ADV_SYNC_ANIMBOT_BLOCK_UNTIL_USER, _ADV_SYNC_ANIMBOT_IN_UNDO, _ADV_SYNC_ANIMBOT_UNDO_BLOCK_UNTIL
    
    if _ADV_SYNC_TANGENT_WATCH_GUARD:
        return

    # Throttle VERY early: attributeChange callbacks are extremely chatty during drag
    # (and we have 6 jobs per controller: tx/ty/tz/rx/ry/rz). Keep this lightweight.
    try:
        import time
        now_fast = time.time()
    except Exception:
        now_fast = 0.0
    try:
        if now_fast and _ADV_SYNC_TANGENT_WATCH_LAST_TICK and (now_fast - float(_ADV_SYNC_TANGENT_WATCH_LAST_TICK)) < (1.0 / 20.0):
            return
    except Exception:
        pass
    _ADV_SYNC_TANGENT_WATCH_LAST_TICK = now_fast

    # [FIX] Active Defense: If we detect Undo/Redo is happening, LOCK the future immediately.
    # This covers the gap between "Undo Finishing" and "Undo Event Firing" where events might leak.
    try:
        import maya.OpenMaya as _adv_om
        import time
        now_check = time.time()
        
        # Check explicit lock first
        if _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL and now_check < float(_ADV_SYNC_ANIMBOT_SUSPEND_UNTIL):
             return

        # Check engine state
        if _adv_om.MGlobal.isUndoing() or _adv_om.MGlobal.isRedoing():
            # ACTIVELY LOCK future events.
            _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL = now_check + 1.5
            return
    except Exception:
        pass

    try:
        if _ADV_SYNC_ANIMBOT_BLOCK_UNTIL_USER:
            # [FIX] Time-Gated Unlock:
            # IF Block is active, check if the safety window (2.0s) has passed.
            # If passed, unlock automatically (user might have edited without DragPress).
            # If not passed, return (suppress undo echoes).
            try:
                import time
                now_check = time.time()
                # If timestamp is invalid or 0, break lock to avoid permanent kill
                if not _ADV_SYNC_ANIMBOT_UNDO_BLOCK_UNTIL:
                     _ADV_SYNC_ANIMBOT_BLOCK_UNTIL_USER = False
                elif now_check < float(_ADV_SYNC_ANIMBOT_UNDO_BLOCK_UNTIL):
                     return # Still in danger zone
                else:
                     # Time passed, unlock
                     _ADV_SYNC_ANIMBOT_BLOCK_UNTIL_USER = False
            except Exception:
                # If error in time check, unlock to be safe
                _ADV_SYNC_ANIMBOT_BLOCK_UNTIL_USER = False
    except Exception:
        pass
    try:
        if _ADV_SYNC_TANGENT_WATCH_SUSPEND:
            return
    except Exception:
        pass
    try:
        if _ADV_SYNC_SUSPEND:
            return
    except Exception:
        pass

    mode = _adv_sync_get_tangent_mode().strip().lower()
    if mode not in (ADV_SYNC_TANGENT_MODE_AUTO, ADV_SYNC_TANGENT_MODE_SPLINE, ADV_SYNC_TANGENT_MODE_STEP, ADV_SYNC_TANGENT_MODE_LINEAR, ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
        return

    # [Sensitivity] Cache nodes/mode and mark drag_dirty EARLY for animBot modes.
    # This allows DragRelease fallback to arm a single apply even when:
    # - DragPress scriptJob is intermittently missing
    # - watcher is gated during manipulation
    nodes = list(_ADV_SYNC_TANGENT_WATCH_TARGET_NODES or [])
    if not nodes:
        if _ADV_SYNC_TANGENT_WATCH_ACTIVE_NODE and cmds.objExists(_ADV_SYNC_TANGENT_WATCH_ACTIVE_NODE):
            nodes = [_ADV_SYNC_TANGENT_WATCH_ACTIVE_NODE]
    if not nodes:
        return
    if mode in (ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
        try:
            global _ADV_SYNC_ANIMBOT_DRAG_DIRTY, _ADV_SYNC_ANIMBOT_DRAG_CACHED_MODE, _ADV_SYNC_ANIMBOT_DRAG_CACHED_NODES
            global _ADV_SYNC_ANIMBOT_DRAG_CHANGE_SERIAL
            _ADV_SYNC_ANIMBOT_DRAG_DIRTY = True
            _ADV_SYNC_ANIMBOT_DRAG_CACHED_MODE = str(mode)
            _ADV_SYNC_ANIMBOT_DRAG_CACHED_NODES = list(nodes)
            try:
                _ADV_SYNC_ANIMBOT_DRAG_CHANGE_SERIAL = int(_ADV_SYNC_ANIMBOT_DRAG_CHANGE_SERIAL or 0) + 1
            except Exception:
                _ADV_SYNC_ANIMBOT_DRAG_CHANGE_SERIAL = 1
        except Exception:
            pass

    # [FIX] Require Active Manipulation (Drag) for AnimBot Tangents
    # We relax strictly requiring DragPress because sometimes it fails to register (e.g. Channel Box or scriptJob missing),
    # causing the tool to appear "dead".
    # Instead, we rely heavily on MGlobal.isUndoing() and _ADV_SYNC_ANIMBOT_APPLYING to prevent loops.
    if mode in (ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
        pass
        # Original strict drag check removed to fix "No Response" issue.


    # Avoid feedback loops when animBot itself is applying tangents.
    if mode in (ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
        try:
            if _ADV_SYNC_ANIMBOT_APPLYING:
                return
        except Exception:
            pass
        try:
            import time
            now_guard = time.time()
            # After an animBot apply, animBot (and/or evaluation) may continue to touch curves
            # for a while. Those attributeChange events must NOT queue another apply.
            # Allow re-queue only when the user has just released a manipulation.
            try:
                if _ADV_SYNC_ANIMBOT_POST_APPLY_GUARD_UNTIL and now_guard < float(_ADV_SYNC_ANIMBOT_POST_APPLY_GUARD_UNTIL):
                    try:
                        if _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME and (now_guard - float(_ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME)) < float(_ADV_SYNC_ANIMBOT_POST_APPLY_ALLOW_RELEASE_WINDOW):
                            pass
                        else:
                            return
                    except Exception:
                        return
            except Exception:
                pass
            if _ADV_SYNC_ANIMBOT_LAST_APPLY_TIME and (now_guard - float(_ADV_SYNC_ANIMBOT_LAST_APPLY_TIME)) < float(_ADV_SYNC_ANIMBOT_CHANGE_COOLDOWN):
                return
        except Exception:
            pass

    # Hard gate: animBot tangent auto-apply should only be queued right after a user manipulation release.
    # This prevents animBot's own deferred curve edits from re-triggering the watcher.
    if mode in (ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
        try:
            import time
            now_gate = time.time()
        except Exception:
            now_gate = 0.0
        try:
            if (not _ADV_SYNC_ANIMBOT_IN_DRAG) and (not _ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME or (now_gate - float(_ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME)) > float(_ADV_SYNC_ANIMBOT_POST_APPLY_ALLOW_RELEASE_WINDOW)):
                return
        except Exception:
            return

    # Decide whether we should react to this manipulation:
    # - AutoKey ON: always react (keys will be written on release)
    # - AutoKey OFF: only react when the current frame already has keys (editing keyed poses)
    try:
        t = cmds.currentTime(q=True)
    except Exception:
        t = None
    autokey_on = False
    try:
        autokey_on = bool(_adv_sync_is_autokey_on())
    except Exception:
        autokey_on = False

    # (throttle moved to top)

    if (not autokey_on) and (t is not None):
        try:
            if not _adv_sync_has_keys_at_time(nodes, t):
                return
        except Exception:
            return

    # Prevent immediate re-queue on the same frame right after animBot applies.
    if mode in (ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
        try:
            last_frame = _ADV_SYNC_ANIMBOT_LAST_APPLIED_FRAME.get(str(mode))
        except Exception:
            last_frame = None
        try:
            last_time = float(_ADV_SYNC_ANIMBOT_LAST_APPLIED.get(str(mode)) or 0.0)
        except Exception:
            last_time = 0.0
        try:
            if t is not None and last_frame is not None and float(t) == float(last_frame):
                if now and last_time and (now - last_time) < 0.6:
                    return
        except Exception:
            pass

    # Do NOT apply immediately here.
    # During manipulation, Maya's AutoKey may only actually write keys on mouse release.
    # If we apply tangents too early (or return due to SuperContext), it appears "not working".
    # We instead mark a pending request and apply on idle after manipulation settles.
    _ADV_SYNC_TANGENT_WATCH_GUARD = True
    try:
        # Ensure an idle job exists so pending requests can be processed.
        global _ADV_SYNC_TANGENT_WATCH_IDLE_JOB_ID
        try:
            if _ADV_SYNC_TANGENT_WATCH_IDLE_JOB_ID and (not cmds.scriptJob(exists=_ADV_SYNC_TANGENT_WATCH_IDLE_JOB_ID)):
                _ADV_SYNC_TANGENT_WATCH_IDLE_JOB_ID = None
        except Exception:
            _ADV_SYNC_TANGENT_WATCH_IDLE_JOB_ID = None
        if not _ADV_SYNC_TANGENT_WATCH_IDLE_JOB_ID:
            try:
                _ADV_SYNC_TANGENT_WATCH_IDLE_JOB_ID = cmds.scriptJob(event=["idle", _adv_sync_tangent_idle_tick], protected=True)
            except Exception:
                _ADV_SYNC_TANGENT_WATCH_IDLE_JOB_ID = None

        if mode in (ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
            global _ADV_SYNC_ANIMBOT_PENDING, _ADV_SYNC_ANIMBOT_PENDING_MODE, _ADV_SYNC_ANIMBOT_PENDING_NODES, _ADV_SYNC_ANIMBOT_LAST_CHANGE_TIME
            global _ADV_SYNC_ANIMBOT_PENDING_TOKEN
            # global _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL  <-- Moved to top to avoid SyntaxError
            try:
                import time
                now3 = time.time()
            except Exception:
                now3 = 0.0
            try:
                if now3 and _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL and (now3 < float(_ADV_SYNC_ANIMBOT_SUSPEND_UNTIL)):
                    _adv_sync_tangent_debug_log('animbot watcher ignored (post-undo cooldown)')
                    return
            except Exception:
                pass
            try:
                import time
                _ADV_SYNC_ANIMBOT_LAST_CHANGE_TIME = time.time()
            except Exception:
                _ADV_SYNC_ANIMBOT_LAST_CHANGE_TIME = 0.0
            
            # Always use debounce-based application (simpler and more reliable)
            _ADV_SYNC_ANIMBOT_PENDING = True
            _ADV_SYNC_ANIMBOT_PENDING_MODE = mode
            _ADV_SYNC_ANIMBOT_PENDING_NODES = list(nodes)
            _ADV_SYNC_ANIMBOT_PENDING_TOKEN = 0
            try:
                _ADV_SYNC_ANIMBOT_DRAG_CACHED_MODE = str(mode)
                _ADV_SYNC_ANIMBOT_DRAG_CACHED_NODES = list(nodes)
            except Exception:
                pass
            _adv_sync_tangent_debug_log("animbot pending mode=%s nodes=%d" % (_ADV_SYNC_ANIMBOT_PENDING_MODE, len(nodes)))
            return

        global _ADV_SYNC_TANGENT_PENDING, _ADV_SYNC_TANGENT_PENDING_MODE, _ADV_SYNC_TANGENT_PENDING_NODES, _ADV_SYNC_TANGENT_LAST_CHANGE_TIME
        try:
            import time
            _ADV_SYNC_TANGENT_LAST_CHANGE_TIME = time.time()
        except Exception:
            _ADV_SYNC_TANGENT_LAST_CHANGE_TIME = 0.0
        _ADV_SYNC_TANGENT_PENDING = True
        _ADV_SYNC_TANGENT_PENDING_MODE = mode
        _ADV_SYNC_TANGENT_PENDING_NODES = list(nodes)
        _adv_sync_tangent_debug_log("tangent pending mode=%s nodes=%d" % (mode, len(nodes)))
    finally:
        _ADV_SYNC_TANGENT_WATCH_GUARD = False


def _adv_sync_tangent_watch_set_enabled(enabled):
    # (Removed) Tangent/curve debug feature.
    try:
        _adv_sync_tangent_watch_clear_jobs()
    except Exception:
        pass
    return


def _adv_sync_tangent_idle_tick():
    """Idle tick: auto-apply tangents after manipulation settles."""
    try:
        _adv_ensure_undo_enabled()
    except Exception:
        pass
    try:
        if _ADV_SYNC_SUSPEND:
            return
    except Exception:
        pass
    if not _adv_sync_tangent_tools_enabled():
        return
    try:
        _adv_sync_animbot_undoname_watch_tick()
    except Exception:
        pass


def _adv_sync_animbot_idle_tick():
    """Idle tick for animBot tangents: run once after changes stop and keys exist."""
    try:
        _adv_ensure_undo_enabled()
    except Exception:
        pass
    # Safety: ensure we don't leave a drag undo chunk open forever.
    try:
        _adv_sync_animbot_drag_chunk_maybe_close_when_idle()
    except Exception:
        pass
    try:
        if _ADV_SYNC_SUSPEND:
            return
    except Exception:
        pass
    try:
        if _ADV_SYNC_ANIMBOT_BLOCK_UNTIL_USER:
            return
    except Exception:
        pass
    try:
        import time
        now0 = time.time()
    except Exception:
        now0 = 0.0
    try:
        global _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL
        if now0 and _ADV_SYNC_ANIMBOT_SUSPEND_UNTIL and (now0 < float(_ADV_SYNC_ANIMBOT_SUSPEND_UNTIL)):
            return
    except Exception:
        pass
    # Give Maya a short moment after timeline changes / drag release to commit the
    # transform operation into the Undo queue before we touch keys/animbot.
    try:
        lr = float(globals().get('_ADV_SYNC_ANIMBOT_DRAG_LAST_RELEASE_TIME', 0.0) or 0.0)
        if now0 and lr and (now0 - lr) < 0.12:
            return
    except Exception:
        pass
    if _adv_sync_get_tangent_mode().strip().lower() not in (ADV_SYNC_TANGENT_MODE_FLOW, ADV_SYNC_TANGENT_MODE_BESTGUESS, ADV_SYNC_TANGENT_MODE_CYCLEMATCH, ADV_SYNC_TANGENT_MODE_POLISHED):
        return
    global _ADV_SYNC_ANIMBOT_PENDING, _ADV_SYNC_ANIMBOT_PENDING_MODE, _ADV_SYNC_ANIMBOT_PENDING_NODES, _ADV_SYNC_ANIMBOT_LAST_CHANGE_TIME, _ADV_SYNC_ANIMBOT_LAST_APPLIED
    global _ADV_SYNC_ANIMBOT_PENDING_TRIES, _ADV_SYNC_ANIMBOT_FORCE_APPLY_ON_NEXT_IDLE
    global _ADV_SYNC_ANIMBOT_RELEASE_TOKEN, _ADV_SYNC_ANIMBOT_PENDING_TOKEN
    if not _ADV_SYNC_ANIMBOT_PENDING:
        return

    # Only allow a pending apply that has been armed by a DragRelease.
    try:
        if (not _ADV_SYNC_ANIMBOT_PENDING_TOKEN) or (int(_ADV_SYNC_ANIMBOT_PENDING_TOKEN) != int(_ADV_SYNC_ANIMBOT_RELEASE_TOKEN)):
            return
    except Exception:
        return

    # Check if drag release forced immediate apply (bypass debounce)
    force_apply = False
    try:
        if _ADV_SYNC_ANIMBOT_FORCE_APPLY_ON_NEXT_IDLE:
            force_apply = True
            _ADV_SYNC_ANIMBOT_FORCE_APPLY_ON_NEXT_IDLE = False
    except Exception:
        pass

    # Normal debounce check (skip if force apply is set)
    if not force_apply:
        try:
            import time
            now = time.time()
            if _ADV_SYNC_ANIMBOT_LAST_CHANGE_TIME and (now - float(_ADV_SYNC_ANIMBOT_LAST_CHANGE_TIME)) < float(_ADV_SYNC_ANIMBOT_DEBOUNCE_SECONDS):
                return
        except Exception:
            pass

    # Throttle by time (not frame)
    try:
        import time
        now2 = time.time()
    except Exception:
        now2 = 0.0
    try:
        t = cmds.currentTime(q=True)
    except Exception:
        t = None
    pending_mode = str(_ADV_SYNC_ANIMBOT_PENDING_MODE or "").strip().lower()
    try:
        last_t = float(_ADV_SYNC_ANIMBOT_LAST_APPLIED.get(pending_mode) or 0.0)
    except Exception:
        last_t = 0.0
    try:
        last_frame = _ADV_SYNC_ANIMBOT_LAST_APPLIED_FRAME.get(pending_mode)
    except Exception:
        last_frame = None
    if now2 and last_t and (now2 - last_t) < 0.18:
        return
    try:
        if t is not None and last_frame is not None and float(t) == float(last_frame):
            if now2 and last_t and (now2 - last_t) < 0.6:
                _ADV_SYNC_ANIMBOT_PENDING = False
                _ADV_SYNC_ANIMBOT_PENDING_NODES = []
                _ADV_SYNC_ANIMBOT_PENDING_TRIES = 0
                return
    except Exception:
        pass

    nodes = list(_ADV_SYNC_ANIMBOT_PENDING_NODES or [])
    if not nodes:
        _ADV_SYNC_ANIMBOT_PENDING = False
        _ADV_SYNC_ANIMBOT_PENDING_NODES = []
        _ADV_SYNC_ANIMBOT_PENDING_TRIES = 0
        return

    # Do NOT select keys here.
    # Selecting keys can clear object selection ("select -cl") and interfere with manipulation.
    # We only check for key existence; the unified apply path will handle key selection.
    has_keys = False
    try:
        if t is not None:
            has_keys = bool(_adv_sync_has_keys_at_time(nodes, t))
    except Exception:
        has_keys = False
    if not has_keys:
        _ADV_SYNC_ANIMBOT_PENDING_TRIES = int(_ADV_SYNC_ANIMBOT_PENDING_TRIES) + 1
        if _ADV_SYNC_ANIMBOT_PENDING_TRIES <= 10:
            _adv_sync_tangent_debug_log("animbot idle retry (no keys yet) mode=%s tries=%d" % (pending_mode, int(_ADV_SYNC_ANIMBOT_PENDING_TRIES)))
            return
        _adv_sync_tangent_debug_log("animbot idle giveup mode=%s (no keys)" % pending_mode)
        _ADV_SYNC_ANIMBOT_PENDING = False
        _ADV_SYNC_ANIMBOT_PENDING_NODES = []
        _ADV_SYNC_ANIMBOT_PENDING_TRIES = 0
        return

    _ADV_SYNC_ANIMBOT_PENDING = False
    _ADV_SYNC_ANIMBOT_PENDING_NODES = []
    _ADV_SYNC_ANIMBOT_PENDING_TRIES = 0
    _ADV_SYNC_ANIMBOT_PENDING_TOKEN = 0

    if pending_mode:
        _ADV_SYNC_ANIMBOT_LAST_APPLIED[pending_mode] = now2
    _adv_sync_tangent_debug_log("animbot idle apply mode=%s nodes=%d" % (pending_mode, len(nodes)))

    # IMPORTANT: Use the unified tangent apply path so animBot undo/redo snapshots
    # (marker-based) are created. Directly calling animBot here would not be undoable.
    try:
        _adv_sync_apply_tangent_to_nodes(nodes)
    except Exception as e:
        global _ADV_SYNC_TANGENT_DEBUG_LAST_ERROR
        _ADV_SYNC_TANGENT_DEBUG_LAST_ERROR = str(e)
        _adv_sync_tangent_debug_log("animbot idle ERROR: %s" % str(e))


def _adv_sync_icon_path(filename):
    """Return absolute path for icons placed next to this script (safe fallback)."""
    if not filename:
        return ""

    def _norm(p):
        try:
            return str(p).replace('\\', '/')
        except Exception:
            return p

    def _try_dir(folder):
        try:
            import os
            if not folder:
                return ""
            p = os.path.join(folder, filename)
            if os.path.exists(p):
                return _norm(p)
            # Also try a UI subfolder (user requested moving images to ./UI)
            p2 = os.path.join(folder, 'UI', filename)
            if os.path.exists(p2):
                return _norm(p2)
        except Exception:
            return ""
        return ""

    # 0) Prefer the folder of the registered script path (works even when loaded via exec())
    try:
        import os
        if cmds.optionVar(exists='ADV_FastSelectScriptPath'):
            sp = cmds.optionVar(q='ADV_FastSelectScriptPath') or ""
            if sp:
                hit = _try_dir(os.path.dirname(sp))
                if hit:
                    return hit
    except Exception:
        pass

    try:
        import os
        here = os.path.dirname(__file__)
        hit = _try_dir(here)
        if hit:
            return hit
    except Exception:
        pass
    # Fallback to known folder layout from Maya userAppDir
    try:
        import os
        base = cmds.internalVar(userAppDir=True)
        hit = _try_dir(os.path.join(base, 'scripts', 'ADV Fast select'))
        if hit:
            return hit
        hit = _try_dir(os.path.join(base, 'scripts', 'ADV Fast select', 'UI'))
        if hit:
            return hit
    except Exception:
        pass
    # Last resort: let Maya search its image paths
    return filename


