def adv_sync_set_key_intercept():
    """Intercept Set Key (S): run SetKey, then sync keys for the matched group(s)."""
    # Snapshot selection before SetKey in case the underlying command changes selection.
    try:
        sel_snapshot = cmds.ls(sl=True) or []
    except Exception:
        sel_snapshot = []
    # IMPORTANT:
    # Do NOT call MEL 'SetKey;' here.
    # Maya's default SetKey will attempt to key connected attrs (e.g. visibility), producing warnings
    # like: "属性已连接: PoleOffsetArm_L.visibility".
    # Instead, we key only safe (unconnected) attributes, then propagate to the matched sync group(s).

    # Use shared helpers so behavior stays consistent across script copies.
    # NOTE: _adv_sync_keyable_unconnected_attrs now allows animCurve/animBlend connections
    # so S still keys normally-animated channels while avoiding warning-prone connections.
    preferred = _adv_sync_channelbox_selected_attrs()
    try:
        cmds.undoInfo(openChunk=True)
    except Exception:
        pass
    try:
        for n in sel_snapshot:
            try:
                attrs = _adv_sync_keyable_unconnected_attrs(n, preferred_attrs=preferred)
                if attrs:
                    cmds.setKeyframe(n, attribute=attrs)
            except Exception:
                pass

        try:
            try:
                switchRuntime = _adv_import_switch_runtime()
            except Exception:
                switchRuntime = None

            if switchRuntime is not None:
                try:
                    _sr_mod = _adv_import_switch_runtime()
                    _kfp = getattr(_sr_mod, 'key_frame_post', None)
                    try:
                        _kfp.set_key_frame_pose()
                    except Exception:
                        for n in (sel_snapshot or []):
                            try:
                                _kfp._sync_group_set_key_for_ctrl(n, reason='postSetKey')
                            except Exception:
                                pass
                except Exception:
                    adv_sync_set_key(warn=False, selection=sel_snapshot)
            else:
                adv_sync_set_key(warn=False, selection=sel_snapshot)
        except Exception:
            pass
    finally:
        try:
            cmds.undoInfo(closeChunk=True)
        except Exception:
            pass


def _adv_sync_setkey_hotkey_command_mel():
    """Return a MEL command string that imports this file then runs adv_sync_set_key_intercept()."""
    py = (
        "import maya.cmds as cmds;import importlib.util,sys,os;"
        "p='';"
        "p=(cmds.optionVar(q='ADV_FastSelectScriptPath') if cmds.optionVar(exists='ADV_FastSelectScriptPath') else '');"
        "p=os.path.join(p,'ADV_extension.py') if (p and os.path.isdir(p)) else p;"
        "base=cmds.internalVar(userAppDir=True);"
        "cand=os.path.join(base,'scripts','ADV Fast select','ADV_extension.py');"
        "p=(p if (p and os.path.isfile(p)) else (cand if os.path.isfile(cand) else ''));"
        "mn='adv_fast_select_runtime';"
        "m=sys.modules.get(mn);"
        "(m.adv_sync_set_key_intercept() if (m and getattr(m,'__file__',None)==p) else (lambda: (lambda s: (s.loader.exec_module((lambda mm: (sys.modules.__setitem__(mn,mm),mm)[1])(importlib.util.module_from_spec(s))), sys.modules[mn].adv_sync_set_key_intercept()))(importlib.util.spec_from_file_location(mn,p)) )() ) ) if (p and os.path.isfile(p)) else cmds.warning('ADV: Script path not found. Open ADV Fast Select window first.');"
    )
    py_escaped = py.replace('\\', '\\\\').replace('"', '\\"')
    return 'python(\\"%s\\")' % py_escaped


def _adv_sync_setkey_runtime_command_python():
    """Return python code for Maya runTimeCommand to intercept SetKey and then sync keys."""
    # IMPORTANT:
    # Do NOT rely on a file path. Some users load this tool via exec() so __file__/optionVar may be missing.
    # Instead, we register a runtime module in sys.modules and call it directly.
    return (
        "import maya.cmds as cmds\n"
        "import maya.mel as mel\n"
        "import sys\n"
        "mn='adv_fast_select_runtime'\n"
        "m=sys.modules.get(mn)\n"
        "if m and hasattr(m,'adv_sync_set_key_intercept'):\n"
        "    m.adv_sync_set_key_intercept()\n"
        "else:\n"
        "    # Fallback: don't warn or break the user's SetKey hotkey.\n"
        "    try:\n"
        "        mel.eval('SetKey;')\n"
        "    except Exception:\n"
        "        pass\n"
    )


def _adv_sync_register_runtime_module():
    """Register current globals as a callable runtime module.

    This avoids relying on disk paths when the tool was loaded via exec().
    """
    try:
        import sys
        import types
        mn = 'adv_fast_select_runtime'
        m = sys.modules.get(mn)
        if m is None:
            m = types.ModuleType(mn)
            sys.modules[mn] = m
        try:
            m.__dict__.update(globals())
        except Exception:
            pass
        return m
    except Exception:
        return None


def _adv_sync_ensure_runtime_command():
    """Ensure Maya runTimeCommand exists for intercepting SetKey."""
    py = _adv_sync_setkey_runtime_command_python()
    try:
        # Use the shared safe helper to avoid duplicate-name errors
        # (e.g. "Object's name is not unique: ADVSyncSetKeyRT").
        _adv_ensure_runtime_command(
            ADV_SYNC_SETKEY_RUNTIME_COMMAND,
            "ADV Key Sync (Intercept SetKey)",
            py,
            language="python",
        )
    except Exception:
        # Final fallback for very old/odd Maya builds.
        try:
            cmds.runTimeCommand(
                ADV_SYNC_SETKEY_RUNTIME_COMMAND,
                edit=True,
                annotation="ADV Key Sync (Intercept SetKey)",
                category="User",
                commandLanguage="python",
                command=py,
            )
        except Exception:
            pass


