def adv_sync_debug_print_setkey_binding():
    """Print current S hotkey binding and command details for debugging."""
    key = "s"
    bound = ""
    try:
        bound = _adv_hotkey_query_name(key) or ""
    except Exception:
        bound = ""

    print("[ADV][KeySync][Debug] hotkey S bound name: %s" % (bound or "<EMPTY>"))

    if not bound:
        return

    # If it's a runTimeCommand, print language and command.
    is_rt = bool(_adv_runtime_command_exists(str(bound)))

    if is_rt:
        lang = ""
        cmd = ""
        try:
            lang = cmds.runTimeCommand(str(bound), query=True, commandLanguage=True)
        except Exception:
            lang = ""
        try:
            cmd = cmds.runTimeCommand(str(bound), query=True, command=True)
        except Exception:
            cmd = ""

        print("[ADV][KeySync][Debug] runTimeCommand language: %s" % (lang or "<UNKNOWN>"))
        if cmd:
            print("[ADV][KeySync][Debug] runTimeCommand command (first 120): %s" % str(cmd)[:120].replace("\n", "\\n"))
        return

    # Otherwise try to treat as nameCommand.
    try:
        cmd = ""
        try:
            # Prefer cmds.nameCommand (avoids MEL '-q' issues seen in some setups)
            cmd = cmds.nameCommand(str(bound), q=True, command=True) or ""
        except Exception:
            cmd = ""
        if cmd:
            print("[ADV][KeySync][Debug] nameCommand command (first 120): %s" % str(cmd)[:120].replace("\n", "\\n"))
    except Exception:
        pass


def _adv_hotkey_query_name(key, alt=False, ctrl=False, shift=False):
    """Query bound nameCommand for a key+modifier combo."""
    # Prefer assignCommand query: it is more stable across Maya versions/languages.
    # keyString formats vary, so try a few common variants.
    base = str(key)
    base_low = base.lower()
    base_up = base.upper()

    variants = []
    # No modifiers
    variants.extend([base_low, base_up])
    # With modifiers (common formats)
    if alt:
        variants.extend(['Alt+' + base_low, 'Alt+' + base_up, 'alt+' + base_low, 'alt+' + base_up])
    if ctrl:
        variants.extend(['Ctrl+' + base_low, 'Ctrl+' + base_up, 'ctrl+' + base_low, 'ctrl+' + base_up])
    if shift:
        variants.extend(['Shift+' + base_low, 'Shift+' + base_up, 'shift+' + base_low, 'shift+' + base_up])

    # Combined modifiers (order variants)
    if alt or ctrl or shift:
        prefix_orders = []
        mods = []
        if ctrl:
            mods.append('Ctrl')
        if alt:
            mods.append('Alt')
        if shift:
            mods.append('Shift')
        if mods:
            prefix_orders.append('+'.join(mods) + '+')
            prefix_orders.append('+'.join(reversed(mods)) + '+')
        for pref in prefix_orders:
            variants.extend([pref + base_low, pref + base_up, pref.lower() + base_low, pref.lower() + base_up])

    seen = set()
    for ks in variants:
        if not ks or ks in seen:
            continue
        seen.add(ks)
        try:
            r = cmds.assignCommand(q=True, keyString=ks)
            if r:
                return str(r)
        except Exception:
            continue

    # Fallback: try MEL hotkey query (some builds have query-flag quirks with -k)
    try:
        mods = []
        if alt:
            mods.append('-alt')
        if ctrl:
            mods.append('-ctl')
        if shift:
            mods.append('-sht')
        mod_str = ' '.join(mods)
        # Query without '-name' to avoid parsing differences; many Mayas return the nameCommand directly.
        r = mel.eval('hotkey %s -q -k "%s"' % (mod_str, str(key)))
        return str(r) if r else ""
    except Exception:
        return ""


def _adv_hotkey_set_name(key, name_cmd, alt=False, ctrl=False, shift=False):
    """Bind a nameCommand to a key+modifier combo."""
    # Prefer MEL for compatibility with Maya's hotkey command.
    try:
        parts = ["hotkey", '-name', '"%s"' % str(name_cmd)]
        if alt:
            parts.append("-alt")
        if ctrl:
            parts.append("-ctl")
        if shift:
            parts.append("-sht")
        parts += ["-k", '"%s"' % str(key)]
        mel.eval(" ".join(parts))
        return
    except Exception:
        pass

    # Fallback: cmds.hotkey
    try:
        cmds.hotkey(k=str(key), name=str(name_cmd), alt=alt, ctl=ctrl, sht=shift)
    except Exception:
        pass


def adv_cleanup_legacy_setkey_hotkey(restore_to_setkey=True):
    """Cleanup legacy ADV key-sync hotkey interception (S -> ADVSyncSetKeyCmd/RT).

    Background:
        Older versions of this tool used a nameCommand/runtimeCommand pair to intercept SetKey.
        Users may still have S bound to ADVSyncSetKeyCmd after Maya restart, causing warnings.

    This tool no longer needs to intercept S (key sync is handled by switchRuntime key-frame hook),
    so we proactively remove the legacy commands and restore S to SetKey (or stored previous).
    """
    import maya.mel as mel

    def _is_legacy_binding(bound_name):
        try:
            s = str(bound_name or "")
        except Exception:
            s = ""
        if not s:
            return False
        sl = s.lower()
        return ('advsyncsetkey' in sl) or (sl in ('advsyncsetkeycmd', 'advsyncsetkeyrt'))

    def _cleanup_one_key(key, alt=False, ctrl=False, shift=False):
        # If key is still bound to legacy cmd, restore it.
        try:
            cur = _adv_hotkey_query_name(key, alt=alt, ctrl=ctrl, shift=shift) or ""
        except Exception:
            cur = ""

        # If plain S is unbound (can happen after a crash or failed hotkey creation),
        # restore to Maya's default SetKey to avoid "S does nothing".
        if (not cur) and (not alt) and (not ctrl) and (not shift) and restore_to_setkey:
            try:
                _adv_hotkey_set_name(key, "SetKey", alt=alt, ctrl=ctrl, shift=shift)
                return
            except Exception:
                pass

        if not _is_legacy_binding(cur):
            return

        # Only plain "S" restores previous binding; modifier combos are simply cleared.
        if (not alt) and (not ctrl) and (not shift):
            prev = ""
            try:
                prev = cmds.optionVar(q=ADV_SYNC_S_PREV_NAMECMD_OPTIONVAR) if cmds.optionVar(exists=ADV_SYNC_S_PREV_NAMECMD_OPTIONVAR) else ""
            except Exception:
                prev = ""
            try:
                prev_s = str(prev) if prev else ""
            except Exception:
                prev_s = ""

            # Avoid restoring back to legacy ADV commands.
            if prev_s and (not _is_legacy_binding(prev_s)):
                try:
                    _adv_hotkey_set_name(key, prev_s, alt=alt, ctrl=ctrl, shift=shift)
                    return
                except Exception:
                    pass

            if restore_to_setkey:
                try:
                    _adv_hotkey_set_name(key, "SetKey", alt=alt, ctrl=ctrl, shift=shift)
                    return
                except Exception:
                    pass

        # IMPORTANT: Do NOT clear the binding as a fallback.
        # On some Maya installs/hotkeySets (read-only or partially locked), attempts
        # to restore to SetKey can fail, but clearing may still succeed, leaving
        # users with a dead S hotkey across hotkey sets. If we can't restore,
        # leave the user's binding untouched.
        return

    # Try to cleanup across all hotkey sets, because users may switch sets.
    try:
        all_sets = cmds.hotkeySet(q=True, hotkeySetArray=True) or []
    except Exception:
        try:
            all_sets = cmds.hotkeySet(q=True, hotkeySets=True) or []
        except Exception:
            all_sets = []
    try:
        cur_set = cmds.hotkeySet(q=True, current=True)
    except Exception:
        cur_set = None

    def _with_hotkey_set(name, fn):
        if not name:
            return fn()
        try:
            mel.eval('hotkeySet -e -current "%s"' % str(name))
        except Exception:
            try:
                cmds.hotkeySet(e=True, current=name)
            except Exception:
                return fn()
        return fn()

    # Keys/modifier combos to scan (keep small but robust)
    keys = ("s", "S")
    combos = (
        (False, False, False),
        (False, False, True),
        (False, True, False),
        (True, False, False),
    )

    sets_to_scan = list(all_sets) if all_sets else [cur_set]
    scanned = set()
    for hs in sets_to_scan:
        if not hs or hs in scanned:
            continue
        scanned.add(hs)

        def _do():
            for k in keys:
                for alt, ctrl, shift in combos:
                    _cleanup_one_key(k, alt=alt, ctrl=ctrl, shift=shift)
        _with_hotkey_set(hs, _do)

    # Restore original hotkey set
    if cur_set:
        try:
            mel.eval('hotkeySet -e -current "%s"' % str(cur_set))
        except Exception:
            try:
                cmds.hotkeySet(e=True, current=cur_set)
            except Exception:
                pass

    # Remove legacy commands so they can't be rebound from old prefs.
    # IMPORTANT: Even if deletion fails (locked prefs / referenced hotkeySet),
    # patch the runtimeCommand to a no-warning SetKey fallback to stop spam.
    try:
        rt = ADV_SYNC_SETKEY_RUNTIME_COMMAND
        if rt:
            safe_py = (
                "import maya.mel as mel\n"
                "try:\n"
                "    mel.eval('SetKey;')\n"
                "except Exception:\n"
                "    pass\n"
            )
            try:
                if _adv_runtime_command_exists(rt):
                    try:
                        cmds.runTimeCommand(rt, e=True, commandLanguage='python', command=safe_py,
                                           annotation='ADV Legacy SetKey (no-warning fallback)')
                    except Exception:
                        cmds.runTimeCommand(rt, edit=True, commandLanguage='python', command=safe_py,
                                           annotation='ADV Legacy SetKey (no-warning fallback)')
            except Exception:
                pass
    except Exception:
        pass

    try:
        _adv_delete_command_ui_if_exists("ADVSyncSetKeyCmd")
    except Exception:
        pass
    try:
        _adv_runtime_command_delete_all(ADV_SYNC_SETKEY_RUNTIME_COMMAND, max_iter=64)
    except Exception:
        pass



def adv_sync_hotkey_set_enabled(enabled):
    """Enable/disable intercepting Set Key (S) for key sync, restoring previous binding when disabled."""
    try:
        enabled = bool(enabled)
        cmds.optionVar(intValue=(ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR, 1 if enabled else 0))
    except Exception:
        pass

    # Toggle switchRuntime key-frame post hook.
    try:
        try:
            import os
            import sys
            local_scripts = os.path.join(os.path.dirname(__file__), 'scripts')
            local_scripts = local_scripts.replace('\\', '/')
            if local_scripts and local_scripts not in sys.path:
                sys.path.insert(0, local_scripts)

            local_pkg = _adv_runtime_pkg_dir(local_scripts)
            if os.path.isdir(local_pkg) and 'switchRuntime' in sys.modules:
                try:
                    loaded = getattr(sys.modules.get('switchRuntime'), '__file__', '') or ''
                except Exception:
                    loaded = ''
                if loaded and (local_pkg.replace('\\', '/') not in loaded.replace('\\', '/')):
                    for k in list(sys.modules.keys()):
                        if _adv_is_switch_runtime_module_key(k):
                            sys.modules.pop(k, None)
        except Exception:
            pass
        switchRuntime = _adv_import_switch_runtime()
        # Stale detection: if modules exist but do not have our new fields, purge+reimport.
        try:
            kfp = getattr(switchRuntime, 'key_frame_post', None)
            cbm = getattr(switchRuntime, 'callback', None)
            if kfp and (not hasattr(kfp, '_KEYSYNC_DEBUG_RING')):
                for k in list(sys.modules.keys()):
                    if _adv_is_switch_runtime_module_key(k):
                        sys.modules.pop(k, None)
                _sr2 = _adv_import_switch_runtime()
                switchRuntime = _sr2
            elif kfp and (not hasattr(kfp, '_KEYSYNC_TIME_PARSE_V2')):
                for k in list(sys.modules.keys()):
                    if _adv_is_switch_runtime_module_key(k):
                        sys.modules.pop(k, None)
                _sr2 = _adv_import_switch_runtime()
                switchRuntime = _sr2
            elif kfp and ((not hasattr(kfp, '_KEYSYNC_DELETE_CURVE_V3')) or (not hasattr(kfp, '_KEYSYNC_DELETE_DEDUPE_V4')) or (not hasattr(kfp, '_KEYSYNC_DELETE_ALIGN_IKFK_V5')) or (not hasattr(kfp, '_KEYSYNC_DELETE_ALIGN_ORDER_V6'))):
                for k in list(sys.modules.keys()):
                    if _adv_is_switch_runtime_module_key(k):
                        sys.modules.pop(k, None)
                _sr2 = _adv_import_switch_runtime()
                switchRuntime = _sr2
            elif cbm and (not hasattr(cbm, '_AUTOKEY_GROUP_SYNC_COUNT')):
                for k in list(sys.modules.keys()):
                    if _adv_is_switch_runtime_module_key(k):
                        sys.modules.pop(k, None)
                _sr2 = _adv_import_switch_runtime()
                switchRuntime = _sr2
        except Exception:
            pass

        tools = switchRuntime.tools
    except Exception as e:
        tools = None
        if enabled:
            try:
                _adv_safe_warning(u"[ADV] 未找到 switchRuntime（请先拖拽安装 Install.mel）：%s" % str(e))
            except Exception:
                pass
            try:
                cmds.optionVar(intValue=(ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR, 0))
            except Exception:
                pass
            try:
                if cmds.checkBox(ADV_SYNC_UI_ENABLE_CB, exists=True):
                    cmds.checkBox(ADV_SYNC_UI_ENABLE_CB, e=True, v=False)
            except Exception:
                pass
        return

    if enabled:
        try:
            tools.open_key_frame_post()
            cmds.inViewMessage(amg=u"<hl>关键帧同步: ON</hl>", pos='midCenter', fade=True)
        except Exception:
            pass
    else:
        try:
            tools.close_key_frame_post()
            cmds.inViewMessage(amg=u"<hl>关键帧同步: OFF</hl>", pos='midCenter', fade=True)
        except Exception:
            pass

    # IMPORTANT:
    # Do not edit Maya's S hotkey here.
    # Some managed hotkeySets (e.g. PathMgr) will clear keys and refuse to rebind,
    # leaving the user with "S does nothing" until they manually refresh hotkeys.
    #
    # Instead, Key Sync intercepts SetKey via the Qt fallback hotkey filter.
    if enabled:
        try:
            _adv_sync_register_runtime_module()
        except Exception:
            pass

    # Refresh Qt fallback hotkey filter so KeySync S fallback is applied/removed immediately.
    # Use force=True to re-install the eventFilter last, so we win if other tools installed one.
    try:
        _adv_install_hotkey_fallback_filter(force=True)
    except Exception:
        pass


def _adv_sync_set_suspend(v):
    global _ADV_SYNC_SUSPEND
    _ADV_SYNC_SUSPEND = bool(v)


def _adv_sync_resume(*_):
    _adv_sync_set_suspend(False)


def _adv_sync_suspend_briefly(*_):
    """Suspend key-sync watchers briefly during Undo/Redo."""
    _adv_sync_set_suspend(True)

    # Clear pending states so we don't apply right after undo
    global _ADV_SYNC_AUTOKEY_PENDING, _ADV_SYNC_AUTOKEY_PENDING_NODES
    try:
        _ADV_SYNC_AUTOKEY_PENDING = False
        _ADV_SYNC_AUTOKEY_PENDING_NODES = []
    except Exception:
        pass

    # Resume after Maya finishes Undo/Redo
    try:
        import maya.utils as _adv_maya_utils
        _adv_maya_utils.executeDeferred(_adv_sync_resume)
    except Exception:
        _adv_sync_resume()


def _adv_sync_watch_undo_redo_set_enabled(enabled):
    """Create/kill Undo/Redo scriptJobs for Key Sync watchers."""
    enabled = bool(enabled)
    global _ADV_SYNC_UNDO_JOB_ID, _ADV_SYNC_REDO_JOB_ID

    # Kill existing
    try:
        if _ADV_SYNC_UNDO_JOB_ID and cmds.scriptJob(exists=_ADV_SYNC_UNDO_JOB_ID):
            cmds.scriptJob(kill=_ADV_SYNC_UNDO_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_SYNC_UNDO_JOB_ID = None

    try:
        if _ADV_SYNC_REDO_JOB_ID and cmds.scriptJob(exists=_ADV_SYNC_REDO_JOB_ID):
            cmds.scriptJob(kill=_ADV_SYNC_REDO_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_SYNC_REDO_JOB_ID = None

    if not enabled:
        return

    parent = ADV_MAIN_WINDOW_NAME if cmds.window(ADV_MAIN_WINDOW_NAME, exists=True) else None
    try:
        _ADV_SYNC_UNDO_JOB_ID = cmds.scriptJob(
            event=["Undo", _adv_sync_suspend_briefly],
            protected=True,
            parent=parent
        )
    except Exception:
        _ADV_SYNC_UNDO_JOB_ID = None

    try:
        _ADV_SYNC_REDO_JOB_ID = cmds.scriptJob(
            event=["Redo", _adv_sync_suspend_briefly],
            protected=True,
            parent=parent
        )
    except Exception:
        _ADV_SYNC_REDO_JOB_ID = None


def _adv_kill_scriptjobs_by_keywords(keywords):
    """Best-effort: kill scriptJobs whose description contains any keyword.

    Used to clean up stale jobs from older loaded copies of this tool.
    """
    try:
        keys = [str(k).lower() for k in (keywords or []) if k]
    except Exception:
        keys = []
    if not keys:
        return 0
    try:
        jobs = cmds.scriptJob(listJobs=True) or []
    except Exception:
        jobs = []
    killed = 0
    for j in jobs:
        try:
            s = str(j)
        except Exception:
            continue
        sl = s.lower()
        if not any(k in sl for k in keys):
            continue
        try:
            jid = int(s.split(':', 1)[0].strip())
        except Exception:
            continue
        try:
            if cmds.scriptJob(exists=jid):
                cmds.scriptJob(kill=jid, force=True)
                killed += 1
        except Exception:
            pass
    return killed


def _adv_sync_autokey_watch_clear_jobs():
    global _ADV_SYNC_AUTOKEY_WATCH_SEL_JOB_ID, _ADV_SYNC_AUTOKEY_WATCH_ATTR_JOB_IDS
    global _ADV_SYNC_AUTOKEY_WATCH_IDLE_JOB_ID
    try:
        if _ADV_SYNC_AUTOKEY_WATCH_SEL_JOB_ID and cmds.scriptJob(exists=_ADV_SYNC_AUTOKEY_WATCH_SEL_JOB_ID):
            cmds.scriptJob(kill=_ADV_SYNC_AUTOKEY_WATCH_SEL_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_SYNC_AUTOKEY_WATCH_SEL_JOB_ID = None

    for jid in list(_ADV_SYNC_AUTOKEY_WATCH_ATTR_JOB_IDS or []):
        try:
            if cmds.scriptJob(exists=jid):
                cmds.scriptJob(kill=jid, force=True)
        except Exception:
            pass
    _ADV_SYNC_AUTOKEY_WATCH_ATTR_JOB_IDS = []

    try:
        if _ADV_SYNC_AUTOKEY_WATCH_IDLE_JOB_ID and cmds.scriptJob(exists=_ADV_SYNC_AUTOKEY_WATCH_IDLE_JOB_ID):
            cmds.scriptJob(kill=_ADV_SYNC_AUTOKEY_WATCH_IDLE_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_SYNC_AUTOKEY_WATCH_IDLE_JOB_ID = None

    # Also kill stale jobs from older loaded copies (different module namespace).
    try:
        _adv_kill_scriptjobs_by_keywords([
            'adv_sync_autokey',
            'ADV_SYNC_AUTOKEY',
            'adv_fast_select_runtime',
        ])
    except Exception:
        pass


def _adv_sync_autokey_watch_rebuild_from_selection(*_):
    """Rebuild AutoKey sync watcher to follow current active selection."""
    global _ADV_SYNC_AUTOKEY_WATCH_TARGET_NODES, _ADV_SYNC_AUTOKEY_WATCH_ACTIVE_NODE, _ADV_SYNC_AUTOKEY_WATCH_LAST_APPLIED_KEY
    global _ADV_SYNC_AUTOKEY_WATCH_ATTR_JOB_IDS
    # clear old attr jobs
    for jid in list(_ADV_SYNC_AUTOKEY_WATCH_ATTR_JOB_IDS or []):
        try:
            if cmds.scriptJob(exists=jid):
                cmds.scriptJob(kill=jid, force=True)
        except Exception:
            pass
    _ADV_SYNC_AUTOKEY_WATCH_ATTR_JOB_IDS = []
    _ADV_SYNC_AUTOKEY_WATCH_TARGET_NODES = []
    _ADV_SYNC_AUTOKEY_WATCH_ACTIVE_NODE = None
    _ADV_SYNC_AUTOKEY_WATCH_LAST_APPLIED_KEY = None

    try:
        sel = cmds.ls(orderedSelection=True, long=True) or []
    except Exception:
        sel = cmds.ls(sl=True, long=True) or []
    if not sel:
        return

    active = sel[-1]
    if not active or not cmds.objExists(active):
        return
    _ADV_SYNC_AUTOKEY_WATCH_ACTIVE_NODE = active

    # Cache resolved group nodes (namespace-safe)
    try:
        _ADV_SYNC_AUTOKEY_WATCH_TARGET_NODES = _adv_sync_collect_group_nodes_for_selection([active])
    except Exception:
        _ADV_SYNC_AUTOKEY_WATCH_TARGET_NODES = []

    if not _ADV_SYNC_AUTOKEY_WATCH_TARGET_NODES:
        return

    from functools import partial
    attrs = (
        "translateX", "translateY", "translateZ",
        "rotateX", "rotateY", "rotateZ",
    )
    parent = ADV_MAIN_WINDOW_NAME if cmds.window(ADV_MAIN_WINDOW_NAME, exists=True) else None
    for a in attrs:
        plug = "{}.{}".format(active, a)
        try:
            jid = cmds.scriptJob(
                attributeChange=[plug, partial(_adv_sync_autokey_watch_on_change)],
                protected=True,
                parent=parent
            )
            _ADV_SYNC_AUTOKEY_WATCH_ATTR_JOB_IDS.append(jid)
        except Exception:
            pass


def _adv_sync_autokey_watch_on_change(*_):
    """When AutoKey is ON and a controller in a group changes, key the whole group at current frame."""
    global _ADV_SYNC_AUTOKEY_WATCH_GUARD, _ADV_SYNC_AUTOKEY_WATCH_LAST_TICK, _ADV_SYNC_AUTOKEY_WATCH_LAST_APPLIED_KEY
    global _ADV_SYNC_AUTOKEY_PENDING, _ADV_SYNC_AUTOKEY_LAST_CHANGE_TIME
    global _ADV_SYNC_AUTOKEY_PENDING_FRAME, _ADV_SYNC_AUTOKEY_PENDING_NODES, _ADV_SYNC_AUTOKEY_PENDING_KEY
    if _ADV_SYNC_AUTOKEY_WATCH_GUARD:
        return

    if _ADV_SYNC_SUSPEND:
        return

    # Throttle
    try:
        import time
        now = time.time()
    except Exception:
        now = 0.0
    if now and _ADV_SYNC_AUTOKEY_WATCH_LAST_TICK and (now - float(_ADV_SYNC_AUTOKEY_WATCH_LAST_TICK)) < (1.0 / 15.0):
        return
    _ADV_SYNC_AUTOKEY_WATCH_LAST_TICK = now

    try:
        frame = int(round(float(cmds.currentTime(q=True))))
    except Exception:
        frame = None
    if frame is None:
        return

    nodes = list(_ADV_SYNC_AUTOKEY_WATCH_TARGET_NODES or [])
    if not nodes:
        if _adv_sync_diag_enabled():
            _adv_sync_diag('autokey on_change active=%s -> no target nodes (group not matched/resolved)' % str(_ADV_SYNC_AUTOKEY_WATCH_ACTIVE_NODE))
        return

    # Debounce: during drag this callback can fire a lot. We only apply once
    # after manipulation settles (idle tick), to keep viewport responsive.
    active_stripped = _adv_sync_strip_name(_ADV_SYNC_AUTOKEY_WATCH_ACTIVE_NODE or "")
    _ADV_SYNC_AUTOKEY_PENDING = True
    _ADV_SYNC_AUTOKEY_PENDING_FRAME = frame
    _ADV_SYNC_AUTOKEY_PENDING_NODES = list(nodes)
    _ADV_SYNC_AUTOKEY_PENDING_KEY = (active_stripped, frame)
    try:
        import time
        _ADV_SYNC_AUTOKEY_LAST_CHANGE_TIME = time.time()
    except Exception:
        _ADV_SYNC_AUTOKEY_LAST_CHANGE_TIME = 0.0


def _adv_sync_autokey_watch_set_enabled(enabled):
    enabled = bool(enabled)
    if not enabled:
        _adv_sync_autokey_watch_clear_jobs()
        return

    # Safety: clear stale jobs before enabling, to avoid duplicate/old callbacks.
    try:
        _adv_sync_autokey_watch_clear_jobs()
    except Exception:
        pass
    parent = ADV_MAIN_WINDOW_NAME if cmds.window(ADV_MAIN_WINDOW_NAME, exists=True) else None
    global _ADV_SYNC_AUTOKEY_WATCH_SEL_JOB_ID
    global _ADV_SYNC_AUTOKEY_WATCH_IDLE_JOB_ID
    if not _ADV_SYNC_AUTOKEY_WATCH_SEL_JOB_ID:
        try:
            _ADV_SYNC_AUTOKEY_WATCH_SEL_JOB_ID = cmds.scriptJob(
                event=["SelectionChanged", _adv_sync_autokey_watch_rebuild_from_selection],
                protected=True,
                parent=parent
            )
        except Exception:
            _ADV_SYNC_AUTOKEY_WATCH_SEL_JOB_ID = None

    # Idle tick to apply debounced autokey sync
    if not _ADV_SYNC_AUTOKEY_WATCH_IDLE_JOB_ID:
        try:
            _ADV_SYNC_AUTOKEY_WATCH_IDLE_JOB_ID = cmds.scriptJob(
                event=["idle", _adv_sync_autokey_idle_tick],
                protected=True,
                parent=parent
            )
        except Exception:
            _ADV_SYNC_AUTOKEY_WATCH_IDLE_JOB_ID = None
    _adv_sync_autokey_watch_rebuild_from_selection()


def _adv_sync_autokey_idle_tick():
    """Apply AutoKey group keying once after manipulation settles (debounced)."""
    global _ADV_SYNC_AUTOKEY_PENDING, _ADV_SYNC_AUTOKEY_LAST_CHANGE_TIME
    global _ADV_SYNC_AUTOKEY_PENDING_FRAME, _ADV_SYNC_AUTOKEY_PENDING_NODES, _ADV_SYNC_AUTOKEY_PENDING_KEY
    global _ADV_SYNC_AUTOKEY_WATCH_GUARD, _ADV_SYNC_AUTOKEY_WATCH_LAST_APPLIED_KEY

    if not _ADV_SYNC_AUTOKEY_PENDING:
        return

    if _ADV_SYNC_SUSPEND:
        _ADV_SYNC_AUTOKEY_PENDING = False
        _ADV_SYNC_AUTOKEY_PENDING_NODES = []
        return

    # Avoid running during active manipulation
    try:
        ctx = cmds.currentCtx()
        if 'SuperContext' in str(ctx or ''):
            if _adv_sync_diag_enabled():
                _adv_sync_diag('autokey idle skip: still in SuperContext')
            return
    except Exception:
        pass

    # Must have AutoKey ON (query only after manipulation ends)
    if not _adv_sync_is_autokey_on():
        if _adv_sync_diag_enabled():
            _adv_sync_diag('autokey idle cancel: AutoKey is OFF')
        _ADV_SYNC_AUTOKEY_PENDING = False
        _ADV_SYNC_AUTOKEY_PENDING_NODES = []
        return

    try:
        import time
        now = time.time()
    except Exception:
        now = 0.0

    try:
        debounce = float(_ADV_SYNC_AUTOKEY_DEBOUNCE_SECONDS)
    except Exception:
        debounce = 0.18
    try:
        if now and _ADV_SYNC_AUTOKEY_LAST_CHANGE_TIME and (now - float(_ADV_SYNC_AUTOKEY_LAST_CHANGE_TIME)) < debounce:
            return
    except Exception:
        pass

    frame = _ADV_SYNC_AUTOKEY_PENDING_FRAME
    nodes = list(_ADV_SYNC_AUTOKEY_PENDING_NODES or [])
    pending_key = _ADV_SYNC_AUTOKEY_PENDING_KEY
    _ADV_SYNC_AUTOKEY_PENDING = False
    _ADV_SYNC_AUTOKEY_PENDING_NODES = []

    if frame is None or not nodes:
        return

    if pending_key and (_ADV_SYNC_AUTOKEY_WATCH_LAST_APPLIED_KEY == pending_key):
        return

    if _ADV_SYNC_AUTOKEY_WATCH_GUARD:
        return

    _ADV_SYNC_AUTOKEY_WATCH_GUARD = True
    try:
        prev_se = None
        try:
            prev_se = _adv_script_editor_suppress_begin()
        except Exception:
            prev_se = None

        try:
            cmds.undoInfo(openChunk=True)
        except Exception:
            pass
        try:
            # Key ONLY safe (unconnected/settable/unlocked) attrs to avoid warnings like:
            # "属性已连接: XXX.visibility".
            if _adv_sync_diag_enabled():
                _adv_sync_diag('autokey apply begin active=%s frame=%s nodes=%s' % (
                    str(_ADV_SYNC_AUTOKEY_WATCH_ACTIVE_NODE),
                    str(frame),
                    _adv_sync_diag_short_list(nodes, 10),
                ))

            keyed_nodes = 0
            skipped_nodes = 0
            for n in nodes:
                try:
                    attrs = _adv_sync_keyable_unconnected_attrs(n)
                    if attrs:
                        cmds.setKeyframe(n, time=(frame, frame), attribute=attrs)
                        keyed_nodes += 1
                        if _adv_sync_diag_enabled() and keyed_nodes <= 4:
                            _adv_sync_diag('autokey keyed node=%s attrs=%s' % (str(n), _adv_sync_diag_short_list(attrs, 10)))
                    else:
                        skipped_nodes += 1
                        if _adv_sync_diag_enabled():
                            ok, r = _adv_sync_diag_attr_reasons(n, preferred_attrs=None)
                            _adv_sync_diag('autokey SKIP node=%s ok=%d reasons=%s' % (str(n), int(len(ok or [])), str(r)))
                except Exception:
                    pass

            if _adv_sync_diag_enabled():
                _adv_sync_diag('autokey apply end keyedNodes=%d skippedNodes=%d' % (int(keyed_nodes), int(skipped_nodes)))
        finally:
            try:
                cmds.undoInfo(closeChunk=True)
            except Exception:
                pass
            try:
                if prev_se is not None:
                    _adv_script_editor_suppress_end(prev_se)
            except Exception:
                pass
        if pending_key:
            _ADV_SYNC_AUTOKEY_WATCH_LAST_APPLIED_KEY = pending_key
    finally:
        _ADV_SYNC_AUTOKEY_WATCH_GUARD = False


def _adv_ensure_undo_enabled():
    """Best-effort ensure Maya Undo is enabled.

    Some operations (or other scripts) may leave Undo disabled, which makes
    animator transforms non-undoable. This tool should never leave Undo off.
    """
    try:
        if not bool(cmds.undoInfo(q=True, state=True)):
            cmds.undoInfo(state=True)
    except Exception:
        pass
    # Some Maya versions support stateWithoutFlush; keep it enabled if available.
    try:
        cmds.undoInfo(stateWithoutFlush=True)
    except Exception:
        pass


def _adv_force_close_undo_chunks(max_tries=12):
    closed = 0
    for _ in range(int(max_tries or 0)):
        try:
            cmds.undoInfo(closeChunk=True)
            closed += 1
        except Exception:
            break
    try:
        if closed and _adv_sync_tangent_debug_enabled():
            _adv_sync_tangent_debug_log("force close undo chunks closed=%d" % int(closed))
    except Exception:
        pass


def _adv_sync_delete_watch_clear_jobs():
    global _ADV_SYNC_DELETE_WATCH_IDLE_JOB_ID
    try:
        if _ADV_SYNC_DELETE_WATCH_IDLE_JOB_ID and cmds.scriptJob(exists=_ADV_SYNC_DELETE_WATCH_IDLE_JOB_ID):
            cmds.scriptJob(kill=_ADV_SYNC_DELETE_WATCH_IDLE_JOB_ID, force=True)
    except Exception:
        pass
    _ADV_SYNC_DELETE_WATCH_IDLE_JOB_ID = None


def _adv_sync_delete_watch_set_enabled(enabled):
    """Enable/disable delete-key sync watcher."""
    enabled = bool(enabled)
    if not enabled:
        _adv_sync_delete_watch_clear_jobs()
        return

    # Ensure only one job
    global _ADV_SYNC_DELETE_WATCH_IDLE_JOB_ID
    if _ADV_SYNC_DELETE_WATCH_IDLE_JOB_ID and cmds.scriptJob(exists=_ADV_SYNC_DELETE_WATCH_IDLE_JOB_ID):
        return

    parent = ADV_MAIN_WINDOW_NAME if cmds.window(ADV_MAIN_WINDOW_NAME, exists=True) else None
    try:
        _ADV_SYNC_DELETE_WATCH_IDLE_JOB_ID = cmds.scriptJob(
            event=["idle", _adv_sync_delete_watch_idle_tick],
            protected=True,
            parent=parent
        )
    except Exception:
        # Fallback: no parent
        try:
            _ADV_SYNC_DELETE_WATCH_IDLE_JOB_ID = cmds.scriptJob(
                event=["idle", _adv_sync_delete_watch_idle_tick],
                protected=True,
            )
        except Exception:
            _ADV_SYNC_DELETE_WATCH_IDLE_JOB_ID = None


def _adv_sync_has_key_at_frame(node, frame):
    """Return True if node has any key at the given frame."""
    if not node:
        return False
    try:
        if not cmds.objExists(node):
            return False
    except Exception:
        return False
    try:
        kc = cmds.keyframe(node, q=True, time=(frame, frame), kc=True)
    except Exception:
        kc = 0
    try:
        if isinstance(kc, (list, tuple)):
            return sum(int(x) for x in kc if x) > 0
        return int(kc) > 0
    except Exception:
        return bool(kc)


def _adv_sync_delete_keys_at_frame(nodes, frame):
    """Delete keys at the given frame for all provided nodes."""
    if not nodes:
        return
    try:
        cmds.undoInfo(openChunk=True)
    except Exception:
        pass
    suppress_results = None
    suppress_info = None
    try:
        try:
            suppress_results = cmds.scriptEditorInfo(q=True, suppressResults=True)
            suppress_info = cmds.scriptEditorInfo(q=True, suppressInfo=True)
            cmds.scriptEditorInfo(suppressResults=True, suppressInfo=True)
        except Exception:
            suppress_results = None
            suppress_info = None

        for n in nodes:
            try:
                if n and cmds.objExists(n):
                    cmds.cutKey(n, time=(frame, frame))
            except Exception:
                pass
    finally:
        try:
            if suppress_results is not None and suppress_info is not None:
                cmds.scriptEditorInfo(suppressResults=suppress_results, suppressInfo=suppress_info)
        except Exception:
            pass
        try:
            cmds.undoInfo(closeChunk=True)
        except Exception:
            pass


def _adv_sync_delete_watch_idle_tick():
    """Idle tick: detect key deletion on selected controllers and propagate to group."""
    global _ADV_SYNC_DELETE_WATCH_LAST_TICK, _ADV_SYNC_DELETE_WATCH_GUARD, _ADV_SYNC_DELETE_WATCH_LAST_STATE

    if _ADV_SYNC_SUSPEND:
        return

    # Only active when Key Sync hotkey is enabled
    try:
        if not (cmds.optionVar(exists=ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR) and bool(cmds.optionVar(q=ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR))):
            return
    except Exception:
        return

    # Throttle to reduce overhead
    try:
        import time
        now = time.time()
    except Exception:
        now = 0.0
    if now and _ADV_SYNC_DELETE_WATCH_LAST_TICK and (now - float(_ADV_SYNC_DELETE_WATCH_LAST_TICK)) < 0.12:
        return
    _ADV_SYNC_DELETE_WATCH_LAST_TICK = now

    if _ADV_SYNC_DELETE_WATCH_GUARD:
        return

    try:
        sel = cmds.ls(sl=True, long=True) or []
    except Exception:
        sel = []
    if not sel:
        return

    try:
        frame = int(round(float(cmds.currentTime(q=True))))
    except Exception:
        return

    # Resolve group nodes based on current selection
    try:
        targets = _adv_sync_collect_group_nodes_for_selection(sel)
    except Exception:
        targets = []
    if not targets:
        return

    targets_stripped = set(_adv_sync_strip_name(n) for n in targets if n)

    # Candidates: selected nodes that belong to this group
    candidates = []
    for s in sel:
        sn = _adv_sync_strip_name(s)
        if sn and sn in targets_stripped:
            # resolve actual node(s) by stripped name (namespace-safe)
            try:
                rs = _adv_sync_resolve_targets(sn)
            except Exception:
                rs = []
            if rs:
                candidates.extend(rs)
            else:
                candidates.append(s)

    # De-dup
    cand_seen = set()
    cand = []
    for c in candidates:
        if c and c not in cand_seen:
            cand.append(c)
            cand_seen.add(c)

    if not cand:
        return

    # Detect: previously had key at frame, now no key => propagate deletion
    deleted = False
    for c in cand:
        sn = _adv_sync_strip_name(c)
        if not sn:
            continue
        prev = _ADV_SYNC_DELETE_WATCH_LAST_STATE.get((sn, frame))
        now_has = _adv_sync_has_key_at_frame(c, frame)
        if prev is True and (not now_has):
            deleted = True
            break

    if deleted:
        _ADV_SYNC_DELETE_WATCH_GUARD = True
        try:
            _adv_sync_delete_keys_at_frame(list(targets), frame)
        finally:
            # Update cache for this frame to avoid repeated triggers
            try:
                for n in targets:
                    sn = _adv_sync_strip_name(n)
                    if sn:
                        _ADV_SYNC_DELETE_WATCH_LAST_STATE[(sn, frame)] = _adv_sync_has_key_at_frame(n, frame)
            except Exception:
                pass
            _ADV_SYNC_DELETE_WATCH_GUARD = False
        return

    # Update cache for candidates
    try:
        for c in cand:
            sn = _adv_sync_strip_name(c)
            if sn:
                _ADV_SYNC_DELETE_WATCH_LAST_STATE[(sn, frame)] = _adv_sync_has_key_at_frame(c, frame)
    except Exception:
        pass


def _adv_sync_ui_clear_layout_children(layout):
    try:
        children = cmds.layout(layout, q=True, ca=True) or []
        for c in children:
            try:
                cmds.deleteUI(c)
            except Exception:
                pass
    except Exception:
        pass


def _adv_sync_ui_rebuild_groups():
    if not cmds.columnLayout(ADV_SYNC_UI_GROUPS_COL, exists=True):
        return

    groups = _adv_sync_groups_load()
    _adv_sync_ui_clear_layout_children(ADV_SYNC_UI_GROUPS_COL)
    cmds.setParent(ADV_SYNC_UI_GROUPS_COL)

    for g in groups:
        gname = g.get("name", "")
        ctrls = g.get("controllers", []) or []
        if not gname:
            continue

        frame = cmds.frameLayout(label=gname, collapsable=True, collapse=True, marginWidth=4, marginHeight=4)
        cmds.columnLayout(adjustableColumn=True, rowSpacing=3)

        tsl = cmds.textScrollList(allowMultiSelection=True, height=70)
        for c in ctrls:
            cmds.textScrollList(tsl, e=True, append=c)

        cmds.rowLayout(numberOfColumns=3, columnWidth3=(120, 120, 100), adjustableColumn=2)
        cmds.button(label=get_text("sync_key_add_ctrl"), height=24,
                    command=lambda _x, group_name=gname: adv_sync_group_add_selected_controllers(group_name))
        cmds.button(label=get_text("sync_key_remove_ctrl"), height=24,
                    command=lambda _x, group_name=gname, tsl_name=tsl: adv_sync_group_remove_selected_items(group_name, tsl_name))
        cmds.button(label=get_text("sync_key_delete_group"), height=24, backgroundColor=(0.7, 0.35, 0.35),
                    command=lambda _x, group_name=gname: adv_sync_group_delete(group_name))
        cmds.setParent('..')

        cmds.setParent('..')  # columnLayout
        cmds.setParent('..')  # frameLayout


def adv_sync_group_add():
    groups = _adv_sync_groups_load()
    default_name = _adv_sync_default_group_name(groups)
    if cmds.promptDialog(title=get_text("sync_key_add_group"),
                         message=get_text("sync_key_prompt_group_name"),
                         button=['OK', 'Cancel'],
                         defaultButton='OK',
                         cancelButton='Cancel',
                         dismissString='Cancel',
                         text=default_name) != 'OK':
        return
    name = cmds.promptDialog(q=True, text=True).strip()
    if not name:
        return
    if _adv_sync_group_name_exists(groups, name):
        cmds.warning(get_text("sync_key_group_exists") % name)
        return
    groups.append({"name": name, "controllers": []})
    _adv_sync_groups_save(groups)
    _adv_sync_ui_rebuild_groups()


def adv_sync_group_delete(group_name):
    groups = _adv_sync_groups_load()
    groups = [g for g in groups if str(g.get("name", "")) != str(group_name)]
    _adv_sync_groups_save(groups)
    _adv_sync_ui_rebuild_groups()


def adv_sync_group_add_selected_controllers(group_name):
    sel = cmds.ls(sl=True) or []
    if not sel:
        cmds.warning(get_text("sync_key_select_object"))
        return
    groups = _adv_sync_groups_load()
    for g in groups:
        if str(g.get("name", "")) != str(group_name):
            continue
        ctrls = g.get("controllers", []) or []
        for s in sel:
            if s not in ctrls:
                ctrls.append(s)
        g["controllers"] = ctrls
        break
    _adv_sync_groups_save(groups)
    _adv_sync_ui_rebuild_groups()


def adv_sync_group_remove_selected_items(group_name, text_scroll_list):
    try:
        items = cmds.textScrollList(text_scroll_list, q=True, si=True) or []
    except Exception:
        items = []
    if not items:
        return

    groups = _adv_sync_groups_load()
    for g in groups:
        if str(g.get("name", "")) != str(group_name):
            continue
        ctrls = g.get("controllers", []) or []
        ctrls = [c for c in ctrls if c not in items]
        g["controllers"] = ctrls
        break
    _adv_sync_groups_save(groups)
    _adv_sync_ui_rebuild_groups()


def _adv_sync_groups_window_exists():
    return cmds.window(ADV_SYNC_GROUPS_WINDOW, exists=True)


def _adv_sync_groups_window_refresh(select_group_name=None):
    """Refresh groups + controller list in the dedicated editor window."""
    if not _adv_sync_groups_window_exists():
        return

    groups = _adv_sync_groups_load()
    if cmds.textScrollList(ADV_SYNC_GROUPS_TSL, exists=True):
        cmds.textScrollList(ADV_SYNC_GROUPS_TSL, e=True, removeAll=True)
        for g in groups:
            n = g.get("name")
            if n:
                cmds.textScrollList(ADV_SYNC_GROUPS_TSL, e=True, append=n)

    # restore selection
    if select_group_name and cmds.textScrollList(ADV_SYNC_GROUPS_TSL, exists=True):
        try:
            cmds.textScrollList(ADV_SYNC_GROUPS_TSL, e=True, selectItem=select_group_name)
        except Exception:
            pass

    adv_sync_groups_window_on_group_select()


def adv_sync_groups_window_on_group_select():
    if not _adv_sync_groups_window_exists():
        return

    groups = _adv_sync_groups_load()
    selected = []
    try:
        selected = cmds.textScrollList(ADV_SYNC_GROUPS_TSL, q=True, si=True) or []
    except Exception:
        selected = []

    name = selected[0] if selected else ""
    ctrls = []
    for g in groups:
        if str(g.get("name", "")) == str(name):
            ctrls = g.get("controllers", []) or []
            break

    if cmds.textScrollList(ADV_SYNC_GROUPS_CTRLS_TSL, exists=True):
        cmds.textScrollList(ADV_SYNC_GROUPS_CTRLS_TSL, e=True, removeAll=True)
        for c in ctrls:
            cmds.textScrollList(ADV_SYNC_GROUPS_CTRLS_TSL, e=True, append=c)

    # Selecting a group also selects corresponding controllers in the scene.
    if name:
        adv_sync_select_group_controllers(name)


