def _adv_sync_resolve_controller_patterns_to_scene_nodes(patterns):
    import fnmatch
    out = []
    if not patterns:
        return out
    try:
        nodes = cmds.ls(type='transform') or []
    except Exception:
        nodes = []

    def _strip(n):
        try:
            s = str(n)
        except Exception:
            return ''
        if not s:
            return ''
        s = s.split('|')[-1]
        s = s.split(':')[-1]
        return s

    for p in patterns:
        if not p:
            continue
        pat = _strip(p)
        if not pat:
            continue
        use_glob = ('*' in pat) or ('?' in pat)
        for n in nodes:
            sn = _strip(n)
            if not sn:
                continue
            if use_glob:
                if fnmatch.fnmatch(sn, pat):
                    out.append(n)
            else:
                if sn == pat:
                    out.append(n)
    try:
        return list(dict.fromkeys(out))
    except Exception:
        return out


def adv_sync_groups_window_select_controllers():
    if not _adv_sync_groups_window_exists():
        return
    items = []
    try:
        items = cmds.textScrollList(ADV_SYNC_GROUPS_CTRLS_TSL, q=True, si=True) or []
    except Exception:
        items = []
    if not items:
        try:
            items = cmds.textScrollList(ADV_SYNC_GROUPS_CTRLS_TSL, q=True, ai=True) or []
        except Exception:
            items = []
    nodes = _adv_sync_resolve_controller_patterns_to_scene_nodes(items)
    if not nodes:
        try:
            cmds.warning(get_text("sync_key_select_object"))
        except Exception:
            pass
        return
    try:
        cmds.select(nodes, r=True)
    except Exception:
        pass

_adv_sync_groups_qt_dialog = None


def open_sync_key_groups_window_qt():
    """Qt version of sync key groups editor."""
    try:
        from PySide2 import QtWidgets, QtCore, QtGui
    except ImportError:
        return False

    # Ensure default ADV groups exist / upgraded
    adv_sync_ensure_default_groups(force=False)
    try:
        adv_sync_presets_ensure_defaults()
    except Exception:
        pass

    enabled = False
    try:
        enabled = bool(cmds.optionVar(q=ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR)) if cmds.optionVar(exists=ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR) else False
    except Exception:
        enabled = False
    if enabled:
        try:
            adv_sync_hotkey_set_enabled(True)
        except Exception:
            pass

    parent = None
    try:
        parent = _adv_get_qt_window_widget(ADV_MAIN_WINDOW_NAME)
    except Exception:
        parent = None

    global _adv_sync_groups_qt_dialog
    try:
        if _adv_sync_groups_qt_dialog is not None:
            _adv_sync_groups_qt_dialog.close()
    except Exception:
        pass

    class AdvSyncGroupsDialog(QtWidgets.QDialog):
        def __init__(self, parent=None):
            super(AdvSyncGroupsDialog, self).__init__(parent)
            self.setWindowTitle(get_text("sync_key_open_groups"))
            try:
                self.setWindowFlags(self.windowFlags() | QtCore.Qt.Tool)
            except Exception:
                pass
            self.resize(520, 480)

            outer = QtWidgets.QVBoxLayout(self)
            outer.setContentsMargins(12, 12, 12, 12)
            outer.setSpacing(8)

            self.cb_enable = QtWidgets.QCheckBox(get_text("sync_key_enable"))
            self.cb_enable.setChecked(enabled)
            self.cb_enable.toggled.connect(lambda v: adv_sync_hotkey_set_enabled(bool(v)))
            outer.addWidget(self.cb_enable)

            # Preset row
            preset_row = QtWidgets.QHBoxLayout()
            preset_row.setSpacing(6)
            preset_row.addWidget(QtWidgets.QLabel(get_text("sync_key_preset")))
            self.preset_combo = QtWidgets.QComboBox()
            preset_row.addWidget(self.preset_combo, 1)
            self.btn_preset_load = QtWidgets.QPushButton(get_text("sync_key_load_preset"))
            self.btn_preset_new = QtWidgets.QPushButton(get_text("sync_key_new_preset"))
            self.btn_preset_save = QtWidgets.QPushButton(get_text("sync_key_save_preset"))
            self.btn_preset_rename = QtWidgets.QPushButton((u"重命名" if LANGUAGE == 'CN' else "Rename"))
            self.btn_preset_delete = QtWidgets.QPushButton(get_text("sync_key_delete_preset"))
            for b in (self.btn_preset_load, self.btn_preset_new, self.btn_preset_save, self.btn_preset_rename, self.btn_preset_delete):
                b.setFixedHeight(24)
                preset_row.addWidget(b)
            outer.addLayout(preset_row)

            # Import / Export
            ie_row = QtWidgets.QHBoxLayout()
            ie_row.setSpacing(6)
            self.btn_export = QtWidgets.QPushButton(get_text('preset_export'))
            self.btn_import = QtWidgets.QPushButton(get_text('preset_import'))
            self.btn_export.setFixedHeight(24)
            self.btn_import.setFixedHeight(24)
            ie_row.addWidget(self.btn_export)
            ie_row.addWidget(self.btn_import)
            ie_row.addStretch(1)
            outer.addLayout(ie_row)

            # Add/Delete group
            grp_btns = QtWidgets.QHBoxLayout()
            grp_btns.setSpacing(6)
            self.btn_group_add = QtWidgets.QPushButton(get_text("sync_key_add_group"))
            self.btn_group_del = QtWidgets.QPushButton(get_text("sync_key_delete_group"))
            self.btn_group_add.setFixedHeight(26)
            self.btn_group_del.setFixedHeight(26)
            grp_btns.addWidget(self.btn_group_add)
            grp_btns.addWidget(self.btn_group_del)
            grp_btns.addStretch(1)
            outer.addLayout(grp_btns)

            # Main lists
            lists = QtWidgets.QHBoxLayout()
            lists.setSpacing(12)
            outer.addLayout(lists, 1)

            left = QtWidgets.QVBoxLayout()
            left.setSpacing(6)
            lists.addLayout(left, 1)
            left.addWidget(QtWidgets.QLabel(get_text("sync_key_groups")))
            self.group_list = QtWidgets.QListWidget()
            left.addWidget(self.group_list, 1)

            right = QtWidgets.QVBoxLayout()
            right.setSpacing(6)
            lists.addLayout(right, 1)
            right.addWidget(QtWidgets.QLabel(get_text("sync_key_title")))
            self.ctrl_list = QtWidgets.QListWidget()
            self.ctrl_list.setSelectionMode(QtWidgets.QAbstractItemView.ExtendedSelection)
            right.addWidget(self.ctrl_list, 1)
            ctrl_btns = QtWidgets.QHBoxLayout()
            self.btn_add_ctrl = QtWidgets.QPushButton(get_text("sync_key_add_ctrl"))
            self.btn_remove_ctrl = QtWidgets.QPushButton(get_text("sync_key_remove_ctrl"))
            self.btn_select_ctrl = QtWidgets.QPushButton((u"选择" if LANGUAGE == 'CN' else "Select"))
            self.btn_add_ctrl.setFixedHeight(26)
            self.btn_remove_ctrl.setFixedHeight(26)
            ctrl_btns.addWidget(self.btn_add_ctrl)
            ctrl_btns.addWidget(self.btn_remove_ctrl)
            ctrl_btns.addWidget(self.btn_select_ctrl)
            right.addLayout(ctrl_btns)

            # Wiring
            self.group_list.itemSelectionChanged.connect(self._on_group_selected)
            self.btn_group_add.clicked.connect(self._add_group)
            self.btn_group_del.clicked.connect(self._delete_group)
            self.btn_add_ctrl.clicked.connect(self._add_selected_controllers)
            self.btn_remove_ctrl.clicked.connect(self._remove_selected_controllers)
            self.btn_select_ctrl.clicked.connect(self._select_controllers_in_scene)

            self.btn_export.clicked.connect(adv_export_all_presets_to_file)
            self.btn_import.clicked.connect(adv_import_all_presets_from_file)

            self.preset_combo.currentIndexChanged.connect(self._on_preset_changed)
            self.btn_preset_load.clicked.connect(self._load_preset)
            self.btn_preset_new.clicked.connect(self._new_preset)
            self.btn_preset_save.clicked.connect(self._save_preset)
            self.btn_preset_rename.clicked.connect(self._rename_preset)
            self.btn_preset_delete.clicked.connect(self._delete_preset)

            self._rebuild_preset_menu()
            self._refresh_groups()

        def _current_group(self):
            item = self.group_list.currentItem()
            if not item:
                return None
            return item.data(QtCore.Qt.UserRole)

        def _refresh_groups(self, select_name=None):
            groups = _adv_sync_groups_load()
            names = [str(g.get("name", "")) for g in groups if str(g.get("name", ""))]
            self.group_list.blockSignals(True)
            self.group_list.clear()
            for n in names:
                it = QtWidgets.QListWidgetItem(n)
                it.setData(QtCore.Qt.UserRole, n)
                self.group_list.addItem(it)
            self.group_list.blockSignals(False)
            want = select_name or (names[0] if names else None)
            if want:
                for i in range(self.group_list.count()):
                    it = self.group_list.item(i)
                    if it.data(QtCore.Qt.UserRole) == want:
                        self.group_list.setCurrentItem(it)
                        break

        def _on_group_selected(self):
            name = self._current_group()
            if not name:
                self.ctrl_list.clear()
                return
            groups = _adv_sync_groups_load()
            ctrls = []
            for g in groups:
                if str(g.get("name", "")) == str(name):
                    ctrls = g.get("controllers", []) or []
                    break
            self.ctrl_list.clear()
            for c in ctrls:
                self.ctrl_list.addItem(c)

        def _add_group(self):
            groups = _adv_sync_groups_load()
            default_name = _adv_sync_default_group_name(groups)
            title = get_text("sync_key_add_group")
            msg = get_text("sync_key_prompt_preset_name") if LANGUAGE != 'CN' else u"请输入组名称"
            name, ok = QtWidgets.QInputDialog.getText(self, title, msg, text=default_name)
            if not ok:
                return
            name = str(name or '').strip()
            if not name:
                return
            if _adv_sync_group_name_exists(groups, name):
                try:
                    cmds.warning(get_text("sync_key_group_exists") % name)
                except Exception:
                    pass
                return
            groups.append({"name": name, "controllers": []})
            _adv_sync_groups_save(groups)
            self._refresh_groups(select_name=name)

        def _delete_group(self):
            name = self._current_group()
            if not name:
                return
            reply = QtWidgets.QMessageBox.question(self, get_text("sync_key_delete_group"),
                                                   (get_text("sync_key_delete_group") + ": " + name))
            if reply != QtWidgets.QMessageBox.Yes:
                return
            groups = _adv_sync_groups_load()
            groups = [g for g in groups if str(g.get("name", "")) != str(name)]
            _adv_sync_groups_save(groups)
            self._refresh_groups()

        def _add_selected_controllers(self):
            name = self._current_group()
            if not name:
                return
            sel = cmds.ls(sl=True) or []
            if not sel:
                try:
                    cmds.warning(get_text("sync_key_select_object"))
                except Exception:
                    pass
                return
            groups = _adv_sync_groups_load()
            for g in groups:
                if str(g.get("name", "")) != str(name):
                    continue
                ctrls = g.get("controllers", []) or []
                for s in sel:
                    if s not in ctrls:
                        ctrls.append(s)
                g["controllers"] = ctrls
                break
            _adv_sync_groups_save(groups)
            self._refresh_groups(select_name=name)

        def _remove_selected_controllers(self):
            name = self._current_group()
            if not name:
                return
            items = [it.text() for it in self.ctrl_list.selectedItems()]
            if not items:
                return
            groups = _adv_sync_groups_load()
            for g in groups:
                if str(g.get("name", "")) != str(name):
                    continue
                ctrls = g.get("controllers", []) or []
                ctrls = [c for c in ctrls if c not in items]
                g["controllers"] = ctrls
                break
            _adv_sync_groups_save(groups)
            self._refresh_groups(select_name=name)

        def _select_controllers_in_scene(self):
            items = []
            try:
                items = [it.text() for it in self.ctrl_list.selectedItems()]
            except Exception:
                items = []
            if not items:
                try:
                    items = [self.ctrl_list.item(i).text() for i in range(self.ctrl_list.count())]
                except Exception:
                    items = []
            nodes = _adv_sync_resolve_controller_patterns_to_scene_nodes(items)
            if not nodes:
                return
            try:
                cmds.select(nodes, r=True)
            except Exception:
                pass

        def _rebuild_preset_menu(self, select_name=None):
            self.preset_combo.blockSignals(True)
            self.preset_combo.clear()
            presets = _adv_sync_presets_load()
            names = [n for n in presets.keys() if n]
            names_sorted = []
            if "ADV" in names:
                names_sorted.append("ADV")
            for n in sorted([x for x in names if x != "ADV"], key=lambda s: s.lower()):
                names_sorted.append(n)
            if not names_sorted:
                names_sorted = ["ADV"]
            for n in names_sorted:
                self.preset_combo.addItem(n)
            want = select_name or _adv_sync_presets_get_active() or "ADV"
            if want not in names_sorted:
                want = names_sorted[0]
            idx = self.preset_combo.findText(want)
            if idx >= 0:
                self.preset_combo.setCurrentIndex(idx)
            self.preset_combo.blockSignals(False)

        def _current_preset(self):
            try:
                return self.preset_combo.currentText() or ""
            except Exception:
                return ""

        def _on_preset_changed(self):
            preset_name = self._current_preset()
            if preset_name:
                _adv_sync_presets_set_active(preset_name)

        def _load_preset(self):
            preset_name = self._current_preset()
            if preset_name:
                adv_sync_presets_apply(preset_name)
                self._rebuild_preset_menu(select_name=preset_name)
                self._refresh_groups()

        def _new_preset(self):
            title = get_text("sync_key_save_preset")
            msg = get_text("sync_key_prompt_preset_name")
            name, ok = QtWidgets.QInputDialog.getText(self, title, msg)
            if not ok:
                return
            name = str(name or '').strip()
            if not name:
                return
            if adv_sync_presets_save_current_as(name):
                self._rebuild_preset_menu(select_name=name)

        def _save_preset(self):
            preset_name = self._current_preset()
            if not preset_name:
                return
            if preset_name == "ADV":
                try:
                    cmds.warning(get_text("sync_key_preset_protect_adv"))
                except Exception:
                    pass
                return
            msg = get_text("sync_key_preset_confirm_overwrite") % preset_name
            reply = QtWidgets.QMessageBox.question(self, get_text("sync_key_save_preset"), msg)
            if reply != QtWidgets.QMessageBox.Yes:
                return
            if adv_sync_presets_overwrite(preset_name):
                self._rebuild_preset_menu(select_name=preset_name)

        def _delete_preset(self):
            preset_name = self._current_preset()
            if not preset_name:
                return
            if preset_name == "ADV":
                try:
                    cmds.warning(get_text("sync_key_preset_protect_adv"))
                except Exception:
                    pass
                return
            msg = get_text("sync_key_preset_confirm_delete") % preset_name
            reply = QtWidgets.QMessageBox.question(self, get_text("sync_key_delete_preset"), msg)
            if reply != QtWidgets.QMessageBox.Yes:
                return
            if adv_sync_presets_delete(preset_name):
                self._rebuild_preset_menu(select_name=_adv_sync_presets_get_active())

        def _rename_preset(self):
            old = self._current_preset()
            if not old:
                return
            if old == 'ADV':
                try:
                    cmds.warning(get_text("sync_key_preset_protect_adv"))
                except Exception:
                    pass
                return
            title = (u"重命名" if LANGUAGE == 'CN' else "Rename")
            msg = (u"将预设 %s 重命名为：" % old) if LANGUAGE == 'CN' else ("Rename preset %s to:" % old)
            new, ok = QtWidgets.QInputDialog.getText(self, title, msg, text=str(old))
            if not ok:
                return
            new = str(new or '').strip()
            if not new or new == old:
                return
            presets = _adv_sync_presets_load() or {}
            if new in presets:
                try:
                    _adv_safe_warning(u"预设已存在：%s" % new if LANGUAGE == 'CN' else ("Preset already exists: %s" % new))
                except Exception:
                    pass
                return
            if old not in presets:
                return
            presets[new] = presets.get(old)
            try:
                del presets[old]
            except Exception:
                pass
            _adv_sync_presets_save(presets)
            active = _adv_sync_presets_get_active() or 'ADV'
            if active == old:
                _adv_sync_presets_set_active(new)
            self._rebuild_preset_menu(select_name=new)

        def closeEvent(self, event):
            try:
                _adv_unregister_qt_style_target('ADV_SYNC_GROUPS_QT')
            except Exception:
                pass
            return super(AdvSyncGroupsDialog, self).closeEvent(event)

    dlg = AdvSyncGroupsDialog(parent)
    _adv_sync_groups_qt_dialog = dlg
    try:
        _adv_register_qt_style_target('ADV_SYNC_GROUPS_QT', dlg, allow_bg_image=True)
        _adv_apply_qstyle_to_qt_widget(dlg, enabled=_adv_qstyle_is_enabled(default=True), object_name='ADV_SYNC_GROUPS_QT', allow_bg_image=True)
    except Exception:
        pass
    dlg.show()
    dlg.raise_()
    dlg.activateWindow()
    return dlg


def open_sync_key_groups_window():
    """Open dedicated editor window for sync key groups (like Macro Menu)."""
    try:
        if open_sync_key_groups_window_qt():
            return
    except Exception:
        pass
    if cmds.window(ADV_SYNC_GROUPS_WINDOW, exists=True):
        cmds.deleteUI(ADV_SYNC_GROUPS_WINDOW)

    # Ensure default ADV groups exist / upgraded
    adv_sync_ensure_default_groups(force=False)
    # Ensure presets exist (ADV preset includes the 6 default groups)
    try:
        adv_sync_presets_ensure_defaults()
    except Exception:
        pass

    enabled = False
    try:
        enabled = bool(cmds.optionVar(q=ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR)) if cmds.optionVar(exists=ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR) else False
    except Exception:
        enabled = False

    # If sync is already enabled, ensure S is still bound (hotkeys can be overridden by other scripts/hotkey sets).
    if enabled:
        try:
            adv_sync_hotkey_set_enabled(True)
        except Exception:
            pass

    w = cmds.window(ADV_SYNC_GROUPS_WINDOW, title=get_text("sync_key_open_groups"), widthHeight=(420, 380), resizeToFitChildren=True)
    cmds.columnLayout(adjustableColumn=True, columnAttach=('both', 10), rowSpacing=6)

    cmds.checkBox(label=get_text("sync_key_enable"), v=enabled,
                 onc=lambda _x: adv_sync_hotkey_set_enabled(True),
                 ofc=lambda _x: adv_sync_hotkey_set_enabled(False))

    # Preset selector (AutoIKFKAlign-like: select + Load/New/Save/Delete)
    def _rebuild_preset_menu(select_name=None):
        if not cmds.optionMenu(ADV_SYNC_GROUPS_PRESET_OM, exists=True):
            return
        try:
            cmds.optionMenu(ADV_SYNC_GROUPS_PRESET_OM, e=True, dai=True)
        except Exception:
            # Older Maya fallback
            items = cmds.optionMenu(ADV_SYNC_GROUPS_PRESET_OM, q=True, ill=True) or []
            for it in items:
                try:
                    cmds.deleteUI(it)
                except Exception:
                    pass

        presets = _adv_sync_presets_load()
        names = list(presets.keys())
        names = [n for n in names if n]
        names_sorted = []
        if "ADV" in names:
            names_sorted.append("ADV")
        for n in sorted([x for x in names if x != "ADV"], key=lambda s: s.lower()):
            names_sorted.append(n)
        if not names_sorted:
            names_sorted = ["ADV"]

        for n in names_sorted:
            cmds.menuItem(label=n)

        want = select_name or _adv_sync_presets_get_active() or "ADV"
        if want not in names_sorted:
            want = names_sorted[0]
        try:
            cmds.optionMenu(ADV_SYNC_GROUPS_PRESET_OM, e=True, v=want)
        except Exception:
            pass

    def _get_selected_preset_name():
        try:
            return cmds.optionMenu(ADV_SYNC_GROUPS_PRESET_OM, q=True, v=True) or ""
        except Exception:
            return ""

    def _on_preset_changed(*_):
        # Only remember selection; do not auto-apply (safer for editing)
        preset_name = _get_selected_preset_name()
        if preset_name:
            _adv_sync_presets_set_active(preset_name)

    def _load_preset(*_):
        preset_name = _get_selected_preset_name()
        if preset_name:
            adv_sync_presets_apply(preset_name)

    def _new_preset(*_):
        if cmds.promptDialog(title=get_text("sync_key_save_preset"),
                             message=get_text("sync_key_prompt_preset_name"),
                             button=['OK', 'Cancel'],
                             defaultButton='OK',
                             cancelButton='Cancel',
                             dismissString='Cancel',
                             text="") != 'OK':
            return
        name = cmds.promptDialog(q=True, text=True).strip()
        if not name:
            return
        if adv_sync_presets_save_current_as(name):
            _rebuild_preset_menu(select_name=name)

    def _save_preset(*_):
        preset_name = _get_selected_preset_name()
        if not preset_name:
            return
        if preset_name == "ADV":
            cmds.warning(get_text("sync_key_preset_protect_adv"))
            return
        msg = get_text("sync_key_preset_confirm_overwrite") % preset_name
        try:
            ok = (cmds.confirmDialog(title=get_text("sync_key_save_preset"), message=msg, button=['OK', 'Cancel'], defaultButton='OK', cancelButton='Cancel', dismissString='Cancel') == 'OK')
        except Exception:
            ok = True
        if not ok:
            return
        if adv_sync_presets_overwrite(preset_name):
            _rebuild_preset_menu(select_name=preset_name)

    def _delete_preset(*_):
        preset_name = _get_selected_preset_name()
        if not preset_name:
            return
        if preset_name == "ADV":
            cmds.warning(get_text("sync_key_preset_protect_adv"))
            return
        msg = get_text("sync_key_preset_confirm_delete") % preset_name
        try:
            ok = (cmds.confirmDialog(title=get_text("sync_key_delete_preset"), message=msg, button=['OK', 'Cancel'], defaultButton='OK', cancelButton='Cancel', dismissString='Cancel') == 'OK')
        except Exception:
            ok = True
        if not ok:
            return
        if adv_sync_presets_delete(preset_name):
            _rebuild_preset_menu(select_name=_adv_sync_presets_get_active())

    def _rename_preset(*_):
        old = _get_selected_preset_name()
        if not old:
            return
        if old == 'ADV':
            cmds.warning(get_text("sync_key_preset_protect_adv"))
            return

        title = (u"重命名" if LANGUAGE == 'CN' else "Rename")
        msg = (u"将预设 %s 重命名为：" % old) if LANGUAGE == 'CN' else ("Rename preset %s to:" % old)
        try:
            ok = (cmds.promptDialog(title=title, message=msg, button=['OK', 'Cancel'], defaultButton='OK', cancelButton='Cancel', dismissString='Cancel', text=str(old)) == 'OK')
        except Exception:
            ok = False
        if not ok:
            return
        try:
            new = (cmds.promptDialog(q=True, text=True) or '').strip()
        except Exception:
            new = ''
        if not new or new == old:
            return

        presets = _adv_sync_presets_load() or {}
        if new in presets:
            try:
                _adv_safe_warning(u"预设已存在：%s" % new if LANGUAGE == 'CN' else ("Preset already exists: %s" % new))
            except Exception:
                pass
            return
        if old not in presets:
            return

        presets[new] = presets.get(old)
        try:
            del presets[old]
        except Exception:
            pass
        _adv_sync_presets_save(presets)

        active = _adv_sync_presets_get_active() or 'ADV'
        if active == old:
            _adv_sync_presets_set_active(new)
        _rebuild_preset_menu(select_name=new)

    # compact preset row (7 cols: +Rename)
    cmds.rowLayout(
        numberOfColumns=7,
        adjustableColumn=2,
        columnWidth=[(1, 42), (2, 150), (3, 44), (4, 44), (5, 44), (6, 60), (7, 44)],
        columnAlign=[(1, 'left'), (2, 'left'), (3, 'left'), (4, 'left'), (5, 'left'), (6, 'left'), (7, 'left')],
        columnAttach=[(1, 'left', 0), (2, 'left', 0), (3, 'left', 0), (4, 'left', 0), (5, 'left', 0), (6, 'left', 0), (7, 'left', 0)],
    )
    cmds.text(label=get_text("sync_key_preset"), align='left')
    cmds.optionMenu(ADV_SYNC_GROUPS_PRESET_OM, changeCommand=_on_preset_changed)
    cmds.button(label=get_text("sync_key_load_preset"), height=24,
                backgroundColor=(0.35, 0.55, 0.75),
                command=_load_preset)
    cmds.button(label=get_text("sync_key_new_preset"), height=24,
                backgroundColor=(0.55, 0.55, 0.65),
                command=_new_preset)
    cmds.button(label=get_text("sync_key_save_preset"), height=24,
                backgroundColor=(0.55, 0.55, 0.65),
                command=_save_preset)
    cmds.button(label=(u"重命名" if LANGUAGE == 'CN' else "Rename"), height=24,
                backgroundColor=(0.55, 0.55, 0.65),
                command=_rename_preset)
    cmds.button(label=get_text("sync_key_delete_preset"), height=24,
                backgroundColor=(0.7, 0.35, 0.35),
                command=_delete_preset)
    cmds.setParent('..')

    # Unified import/export (Macro + SyncKey groups + SwitchRuntime groups)
    cmds.rowLayout(numberOfColumns=2, columnWidth2=(200, 200), adjustableColumn=2, columnAlign2=('left', 'left'))
    cmds.button(label=get_text('preset_export'), height=24, backgroundColor=(0.55, 0.55, 0.65), command=adv_export_all_presets_to_file)
    cmds.button(label=get_text('preset_import'), height=24, backgroundColor=(0.55, 0.55, 0.65), command=adv_import_all_presets_from_file)
    cmds.setParent('..')

    # compact add/delete group buttons (fixed width, no stretching)
