def _adv_ui_update_global_hotkey_mute_button():
    """Update global mute button UI (label/color)."""
    try:
        is_on = _adv_global_hotkey_mute_is_on()
        try:
            if cmds.button(ADV_GLOBAL_HOTKEY_MUTE_BUTTON, exists=True):
                # Label reflects the action user will take next.
                next_label = get_text('enable_all_hotkeys') if is_on else get_text('disable_all_hotkeys')
                bc_btn = (0.85, 0.55, 0.2) if is_on else (0.6, 0.5, 0.7)
                cmds.button(ADV_GLOBAL_HOTKEY_MUTE_BUTTON, e=True, label=next_label, backgroundColor=bc_btn)
        except Exception:
            pass
    except Exception:
        pass


def _adv_install_global_hotkey_mute_block_filter(force=False):
    """When global hotkey mute is ON, consume configured ADV hotkey keypresses.

    This makes "鍏ㄩ儴绂佺敤" reliable even when Maya hotkeySet is read-only and
    bindings cannot be removed (the hotkey would otherwise still fire).
    """
    global _ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER

    try:
        from PySide2 import QtCore, QtWidgets
    except ImportError:
        try:
            from PySide6 import QtCore, QtWidgets  # type: ignore
        except ImportError:
            return False

    try:
        if not _adv_global_hotkey_mute_is_on():
            return False
    except Exception:
        return False

    app = None
    try:
        app = QtWidgets.QApplication.instance()
    except Exception:
        app = None
    if not app:
        return False

    # Build key set: (qt_key, alt, ctrl, shift) -> True
    keyset = set()

    def _try_add_hotkey(hk):
        try:
            mod_token, main_key = _adv_split_hotkey_string(hk)
        except Exception:
            return
        if not main_key:
            return
        # Avoid mouse+key combos in the blocker (too intrusive).
        try:
            if _adv_mod_token_has_mouse(mod_token):
                return
        except Exception:
            return
        try:
            qt_key = _adv_qt_key_from_main_key(main_key)
        except Exception:
            qt_key = None
        if qt_key is None:
            return
        try:
            alt, ctrl, shift = _adv_modifier_token_to_bools(mod_token)
        except Exception:
            alt = ctrl = shift = False
        keyset.add((int(qt_key), bool(alt), bool(ctrl), bool(shift)))

    # Collect configured hotkeys from prefs (optionVars).
    for _type_name, opt, _cur_var, _custom in _adv_iter_managed_hotkey_specs():
        try:
            hk = cmds.optionVar(q=opt) if cmds.optionVar(exists=opt) else ''
        except Exception:
            hk = ''
        if hk:
            _try_add_hotkey(hk)

    if not keyset:
        return False

    class _ADVGlobalMuteBlockFilter(QtCore.QObject):
        def __init__(self, ks):
            super(_ADVGlobalMuteBlockFilter, self).__init__()
            self._ks = set(ks or [])

        def set_keyset(self, ks):
            self._ks = set(ks or [])

        def eventFilter(self, obj, event):
            try:
                if not _adv_global_hotkey_mute_is_on():
                    return False
            except Exception:
                return False

            try:
                if event.type() != QtCore.QEvent.KeyPress:
                    return False
            except Exception:
                return False

            try:
                if event.isAutoRepeat():
                    return False
            except Exception:
                pass

            fw = None
            try:
                fw = QtWidgets.QApplication.focusWidget()
            except Exception:
                fw = None
            try:
                if _adv_is_text_input_widget(fw) or _adv_is_text_input_widget(obj):
                    return False
            except Exception:
                pass

            try:
                mods = event.modifiers()
                alt = bool(mods & QtCore.Qt.AltModifier)
                ctrl = bool(mods & QtCore.Qt.ControlModifier)
                shift = bool(mods & QtCore.Qt.ShiftModifier)
                base = (int(event.key()), alt, ctrl, shift)
            except Exception:
                return False

            if base not in self._ks:
                return False

            # Consume the event so the bound Maya hotkey (if any) won't fire.
            try:
                event.accept()
            except Exception:
                pass
            return True

    if _ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER is None:
        _ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER = _ADVGlobalMuteBlockFilter(keyset)
        try:
            app.installEventFilter(_ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER)
        except Exception:
            _ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER = None
            return False
    else:
        try:
            _ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER.set_keyset(keyset)
        except Exception:
            pass
        if force:
            try:
                app.removeEventFilter(_ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER)
            except Exception:
                pass
            try:
                app.installEventFilter(_ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER)
            except Exception:
                pass
    return True


def _adv_remove_global_hotkey_mute_block_filter():
    global _ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER
    try:
        from PySide2 import QtWidgets
    except ImportError:
        try:
            from PySide6 import QtWidgets  # type: ignore
        except ImportError:
            _ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER = None
            return

    try:
        app = QtWidgets.QApplication.instance()
    except Exception:
        app = None
    if not app:
        _ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER = None
        return
    if _ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER is not None:
        try:
            app.removeEventFilter(_ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER)
        except Exception:
            pass
    _ADV_GLOBAL_HOTKEY_MUTE_BLOCK_FILTER = None


