        ('file_open', 'ADV_FileOpenHotkey', 'CURRENT_FILE_OPEN_HOTKEY', None),
        ('file_save', 'ADV_FileSaveHotkey', 'CURRENT_FILE_SAVE_HOTKEY', None),
