        ('prev_frame', 'ADV_PrevFrameHotkey', 'CURRENT_PREV_FRAME_HOTKEY', None),
        ('next_frame', 'ADV_NextFrameHotkey', 'CURRENT_NEXT_FRAME_HOTKEY', None),
        ('prev_keyframe', 'ADV_PrevKeyframeHotkey', 'CURRENT_PREV_KEYFRAME_HOTKEY', None),
        ('next_keyframe', 'ADV_NextKeyframeHotkey', 'CURRENT_NEXT_KEYFRAME_HOTKEY', None),
        ('focus_object', 'ADV_FocusObjectHotkey', 'CURRENT_FOCUS_OBJECT_HOTKEY', None),
        ('toggle_wireframe', 'ADV_ToggleWireframeHotkey', 'CURRENT_TOGGLE_WIREFRAME_HOTKEY', None),
        ('toggle_uv_wireframe', 'ADV_ToggleUVWireframeHotkey', 'CURRENT_TOGGLE_UV_WIREFRAME_HOTKEY', None),

        ('time_slider_drag', 'ADV_TimeSliderHotkey', 'CURRENT_TIME_SLIDER_HOTKEY', None),
