def _adv_hotkey_spec_is_relevant(option_var, current_var_name):
    """Only mute hotkeys that actually exist or have been set this session."""
    try:
        if cmds.optionVar(exists=option_var):
            return True
    except Exception:
        pass
    try:
        cur = globals().get(current_var_name)
        return bool(cur)
    except Exception:
        return False


def _adv_set_hotkey_enabled_by_spec(type_name, option_var, current_var_name, use_custom_toggle, enabled):
    try:
        # If disabling and current hotkey string isn't cached yet, pull from prefs so we can unbind.
        if not enabled:
            try:
                if not globals().get(current_var_name) and cmds.optionVar(exists=option_var):
                    globals()[current_var_name] = cmds.optionVar(q=option_var)
            except Exception:
                pass
        if use_custom_toggle == 'time_slider_clear_key':
            _toggle_time_slider_clear_key_hotkey_enabled(bool(enabled))
        else:
            _toggle_hotkey_enabled(type_name, option_var, current_var_name, bool(enabled))
    except Exception:
        pass


def _adv_global_mute_snapshot():
    """Snapshot all toggles affected by global mute."""
    snapshot = {}

    # Remember current hotkeySet so we can restore Maya default behavior when muting.
    try:
        snapshot['__ADV_PreMute_HotkeySet'] = cmds.hotkeySet(q=True, current=True) or ''
    except Exception:
        snapshot['__ADV_PreMute_HotkeySet'] = ''

    # Hotkey enable states
    for _type_name, opt, _cur_var, _custom in _adv_iter_managed_hotkey_specs():
        try:
            snapshot[opt] = bool(_adv_hotkey_enabled(opt))
        except Exception:
            snapshot[opt] = True

    # Feature enable states (non-hotkey toggles)
    try:
        snapshot[_ADV_TIME_SLIDER_ENABLED_OPTIONVAR] = bool(_adv_time_slider_is_enabled())
    except Exception:
        snapshot[_ADV_TIME_SLIDER_ENABLED_OPTIONVAR] = False

    try:
        snapshot[_ADV_AXIS_POPUP_ENABLED_OPTIONVAR] = bool(_adv_axis_popup_is_enabled(default=True))
    except Exception:
        snapshot[_ADV_AXIS_POPUP_ENABLED_OPTIONVAR] = True

    try:
        snapshot[_ADV_SELECT_SAME_LAYER_ENABLED_OPTIONVAR] = bool(_adv_select_same_layer_is_enabled(default=True))
    except Exception:
        snapshot[_ADV_SELECT_SAME_LAYER_ENABLED_OPTIONVAR] = True

    try:
        snapshot['ADV_KeyRepeatEnabled'] = bool(_adv_key_repeat_is_enabled())
    except Exception:
        snapshot['ADV_KeyRepeatEnabled'] = True

    try:
        snapshot[_ADV_SEAMLESS_VIEW_SWITCH_ENABLED_OPTIONVAR] = bool(_adv_seamless_view_switch_is_enabled(default=True))
    except Exception:
        snapshot[_ADV_SEAMLESS_VIEW_SWITCH_ENABLED_OPTIONVAR] = True

    try:
        snapshot['ADV_PathManagerEnabled'] = bool(adv_path_manager_is_enabled(default=False))
    except Exception:
        snapshot['ADV_PathManagerEnabled'] = False

    return snapshot


def _adv_global_mute_apply_features(time_slider_enabled=None, axis_popup_enabled=None, select_same_layer_enabled=None, key_repeat_enabled=None, seamless_view_switch_enabled=None, path_manager_enabled=None):
    """Apply non-hotkey feature toggles and sync UI if present.

    Any argument can be None to skip applying that feature.
    """
    if time_slider_enabled is not None:
        try:
            _adv_toggle_time_slider_enable(bool(time_slider_enabled))
        except Exception:
            pass
        _adv_ui_set_checkbox_if_exists('timeSliderEnableCheckbox', bool(time_slider_enabled))

    if axis_popup_enabled is not None:
        try:
            _adv_set_axis_popup_enabled(bool(axis_popup_enabled))
        except Exception:
            pass
        # axis_popup UI toggle now lives in the hotkey mapping window top row (axisPopupRowEnableCB).
        _adv_ui_set_checkbox_if_exists('axisPopupRowEnableCB', bool(axis_popup_enabled))

    if select_same_layer_enabled is not None:
        try:
            _adv_toggle_select_same_layer_enable(bool(select_same_layer_enabled))
        except Exception:
            pass
        _adv_ui_set_checkbox_if_exists('selectSameLayerQuickEnableCheckbox', bool(select_same_layer_enabled))

    if key_repeat_enabled is not None:
        try:
            _adv_ui_on_key_repeat_enabled_changed(bool(key_repeat_enabled))
        except Exception:
            pass
        _adv_ui_set_checkbox_if_exists('advKeyRepeatEnableCB', bool(key_repeat_enabled))

    if seamless_view_switch_enabled is not None:
        try:
            _adv_set_seamless_view_switch_enabled(bool(seamless_view_switch_enabled))
        except Exception:
            pass
        _adv_ui_set_checkbox_if_exists('cb_seamless_view', bool(seamless_view_switch_enabled))

    if path_manager_enabled is not None:
        try:
            adv_path_manager_set_enabled(bool(path_manager_enabled))
        except Exception:
            pass
        _adv_ui_set_checkbox_if_exists('cb_path_manager', bool(path_manager_enabled))


def _adv_ui_toggle_global_hotkey_mute(*_):
    """Toggle global mute for all ADV hotkey mappings.

    - When turning ON: snapshot which hotkeys were enabled, then disable all.
    - When turning OFF: restore only those that were previously enabled.
    """
    is_on = _adv_global_hotkey_mute_is_on()

    if not is_on:
        # Snapshot current enabled states (hotkeys + features)
        snapshot = _adv_global_mute_snapshot()

        try:
            cmds.optionVar(stringValue=(ADV_GLOBAL_HOTKEY_MUTE_SNAPSHOT_OPTIONVAR, json.dumps(snapshot, ensure_ascii=False)))
        except Exception:
            try:
                cmds.optionVar(stringValue=(ADV_GLOBAL_HOTKEY_MUTE_SNAPSHOT_OPTIONVAR, json.dumps(snapshot)))
            except Exception:
                pass

        # Disable all hotkeys
        for type_name, opt, cur_var, custom in _adv_iter_managed_hotkey_specs():
            if opt not in snapshot:
                continue
            _adv_set_hotkey_enabled_by_spec(type_name, opt, cur_var, custom, False)
            _adv_ui_set_hotkey_enable_checkbox(opt, False)

        # Disable features
        _adv_global_mute_apply_features(time_slider_enabled=False, axis_popup_enabled=False, select_same_layer_enabled=False, key_repeat_enabled=False, seamless_view_switch_enabled=False, path_manager_enabled=False)

        _adv_global_hotkey_mute_set_on(True)
        # Restore Maya default hotkey behavior:
        # - remove ADV Qt filters (fallback/repeat) so Maya can handle keys normally
        # - switch away from ADV_FastSelect hotkeySet to Maya_Default (or another non-ADV set)
        try:
            _adv_remove_hotkey_fallback_filter()
        except Exception:
            pass
        try:
            _adv_remove_key_repeat_filter()
        except Exception:
            pass
        try:
            _adv_remove_global_hotkey_mute_block_filter()
        except Exception:
            pass
        try:
            # Pick a default set.
            cur = ''
            try:
                cur = cmds.hotkeySet(q=True, current=True) or ''
            except Exception:
                cur = ''
            try:
                all_sets = cmds.hotkeySet(q=True, hotkeySetArray=True) or []
            except Exception:
                try:
                    all_sets = cmds.hotkeySet(q=True, hotkeySets=True) or []
                except Exception:
                    all_sets = []
            all_sets = [str(s) for s in (all_sets or []) if s]
            target = ''
            if 'Maya_Default' in all_sets:
                target = 'Maya_Default'
            else:
                for s in all_sets:
                    if s != 'ADV_FastSelect':
                        target = s
                        break
            if target and str(cur) != str(target):
                try:
                    mel.eval('hotkeySet -e -current "%s";' % str(target))
                except Exception:
                    try:
                        cmds.hotkeySet(e=True, current=target)
                    except Exception:
                        pass
        except Exception:
            pass
        _adv_ui_update_global_hotkey_mute_button()
        try:
            update_main_window_labels()
        except Exception:
            pass
        return

    # Turning OFF: restore snapshot
    try:
        _adv_remove_global_hotkey_mute_block_filter()
    except Exception:
        pass

    snapshot = {}
    try:
        raw = cmds.optionVar(q=ADV_GLOBAL_HOTKEY_MUTE_SNAPSHOT_OPTIONVAR) if cmds.optionVar(exists=ADV_GLOBAL_HOTKEY_MUTE_SNAPSHOT_OPTIONVAR) else ''
        if raw:
            snapshot = json.loads(raw) or {}
    except Exception:
        snapshot = {}

    for type_name, opt, cur_var, custom in _adv_iter_managed_hotkey_specs():
        if opt not in snapshot:
            continue
        want = bool(snapshot.get(opt))
        _adv_set_hotkey_enabled_by_spec(type_name, opt, cur_var, custom, want)
        _adv_ui_set_hotkey_enable_checkbox(opt, want)

    # Restore features
    try:
        _adv_global_mute_apply_features(
            time_slider_enabled=bool(snapshot.get(_ADV_TIME_SLIDER_ENABLED_OPTIONVAR, False)),
            axis_popup_enabled=bool(snapshot.get(_ADV_AXIS_POPUP_ENABLED_OPTIONVAR, True)),
            select_same_layer_enabled=bool(snapshot.get(_ADV_SELECT_SAME_LAYER_ENABLED_OPTIONVAR, True)),
            key_repeat_enabled=bool(snapshot.get('ADV_KeyRepeatEnabled', True)),
            seamless_view_switch_enabled=bool(snapshot.get(_ADV_SEAMLESS_VIEW_SWITCH_ENABLED_OPTIONVAR, True)),
            path_manager_enabled=bool(snapshot.get('ADV_PathManagerEnabled', True)),
        )
    except Exception:
        pass

    # Switch back to ADV hotkeySet so ADV bindings are active again.
    try:
        _adv_ensure_adv_hotkey_set_current()
    except Exception:
        pass

    _adv_global_hotkey_mute_set_on(False)
    _adv_ui_update_global_hotkey_mute_button()
    try:
        update_main_window_labels()
    except Exception:
        pass


def _adv_set_hotkey_enabled(option_var, enabled):
    try:
        cmds.optionVar(iv=(option_var + "_Enabled", 1 if enabled else 0))
    except Exception:
        pass


def adv_export_hotkey_document(file_path):
    import datetime
    data = {
        'type': 'ADV_HOTKEY_DOCUMENT',
        'version': 1,
        'time': datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        'hotkeys': {},
        'enabled': {},
        'features': {},
    }

    for _type_name, opt, cur_var, _custom in _adv_iter_managed_hotkey_specs():
        val = ''
        try:
            if cmds.optionVar(exists=opt):
                val = cmds.optionVar(q=opt) or ''
        except Exception:
            val = ''
        if not val:
            try:
                val = globals().get(cur_var) or ''
            except Exception:
                val = ''
        data['hotkeys'][opt] = str(val or '')
        try:
            data['enabled'][opt + '_Enabled'] = 1 if bool(_adv_hotkey_enabled(opt)) else 0
        except Exception:
            data['enabled'][opt + '_Enabled'] = 1

    try:
        data['features'][ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR] = 1 if (cmds.optionVar(exists=ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR) and bool(cmds.optionVar(q=ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR))) else 0
    except Exception:
        data['features'][ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR] = 0

    try:
        data['features'][_ADV_TIME_SLIDER_ENABLED_OPTIONVAR] = 1 if bool(_adv_time_slider_is_enabled()) else 0
    except Exception:
        data['features'][_ADV_TIME_SLIDER_ENABLED_OPTIONVAR] = 0
    try:
        data['features'][_ADV_AXIS_POPUP_ENABLED_OPTIONVAR] = 1 if bool(_adv_axis_popup_is_enabled(default=True)) else 0
    except Exception:
        data['features'][_ADV_AXIS_POPUP_ENABLED_OPTIONVAR] = 1
    try:
        data['features'][_ADV_SELECT_SAME_LAYER_ENABLED_OPTIONVAR] = 1 if bool(_adv_select_same_layer_is_enabled(default=True)) else 0
    except Exception:
        data['features'][_ADV_SELECT_SAME_LAYER_ENABLED_OPTIONVAR] = 1
    try:
        data['features']['ADV_KeyRepeatEnabled'] = 1 if bool(_adv_key_repeat_is_enabled()) else 0
    except Exception:
        data['features']['ADV_KeyRepeatEnabled'] = 1

    try:
        if cmds.optionVar(exists='ADV_TimeSliderDragScriptPath'):
            data['features']['ADV_TimeSliderDragScriptPath'] = cmds.optionVar(q='ADV_TimeSliderDragScriptPath') or ''
    except Exception:
        pass

    text = json.dumps(data, ensure_ascii=False, indent=2)
    try:
        with io.open(file_path, 'w', encoding='utf-8') as f:
            f.write(text)
    except TypeError:
        with io.open(file_path, 'w', encoding='utf-8') as f:
            f.write(text)


def adv_import_hotkey_document(file_path):
    try:
        with io.open(file_path, 'r', encoding='utf-8') as f:
            raw = f.read()
    except TypeError:
        with io.open(file_path, 'r', encoding='utf-8') as f:
            raw = f.read()

    try:
        data = json.loads(raw) or {}
    except Exception:
        data = {}

    hotkeys = data.get('hotkeys') or {}
    enabled = data.get('enabled') or {}
    features = data.get('features') or {}

    for _type_name, opt, _cur_var, _custom in _adv_iter_managed_hotkey_specs():
        v = hotkeys.get(opt, None)
        if v is not None:
            try:
                v = str(v)
            except Exception:
                v = ''
            try:
                if v:
                    cmds.optionVar(sv=(opt, v))
                else:
                    if cmds.optionVar(exists=opt):
                        cmds.optionVar(remove=opt)
            except Exception:
                pass

        en_key = opt + '_Enabled'
        if en_key in enabled:
            try:
                cmds.optionVar(iv=(en_key, 1 if bool(int(enabled.get(en_key))) else 0))
            except Exception:
                try:
                    cmds.optionVar(iv=(en_key, 1 if bool(enabled.get(en_key)) else 0))
                except Exception:
                    pass

    try:
        if ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR in features:
            cmds.optionVar(iv=(ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR, 1 if bool(int(features.get(ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR))) else 0))
    except Exception:
        pass

    try:
        if _ADV_TIME_SLIDER_ENABLED_OPTIONVAR in features:
            _adv_toggle_time_slider_enable(bool(int(features.get(_ADV_TIME_SLIDER_ENABLED_OPTIONVAR))))
    except Exception:
        pass
    try:
        if _ADV_AXIS_POPUP_ENABLED_OPTIONVAR in features:
            _adv_set_axis_popup_enabled(bool(int(features.get(_ADV_AXIS_POPUP_ENABLED_OPTIONVAR))))
    except Exception:
        pass
    try:
        if _ADV_SELECT_SAME_LAYER_ENABLED_OPTIONVAR in features:
            _adv_toggle_select_same_layer_enable(bool(int(features.get(_ADV_SELECT_SAME_LAYER_ENABLED_OPTIONVAR))))
    except Exception:
        pass
    try:
        if 'ADV_KeyRepeatEnabled' in features:
            _adv_ui_on_key_repeat_enabled_changed(bool(int(features.get('ADV_KeyRepeatEnabled'))))
    except Exception:
        pass

    try:
        if 'ADV_TimeSliderDragScriptPath' in features:
            p = features.get('ADV_TimeSliderDragScriptPath') or ''
            if p:
                cmds.optionVar(sv=('ADV_TimeSliderDragScriptPath', str(p)))
    except Exception:
        pass

    try:
        load_hotkeys_from_prefs()
    except Exception:
        pass
    try:
        update_main_window_labels()
    except Exception:
        pass

