def _unbind_hotkey_string(hotkey_str):
    if not hotkey_str:
        return
    try:
        mod_token, key = _adv_split_hotkey_string(hotkey_str)
        if _adv_mod_token_has_mouse(mod_token):
            return
        _adv_hotkey_clear(key, mod_token)
    except Exception:
        pass


def _toggle_hotkey_enabled(type_name, option_var, current_var_name, enabled):
    _adv_set_hotkey_enabled(option_var, enabled)
    if enabled:
        try:
            if cmds.optionVar(exists=option_var):
                apply_hotkey(type_name, cmds.optionVar(q=option_var))
            else:
                update_main_window_labels()
        except Exception:
            pass

        # Update key-repeat filter (press-and-hold) when enabling hotkeys.
        try:
            _adv_install_key_repeat_filter(force=True)
        except Exception:
            pass

        # Update fallback filter so disabled/enabled states take effect immediately.
        try:
            _adv_install_hotkey_fallback_filter(force=True)
        except Exception:
            pass
    else:
        try:
            cur = globals().get(current_var_name)
            # If the session cache is empty, pull from prefs so we can actually unbind.
            if (not cur) and cmds.optionVar(exists=option_var):
                try:
                    cur = cmds.optionVar(q=option_var)
                    globals()[current_var_name] = cur
                except Exception:
                    cur = cur
            if cur:
                _unbind_hotkey_string(cur)
                # Special handling: restore Maya default hotkey if needed
                _restore_maya_default_hotkey(cur)
        except Exception:
            pass

        # Update key-repeat filter (press-and-hold) when disabling hotkeys.
        try:
            _adv_install_key_repeat_filter(force=True)
        except Exception:
            pass

        # Update fallback filter so disabled/enabled states take effect immediately.
        try:
            _adv_install_hotkey_fallback_filter(force=True)
        except Exception:
            pass
        update_main_window_labels()


def _restore_maya_default_hotkey(hotkey_str):
    """Restore Maya's default hotkey binding when our custom hotkey is disabled."""
    import maya.mel as mel
    if not hotkey_str:
        return
    
    # Parse the hotkey string
    if '|' in hotkey_str:
        parts = hotkey_str.split('|')
        modifier = parts[0].lower()
        key = parts[1].lower()
    else:
        modifier = None
        key = hotkey_str.lower()
    
    # Special case: Space key should restore Maya's default hotbox
    if key == 'space':
        _restore_space_hotbox()


def _restore_space_hotbox():
    """Restore Maya's default Space key = HotBox behavior."""
    import maya.mel as mel
    try:
        # First, query what nameCommands exist for ShowHotbox/HideHotbox
        # Maya uses nameCommand objects that wrap runTimeCommands
        
        # Ensure the nameCommand exists for ShowHotbox
        if not _adv_runtime_command_exists('ShowHotbox'):
            print("[ADV] Warning: ShowHotbox runTimeCommand not found")
            return
        if not _adv_runtime_command_exists('HideHotbox'):
            print("[ADV] Warning: HideHotbox runTimeCommand not found")
            return
        
        # Create nameCommands if they don't exist
        # Maya's default nameCommands are typically named like 'ShowHotboxNameCommand'
        show_nc = 'ShowHotboxNameCommand'
        hide_nc = 'HideHotboxNameCommand'
        
        try:
            _adv_delete_command_ui_if_exists(show_nc)
            cmds.nameCommand(show_nc, annotation='Show Hotbox', command='ShowHotbox')
        except Exception:
            pass

        try:
            _adv_delete_command_ui_if_exists(hide_nc)
            cmds.nameCommand(hide_nc, annotation='Hide Hotbox', command='HideHotbox')
        except Exception:
            pass
        
        # Unbind any existing binding first
        try:
            cmds.hotkey(k='Space', name='', releaseName='')
        except Exception:
            pass
        
        # Bind Space key: press=ShowHotbox, release=HideHotbox
        cmds.hotkey(k='Space', name=show_nc, releaseName=hide_nc)
        print("[ADV] Restored Maya default Space key (ShowHotbox / HideHotbox)")
                
    except Exception as e:
        print("[ADV] Failed to restore Space key default: %s" % str(e))


def _adv_hotbox_altq_is_enabled(default=False):
    try:
        if cmds.optionVar(exists='ADV_HotboxAltQEnabled'):
            return bool(int(cmds.optionVar(q='ADV_HotboxAltQEnabled')))
    except Exception:
        pass
    return bool(default)


def _adv_purge_stale_toggle_pane_layout_filters():
    try:
        try:
            from PySide2 import QtCore, QtWidgets
        except ImportError:
            from PySide6 import QtCore, QtWidgets  # type: ignore
    except ImportError:
        return 0

    app = None
    try:
        app = QtWidgets.QApplication.instance()
    except Exception:
        app = None
    if not app:
        return 0

    try:
        import gc
    except Exception:
        return 0

    removed = 0
    # 娓呯悊鎵€鏈夊彲鑳藉共鎵扮殑鏃ц繃婊ゅ櫒
    filter_names_to_remove = (
        '_ADVNativeFilter', 
        '_ADVToggPaneOverrideFilter',
        '_AdvHotboxAltQFilter',
    )
    
    for o in gc.get_objects():
        try:
            n = o.__class__.__name__
        except Exception:
            continue

        if n not in filter_names_to_remove:
            continue

        try:
            if isinstance(o, QtCore.QAbstractNativeEventFilter):
                try:
                    app.removeNativeEventFilter(o)
                    removed += 1
                except Exception:
                    pass
        except Exception:
            pass

        try:
            if isinstance(o, QtCore.QObject):
                try:
                    app.removeEventFilter(o)
                    removed += 1
                except Exception:
                    pass
        except Exception:
            pass

    # 鍚屾椂娓呯悊鍏ㄥ眬鍙橀噺涓殑鏃ц繃婊ゅ櫒寮曠敤
    global _ADV_HOTBOX_ALTQ_FILTER
    if _ADV_HOTBOX_ALTQ_FILTER is not None:
        try:
            app.removeEventFilter(_ADV_HOTBOX_ALTQ_FILTER)
            removed += 1
        except Exception:
            pass
        _ADV_HOTBOX_ALTQ_FILTER = None

    return removed


def _adv_apply_hotbox_altq_enabled_state(enabled=None):
    """应用快捷键切换：Alt+Q 绑定到?Hotbox，空格键绑定到版挱鏀?    
    杩欎釜鐗堟湰鐩存帴浣跨敤 Qt 浜嬩欢杩囨护控制潵瀹炵幇 Alt+Q 鏄剧ず Hotbox锛?    閬垮厤 Maya hotkey 绯荤粺鐨勫悇绉嶅吋瀹规€ч棶棰樸€?    """
    if enabled is None:
        enabled = _adv_hotbox_altq_is_enabled(default=False)
    enabled = bool(enabled)

    prev_set = ''
    try:
        import maya.mel as mel
    except Exception:
        mel = None

    def _cur_set():
        try:
            s = cmds.hotkeySet(q=True, current=True) or ''
        except Exception:
            s = ''
        if (not s) and mel:
            try:
                s = mel.eval('hotkeySet -q -current;') or ''
            except Exception:
                s = ''
        try:
            return str(s) if s else ''
        except Exception:
            return ''

    def _set_set(name):
        if not name:
            return False
        if mel:
            try:
                mel.eval('catch(`hotkeySet -e -current "%s"`);' % str(name))
                return True
            except Exception:
                return False
        try:
            cmds.hotkeySet(e=True, current=str(name))
            return True
        except Exception:
            return False

    def _list_sets():
        try:
            return [str(s) for s in (cmds.hotkeySet(q=True, hotkeySetArray=True) or []) if s]
        except Exception:
            try:
                return [str(s) for s in (cmds.hotkeySet(q=True, hotkeySets=True) or []) if s]
            except Exception:
                return []

    def _ensure_set(name, source):
        if not name:
            return False
        name = str(name)
        source = str(source or 'Maya_Default')
        sets = _list_sets()
        if name in sets:
            return True
        if mel:
            try:
                mel.eval('catch(`hotkeySet -source "%s" "%s"`);' % (source, name))
            except Exception:
                pass
        try:
            sets2 = _list_sets()
            return name in sets2
        except Exception:
            return False

    # Cleanup stale filters from previous runs.
    try:
        _adv_purge_stale_toggle_pane_layout_filters()
    except Exception:
        pass

    if enabled:
        try:
            prev_set = _cur_set()
        except Exception:
            prev_set = ''
        try:
            if prev_set:
                cmds.optionVar(sv=('ADV_HotboxAltQPrevHotkeySet', str(prev_set)))
        except Exception:
            pass

        try:
            if str(prev_set) == 'Maya_Default':
                target = ''
                sets = _list_sets()
                for cand in ('ADV_PathMgr_HotkeySet', 'User_Custom', 'Maya_Default_Duplicate', 'ADV_FastSelect'):
                    if cand in sets and cand != 'Maya_Default':
                        target = cand
                        break
                if (not target) and _ensure_set('Maya_Default_Duplicate', 'Maya_Default'):
                    target = 'Maya_Default_Duplicate'
                if target:
                    _set_set(target)
        except Exception:
            pass
        try:
            _adv_ensure_adv_hotkey_set_current()
        except Exception:
            pass

        # ========== 启用模式：锛欰lt+Q = Hotbox, 空格� = 鎾斁 ==========

        # Legacy feature cleanup: the old "Space quad-view toggle" was removed.
        try:
            _adv_cleanup_removed_toggle_pane_layout_feature()
        except Exception:
            pass
        # Refresh keymap immediately.
        try:
            _adv_install_hotkey_fallback_filter(force=True)
        except Exception:
            pass
        
        try:
            import maya.mel as mel
            sp_n = mel.eval('hotkey -q -name -keyShortcut "space";') or ''
            sp_r = mel.eval('hotkey -q -releaseName -keyShortcut "space";') or ''
            cmds.optionVar(sv=('ADV_HotboxAltQPrevSpacePress', sp_n))
            cmds.optionVar(sv=('ADV_HotboxAltQPrevSpaceRelease', sp_r))
        except Exception:
            pass

        try:
            import maya.mel as mel
            aq_n = mel.eval('hotkey -q -name -alt -keyShortcut "q";') or ''
            aq_r = mel.eval('hotkey -q -releaseName -alt -keyShortcut "q";') or ''
            cmds.optionVar(sv=('ADV_HotboxAltQPrevAltQPress', aq_n))
            cmds.optionVar(sv=('ADV_HotboxAltQPrevAltQRelease', aq_r))
        except Exception:
            pass

        # ---------- 鍒涘缓鎾斁/停止的运行时鍛戒护 ----------
        try:
            if _adv_runtime_command_exists('ADV_PlayToggle'):
                cmds.runTimeCommand('ADV_PlayToggle', edit=True, delete=True)
            cmds.runTimeCommand(
                'ADV_PlayToggle',
                annotation='Toggle Playback',
                category='ADV Scripts',
                commandLanguage='mel',
                command='playButtonForward'
            )
            cmds.nameCommand(
                'ADV_PlayToggleNameCommand',
                annotation='Toggle Playback',
                command='ADV_PlayToggle',
                sourceType='mel'
            )
        except Exception as e:
            print('[ADV] Failed to create Play toggle runtime command: %s' % str(e))

        
        try:
            cmds.hotkey(keyShortcut='Space', name='', releaseName='')
        except Exception:
            pass

        # ---------- 缁戝畾空格�閿埌鎾斁 ----------
        try:
            cmds.hotkey(
                keyShortcut='Space',
                name='ADV_PlayToggleNameCommand'
            )
            print('[ADV] Space -> Play/Stop bound successfully')
        except Exception as e:
            print('[ADV] Failed to bind Space to Play: %s' % str(e))

        
        try:
            try:
                if _adv_runtime_command_exists('ADV_HotboxAltQ_Show'):
                    cmds.runTimeCommand('ADV_HotboxAltQ_Show', edit=True, delete=True)
            except Exception:
                pass
            try:
                if _adv_runtime_command_exists('ADV_HotboxAltQ_Hide'):
                    cmds.runTimeCommand('ADV_HotboxAltQ_Hide', edit=True, delete=True)
            except Exception:
                pass

            cmds.runTimeCommand(
                'ADV_HotboxAltQ_Show',
                annotation='Show Hotbox (Alt+Q)',
                category='ADV Scripts',
                commandLanguage='mel',
                command='hotBox;'
            )
            cmds.runTimeCommand(
                'ADV_HotboxAltQ_Hide',
                annotation='Hide Hotbox (Alt+Q)',
                category='ADV Scripts',
                commandLanguage='mel',
                command='hotBox -release;'
            )
            try:
                _adv_delete_command_ui_if_exists('ADV_HotboxAltQ_ShowNC')
                _adv_delete_command_ui_if_exists('ADV_HotboxAltQ_HideNC')
            except Exception:
                pass
            try:
                cmds.nameCommand('ADV_HotboxAltQ_ShowNC', annotation='Show Hotbox (Alt+Q)', command='ADV_HotboxAltQ_Show', sourceType='mel')
            except Exception:
                try:
                    cmds.nameCommand('ADV_HotboxAltQ_ShowNC', annotation='Show Hotbox (Alt+Q)', command='ADV_HotboxAltQ_Show')
                except Exception:
                    pass
            try:
                cmds.nameCommand('ADV_HotboxAltQ_HideNC', annotation='Hide Hotbox (Alt+Q)', command='ADV_HotboxAltQ_Hide', sourceType='mel')
            except Exception:
                try:
                    cmds.nameCommand('ADV_HotboxAltQ_HideNC', annotation='Hide Hotbox (Alt+Q)', command='ADV_HotboxAltQ_Hide')
                except Exception:
                    pass

            try:
                cmds.hotkey(k='q', name='', releaseName='', alt=True)
            except Exception:
                try:
                    cmds.hotkey(keyShortcut='q', name='', releaseName='', alt=True)
                except Exception:
                    pass
            try:
                cmds.hotkey(k='q', name='ADV_HotboxAltQ_ShowNC', releaseName='ADV_HotboxAltQ_HideNC', alt=True)
            except Exception:
                try:
                    cmds.hotkey(keyShortcut='q', name='ADV_HotboxAltQ_ShowNC', releaseName='ADV_HotboxAltQ_HideNC', alt=True)
                except Exception:
                    pass

            try:
                import maya.mel as mel
                ok = False
                try:
                    bound = mel.eval('hotkey -q -name -alt -keyShortcut "q";') or ''
                    ok = (str(bound) == 'ADV_HotboxAltQ_ShowNC')
                except Exception:
                    ok = False
                if not ok:
                    try:
                        mel.eval('hotkey -keyShortcut "q" -alt -name "" -releaseName "";')
                    except Exception:
                        pass
                    mel.eval('hotkey -keyShortcut "q" -alt -name "ADV_HotboxAltQ_ShowNC" -releaseName "ADV_HotboxAltQ_HideNC";')
            except Exception:
                pass
        except Exception:
            pass

        
        try:
            _adv_install_hotbox_altq_fallback_filter(force=True)
            print('[ADV] Alt+Q -> Hotbox installed via Qt filter')
        except Exception as e:
            print('[ADV] Failed to install Alt+Q filter: %s' % str(e))

        try:
            cmds.savePrefs(hotkeys=True)
        except Exception:
            pass

        print('[ADV] Hotkey switch applied: Alt+Q=Hotbox, Space=Play')

    else:
        try:
            prev_set = cmds.optionVar(q='ADV_HotboxAltQPrevHotkeySet') if cmds.optionVar(exists='ADV_HotboxAltQPrevHotkeySet') else ''
        except Exception:
            prev_set = ''
        # ========== 绂佺敤妯″紡锛氭仮澶嶉粯璁ゅ揩鎹烽敭 ==========
        
        # Remove Qt event filter fallback.
        try:
            _adv_remove_hotbox_altq_fallback_filter()
        except Exception:
            pass

        # 鎭㈠涔嬪墠淇濆瓨鐨勭┖鏍奸敭璁剧疆
        try:
            sp_n = cmds.optionVar(q='ADV_HotboxAltQPrevSpacePress') if cmds.optionVar(exists='ADV_HotboxAltQPrevSpacePress') else ''
            sp_r = cmds.optionVar(q='ADV_HotboxAltQPrevSpaceRelease') if cmds.optionVar(exists='ADV_HotboxAltQPrevSpaceRelease') else ''
            
            # Restore Space hotkey binding.
            if sp_n or sp_r:
                cmds.hotkey(keyShortcut='Space', name=sp_n or '', releaseName=sp_r or '')
            else:
                # 初始化全局快捷键鎭㈠ Maya 榛樿 Hotbox
                cmds.hotkey(keyShortcut='Space', name='ToolBox', releaseName='ToolBoxRelease')
        except Exception as e:
            print('[ADV] Failed to restore previous hotkeys: %s' % str(e))

        try:
            aq_n = cmds.optionVar(q='ADV_HotboxAltQPrevAltQPress') if cmds.optionVar(exists='ADV_HotboxAltQPrevAltQPress') else ''
            aq_r = cmds.optionVar(q='ADV_HotboxAltQPrevAltQRelease') if cmds.optionVar(exists='ADV_HotboxAltQPrevAltQRelease') else ''
            try:
                cmds.hotkey(k='q', name=aq_n or '', releaseName=aq_r or '', alt=True)
            except Exception:
                try:
                    cmds.hotkey(keyShortcut='q', name=aq_n or '', releaseName=aq_r or '', alt=True)
                except Exception:
                    pass
        except Exception:
            pass

        # Refresh fallback keymap.
        try:
            _adv_install_hotkey_fallback_filter(force=True)
        except Exception:
            pass

        try:
            cmds.savePrefs(hotkeys=True)
        except Exception:
            pass

        print('[ADV] Hotkeys restored to previous/default settings')

        try:
            if prev_set:
                _set_set(prev_set)
            else:
                _set_set('Maya_Default')
        except Exception:
            pass

    # Refresh UI states.
    try:
        update_main_window_labels()
    except Exception:
        pass
    try:
        update_hotkey_mapping_window_labels()
    except Exception:
        pass
    try:
        if cmds.checkBox("advHotboxAltQEnabledCB", exists=True):
            cmds.checkBox("advHotboxAltQEnabledCB", e=True, v=enabled)
    except Exception:
        pass


