def _adv_cleanup_removed_toggle_pane_layout_feature():
    """Remove legacy optionVars from the removed "Space quad-view toggle" feature."""
    keys = (
        'ADV_TogglePaneLayoutHotkey',
        'ADV_TogglePaneLayoutHotkey_Enabled',
        'ADV_TogglePaneLayout_ForceSpaceTap',
        'ADV_DebugTogglePaneLayout',
        'ADV_HotboxAltQPrevTogglePaneLayoutHotkey',
        'ADV_HotboxAltQPrevTogglePaneLayoutHotkey_Enabled',
    )
    for k in keys:
        try:
            if cmds.optionVar(exists=k):
                cmds.optionVar(remove=k)
        except Exception:
            pass


# Bump this string whenever we change hotbox/quad-toggle binding logic.
ADV_HOTBOX_ALTQ_BUILD = '2026-02-02-hotboxaltq-fallback-v2'


def adv_force_reload(path=''):
    """Force-reload this script into the adv_fast_select_runtime module.

    Useful in Maya where import caching often keeps an older module instance alive.
    Returns the reloaded module.
    """
    try:
        import importlib.util as iu
        import sys
        import os
        p = str(path or '').strip()
        if not p:
            try:
                if cmds.optionVar(exists='ADV_FastSelectScriptPath'):
                    p = cmds.optionVar(q='ADV_FastSelectScriptPath') or ''
            except Exception:
                p = ''
        if p and os.path.isdir(p):
            p = os.path.join(p, 'ADV蹇选择夋嫨鐖跺瓙.py')
        if not (p and os.path.isfile(p)):
            try:
                cmds.warning('[ADV] adv_force_reload failed: invalid path: %s' % str(p))
            except Exception:
                pass
            return sys.modules.get('adv_fast_select_runtime')

        mn = 'adv_fast_select_runtime'
        spec = iu.spec_from_file_location(mn, p)
        m = iu.module_from_spec(spec)

        # IMPORTANT: register in sys.modules BEFORE executing.
        # Some dependencies (notably shiboken2's __feature__) may try to import the
        # caller module by name during import-time; if we only register after exec,
        # reload can fail with ModuleNotFoundError.
        old_m = sys.modules.get(mn)
        sys.modules[mn] = m
        try:
            spec.loader.exec_module(m)
        except Exception:
            # Restore previous module on failure.
            if old_m is not None:
                sys.modules[mn] = old_m
            else:
                try:
                    del sys.modules[mn]
                except Exception:
                    pass
            raise
        try:
            print('[ADV] adv_force_reload OK:', getattr(m, '__file__', None))
            print('[ADV] build =', getattr(m, 'ADV_HOTBOX_ALTQ_BUILD', '<missing>'))
        except Exception:
            pass
        return m
    except Exception as e:
        try:
            cmds.warning('[ADV] adv_force_reload failed: %s' % str(e))
        except Exception:
            pass
        try:
            import sys
            return sys.modules.get('adv_fast_select_runtime')
        except Exception:
            return None


def adv_hotbox_altq_diagnose(try_fix=False):
    """Diagnostics for the HotboxAltQ swap.

    Prints current bindings and checks whether Maya accepted the hotkey override.
    If try_fix=True, will attempt to switch to a writable hotkeySet and re-apply.
    """
    import maya.mel as mel

    def _safe_eval(s):
        try:
            return mel.eval(s)
        except Exception as e:
            return '<ERR: %s>' % str(e)

    def _hk_query(key_shortcut, alt=False):
        try:
            if alt:
                n = _safe_eval('hotkey -q -name -alt -keyShortcut "%s";' % str(key_shortcut)) or ''
                r = _safe_eval('hotkey -q -releaseName -alt -keyShortcut "%s";' % str(key_shortcut)) or ''
            else:
                n = _safe_eval('hotkey -q -name -keyShortcut "%s";' % str(key_shortcut)) or ''
                r = _safe_eval('hotkey -q -releaseName -keyShortcut "%s";' % str(key_shortcut)) or ''
            return (str(n), str(r))
        except Exception as e:
            return ('<ERR: %s>' % str(e), '<ERR>')

    print('--- [ADV] HotboxAltQ diagnostics ---')
    try:
        print('module file =', __file__)
    except Exception:
        pass
    try:
        print('build       =', ADV_HOTBOX_ALTQ_BUILD)
    except Exception:
        pass
    try:
        en = bool(int(cmds.optionVar(q='ADV_HotboxAltQEnabled'))) if cmds.optionVar(exists='ADV_HotboxAltQEnabled') else False
    except Exception:
        en = False
    print('enabled(optionVar ADV_HotboxAltQEnabled) =', en)

    cur_set_cmds = ''
    try:
        cur_set_cmds = cmds.hotkeySet(q=True, current=True) or ''
    except Exception:
        cur_set_cmds = ''
    cur_set_mel = _safe_eval('hotkeySet -q -current;') or ''
    print('current hotkeySet(cmds) =', cur_set_cmds)
    print('current hotkeySet(mel ) =', cur_set_mel)

    sp_n, sp_r = _hk_query('space', alt=False)
    aq_n, aq_r = _hk_query('q', alt=True)
    print('Space press  =', sp_n)
    print('Space release=', sp_r)
    print('Alt+Q press  =', aq_n)
    print('Alt+Q release=', aq_r)

    try:
        print('fallback filter active =', bool(_ADV_HOTBOX_ALTQ_FILTER is not None))
    except Exception:
        pass

    if try_fix:
        print('--- [ADV] HotboxAltQ try_fix=True ---')
        try:
            new_set = _adv_ensure_adv_hotkey_set_current()
            print('switched hotkeySet ->', new_set)
        except Exception as e:
            print('switch hotkeySet failed:', e)
        try:
            _adv_apply_hotbox_altq_enabled_state(enabled=en)
        except Exception as e:
            print('re-apply failed:', e)
        aq_n2, aq_r2 = _hk_query('q', alt=True)
        print('Alt+Q press(after)  =', aq_n2)
        print('Alt+Q release(after)=', aq_r2)

    print('--- [ADV] HotboxAltQ diagnostics end ---')


def _ensure_self_path_optionvar():
    """Persist this script path so hotkeys can find it after Maya restart."""
    try:
        p = ''
        try:
            p = os.path.abspath(__file__)
        except Exception:
            p = ''

        # Some loaders (exec/open/read) may not populate __file__.
        if not p:
            try:
                import inspect
                p = inspect.getsourcefile(_ensure_self_path_optionvar) or inspect.getfile(_ensure_self_path_optionvar) or ''
            except Exception:
                p = ''

        if not p:
            try:
                import sys
                m = sys.modules.get(__name__)
                p = os.path.abspath(getattr(m, '__file__', '') or '')
            except Exception:
                p = ''

        # Some loaders may set __file__ to a directory; normalize to this .py.
        if p and os.path.isdir(p):
            p = os.path.join(p, 'ADV蹇选择夋嫨鐖跺瓙.py')
        if p:
            cmds.optionVar(stringValue=("ADV_FastSelectScriptPath", p))
    except Exception:
        pass


def _adv_hotkey_python_call_code(func_name, args_src=None):
    fn = str(func_name or '').strip()
    if not fn:
        return ''
    if not fn.replace('_', '').isalnum():
        return ''

    args_src = list(args_src or [])
    arg_tuple = '(%s%s)' % (', '.join(args_src), ',' if len(args_src) == 1 else '')

    return (
        "import maya.cmds as cmds\n"
        "import maya.mel as mel\n"
        "import sys, os\n"
        "mn='adv_fast_select_runtime'\n"
        "fn=%r\n"
        "args=%s\n"
        "def _pick_main_py(d):\n"
        "    try:\n"
        "        preferred=[u'ADV\u5feb\u901f\u9009\u62e9\u7236\u5b50.py','ADV_fast_select.py']\n"
        "        for nm in preferred:\n"
        "            p=os.path.join(d,nm)\n"
        "            if os.path.isfile(p):\n"
        "                return p\n"
        "        files=[]\n"
        "        for f in os.listdir(d):\n"
        "            fl=f.lower()\n"
        "            if not fl.endswith('.py'):\n"
        "                continue\n"
        "            if (u'\u526f\u672c' in f) or ('backup' in fl) or ('.bak' in fl):\n"
        "                continue\n"
        "            p=os.path.join(d,f)\n"
        "            if os.path.isfile(p):\n"
        "                files.append(p)\n"
        "        if not files:\n"
        "            return ''\n"
        "        files.sort(key=lambda p: (os.path.getsize(p), p))\n"
        "        return files[-1]\n"
        "    except Exception:\n"
        "        return ''\n"
        "def _find_script_path():\n"
        "    p=''\n"
        "    try:\n"
        "        if cmds.optionVar(exists='ADV_FastSelectScriptPath'):\n"
        "            p=cmds.optionVar(q='ADV_FastSelectScriptPath') or ''\n"
        "    except Exception:\n"
        "        p=''\n"
        "    try:\n"
        "        if p and os.path.isfile(p):\n"
        "            return p\n"
        "    except Exception:\n"
        "        pass\n"
        "    d=''\n"
        "    try:\n"
        "        if p and os.path.isdir(p):\n"
        "            d=p\n"
        "        elif p and os.path.isfile(p):\n"
        "            d=os.path.dirname(p)\n"
        "    except Exception:\n"
        "        d=''\n"
        "    if not d:\n"
        "        try:\n"
        "            base=cmds.internalVar(userAppDir=True)\n"
        "            d=os.path.join(base,'scripts','ADV Fast select')\n"
        "        except Exception:\n"
        "            d=''\n"
        "    if d and os.path.isdir(d):\n"
        "        s=_pick_main_py(d)\n"
        "        if s:\n"
        "            return s\n"
        "    return p if (p and os.path.isfile(p)) else ''\n"
        "p=_find_script_path()\n"
        "m=sys.modules.get(mn)\n"
        "need_reload=False\n"
        "try:\n"
        "    need_reload = (not m) or (p and getattr(m,'__file__',None)!=p)\n"
        "except Exception:\n"
        "    need_reload=True\n"
        "if need_reload and p and os.path.isfile(p):\n"
        "    try:\n"
        "        import importlib.util as iu\n"
        "    except Exception:\n"
        "        iu=None\n"
        "    if iu is not None:\n"
        "        spec=iu.spec_from_file_location(mn,p)\n"
        "        m=iu.module_from_spec(spec)\n"
        "        # Register before exec_module to avoid shiboken2 __feature__ reload issues\n"
        "        try:\n"
        "            sys.modules[mn]=m\n"
        "        except Exception:\n"
        "            pass\n"
        "        spec.loader.exec_module(m)\n"
        "    else:\n"
        "        import imp\n"
        "        m=imp.load_source(mn,p)\n"
        "    sys.modules[mn]=m\n"
        "m=sys.modules.get(mn)\n"
        "if m and hasattr(m,fn):\n"
        "    getattr(m,fn)(*args)\n"
        "else:\n"
        "    # Keep SetKey usable even if the tool cannot be resolved/loaded.\n"
        "    _handled=False\n"
        "    if fn == 'adv_set_key':\n"
        "        try:\n"
        "            mel.eval('SetKey;')\n"
        "            _handled=True\n"
        "        except Exception:\n"
        "            _handled=False\n"
        "    if not _handled:\n"
        "        try:\n"
        "            cmds.warning('ADV: runtime module not available')\n"
        "        except Exception:\n"
        "            pass\n"
    ) % (fn, arg_tuple)


def _reset_layer_hotkey_command_mel():
    """Return a MEL command string for nameCommand that runs reset_layer_animation via Python.

    NOTE: This string is meant to be embedded inside a MEL double-quoted argument:
      nameCommand ... -command "<THIS>" ...
    So it must NOT contain raw double quotes; use python(\"...\").
    """
    # Maya 2018 (Python 2.7) executes this source without an encoding cookie.
    # Use the shared ASCII-only loader/caller.
    py = _adv_hotkey_python_call_code('reset_layer_animation')
    py_escaped = py.replace('\\', '\\\\').replace('"', '\\"')
    return 'python(\\"%s\\")' % py_escaped

    py = (
        "import maya.cmds as cmds;import importlib.util,sys,os;"
        "p='';"
        "p=(cmds.optionVar(q='ADV_FastSelectScriptPath') if cmds.optionVar(exists='ADV_FastSelectScriptPath') else '');"
        "p=os.path.join(p,'ADV蹇选择夋嫨鐖跺瓙.py') if (p and os.path.isdir(p)) else p;"
        "base=cmds.internalVar(userAppDir=True);"
        "cand=os.path.join(base,'scripts','ADV Fast select','ADV蹇选择夋嫨鐖跺瓙.py');"
        "p=(p if (p and os.path.isfile(p)) else (cand if os.path.isfile(cand) else ''));"
        "mn='adv_fast_select_runtime';"
        "m=sys.modules.get(mn);"
        "(m.reset_layer_animation() if (m and getattr(m,'__file__',None)==p) else (lambda: (lambda s: (s.loader.exec_module((lambda mm: (sys.modules.__setitem__(mn,mm),mm)[1])(importlib.util.module_from_spec(s))), sys.modules[mn].reset_layer_animation()))(importlib.util.spec_from_file_location(mn,p)) )() ) ) if (p and os.path.isfile(p)) else cmds.warning('ADV: Script path not found. Open ADV Fast Select window first.');"
    )
    # Escape for MEL: backslashes + double quotes
    py_escaped = py.replace('\\', '\\\\').replace('"', '\\"')
    return 'python(\\"%s\\")' % py_escaped


def _view_hotkey_command_mel(view_name):
    """Return the MEL command that calls Python adv_view_set for the given view."""
    py = _adv_hotkey_python_call_code('adv_view_set', args_src=[repr(str(view_name).lower())])
    py_escaped = py.replace('\\', '\\\\').replace('"', '\\"')
    return 'python(\"%s\")' % py_escaped

    py = (
        "import maya.cmds as cmds;import importlib.util,sys,os;"
        "p=(cmds.optionVar(q='ADV_FastSelectScriptPath') if cmds.optionVar(exists='ADV_FastSelectScriptPath') else '');"
        "p=os.path.join(p,'ADV蹇选择夋嫨鐖跺瓙.py') if (p and os.path.isdir(p)) else p;"
        "base=cmds.internalVar(userAppDir=True);"
        "cand=os.path.join(base,'scripts','ADV Fast select','ADV蹇选择夋嫨鐖跺瓙.py');"
        "p=(p if (p and os.path.isfile(p)) else (cand if os.path.isfile(cand) else ''));"
        "spec=(importlib.util.spec_from_file_location('adv_fast_select_runtime', p) if p else None);"
        "mod=(importlib.util.module_from_spec(spec) if spec else None);"
        "spec and spec.loader.exec_module(mod);"
        "mod and mod.adv_view_set('%s');"
    ) % (view_name.lower(),)
