def _adv_call_self_function_hotkey_command_mel(func_name):
    """Return a MEL command string for nameCommand that runs a function in this script via Python."""
    py = _adv_hotkey_python_call_code(func_name)
    py_escaped = py.replace('\\', '\\\\').replace('"', '\\"')
    return 'python(\\"%s\\")' % py_escaped

    py = (
        "import maya.cmds as cmds;import importlib.util,sys,os;"
        "p='';"
        "p=(cmds.optionVar(q='ADV_FastSelectScriptPath') if cmds.optionVar(exists='ADV_FastSelectScriptPath') else '');"
        "p=os.path.join(p,'ADV蹇选择夋嫨鐖跺瓙.py') if (p and os.path.isdir(p)) else p;"
        "base=cmds.internalVar(userAppDir=True);"
        "cand=os.path.join(base,'scripts','ADV Fast select','ADV蹇选择夋嫨鐖跺瓙.py');"
        "p=(p if (p and os.path.isfile(p)) else (cand if os.path.isfile(cand) else ''));"
        "mn='adv_fast_select_runtime';"
        "m=sys.modules.get(mn);"
        "(getattr(m,'%s')() if (m and hasattr(m,'%s')) else ((lambda: (lambda s: (s.loader.exec_module((lambda mm: (sys.modules.__setitem__(mn,mm),mm)[1])(importlib.util.module_from_spec(s))), getattr(sys.modules[mn],'%s')()))(importlib.util.spec_from_file_location(mn,p)) )() )() if (p and os.path.isfile(p)) else cmds.warning('ADV: Script path not found. Open ADV Fast Select window first.');"
    ) % (func_name, func_name, func_name)
    py_escaped = py.replace('\\', '\\\\').replace('"', '\\"')
    return 'python(\\"%s\\")' % py_escaped


def _adv_call_self_function_hotkey_command_py(func_name):
    """Return a Python command body for a runTimeCommand that calls a function in this script.

    This avoids MEL python("...") quoting issues and keeps the 6 new actions purely in Python.
    """
    fn = str(func_name or '').strip()
    if not fn:
        return ''

    return _adv_hotkey_python_call_code(fn)

    # Keep it as a single Python string (runTimeCommand stores a string).
    # Use the same path resolution strategy as the MEL hotkey wrapper.
    return (
        "import maya.cmds as cmds\n"
        "import maya.mel as mel\n"
        "import importlib.util, sys, os, traceback\n"
        "def __adv_call__():\n"
        "    p = ''\n"
        "    try:\n"
        "        if cmds.optionVar(exists='ADV_FastSelectScriptPath'):\n"
        "            p = cmds.optionVar(q='ADV_FastSelectScriptPath') or ''\n"
        "    except Exception:\n"
        "        p = ''\n"
        "    try:\n"
        "        if p and os.path.isdir(p):\n"
        "            p = os.path.join(p, 'ADV蹇选择夋嫨鐖跺瓙.py')\n"
        "    except Exception:\n"
        "        pass\n"
        "    try:\n"
        "        base = cmds.internalVar(userAppDir=True)\n"
        "        cand = os.path.join(base, 'scripts', 'ADV Fast select', 'ADV蹇选择夋嫨鐖跺瓙.py')\n"
        "        if (not p) or (not os.path.isfile(p)):\n"
        "            p = cand if os.path.isfile(cand) else ''\n"
        "    except Exception:\n"
        "        pass\n"
        "    if (not p) or (not os.path.isfile(p)):\n"
        "        try:\n"
        "            cmds.warning('ADV: 找不到脚本路径，请先打开ADV_extension窗口一次?)\n"
        "        except Exception:\n"
        "            pass\n"
        "        return\n"
        "\n"
        "    mn = 'adv_fast_select_runtime'\n"
        "    target_fn = '%s'\n"
        "\n"
        "    def __load_module__():\n"
        "        try:\n"
        "            if mn in sys.modules:\n"
        "                try:\n"
        "                    del sys.modules[mn]\n"
        "                except Exception:\n"
        "                    pass\n"
        "            spec = importlib.util.spec_from_file_location(mn, p)\n"
        "            mm = importlib.util.module_from_spec(spec)\n"
        "            sys.modules[mn] = mm\n"
        "            spec.loader.exec_module(mm)\n"
        "            return mm\n"
        "        except Exception:\n"
        "            try:\n"
        "                cmds.warning('ADV: Script path invalid (see Script Editor): ' + str(p))\n"
        "            except Exception:\n"
        "                pass\n"
        "            try:\n"
        "                traceback.print_exc()\n"
        "            except Exception:\n"
        "                pass\n"
        "            return sys.modules.get(mn)\n"
        "\n"
        "    m = sys.modules.get(mn)\n"
        "    try:\n"
        "        if (m is None) or (getattr(m, '__file__', None) != p) or (not hasattr(m, target_fn)):\n"
        "            m = __load_module__()\n"
        "    except Exception:\n"
        "        m = __load_module__()\n"
        "\n"
        "    try:\n"
        "        f = getattr(m, target_fn, None)\n"
        "        if callable(f):\n"
        "            f()\n"
        "            return\n"
        "    except Exception:\n"
        "        try:\n"
        "            traceback.print_exc()\n"
        "        except Exception:\n"
        "            pass\n"
        "\n"
        "    # Fallback: keep hotkey usable even if module load failed or func missing\n"
        "    try:\n"
        "        cmds.warning('ADV: Function not found: ' + str(target_fn) + ' (script: ' + str(p) + ')\n"
        "    except Exception:\n"
        "        pass\n"
        "    try:\n"
        "        if target_fn == 'adv_set_key':\n"
        "            mel.eval('SetKey;')\n"
        "    except Exception:\n"
        "        pass\n"
        "\n"
        "__adv_call__()\n"
    ) % (fn,)


