def adv_tr_zero():
    sel = cmds.ls(sl=True) or []
    if not sel:
        return
    # If Channel Box attrs are selected, zero only those attrs.
    selected_attrs = _adv_sync_channelbox_selected_attrs()
    if selected_attrs:
        for obj in sel:
            for attr in selected_attrs:
                plug = '%s.%s' % (obj, attr)
                try:
                    if not cmds.objExists(plug):
                        continue
                    if cmds.getAttr(plug, lock=True):
                        continue
                    if cmds.getAttr(plug, settable=True):
                        cmds.setAttr(plug, 0)
                except Exception:
                    pass
        return
    for obj in sel:
        for attr in ('tx', 'ty', 'tz'):
            plug = '%s.%s' % (obj, attr)
            try:
                if cmds.getAttr(plug, lock=True):
                    continue
                if cmds.getAttr(plug, settable=True):
                    cmds.setAttr(plug, 0)
            except Exception:
                pass


