def adv_prev_frame():
    try:
        t = cmds.currentTime(q=True)
    except Exception:
        return
    try:
        cmds.currentTime(t - 1, e=True, update=True)
    except Exception:
        try:
            cmds.currentTime(t - 1, e=True)
        except Exception:
            pass


def adv_next_frame():
    try:
        t = cmds.currentTime(q=True)
    except Exception:
        return
    try:
        cmds.currentTime(t + 1, e=True, update=True)
    except Exception:
        try:
            cmds.currentTime(t + 1, e=True)
        except Exception:
            pass


def _adv_timeline_min_max():
    """Return (min, max) of the time slider as floats."""
    try:
        mn = float(cmds.playbackOptions(q=True, min=True))
        mx = float(cmds.playbackOptions(q=True, max=True))
        if mn > mx:
            mn, mx = mx, mn
        return mn, mx
    except Exception:
        return None, None


def _adv_set_time_safe(t):
    try:
        cmds.currentTime(t, e=True, update=True)
    except Exception:
        try:
            cmds.currentTime(t, e=True)
        except Exception:
            pass


def adv_prev_keyframe():
    """Prev keyframe with wrap-around at timeline start."""
    try:
        cur = float(cmds.currentTime(q=True))
    except Exception:
        cur = None
    mn, mx = _adv_timeline_min_max()

    # Wrap at timeline start (0 -> 100 style)
    if (cur is not None) and (mn is not None) and (mx is not None):
        if cur <= (mn + 1e-6):
            _adv_set_time_safe(mx)
            return

    try:
        t = cmds.findKeyframe(which='previous')
    except Exception:
        t = None

    if t is None:
        # No previous key found -> wrap
        if mx is not None:
            _adv_set_time_safe(mx)
        return

    try:
        t = float(t)
    except Exception:
        pass

    # If Maya returns current time (no movement), also wrap.
    if (cur is not None) and (isinstance(t, (int, float))) and abs(float(t) - float(cur)) <= 1e-6:
        if mx is not None:
            _adv_set_time_safe(mx)
        return

    _adv_set_time_safe(t)


def adv_next_keyframe():
    """Next keyframe with wrap-around at timeline end."""
    try:
        cur = float(cmds.currentTime(q=True))
    except Exception:
        cur = None
    mn, mx = _adv_timeline_min_max()

    # Wrap at timeline end (100 -> 0 style)
    if (cur is not None) and (mn is not None) and (mx is not None):
        if cur >= (mx - 1e-6):
            _adv_set_time_safe(mn)
            return

    try:
        t = cmds.findKeyframe(which='next')
    except Exception:
        t = None

    if t is None:
        # No next key found -> wrap
        if mn is not None:
            _adv_set_time_safe(mn)
        return

    try:
        t = float(t)
    except Exception:
        pass

    if (cur is not None) and (isinstance(t, (int, float))) and abs(float(t) - float(cur)) <= 1e-6:
        if mn is not None:
            _adv_set_time_safe(mn)
        return

    _adv_set_time_safe(t)


def adv_focus_object():
    """Focus on selected object(s) - equivalent to Maya's 'F' key."""
    try:
        mel.eval('FrameSelectedWithoutChildren;')
    except Exception:
        try:
            mel.eval('fitPanel -selected;')
        except Exception:
            try:
                cmds.viewFit(animate=True)
            except Exception:
                pass


def _adv_get_hover_or_active_model_panel():
    """Prefer modelPanel under cursor, else focused/visible modelPanel."""
    try:
        p = _adv_get_last_hover_model_panel(max_age=1.0)
        if p:
            return p
    except Exception:
        pass
    try:
        p = cmds.getPanel(underPointer=True)
        if p and cmds.getPanel(typeOf=p) == 'modelPanel':
            return p
    except Exception:
        pass
    try:
        p = _adv_get_model_panel_under_cursor_qt()
        if p:
            return p
    except Exception:
        pass
    try:
        p = _adv_get_model_panel_under_cursor_geometry()
        if p:
            return p
    except Exception:
        pass
    return _adv_get_active_model_panel()


def _adv_get_model_panel_under_cursor_geometry():
    """Geometry-based hover detection for modelPanel.

    This is a robust fallback when:
    - cmds.getPanel(underPointer=True) reports a non-viewport panel
    - Qt widgetAt(cursor) hits an overlay (HUD/labels) that has no Maya control name

    We map each modelPanel control's global rect and test whether the current cursor
    position falls inside.
    """
    try:
        try:
            from PySide2 import QtCore, QtWidgets, QtGui
        except ImportError:
            from PySide6 import QtCore, QtWidgets, QtGui  # type: ignore
        import shiboken2
        from maya import OpenMayaUI as omui
    except ImportError:
        return None

    app = None
    try:
        app = QtWidgets.QApplication.instance()
    except Exception:
        app = None
    if not app:
        return None

    try:
        gp = QtGui.QCursor.pos()
    except Exception:
        return None

    try:
        panels = cmds.getPanel(type='modelPanel') or []
    except Exception:
        panels = []
    if not panels:
        return None

    # Prefer visible panels.
    visible = []
    for p in panels:
        try:
            if cmds.modelPanel(p, q=True, visible=True):
                visible.append(p)
        except Exception:
            continue
    if visible:
        panels = visible

    best = None
    best_area = None
    for p in panels:
        try:
            ctrl = cmds.modelPanel(p, q=True, control=True) or ''
        except Exception:
            ctrl = ''
        if not ctrl:
            continue
        try:
            ptr = omui.MQtUtil.findControl(ctrl)
        except Exception:
            ptr = None
        if not ptr:
            continue
        try:
            w = shiboken2.wrapInstance(int(ptr), QtWidgets.QWidget)
        except Exception:
            w = None
        if w is None:
            continue
        try:
            r = w.rect()
            tl = w.mapToGlobal(r.topLeft())
            br = w.mapToGlobal(r.bottomRight())
            gr = QtCore.QRect(tl, br)
        except Exception:
            continue
        try:
            if not gr.contains(gp):
                continue
        except Exception:
            continue

        # If multiple rects contain the point, pick the smallest (deepest) one.
        try:
            area = int(gr.width()) * int(gr.height())
        except Exception:
            area = None
        if best is None:
            best = p
            best_area = area
        else:
            try:
                if area is not None and (best_area is None or area < best_area):
                    best = p
                    best_area = area
            except Exception:
                pass

    return best


def _adv_get_model_panel_under_cursor_qt():
    """Qt-based hover detection for modelPanel.

    cmds.getPanel(underPointer=True) sometimes fails when overlays/widgets sit on top of the viewport.
    This uses QWidget under cursor and maps it back to a modelPanel via its control name.
    """
    try:
        try:
            from PySide2 import QtWidgets, QtGui
        except ImportError:
            from PySide6 import QtWidgets, QtGui  # type: ignore
        import shiboken2
        from maya import OpenMayaUI as omui
    except ImportError:
        return None

    app = None
    try:
        app = QtWidgets.QApplication.instance()
    except Exception:
        app = None
    if not app:
        return None

    # Build controlName -> modelPanel mapping.
    mp = []
    try:
        mp = cmds.getPanel(type='modelPanel') or []
    except Exception:
        mp = []
    ctrl_to_panel = {}
    for p in mp:
        try:
            c = cmds.modelPanel(p, q=True, control=True) or ''
        except Exception:
            c = ''
        if c:
            ctrl_to_panel[str(c)] = str(p)

    if not ctrl_to_panel:
        return None

    w = None
    try:
        w = QtWidgets.QApplication.widgetAt(QtGui.QCursor.pos())
    except Exception:
        w = None
    if w is None:
        return None

    def _try_resolve_from_control_name(ui_name):
        ui_name = str(ui_name or '').strip()
        if not ui_name:
            return None
        # Sometimes we get a full path; try both the full and its root.
        candidates = [ui_name]
        if '|' in ui_name:
            candidates.append(ui_name.split('|', 1)[0])
        for nm in candidates:
            nm = str(nm or '').strip()
            if not nm:
                continue
            # If nm itself is a modelPanel, return it.
            try:
                if cmds.getPanel(typeOf=nm) == 'modelPanel':
                    return nm
            except Exception:
                pass
            # If nm is a known modelPanel control, map it.
            if nm in ctrl_to_panel:
                return ctrl_to_panel.get(nm)
            # Ask Maya which panel contains this control.
            try:
                p = cmds.getPanel(containing=nm) or ''
            except Exception:
                p = ''
            if p:
                try:
                    if cmds.getPanel(typeOf=p) == 'modelPanel':
                        return p
                except Exception:
                    pass
        return None

    # Walk up parents and try multiple ways to map Qt widget -> Maya control -> modelPanel.
    cur = w
    for _ in range(40):
        # 1) Direct widgetToName mapping (most reliable when objectName is empty).
        try:
            ptr = shiboken2.getCppPointer(cur)[0]
            ui_name = omui.MQtUtil.widgetToName(int(ptr)) or ''
        except Exception:
            ui_name = ''
        p = _try_resolve_from_control_name(ui_name)
        if p:
            return p

        # 2) Fallback to Qt objectName.
        try:
            obj_name = cur.objectName() or ''
        except Exception:
            obj_name = ''
        p = _try_resolve_from_control_name(obj_name)
        if p:
            return p

        try:
            cur = cur.parentWidget()
        except Exception:
            cur = None
        if cur is None:
            break

    return None


def adv_debug_cursor_panel():
    """Debug what's under the cursor for quad-toggle targeting.

    Useful when cmds.getPanel(underPointer=True) reports a non-viewport panel.
    """
    try:
        import maya.cmds as cmds
        from PySide2 import QtWidgets, QtGui
        import shiboken2
        from maya import OpenMayaUI as omui
    except Exception as e:
        try:
            print('[ADV][cursor] imports failed:', e)
        except Exception:
            pass
        return

    try:
        up = cmds.getPanel(underPointer=True) or ''
    except Exception:
        up = ''
    try:
        fp = cmds.getPanel(withFocus=True) or ''
    except Exception:
        fp = ''

    w = None
    try:
        w = QtWidgets.QApplication.widgetAt(QtGui.QCursor.pos())
    except Exception:
        w = None

    try:
        print('[ADV][cursor] underPointer=', up, ' type=', (cmds.getPanel(typeOf=up) if up else ''))
        print('[ADV][cursor] withFocus   =', fp, ' type=', (cmds.getPanel(typeOf=fp) if fp else ''))
    except Exception:
        pass

    if w is None:
        try:
            print('[ADV][cursor] Qt widgetAt=None')
        except Exception:
            pass
        return

    try:
        cls = w.__class__.__name__
    except Exception:
        cls = '<unknown>'
    try:
        obj = w.objectName() or ''
    except Exception:
        obj = ''
    try:
        ptr = shiboken2.getCppPointer(w)[0]
        ui = omui.MQtUtil.widgetToName(int(ptr)) or ''
    except Exception:
        ui = ''
    try:
        qt_panel = _adv_get_model_panel_under_cursor_qt() or ''
    except Exception:
        qt_panel = ''

    try:
        print('[ADV][cursor] Qt widget=', cls, ' objectName=', obj)
        print('[ADV][cursor] widgetToName=', ui)
        print('[ADV][cursor] qtHover modelPanel=', qt_panel)
    except Exception:
        pass

    # Walk a few parents so we can see if any ancestor maps to a Maya control/panel.
    try:
        cur = w
        for i in range(12):
            try:
                cls_i = cur.__class__.__name__
            except Exception:
                cls_i = '<unknown>'
            try:
                obj_i = cur.objectName() or ''
            except Exception:
                obj_i = ''
            try:
                ptr_i = shiboken2.getCppPointer(cur)[0]
                ui_i = omui.MQtUtil.widgetToName(int(ptr_i)) or ''
            except Exception:
                ui_i = ''
            try:
                containing = cmds.getPanel(containing=str(ui_i)) if ui_i else ''
            except Exception:
                containing = ''
            try:
                print('[ADV][cursor] parent[%d] %s obj=%s ui=%s containing=%s' % (i, cls_i, obj_i, ui_i, containing))
            except Exception:
                pass
            try:
                cur = cur.parentWidget()
            except Exception:
                cur = None
            if cur is None:
                break
    except Exception:
        pass


def adv_debug_cursor_panel_delayed(delay_ms=800):
    """Run adv_debug_cursor_panel() after a delay.

    Use this when testing from Script Editor: run the command, then move the mouse over
    the viewport before the timer fires.
    """
    try:
        ms = int(max(0, int(delay_ms)))
    except Exception:
        ms = 800
    try:
        from PySide2 import QtCore
    except ImportError:
        try:
            from PySide6 import QtCore  # type: ignore
        except ImportError:
            QtCore = None
    if QtCore is None:
        # Fallback: immediate.
        adv_debug_cursor_panel()
        return

    def _run():
        try:
            print('[ADV][cursor] --- delayed sample ---')
        except Exception:
            pass
        adv_debug_cursor_panel()

    try:
        QtCore.QTimer.singleShot(ms, _run)
        try:
            print('[ADV][cursor] will sample in %d ms (move mouse over viewport now)' % ms)
        except Exception:
            pass
    except Exception:
        adv_debug_cursor_panel()


def adv_toggle_wireframe_on_shaded():
    """Toggle Wireframe on Shaded (overlay)."""
    p = _adv_get_hover_or_active_model_panel()
    if not p:
        return
    try:
        ed = cmds.modelPanel(p, q=True, modelEditor=True)
    except Exception:
        ed = None
    if not ed:
        return
    try:
        cur = bool(cmds.modelEditor(ed, q=True, wireframeOnShaded=True))
    except Exception:
        cur = False
    try:
        cmds.modelEditor(ed, e=True, wireframeOnShaded=(not cur))
    except Exception:
        pass


def adv_toggle_uv_wireframe_textured():
    """Toggle between Wireframe (Maya hotkey 4) and Textured (Maya hotkey 6).

    Desired behavior:
    - If currently in wireframe mode -> switch to textured display.
    - Otherwise -> switch to wireframe mode.
    """
    p = _adv_get_hover_or_active_model_panel()
    if not p:
        return
    try:
        ed = cmds.modelPanel(p, q=True, modelEditor=True)
    except Exception:
        ed = None
    if not ed:
        return

    try:
        appearance = cmds.modelEditor(ed, q=True, displayAppearance=True)
    except Exception:
        appearance = ''
    appearance = str(appearance or '')

    if appearance.lower() == 'wireframe':
        # Go to textured (similar to key 6)
        try:
            cmds.modelEditor(ed, e=True, displayAppearance='smoothShaded')
        except Exception:
            pass
        try:
            cmds.modelEditor(ed, e=True, displayTextures=True)
        except Exception:
            pass
    else:
        # Go to wireframe (similar to key 4)
        try:
            cmds.modelEditor(ed, e=True, displayAppearance='wireframe')
        except Exception:
            pass


def adv_set_key():
    """Set Key (same as Maya default 'S').

    If ADV key-sync hotkey is enabled, use the intercept path so groups sync too.
    """
    try:
        if cmds.optionVar(exists=ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR) and bool(cmds.optionVar(q=ADV_SYNC_HOTKEY_ENABLED_OPTIONVAR)):
            try:
                adv_sync_set_key_intercept()
                return
            except Exception:
                pass
    except Exception:
        pass
    try:
        mel.eval('SetKey;')
    except Exception:
        try:
            mel.eval('SetKey')
        except Exception:
            pass


def _adv_get_active_model_panel():
    """Best-effort: return the focused modelPanel, else any visible modelPanel."""
    try:
        p = cmds.getPanel(withFocus=True)
        if p and cmds.getPanel(typeOf=p) == 'modelPanel':
            return p
    except Exception:
        pass
    try:
        for p in (cmds.getPanel(type='modelPanel') or []):
            try:
                if cmds.modelPanel(p, q=True, visible=True):
                    return p
            except Exception:
                continue
    except Exception:
        pass
    try:
        panels = cmds.getPanel(type='modelPanel') or []
        return panels[0] if panels else None
    except Exception:
        return None


def adv_toggle_joints():
    p = _adv_get_active_model_panel()
    if not p:
        return
    try:
        cur = cmds.modelEditor(p, q=True, joints=True)
        cmds.modelEditor(p, e=True, joints=(0 if cur else 1))
    except Exception:
        pass


def adv_toggle_meshes():
    p = _adv_get_active_model_panel()
