def _adv_get_time_slider_widget():
    """Return the Qt widget for Maya's $gPlayBackSlider, or None."""
    try:
        import maya.mel as mel
        slider = mel.eval('$tmp=$gPlayBackSlider')
        if not slider:
            return None
        try:
            from maya import OpenMayaUI as omui
        except Exception:
            return None
        try:
            try:
                from PySide2 import QtWidgets  # type: ignore
                import shiboken2 as shiboken  # type: ignore
            except ImportError:
                from PySide6 import QtWidgets  # type: ignore
                import shiboken6 as shiboken  # type: ignore
        except ImportError:
            return None
        ptr = None
        try:
            ptr = omui.MQtUtil.findControl(slider)
        except Exception:
            ptr = None
        if not ptr:
            return None
        try:
            try:
                w = shiboken.wrapInstance(int(ptr), QtWidgets.QWidget)
            except Exception:
                w = shiboken.wrapInstance(long(ptr), QtWidgets.QWidget)  # type: ignore[name-defined]
        except Exception:
            return None

        # WrapInstance may succeed even when underlying QWidget is mid-destruction.
        try:
            if w is None:
                return None
            if not shiboken.isValid(w):
                return None
        except Exception:
            # If shiboken2 can't validate, fall back to returning the wrapper.
            pass
        return w
    except Exception:
        return None


def _adv_qt_is_valid(obj):
    """Best-effort validity check for a PySide2 QObject/QWidget wrapper."""
    if obj is None:
        return False
    try:
        try:
            import shiboken2 as shiboken  # type: ignore
        except Exception:
            import shiboken6 as shiboken  # type: ignore
        return bool(shiboken.isValid(obj))
    except Exception:
        # If shiboken2 isn't available, assume it's valid.
        return True


def _adv_qt_key_from_main_key(main_key):
    """Map our parsed main_key to a Qt key code. Returns int or None."""
    try:
        try:
            from PySide2 import QtCore  # type: ignore
        except ImportError:
            from PySide6 import QtCore  # type: ignore
    except ImportError:
        return None

    if not main_key:
        return None

    mk = str(main_key)
    if len(mk) == 1:
        ch = mk.upper()
        if 'A' <= ch <= 'Z' or '0' <= ch <= '9':
            return ord(ch)

    mapping = {
        'PageDown': QtCore.Qt.Key_PageDown,
        'PageUp': QtCore.Qt.Key_PageUp,
        'Home': QtCore.Qt.Key_Home,
        'End': QtCore.Qt.Key_End,
        'Insert': QtCore.Qt.Key_Insert,
        'Delete': QtCore.Qt.Key_Delete,
        'Return': QtCore.Qt.Key_Return,
        'BackSpace': QtCore.Qt.Key_Backspace,
        'Tab': QtCore.Qt.Key_Tab,
        'Space': QtCore.Qt.Key_Space,
        'Left': QtCore.Qt.Key_Left,
        'Right': QtCore.Qt.Key_Right,
        'Up': QtCore.Qt.Key_Up,
        'Down': QtCore.Qt.Key_Down,
    }
    if mk in mapping:
        return mapping[mk]

    if mk.startswith('F') and mk[1:].isdigit():
        idx = int(mk[1:])
        try:
            return getattr(QtCore.Qt, 'Key_F%d' % idx)
        except Exception:
            return None

    return None


_ADV_HOTKEY_TEXTFIELD_CAPTURE_FILTERS = {}


def _adv_find_qlineedit_for_control(control_name):
    """Return a QLineEdit for a Maya cmds.textField control name, or None."""
    try:
        from maya import OpenMayaUI as omui
        try:
            import shiboken2 as shiboken  # type: ignore
            from PySide2 import QtWidgets  # type: ignore
        except ImportError:
            import shiboken6 as shiboken  # type: ignore
            from PySide6 import QtWidgets  # type: ignore
    except ImportError:
        return None

    if not control_name:
        return None

    ptr = None
    try:
        ptr = omui.MQtUtil.findControl(str(control_name))
    except Exception:
        ptr = None
    if not ptr:
        return None

    try:
        try:
            w = shiboken.wrapInstance(int(ptr), QtWidgets.QWidget)
        except Exception:
            w = shiboken.wrapInstance(long(ptr), QtWidgets.QWidget)  # type: ignore[name-defined]
    except Exception:
        return None

    if isinstance(w, QtWidgets.QLineEdit):
        return w

    try:
        le = w.findChild(QtWidgets.QLineEdit)
        if le is not None:
            return le
    except Exception:
        pass
    return None


def _adv_main_key_from_qt_event(event):
    """Map a Qt key event to the input token for parse_hotkey_input (lower-case)."""
    try:
        from PySide2 import QtCore
    except ImportError:
        try:
            from PySide6 import QtCore  # type: ignore
        except ImportError:
            return ''

    try:
        k = int(event.key())
    except Exception:
        k = 0

    # Prefer text for printable keys
    try:
        t = event.text() or ''
    except Exception:
        t = ''
    if t:
        if t == ' ':
            return 'space'
        if len(t) == 1 and t.isprintable():
            return t.lower()

    # Special keys
    special = {
        QtCore.Qt.Key_PageDown: 'pgdn',
        QtCore.Qt.Key_PageUp: 'pgup',
        QtCore.Qt.Key_Home: 'home',
        QtCore.Qt.Key_End: 'end',
        QtCore.Qt.Key_Insert: 'insert',
        QtCore.Qt.Key_Delete: 'delete',
        QtCore.Qt.Key_Return: 'enter',
        QtCore.Qt.Key_Enter: 'enter',
        QtCore.Qt.Key_Backspace: 'backspace',
        QtCore.Qt.Key_Tab: 'tab',
        QtCore.Qt.Key_Space: 'space',
        QtCore.Qt.Key_Left: 'left',
        QtCore.Qt.Key_Right: 'right',
        QtCore.Qt.Key_Up: 'up',
        QtCore.Qt.Key_Down: 'down',
    }
    if k in special:
        return special[k]

    # Function keys
    try:
        if QtCore.Qt.Key_F1 <= k <= QtCore.Qt.Key_F35:
            return 'f%d' % (k - int(QtCore.Qt.Key_F1) + 1)
    except Exception:
        pass

    return ''


def _adv_hotkey_input_string_from_qt_event(event):
    """Build a user input string like 'ctrl+alt+w' or 'w' from a Qt key event."""
    try:
        from PySide2 import QtCore
    except ImportError:
        try:
            from PySide6 import QtCore  # type: ignore
        except ImportError:
            return ''

    main = _adv_main_key_from_qt_event(event)
    if not main:
        return ''

    mods = []
    try:
        m = event.modifiers()
    except Exception:
        m = QtCore.Qt.NoModifier

    if bool(m & QtCore.Qt.ControlModifier):
        mods.append('ctrl')
    if bool(m & QtCore.Qt.AltModifier):
        mods.append('alt')
    if bool(m & QtCore.Qt.ShiftModifier):
        mods.append('shift')

    if mods:
        return '%s+%s' % ('+'.join(mods), main)
    return main


def _adv_install_hotkey_textfield_capture_for(control_names):
    """Install per-textField Qt event filters to capture key presses into the input box.

    This avoids Maya default hotkeys (Q/W/E/R/A/S/D etc.) eating the input.
    """
    try:
        from PySide2 import QtCore
    except ImportError:
        try:
            from PySide6 import QtCore  # type: ignore
        except ImportError:
            return

    if not control_names:
        return

    for name in control_names:
        le = _adv_find_qlineedit_for_control(name)
        if le is None:
            continue

        # Keep one filter per control name
        if name in _ADV_HOTKEY_TEXTFIELD_CAPTURE_FILTERS:
            try:
                le.removeEventFilter(_ADV_HOTKEY_TEXTFIELD_CAPTURE_FILTERS[name])
            except Exception:
                pass

        class _AdvHotkeyCaptureFilter(QtCore.QObject):
            def __init__(self, parent=None):
                super(_AdvHotkeyCaptureFilter, self).__init__(parent)
                self._mouse_token = ''

            def eventFilter(self, obj, event):
                try:
                    et = event.type()

                    # Allow capturing RMB/MMB as a prefix (for RMB+S etc.)
                    if et == QtCore.QEvent.MouseButtonPress:
                        try:
                            btn = event.button()
                        except Exception:
                            btn = None
                        if btn == QtCore.Qt.RightButton:
                            self._mouse_token = 'rmb'
                        elif btn == QtCore.Qt.MidButton:
                            self._mouse_token = 'mmb'
                        else:
                            # Don't capture LMB here; keep normal focus behavior.
                            return False

                        try:
                            obj.setText(self._mouse_token + '+')
                            obj.setCursorPosition(len(obj.text()))
                        except Exception:
                            pass
                        try:
                            event.accept()
                        except Exception:
                            pass
                        return True

                    if et != QtCore.QEvent.KeyPress:
                        return False

                    # Clear on Backspace/Delete
                    if int(event.key()) in (int(QtCore.Qt.Key_Backspace), int(QtCore.Qt.Key_Delete)):
                        try:
                            obj.setText('')
                        except Exception:
                            pass
                        event.accept()
                        return True

                    # Escape: clear focus
                    if int(event.key()) == int(QtCore.Qt.Key_Escape):
                        try:
                            obj.clearFocus()
                        except Exception:
                            pass
                        event.accept()
                        return True
                    try:
                        mods = event.modifiers()
                    except Exception:
                        mods = QtCore.Qt.NoModifier
                    has_mod = bool(mods & (QtCore.Qt.ControlModifier | QtCore.Qt.AltModifier | QtCore.Qt.ShiftModifier))

                    if not has_mod:
                        try:
                            t = event.text() or ''
                        except Exception:
                            t = ''
                        if t:
                            try:
                                cur = obj.text() or ''
                            except Exception:
                                cur = ''
                            try:
                                sel = obj.selectedText() or ''
                            except Exception:
                                sel = ''
                            try:
                                if sel:
                                    start = int(obj.selectionStart())
                                    if start < 0:
                                        start = int(obj.cursorPosition())
                                    new = (cur[:start] + t + cur[start + len(sel):])
                                    obj.setText(new)
                                    obj.setCursorPosition(start + len(t))
                                else:
                                    pos = int(obj.cursorPosition())
                                    if pos < 0:
                                        pos = len(cur)
                                    new = (cur[:pos] + t + cur[pos:])
                                    obj.setText(new)
                                    obj.setCursorPosition(pos + len(t))
                            except Exception:
                                try:
                                    obj.setText(t)
                                    obj.setCursorPosition(len(t))
                                except Exception:
                                    pass
                            event.accept()
                            return True

                    s = _adv_hotkey_input_string_from_qt_event(event)
                    if not s:
                        return False

                    if self._mouse_token:
                        s = '%s+%s' % (self._mouse_token, s)
                        self._mouse_token = ''

                    try:
                        obj.setText(s)
                        obj.setCursorPosition(len(s))
                    except Exception:
                        pass

                    event.accept()
                    return True
                except Exception:
                    return False

        f = _AdvHotkeyCaptureFilter(le)
        _ADV_HOTKEY_TEXTFIELD_CAPTURE_FILTERS[name] = f
        try:
            le.installEventFilter(f)
        except Exception:
            pass


def _adv_install_time_slider_clear_key_event_filter():
    global _ADV_TIME_SLIDER_CLEARKEY_EVENT_FILTER
    try:
        from PySide2 import QtCore, QtWidgets, QtGui
    except ImportError:
        try:
            from PySide6 import QtCore, QtWidgets, QtGui  # type: ignore
        except ImportError:
            return

    if _ADV_TIME_SLIDER_CLEARKEY_EVENT_FILTER is not None:
        return

    keypress_t = None
    try:
        keypress_t = QtCore.QEvent.KeyPress
    except Exception:
        try:
            keypress_t = QtCore.QEvent.Type.KeyPress
        except Exception:
            keypress_t = None

    def _qt_mod(name):
        v = None
        try:
            v = getattr(QtCore.Qt, name)
        except Exception:
            v = None
        if v is None:
            try:
                v = getattr(QtCore.Qt.KeyboardModifier, name)
            except Exception:
                v = None
        return v

    ctrl_mod = _qt_mod('ControlModifier')
    alt_mod = _qt_mod('AltModifier')
    shift_mod = _qt_mod('ShiftModifier')

    def _has_mod(mods, token):
        if token is None:
            return False
        try:
            return bool(mods & token)
        except Exception:
            try:
                return bool(int(mods) & int(token))
            except Exception:
                return False

    class _AdvTimeSliderClearKeyFilter(QtCore.QObject):
        def eventFilter(self, obj, event):
            try:
                if keypress_t is not None and int(event.type()) != int(keypress_t):
                    return False

                # Must be enabled
                if not _adv_hotkey_enabled('ADV_TimeSliderClearKeyHotkey'):
                    return False

                hotkey = ''
                try:
                    hotkey = CURRENT_TIME_SLIDER_CLEARKEY_HOTKEY
                except Exception:
                    hotkey = ''
                if not hotkey:
                    try:
                        if cmds.optionVar(exists='ADV_TimeSliderClearKeyHotkey'):
                            hotkey = cmds.optionVar(q='ADV_TimeSliderClearKeyHotkey') or ''
                    except Exception:
                        hotkey = ''
                if not hotkey:
                    return False

                modifier, main_key = _adv_parse_hotkey_str(hotkey)
                qt_key = _adv_qt_key_from_main_key(main_key)
                if qt_key is None:
                    return False

                if int(event.key()) != int(qt_key):
                    return False

                mods = event.modifiers()
                want_alt, want_ctl, want_sht = _adv_modifier_token_to_bools(modifier)
                if want_ctl != _has_mod(mods, ctrl_mod):
                    return False
                if want_alt != _has_mod(mods, alt_mod):
                    return False
                if want_sht != _has_mod(mods, shift_mod):
                    return False

                # Cursor must be over the time slider widget
                slider_w = _adv_get_time_slider_widget()
                if not _adv_qt_is_valid(slider_w):
                    return False
                try:
                    hit = QtWidgets.QApplication.widgetAt(QtGui.QCursor.pos())
                except Exception:
                    hit = None
                if not _adv_qt_is_valid(hit):
                    return False
                w = hit
                ok = False
                # Walk up parents defensively; QWidget wrappers can become invalid during UI rebuilds.
                while _adv_qt_is_valid(w):
                    try:
                        if w == slider_w:
                            ok = True
                            break
                    except Exception:
                        return False
                    try:
                        w = w.parentWidget()
                    except Exception:
                        w = None
                if not ok:
                    return False

                # Consume and run
                try:
                    adv_time_slider_clear_key_if_over()
                except Exception:
                    pass
                try:
                    event.accept()
                except Exception:
                    pass
                return True
            except Exception as e:
                # If UI has been torn down and Qt wrappers are stale, stop filtering to avoid spam/crashes.
                try:
                    msg = str(e)
                except Exception:
                    msg = ''
                if ('Internal C++ object' in msg) and ('already deleted' in msg):
                    try:
                        _adv_remove_time_slider_clear_key_event_filter()
                    except Exception:
                        pass
                return False

    _ADV_TIME_SLIDER_CLEARKEY_EVENT_FILTER = _AdvTimeSliderClearKeyFilter(QtWidgets.QApplication.instance())
    try:
        QtWidgets.QApplication.instance().installEventFilter(_ADV_TIME_SLIDER_CLEARKEY_EVENT_FILTER)
    except Exception:
        _ADV_TIME_SLIDER_CLEARKEY_EVENT_FILTER = None


def _adv_remove_time_slider_clear_key_event_filter():
    global _ADV_TIME_SLIDER_CLEARKEY_EVENT_FILTER
    try:
        from PySide2 import QtWidgets
    except ImportError:
        try:
            from PySide6 import QtWidgets  # type: ignore
        except ImportError:
            _ADV_TIME_SLIDER_CLEARKEY_EVENT_FILTER = None
            return
    try:
        if _ADV_TIME_SLIDER_CLEARKEY_EVENT_FILTER is not None:
            QtWidgets.QApplication.instance().removeEventFilter(_ADV_TIME_SLIDER_CLEARKEY_EVENT_FILTER)
    except Exception:
        pass
    _ADV_TIME_SLIDER_CLEARKEY_EVENT_FILTER = None


def _adv_migrate_restore_previous_time_slider_clear_key_hotkey_override(hotkey_str):
    """If an older version overwrote Maya hotkey binding with our nameCommand,
    restore the original binding (if stored) and clean up legacy optionVars.
    """
    try:
        if not hotkey_str:
            return
        modifier, main_key = _adv_parse_hotkey_str(hotkey_str)
        if not main_key:
            return
        alt, ctl, sht = _adv_modifier_token_to_bools(modifier)
        cur = _adv_hotkey_query_name(main_key, alt=alt, ctrl=ctl, shift=sht) or ''
        if cur != 'AdvTimeSliderClearKeyCmd':
            return

        # Prefer per-key legacy storage
        orig = ''
        per_key = _adv_time_slider_clear_key_orig_optionvar(hotkey_str)
        try:
            if cmds.optionVar(exists=per_key):
                orig = cmds.optionVar(q=per_key) or ''
        except Exception:
            orig = ''

        # Back-compat for the earliest fixed Shift+D version
        if (not orig) and hotkey_str == 'sht|d':
            try:
                if cmds.optionVar(exists='ADV_TimeSliderClearKeyHotkey_OrigNameCmd'):
                    orig = cmds.optionVar(q='ADV_TimeSliderClearKeyHotkey_OrigNameCmd') or ''
            except Exception:
                orig = ''

        if orig:
            _adv_hotkey_set_name(main_key, orig, alt=alt, ctrl=ctl, shift=sht)
        else:
            _adv_hotkey_clear(main_key, modifier)

        # Cleanup legacy storage
        try:
            if cmds.optionVar(exists=per_key):
                cmds.optionVar(remove=per_key)
        except Exception:
            pass
        try:
            if cmds.optionVar(exists='ADV_TimeSliderClearKeyHotkey_OrigNameCmd'):
                cmds.optionVar(remove='ADV_TimeSliderClearKeyHotkey_OrigNameCmd')
        except Exception:
            pass
    except Exception:
        pass


def parse_hotkey_input(key_input):
    """Parse hotkey input like 'alt+o' to internal format ('alt', 'o')."""
    if not key_input:
        return None, None, get_text("enter_hotkey")

    key_input = str(key_input).strip().lower()
    key_norm = key_input.replace('|', '+').replace('-', '+').replace(' ', '')
    parts = [p for p in key_norm.split('+') if p]
    if not parts:
        return None, None, get_text("enter_hotkey")

    main_key = parts[-1].strip()
    mods = parts[:-1]

    alt = False
    ctl = False
    sht = False
    lmb = False
    rmb = False
    mmb = False
    for m in mods:
        ml = str(m).strip().lower()
        if ml in ('ctrl', 'ctl', 'control'):
            ctl = True
        elif ml == 'alt':
            alt = True
        elif ml in ('shift', 'sht'):
            sht = True
        elif ml in ('lmb', 'mouse1', 'leftmouse'):
            lmb = True
        elif ml in ('rmb', 'mouse2', 'rightmouse'):
            rmb = True
        elif ml in ('mmb', 'mouse3', 'middlemouse'):
            mmb = True

    mod_tokens = []
    if lmb:
        mod_tokens.append('lmb')
    if rmb:
        mod_tokens.append('rmb')
    if mmb:
        mod_tokens.append('mmb')
    if ctl:
        mod_tokens.append('ctl')
    if alt:
        mod_tokens.append('alt')
    if sht:
        mod_tokens.append('sht')
    modifier = '+'.join(mod_tokens) if mod_tokens else ''

    key_map = {
        'pgdn': 'PageDown',
        'pudn': 'PageDown',
        'pagedown': 'PageDown',
        'pgup': 'PageUp',
        'puup': 'PageUp',
        'pageup': 'PageUp',
        'home': 'Home',
        'end': 'End',
        'ins': 'Insert',
        'insert': 'Insert',
        'del': 'Delete',
        'delete': 'Delete',
        'return': 'Return',
        'enter': 'Return',
        'backspace': 'BackSpace',
        'tab': 'Tab',
        'space': 'Space',
        'left': 'Left',
        'right': 'Right',
        'up': 'Up',
        'down': 'Down',
    }
    for i in range(1, 13):
        key_map['f%d' % i] = 'F%d' % i

    if main_key in key_map:
        main_key = key_map[main_key]

    if len(main_key) > 1 and main_key not in key_map.values():
        return None, None, get_text("single_letter")

    return modifier, main_key, None


def _set_view_hotkey(field_name, option_var, runtime_cmd, current_var_name, success_key):
    """Set a view hotkey using runTimeCommand + viewSet."""
    try:
        _ensure_self_path_optionvar()
    except Exception:
        pass

    key_input = cmds.textField(field_name, query=True, text=True)
    modifier, main_key, error_msg = parse_hotkey_input(key_input)
    if error_msg:
        cmds.warning(error_msg)
        return

    if modifier:
        new_hotkey_str = "%s|%s" % (modifier, main_key)
    else:
        new_hotkey_str = main_key

    try:
        ok, cleared_name = _adv_auto_resolve_hotkey_conflict(new_hotkey_str, current_var_name)
        if not ok:
            _adv_show_hotkey_conflict_warning(_adv_display_hotkey(modifier, main_key), cleared_name)
            return
    except Exception:
        pass

    view_set_flags = {
        'LeftViewPress': 'viewSet -leftSide',
        'RightViewPress': 'viewSet -rightSide',
        'FrontViewPress': 'viewSet -front',
        'BackViewPress': 'viewSet -back',
        'TopViewPress': 'viewSet -top',
        'PerspViewPress': 'viewSet -persp',
    }
    mel_cmd = view_set_flags.get(runtime_cmd, 'viewSet -home')

    try:
        old_val = globals().get(current_var_name)
        if old_val:
            _unbind_hotkey_string(old_val)

        if not _adv_mod_token_has_mouse(modifier):
            _adv_hotkey_clear(main_key, modifier)

        enabled = _adv_hotkey_enabled(option_var)
        rtc_name = 'ADV_%s_RTC' % runtime_cmd

        if enabled and not _adv_mod_token_has_mouse(modifier):
            try:
                if _adv_runtime_command_exists(rtc_name):
                    cmds.runTimeCommand(rtc_name, edit=True, delete=True)
            except Exception:
                pass
            cmds.runTimeCommand(
                rtc_name,
                annotation='ADV ' + runtime_cmd,
                commandLanguage='mel',
                command=mel_cmd
            )
            _adv_hotkey_bind(rtc_name, main_key, modifier)

        new_val = ("%s|%s" % (modifier, main_key)) if modifier else main_key
        display_key = _adv_display_hotkey(modifier, main_key)
        globals()[current_var_name] = new_val
        save_hotkey_to_prefs(option_var, new_val)

        try:
            if enabled and _adv_mod_token_has_mouse(modifier):
                _adv_install_hotkey_fallback_filter(force=True)
        except Exception:
            pass

        update_main_window_labels()
        cmds.evalDeferred(update_hotkey_mapping_window_labels)
        try:
            cmds.inViewMessage(amg=u"<hl>[ADV]</hl> " + (get_text(success_key) % display_key), pos='botRight', fade=True, alpha=0.9)
        except Exception:
            pass
    except Exception as e:
        print("Error: %s" % str(e))
        cmds.warning(get_text("hotkey_failed"))


def _set_simple_hotkey(field_name, option_var, cmd_name, annotation, mel_command, current_var_name, success_key):
    """Set a normal hotkey binding."""
    try:
        _ensure_self_path_optionvar()
    except Exception:
        pass
    try:
        _adv_ensure_adv_hotkey_set_current()
    except Exception:
        pass

    key_input = cmds.textField(field_name, query=True, text=True)
    modifier, main_key, error_msg = parse_hotkey_input(key_input)
    if error_msg:
        cmds.warning(error_msg)
        return

    if modifier:
        new_hotkey_str = "%s|%s" % (modifier, main_key)
    else:
        new_hotkey_str = main_key

    try:
        ok, cleared_name = _adv_auto_resolve_hotkey_conflict(new_hotkey_str, current_var_name)
        if not ok:
            _adv_show_hotkey_conflict_warning(_adv_display_hotkey(modifier, main_key), cleared_name)
            return
    except Exception:
        pass

    try:
        old_val = globals().get(current_var_name)
        if old_val:
            _unbind_hotkey_string(old_val)

        if not _adv_mod_token_has_mouse(modifier):
            _adv_hotkey_clear(main_key, modifier)

        enabled = _adv_hotkey_enabled(option_var)
        use_runtime_cmd = False
        try:
            use_runtime_cmd = str(cmd_name).startswith('ADV_')
        except Exception:
            use_runtime_cmd = False

        expected = ''
        if enabled and not _adv_mod_token_has_mouse(modifier):
            if use_runtime_cmd:
                rt = '%s_RTC' % str(cmd_name)
                adv_py_map = {
                    'ADV_SetKeyCmd': 'adv_set_key',
                    'ADV_FileOpenCmd': 'adv_file_open_hotkey',
                    'ADV_FileSaveCmd': 'adv_file_save_hotkey',
                    'ADV_FileSaveAsCmd': 'adv_file_save_as_hotkey',
                    'ADV_TRZeroCmd': 'adv_tr_zero',
                    'ADV_ROZeroCmd': 'adv_ro_zero',
                    'ADV_SCZeroCmd': 'adv_sc_zero',
                    'ADV_PrevFrameCmd': 'adv_prev_frame',
                    'ADV_NextFrameCmd': 'adv_next_frame',
                    'ADV_PrevKeyframeCmd': 'adv_prev_keyframe',
                    'ADV_NextKeyframeCmd': 'adv_next_keyframe',
                    'ADV_ToggleWireframeCmd': 'adv_toggle_wireframe_on_shaded',
                    'ADV_ToggleUVWireframeCmd': 'adv_toggle_uv_wireframe_textured',
                    'ADV_ToggleJointsCmd': 'adv_toggle_joints',
                    'ADV_ToggleMeshesCmd': 'adv_toggle_meshes',
                    'ADV_ToggleCurvesCmd': 'adv_toggle_curves',
                    'ADV_CurveEditorCmd': 'adv_open_curve_editor_hotkey',
                    'ADV_ToggleOrthoViewCmd': 'adv_toggle_ortho_view',
                    'ADV_SelectAllVisibleCmd': 'adv_select_all_visible_objects',
                    'ADV_SelectSameLayerCmd': 'adv_select_same_layer',
                }
                py_func = adv_py_map.get(str(cmd_name))
                if py_func:
                    py_body = _adv_call_self_function_hotkey_command_py(py_func)
                    _adv_ensure_runtime_command(rt, annotation, py_body, language='python')
                else:
                    _adv_ensure_runtime_command(rt, annotation, mel_command, language='mel')
                expected = _adv_bind_hotkey_to_runtime_command(rt, main_key, modifier, annotation=annotation) or ''
            else:
                _adv_ensure_name_command(cmd_name, annotation, mel_command)
                _adv_hotkey_bind(cmd_name, main_key, modifier)
                expected = str(cmd_name)

        new_val = ("%s|%s" % (modifier, main_key)) if modifier else main_key
        display_key = _adv_display_hotkey(modifier, main_key)
        globals()[current_var_name] = new_val
        save_hotkey_to_prefs(option_var, new_val)

        try:
            if expected:
                bound_name = _adv_hotkey_query_name_mel(main_key, modifier)
                if str(bound_name or '') != str(expected):
                    _adv_install_hotkey_fallback_filter(force=True)
                    print('[ADV] Hotkey override refused by Maya; using fallback for: %s' % _adv_display_hotkey(modifier, main_key))
        except Exception:
            pass

        try:
            if enabled and _adv_mod_token_has_mouse(modifier):
                _adv_install_hotkey_fallback_filter(force=True)
        except Exception:
            pass

        try:
            _adv_install_key_repeat_filter(force=True)
        except Exception:
            pass

        update_main_window_labels()
        cmds.evalDeferred(update_hotkey_mapping_window_labels)
        try:
            cmds.inViewMessage(amg=u"<hl>[ADV]</hl> " + (get_text(success_key) % display_key), pos='botRight', fade=True, alpha=0.9)
        except Exception:
            pass
    except Exception as e:
        print("Error: %s" % str(e))
        cmds.warning(get_text("hotkey_failed"))


def _delete_simple_hotkey(option_var, current_var_name, field_name, deleted_key):
    cur = globals().get(current_var_name)
    if not cur:
        cmds.warning(get_text("no_hotkey_to_delete"))
        return

    try:
        _unbind_hotkey_string(cur)
        globals()[current_var_name] = None
        save_hotkey_to_prefs(option_var, None)

        update_main_window_labels()
        cmds.evalDeferred(update_hotkey_mapping_window_labels)
        try:
            if field_name and cmds.textField(field_name, exists=True):
                cmds.textField(field_name, edit=True, text="")
        except Exception:
            pass

        try:
            cmds.inViewMessage(amg=u"<hl>[ADV]</hl> " + get_text(deleted_key), pos='botRight', fade=True, alpha=0.9)
        except Exception:
            pass

        try:
            _adv_install_key_repeat_filter(force=True)
        except Exception:
            pass
    except Exception as e:
        print("Error deleting hotkey: %s" % str(e))
        cmds.warning(get_text("hotkey_failed"))


def set_time_slider_clear_key_hotkey_shift_d(show_confirm=True):
    """Backward-compatible wrapper (old fixed Shift+D)."""
    try:
        if cmds.textField('timeSliderClearKeyHotkeyField', exists=True):
            cmds.textField('timeSliderClearKeyHotkeyField', e=True, text='shift+d')
    except Exception:
        pass
    set_time_slider_clear_key_hotkey(show_confirm=show_confirm)


def set_time_slider_clear_key_hotkey(show_confirm=True):
    """Set custom hotkey for time-slider clear-key (only active when cursor is over the time slider)."""
    global CURRENT_TIME_SLIDER_CLEARKEY_HOTKEY
    _ensure_self_path_optionvar()

    try:
        key_input = ''
        if cmds.textField('timeSliderClearKeyHotkeyField', exists=True):
            key_input = cmds.textField('timeSliderClearKeyHotkeyField', q=True, text=True)
        modifier, main_key, error_msg = parse_hotkey_input(key_input)
        if error_msg:
            cmds.warning(error_msg)
            return

        new_hotkey = ('%s|%s' % (modifier, main_key)) if modifier else main_key

        # Migration: if older version overwrote this hotkey, restore it first.
        _adv_migrate_restore_previous_time_slider_clear_key_hotkey_override(new_hotkey)

        # Enable on set
        _adv_set_hotkey_enabled('ADV_TimeSliderClearKeyHotkey', True)
        _apply_time_slider_clear_key_hotkey_binding(new_hotkey, enabled=True)

        CURRENT_TIME_SLIDER_CLEARKEY_HOTKEY = new_hotkey
        save_hotkey_to_prefs('ADV_TimeSliderClearKeyHotkey', new_hotkey)

        try:
            update_main_window_labels()
        except Exception:
            pass

        display_key = _adv_format_hotkey_display(new_hotkey)
        _adv_show_inview('[ADV] <hl>%s</hl> 绑定成功' % display_key)
        if show_confirm:
            cmds.confirmDialog(title=get_text('success'),
                               message=get_text('hotkey_success_time_slider_clear_key') % display_key,
                               button=['OK'])
    except Exception as e:
        print('Error: %s' % str(e))
        cmds.warning(get_text('hotkey_failed'))


def delete_time_slider_clear_key_hotkey_shift_d(show_confirm=True):
    """Backward-compatible wrapper (old fixed Shift+D)."""
    delete_time_slider_clear_key_hotkey(show_confirm=show_confirm)


def delete_time_slider_clear_key_hotkey(show_confirm=True):
    """Unbind the custom hotkey for time-slider clear-key and restore original binding if saved."""
    global CURRENT_TIME_SLIDER_CLEARKEY_HOTKEY
    try:
        cur = CURRENT_TIME_SLIDER_CLEARKEY_HOTKEY
        if not cur and cmds.optionVar(exists='ADV_TimeSliderClearKeyHotkey'):
            try:
                cur = cmds.optionVar(q='ADV_TimeSliderClearKeyHotkey') or ''
            except Exception:
                cur = ''
        if not cur:
            cmds.warning(get_text('no_hotkey_to_delete'))
            return

        _adv_show_inview('[ADV] 正在删除 <hl>%s</hl> 绑定 ...' % _adv_format_hotkey_display(cur))
        _apply_time_slider_clear_key_hotkey_binding(cur, enabled=False)

        CURRENT_TIME_SLIDER_CLEARKEY_HOTKEY = None
        save_hotkey_to_prefs('ADV_TimeSliderClearKeyHotkey', None)

        try:
            update_main_window_labels()
        except Exception:
            pass
        if cmds.textField('timeSliderClearKeyHotkeyField', exists=True):
            cmds.textField('timeSliderClearKeyHotkeyField', e=True, text='')

        if show_confirm:
            cmds.confirmDialog(title=get_text('success'),
                               message=get_text('hotkey_deleted_time_slider_clear_key'),
                               button=['OK'])
    except Exception as e:
        print('Error deleting hotkey: %s' % str(e))
        cmds.warning(get_text('hotkey_failed'))


def _toggle_time_slider_clear_key_hotkey_enabled(enabled):
    _adv_set_hotkey_enabled('ADV_TimeSliderClearKeyHotkey', enabled)
    cur = None
    try:
        cur = CURRENT_TIME_SLIDER_CLEARKEY_HOTKEY
    except Exception:
        cur = None
    if not cur and cmds.optionVar(exists='ADV_TimeSliderClearKeyHotkey'):
        try:
            cur = cmds.optionVar(q='ADV_TimeSliderClearKeyHotkey') or ''
        except Exception:
            cur = ''
    if enabled:
        if cur:
            _apply_time_slider_clear_key_hotkey_binding(cur, enabled=True)
    else:
        _apply_time_slider_clear_key_hotkey_binding(cur, enabled=False)


# Time slider drag enable state helper functions
_ADV_TIME_SLIDER_ENABLED_OPTIONVAR = "ADV_TimeSliderDragEnabled"

def _adv_time_slider_is_enabled():
    """Check if time slider drag is enabled"""
    try:
        if cmds.optionVar(exists=_ADV_TIME_SLIDER_ENABLED_OPTIONVAR):
            return bool(cmds.optionVar(q=_ADV_TIME_SLIDER_ENABLED_OPTIONVAR))
    except Exception:
        pass
    return False

def _adv_toggle_time_slider_enable(enabled):
    """Toggle time slider drag enable state"""
    try:
        cmds.optionVar(iv=(_ADV_TIME_SLIDER_ENABLED_OPTIONVAR, 1 if enabled else 0))
        if enabled:
            adv_time_slider_drag_enable()
            _adv_safe_print(u"[ADV] 时间轴拖动已启用" if LANGUAGE == 'CN' else "[ADV] Time slider drag enabled")
        else:
            # Best-effort disable: try to stop runtime module if it exposes an API.
            stopped = False
            try:
                import sys
                mod = sys.modules.get('adv_time_slider_drag_runtime')
                if mod is not None:
                    for fn_name in ('stop_time_slider_control', 'stop', 'uninstall', 'shutdown'):
                        fn = getattr(mod, fn_name, None)
                        if callable(fn):
                            try:
                                fn()
                                stopped = True
                                break
                            except Exception:
                                pass

                    # If module is already loaded but is an older version (no stop API),
                    # try reload once then stop again.
                    if not stopped and not hasattr(mod, 'stop_time_slider_control'):
                        try:
                            import importlib
                            mod = importlib.reload(mod)
                        except Exception:
                            mod = mod
                        fn = getattr(mod, 'stop_time_slider_control', None)
                        if callable(fn):
                            try:
                                fn()
                                stopped = True
                            except Exception:
                                pass
            except Exception:
                stopped = False

            if stopped:
                _adv_safe_print(u"[ADV] 时间轴拖动已禁用" if LANGUAGE == 'CN' else "[ADV] Time slider drag disabled")
            else:
                _adv_safe_print(u"[ADV] 时间轴拖动已禁用（需重启Maya生效）" if LANGUAGE == 'CN' else "[ADV] Time slider drag disabled (restart Maya to take effect)")
    except Exception as e:
        print("Error toggling time slider: %s" % str(e))


