# Auto-start (writes to userSetup.py)
_ADV_AUTOSTART_ENABLED_OPTIONVAR = "ADV_AutoStartEnabled"
_ADV_AUTOSTART_MARK_BEGIN = "# >>> ADV_FAST_SELECT_AUTOSTART_BEGIN"
_ADV_AUTOSTART_MARK_END = "# <<< ADV_FAST_SELECT_AUTOSTART_END"


def _adv_autostart_is_enabled(default=False):
    try:
        if cmds.optionVar(exists=_ADV_AUTOSTART_ENABLED_OPTIONVAR):
            return bool(cmds.optionVar(q=_ADV_AUTOSTART_ENABLED_OPTIONVAR))
    except Exception:
        pass
    return bool(default)


def _adv_user_setup_py_path():
    try:
        d = cmds.internalVar(userScriptDir=True)
    except Exception:
        d = ''
    try:
        d = d or ''
        return os.path.join(d, 'userSetup.py')
    except Exception:
        return None


def _adv_update_user_setup_autostart(enabled):
    import io
    import re

    p = _adv_user_setup_py_path()
    if not p:
        return False

    old = ''
    try:
        if os.path.isfile(p):
            try:
                with io.open(p, 'r', encoding='utf-8') as f:
                    old = f.read()
            except Exception:
                try:
                    with io.open(p, 'r', encoding='gbk') as f:
                        old = f.read()
                except Exception:
                    old = ''
    except Exception:
        old = ''

    # remove existing block
    try:
        pat = re.compile(re.escape(_ADV_AUTOSTART_MARK_BEGIN) + r".*?" + re.escape(_ADV_AUTOSTART_MARK_END) + r"\s*", re.S)
        new = re.sub(pat, '', old)
    except Exception:
        new = old

    if enabled:
        # Ensure we have a persisted absolute path to this script (used by userSetup)
        try:
            _ensure_self_path_optionvar()
        except Exception:
            pass

        block = "\n".join([
            _ADV_AUTOSTART_MARK_BEGIN,
            "try:",
            "    import maya.utils as _adv_utils",
            "    def _adv_fast_select_autostart():",
            "        try:",
            "            import os, runpy",
            "            import maya.cmds as cmds",
            "            sp = ''",
            "            if cmds.optionVar(exists='ADV_FastSelectScriptPath'):",
            "                sp = cmds.optionVar(q='ADV_FastSelectScriptPath') or ''",
            "            if sp and os.path.isfile(sp):",
            "                runpy.run_path(sp, run_name='__main__')",
            "        except Exception:",
            "            pass",
            "    _adv_utils.executeDeferred(_adv_fast_select_autostart)",
            "except Exception:",
            "    pass",
            _ADV_AUTOSTART_MARK_END,
            "",
        ])
        if new and not new.endswith('\n'):
            new += "\n"
        new += block

    try:
        with io.open(p, 'w', encoding='utf-8') as f:
            f.write(new)
        return True
    except Exception:
        return False


def _adv_set_autostart_enabled(enabled):
    try:
        cmds.optionVar(intValue=(_ADV_AUTOSTART_ENABLED_OPTIONVAR, 1 if enabled else 0))
    except Exception:
        pass
    ok = _adv_update_user_setup_autostart(bool(enabled))
    if ok:
        print("[ADV] Auto-start {} (restart Maya to apply)".format("enabled" if enabled else "disabled"))
    else:
        print("[ADV] Failed to update userSetup.py (check permissions)")


# -------------------------
# UI Scale (DPI / Resolution adaptation)
# -------------------------

_ADV_UI_SCALE_OPTIONVAR = 'ADV_UIScale'

# Scale modes: 0=Auto, 1=Small(1K), 2=Medium(2K), 3=Large(4K), 4=XLarge(8K)
ADV_UI_SCALE_AUTO = 0
ADV_UI_SCALE_SMALL = 1
ADV_UI_SCALE_MEDIUM = 2
ADV_UI_SCALE_LARGE = 3
ADV_UI_SCALE_XLARGE = 4

# Scale factors corresponding to each mode (relative to 2K baseline)
_ADV_UI_SCALE_FACTORS = {
    ADV_UI_SCALE_SMALL: 0.8,    # 1K / lower res
    ADV_UI_SCALE_MEDIUM: 1.0,   # 2K baseline
    ADV_UI_SCALE_LARGE: 1.3,    # 4K / high res
    ADV_UI_SCALE_XLARGE: 1.6,   # 8K / ultra high res
}

# Runtime dynamic scaling override (used by window resize / screen move)
_ADV_UI_SCALE_DYNAMIC = {'v': None}
_ADV_UI_SCALE_EVENT_FILTERS = {}
_ADV_UI_SCALE_RESIZE_TIMER = {}

# Width-follow scaling (proportional width when user drags window horizontally)
_ADV_UI_WIDTH_FOLLOW = {}
_ADV_UI_WIDTH_FOLLOW_FILTERS = {}


def _adv_ui_scale_get(default=ADV_UI_SCALE_AUTO):
    """Get the current UI scale mode from optionVar."""
    try:
        if cmds.optionVar(exists=_ADV_UI_SCALE_OPTIONVAR):
            return int(cmds.optionVar(q=_ADV_UI_SCALE_OPTIONVAR))
    except Exception:
        pass
    return default


def _adv_ui_scale_set(mode):
    """Set the UI scale mode to optionVar."""
    try:
        cmds.optionVar(intValue=(_ADV_UI_SCALE_OPTIONVAR, int(mode)))
    except Exception:
        pass


def _adv_detect_screen_scale():
    """Auto-detect appropriate scale based on screen resolution."""
    try:
        # Try to get screen width via Qt (prefer screen under cursor)
        try:
            from PySide2 import QtWidgets, QtGui
        except ImportError:
            try:
                from PySide6 import QtWidgets, QtGui
            except ImportError:
                return ADV_UI_SCALE_MEDIUM

        app = QtWidgets.QApplication.instance()
        if app:
            screen = None
            try:
                pos = QtGui.QCursor.pos()
                screen = QtGui.QGuiApplication.screenAt(pos)
            except Exception:
                screen = None

            if screen is None:
                try:
                    screen = app.primaryScreen()
                except Exception:
                    screen = None

            if screen:
                geom = screen.availableGeometry()
                width = geom.width()
                height = geom.height()
                dpr = 1.0
                try:
                    dpr = float(getattr(screen, 'devicePixelRatio', lambda: 1.0)() or 1.0)
                except Exception:
                    try:
                        dpr = float(getattr(screen, 'devicePixelRatioF', lambda: 1.0)() or 1.0)
                    except Exception:
                        dpr = 1.0
                try:
                    width = float(width) * float(dpr)
                    height = float(height) * float(dpr)
                except Exception:
                    pass

                # Determine scale based on resolution
                # 8K: >= 7680 width or >= 4320 height
                # 4K: >= 3840 width or >= 2160 height
                # 2K: >= 1920 width
                # 1K: < 1920 width
                if width >= 7680 or height >= 4320:
                    return ADV_UI_SCALE_XLARGE
                elif width >= 3840 or height >= 2160:
                    return ADV_UI_SCALE_LARGE
                elif width >= 1920:
                    base = ADV_UI_SCALE_MEDIUM
                    try:
                        if float(dpr) >= 1.5:
                            base = ADV_UI_SCALE_XLARGE
                        elif float(dpr) >= 1.25:
                            base = ADV_UI_SCALE_LARGE
                    except Exception:
                        pass
                    return base
                else:
                    base = ADV_UI_SCALE_SMALL
                    try:
                        if float(dpr) >= 1.5:
                            base = ADV_UI_SCALE_LARGE
                        elif float(dpr) >= 1.25:
                            base = ADV_UI_SCALE_MEDIUM
                    except Exception:
                        pass
                    return base
    except Exception:
        pass
    
    # Fallback: try Maya's own method
    try:
        # Check Maya viewport width as fallback
        panel = cmds.getPanel(withFocus=True)
        if panel and cmds.modelEditor(panel, exists=True):
            pass  # Could query panel size but it's not reliable for screen detection
    except Exception:
        pass
    
    # Default to medium if detection fails
    return ADV_UI_SCALE_MEDIUM


def _adv_get_ui_scale_factor():
    """Get the actual scale factor to apply based on current mode."""
    try:
        if _ADV_UI_SCALE_DYNAMIC.get('v') is not None:
            return float(_ADV_UI_SCALE_DYNAMIC.get('v'))
    except Exception:
        pass
    mode = _adv_ui_scale_get(ADV_UI_SCALE_AUTO)
    
    if mode == ADV_UI_SCALE_AUTO:
        # Auto-detect
        mode = _adv_detect_screen_scale()
    
    return _ADV_UI_SCALE_FACTORS.get(mode, 1.0)


def _adv_scaled(value):
    """Scale a dimension value by the current UI scale factor."""
    factor = _adv_get_ui_scale_factor()
    try:
        import math
        return int(math.ceil(float(value) * float(factor)))
    except Exception:
        return int(round(value * factor))


def _adv_scaled_tuple(*values):
    """Scale multiple dimension values by the current UI scale factor."""
    factor = _adv_get_ui_scale_factor()
    try:
        import math
        return tuple(int(math.ceil(float(v) * float(factor))) for v in values)
    except Exception:
        return tuple(int(round(v * factor)) for v in values)


def _adv_apply_ui_font_scale(window_name, factor):
    """Apply font scaling to a Maya window (Qt widget)."""
    try:
        if not factor or abs(factor - 1.0) < 0.01:
            return
    except Exception:
        return


def _adv_ui_list_descendants(root_ui):
    """Return a list of all descendant UI items (layouts/controls) under a root UI."""
    out = []
    seen = set()
    stack = [root_ui]
    def _children(node):
        kids = []
        # Layout children
        try:
            kids = cmds.layout(node, q=True, childArray=True) or []
        except Exception:
            kids = []
        if kids:
            return list(kids)

        # Control children (covers many UI controls including some container types)
        try:
            kids = cmds.control(node, q=True, childArray=True) or []
        except Exception:
            kids = []
        if kids:
            return list(kids)

        # Specific container commands that may not respond to cmds.layout
        try:
            kids = cmds.scrollLayout(node, q=True, childArray=True) or []
        except Exception:
            kids = []
        if kids:
            return list(kids)

        try:
            kids = cmds.window(node, q=True, childArray=True) or []
        except Exception:
            kids = []
        if kids:
            return list(kids)

        return []

    while stack:
        node = stack.pop()
        if not node or node in seen:
            continue
        seen.add(node)
        out.append(node)

        kids = _children(node)
        if kids:
            stack.extend(kids)
    return out


def _adv_ui_capture_rowlayout_columns(row_name):
    """Capture rowLayout column widths (cw2/cw3/cw4/cw5/cw6). Return (flagName, widthsTuple) or (None, None)."""
    try:
        if cmds.objectTypeUI(row_name) != 'rowLayout':
            return None, None
    except Exception:
        return None, None

    for n in (6, 5, 4, 3, 2):
        flag = 'columnWidth{0}'.format(n)
        try:
            widths = cmds.rowLayout(row_name, q=True, **{flag: True})
        except Exception:
            widths = None
        if widths:
            try:
                widths_t = tuple(int(round(float(x))) for x in widths)
            except Exception:
                continue
            if len(widths_t) == n:
                return flag, widths_t
    return None, None


def _adv_ui_capture_control_width(ctrl_name):
    """Capture a control's explicit width, if set. Return int width or None."""
    try:
        w = cmds.control(ctrl_name, q=True, width=True)
    except Exception:
        return None
    try:
        w = int(round(float(w)))
    except Exception:
        return None
    # Maya may report 0 for auto; ignore.
    if w <= 0:
        return None
    return w


def _adv_ui_apply_control_width(ctrl_name, width):
    try:
        cmds.control(ctrl_name, e=True, width=int(width))
    except Exception:
        pass


def _adv_ui_apply_rowlayout_columns(row_name, flag, widths):
    try:
        cmds.rowLayout(row_name, e=True, **{flag: tuple(int(x) for x in widths)})
    except Exception:
        pass


def _adv_install_ui_width_follow(window_name, root_ui, min_factor=0.70, max_factor=1.80):
    """Make all rowLayouts under root_ui scale their column widths proportionally with window width while dragging."""
    try:
        from PySide2 import QtCore, QtGui
    except ImportError:
        return

    w = _adv_get_qt_window_widget(window_name)
    if not w:
        return

    key = str(window_name)

    # Capture baseline column widths + control widths once.
    try:
        layouts = {}
        ctrls = {}
        for ui in _adv_ui_list_descendants(root_ui):
            try:
                typ = cmds.objectTypeUI(ui)
            except Exception:
                typ = None

            if typ == 'rowLayout':
                flag, widths = _adv_ui_capture_rowlayout_columns(ui)
                if flag and widths:
                    layouts[ui] = {'flag': flag, 'widths': widths}
                continue

            # Any control that has an explicit width set.
            bw = _adv_ui_capture_control_width(ui)
            if bw is not None:
                ctrls[ui] = bw

        _ADV_UI_WIDTH_FOLLOW[key] = {
            'base_w': None,
            'last_w': None,
            'layouts': layouts,
            'ctrls': ctrls,
            'min_factor': float(min_factor),
            'max_factor': float(max_factor),
        }
    except Exception:
        _ADV_UI_WIDTH_FOLLOW[key] = {'base_w': None, 'last_w': None, 'layouts': {}, 'ctrls': {}, 'min_factor': float(min_factor), 'max_factor': float(max_factor)}

    # Remove previous filter if any.
    try:
        old = _ADV_UI_WIDTH_FOLLOW_FILTERS.get(key)
        if old:
            w.removeEventFilter(old)
    except Exception:
        pass

    class _AdvUiWidthFollowFilter(QtCore.QObject):
        def __init__(self, parent=None):
            super(_AdvUiWidthFollowFilter, self).__init__(parent)
            self._ready = False

        def _hit_test_edge(self, global_pos):
            """Return 'left'/'right'/None depending on whether global_pos is near window edge."""
            try:
                g = w.frameGeometry()  # global coords
            except Exception:
                g = w.geometry()
                g.moveTo(w.mapToGlobal(g.topLeft()))
            try:
                try:
                    g = w.frameGeometry()  # global coords
                except Exception:
                    g = w.geometry()
                    g.moveTo(w.mapToGlobal(g.topLeft()))

                edge_px = 10
                if abs(global_pos.x() - g.left()) <= edge_px:
                    return 'left'
                if abs(global_pos.x() - g.right()) <= edge_px:
                    return 'right'
            except Exception:
                pass
            return None

        def eventFilter(self, obj, event):
            try:
                st = _ADV_UI_WIDTH_FOLLOW.get(key)
                if not st:
                    return False

                et = event.type()
                if et == QtCore.QEvent.Show:
                    try:
                        st['base_w'] = float(w.width())
                        st['last_w'] = float(w.width())
                    except Exception:
                        st['base_w'] = None
                        st['last_w'] = None
                    self._ready = True
                    return False

                # Native window resizing (edge drag) triggers Resize events, not normal MouseMove on the window.
                if et != QtCore.QEvent.Resize:
                    return False

                if not self._ready:
                    self._ready = True
                    try:
                        st['base_w'] = float(w.width())
                        st['last_w'] = float(w.width())
                    except Exception:
                        pass
                    return False

                # Only respond when user is actively dragging the window frame edge.
                try:
                    if not bool(QtGui.QGuiApplication.mouseButtons()):
                        return False
                except Exception:
                    return False

                try:
                    gp = QtGui.QCursor.pos()
                except Exception:
                    return False

                if not self._hit_test_edge(gp):
                    return False

                try:
                    w_now = float(event.size().width())
                    w_old = float(event.oldSize().width())
                except Exception:
                    try:
                        w_now = float(w.width())
                        w_old = float(st.get('last_w') or w_now)
                    except Exception:
                        return False

                # Ignore height-only resizes.
                if abs(w_now - w_old) < 0.5:
                    return False

                st['last_w'] = w_now

                target_w = max(200.0, float(w_now))

                base_w = st.get('base_w')
                if not base_w or base_w <= 1:
                    base_w = float(w.width()) if w.width() > 1 else 1.0
                    st['base_w'] = base_w

                factor = target_w / float(base_w)
                try:
                    factor = max(float(st.get('min_factor', 0.70)), min(float(st.get('max_factor', 1.80)), float(factor)))
                except Exception:
                    factor = max(0.70, min(1.80, float(factor)))

                # Apply scaled widths.
                layouts = st.get('layouts') or {}
                for row, info in layouts.items():
                    try:
                        flag = info.get('flag')
                        base_widths = info.get('widths')
                        if not flag or not base_widths:
                            continue
                        new_widths = []
                        for bw in base_widths:
                            try:
                                v = int(round(float(bw) * float(factor)))
                            except Exception:
                                v = int(bw)
                            new_widths.append(max(10, v))
                        _adv_ui_apply_rowlayout_columns(row, flag, tuple(new_widths))
                    except Exception:
                        pass

                ctrls = st.get('ctrls') or {}
                for name, bw in ctrls.items():
                    try:
                        v = int(round(float(bw) * float(factor)))
                    except Exception:
                        v = int(bw)
                    _adv_ui_apply_control_width(name, max(10, v))

                # Drive the window width too so shrink works even when content previously grew.
                try:
                    w.resize(int(round(target_w)), w.height())
                except Exception:
                    pass
            except Exception:
                pass
            return False

    flt = _AdvUiWidthFollowFilter(w)
    _ADV_UI_WIDTH_FOLLOW_FILTERS[key] = flt
    try:
        w.installEventFilter(flt)
    except Exception:
        pass


def _adv_install_ui_auto_scale(window_name, base_w=380, base_h=520):
    """Install event filter to support drag-resize scaling and auto scale on screen move."""
    try:
        from PySide2 import QtCore, QtGui
    except ImportError:
        return

    w = _adv_get_qt_window_widget(window_name)
    if not w:
        return

    key = str(window_name)

    # Clean existing filter if any
    try:
        old = _ADV_UI_SCALE_EVENT_FILTERS.get(key)
        if old:
            w.removeEventFilter(old)
    except Exception:
        pass

    # Timer for debounced rebuild
    timer = _ADV_UI_SCALE_RESIZE_TIMER.get(key)
    if timer is None:
        timer = QtCore.QTimer(w)
        timer.setSingleShot(True)
        _ADV_UI_SCALE_RESIZE_TIMER[key] = timer

    def _schedule_rebuild(factor):
        try:
            _ADV_UI_SCALE_DYNAMIC['v'] = float(factor)
        except Exception:
            pass

        def _do_rebuild():
            try:
                # Rebuild UI with new scale
                create_hierarchy_selection_ui()
            except Exception:
                pass

        try:
            timer.timeout.disconnect()
        except Exception:
            pass
        timer.timeout.connect(_do_rebuild)
        timer.start(300)

    class _AdvUiScaleFilter(QtCore.QObject):
        def __init__(self, parent=None):
            super(_AdvUiScaleFilter, self).__init__(parent)
            self._last_factor = None
            self._ready = False

        def eventFilter(self, obj, event):
            try:
                et = event.type()
                if et == QtCore.QEvent.Resize:
                    # Ignore the first resize on show to avoid flicker
                    if not self._ready:
                        self._ready = True
                        return False

                    # Drag-resize scaling based on window width (only when user drags)
                    try:
                        size = event.size()
                        w_now = float(size.width())
                        if base_w <= 0:
                            return False
                        factor = max(0.7, min(1.6, w_now / float(base_w)))
                        _adv_apply_ui_font_scale(window_name, factor)

                        try:
                            dragging = bool(QtGui.QGuiApplication.mouseButtons())
                        except Exception:
                            dragging = False

                        if dragging and (self._last_factor is None or abs(factor - self._last_factor) >= 0.03):
                            self._last_factor = factor
                            _schedule_rebuild(factor)
                    except Exception:
                        pass

                elif et == QtCore.QEvent.Move:
                    # Auto scale when moved to another screen (only in Auto mode)
                    try:
                        if _adv_ui_scale_get(ADV_UI_SCALE_AUTO) == ADV_UI_SCALE_AUTO:
                            mode = _adv_detect_screen_scale()
                            factor = _ADV_UI_SCALE_FACTORS.get(mode, 1.0)
                            if self._last_factor is None or abs(factor - self._last_factor) >= 0.03:
                                self._last_factor = factor
                                _adv_apply_ui_font_scale(window_name, factor)
                                _schedule_rebuild(factor)
                    except Exception:
                        pass
            except Exception:
                pass
            return False

    flt = _AdvUiScaleFilter(w)
    _ADV_UI_SCALE_EVENT_FILTERS[key] = flt
    w.installEventFilter(flt)

    try:
        from PySide2 import QtWidgets, QtGui
    except ImportError:
        return

    try:
        w = _adv_get_qt_window_widget(window_name)
        if not w:
            return

        base = w.font()
        pt = base.pointSize()
        use_pixel = False
        if pt <= 0:
            pt = base.pixelSize()
            use_pixel = True
        if pt <= 0:
            pt = 10

        new_size = max(7, int(round(pt * factor)))
        font = QtGui.QFont(base)
        if use_pixel:
            font.setPixelSize(new_size)
        else:
            font.setPointSize(new_size)

        w.setFont(font)
        for child in w.findChildren(QtWidgets.QWidget):
            try:
                child.setFont(font)
            except Exception:
                pass
    except Exception:
        return


