_ADV_WORK_UNIT_LINEAR_OPTIONVAR = 'ADV_WorkUnitLinear'
_ADV_WORK_UNIT_ANGLE_OPTIONVAR = 'ADV_WorkUnitAngle'
_ADV_GRID_SIZE_OPTIONVAR = 'ADV_GridSize'
_ADV_GRID_SPACING_OPTIONVAR = 'ADV_GridSpacing'
_ADV_GRID_DIVISIONS_OPTIONVAR = 'ADV_GridDivisions'
_ADV_GRID_COLOR_R_OPTIONVAR = 'ADV_GridColorR'
_ADV_GRID_COLOR_G_OPTIONVAR = 'ADV_GridColorG'
_ADV_GRID_COLOR_B_OPTIONVAR = 'ADV_GridColorB'

# Viewport grid colors (axes / major lines+labels / division lines)
_ADV_GRID_AXIS_COLOR_R_OPTIONVAR = 'ADV_GridAxisColorR'
_ADV_GRID_AXIS_COLOR_G_OPTIONVAR = 'ADV_GridAxisColorG'
_ADV_GRID_AXIS_COLOR_B_OPTIONVAR = 'ADV_GridAxisColorB'
_ADV_GRID_SUBDIV_COLOR_R_OPTIONVAR = 'ADV_GridSubdivColorR'
_ADV_GRID_SUBDIV_COLOR_G_OPTIONVAR = 'ADV_GridSubdivColorG'
_ADV_GRID_SUBDIV_COLOR_B_OPTIONVAR = 'ADV_GridSubdivColorB'

_ADV_UNITS_GRID_SCENEOPEN_SCRIPTJOBS = []

# Camera status UI (shown under Units/Grid)
_ADV_CAMERA_STATUS_PANEL_TEXT = 'advCameraStatusPanelText'
_ADV_CAMERA_STATUS_CAMERA_TEXT = 'advCameraStatusCameraText'
_ADV_CAMERA_STATUS_PROJ_TEXT = 'advCameraStatusProjText'
_ADV_CAMERA_STATUS_CACHE = {'t': 0.0, 'sig': None}


def adv_ui_camera_status_refresh(force=False):
    """Refresh camera status UI (active panel/camera + persp/ortho).

    This is intentionally defensive: it does nothing when the UI is not open.
    """
    try:
        if not cmds.text(_ADV_CAMERA_STATUS_PANEL_TEXT, exists=True):
            return
        if not cmds.text(_ADV_CAMERA_STATUS_CAMERA_TEXT, exists=True):
            return
        if not cmds.text(_ADV_CAMERA_STATUS_PROJ_TEXT, exists=True):
            return
    except Exception:
        return

    # Throttle updates on idle polling.
    try:
        import time as _adv_time
        now = float(_adv_time.time())
    except Exception:
        now = 0.0
    try:
        last_t = float((_ADV_CAMERA_STATUS_CACHE.get('t') or 0.0))
    except Exception:
        last_t = 0.0
    if (not force) and now and (now - last_t) < 0.25:
        return
    _ADV_CAMERA_STATUS_CACHE['t'] = now

    panel = ''
    cam = ''
    cam_tr = ''
    is_ortho = False
    try:
        panel = _adv_get_active_model_panel() or ''
    except Exception:
        panel = ''
    if panel:
        try:
            cam = cmds.modelPanel(panel, q=True, camera=True) or ''
        except Exception:
            cam = ''
    if cam:
        # modelPanel can return a camera shape; normalize to transform for display.
        try:
            if cmds.nodeType(cam) == 'camera':
                p = cmds.listRelatives(cam, parent=True, fullPath=True) or []
                if p:
                    cam_tr = str(p[0])
        except Exception:
            cam_tr = ''
        if not cam_tr:
            cam_tr = str(cam)
        shp = None
        try:
            shp = _adv_get_camera_shape(cam_tr)
        except Exception:
            shp = None
        if shp:
            try:
                is_ortho = bool(cmds.getAttr(str(shp) + '.orthographic'))
            except Exception:
                is_ortho = False

    sig = (str(panel), str(cam_tr), bool(is_ortho))
    if (not force) and (_ADV_CAMERA_STATUS_CACHE.get('sig') == sig):
        return
    _ADV_CAMERA_STATUS_CACHE['sig'] = sig

    def _short(n):
        try:
            return str(n).split('|')[-1]
        except Exception:
            return str(n)

    try:
        cmds.text(_ADV_CAMERA_STATUS_PANEL_TEXT, e=True, label=_short(panel) if panel else '-')
    except Exception:
        pass
    try:
        cmds.text(_ADV_CAMERA_STATUS_CAMERA_TEXT, e=True, label=_short(cam_tr) if cam_tr else '-')
    except Exception:
        pass
    try:
        proj = get_text('camera_proj_ortho') if is_ortho else get_text('camera_proj_persp')
        cmds.text(_ADV_CAMERA_STATUS_PROJ_TEXT, e=True, label=str(proj))
    except Exception:
        pass


def adv_ui_camera_reset():
    """Delete ADV temporary/view cameras and clear cached camera optionVars."""
    def _as_cam_transform(node):
        try:
            n = str(node or '')
            if not n:
                return ''
            if cmds.nodeType(n) == 'camera':
                p = cmds.listRelatives(n, parent=True, fullPath=True) or []
                return str(p[0]) if p else ''
            return n
        except Exception:
            return ''

    def _is_adv_view_tagged(cam_tr):
        try:
            if not cam_tr:
                return False
            leaf = str(cam_tr).split('|')[-1]
            if leaf.startswith('ADV_View_'):
                return True
            if cmds.attributeQuery('advViewCamera', node=cam_tr, exists=True):
                try:
                    return bool(cmds.getAttr(cam_tr + '.advViewCamera'))
                except Exception:
                    return True
        except Exception:
            pass
        return False

    def _do():
        all_cam_shapes = []
        try:
            all_cam_shapes = cmds.ls(type='camera') or []
        except Exception:
            all_cam_shapes = []

        delete_list = []
        temp_cam = ''
        try:
            if cmds.optionVar(exists='ADV_SeamlessViewSwitchTempPerspCamera'):
                temp_cam = _as_cam_transform(cmds.optionVar(q='ADV_SeamlessViewSwitchTempPerspCamera'))
        except Exception:
            temp_cam = ''

        for shp in all_cam_shapes:
            tr = _as_cam_transform(shp)
            if not tr:
                continue
            try:
                if _is_adv_view_tagged(tr):
                    delete_list.append(tr)
                    continue
            except Exception:
                pass
            try:
                if _adv_is_seamless_view_switch_temp_camera(tr):
                    delete_list.append(tr)
                    continue
            except Exception:
                pass

        if temp_cam:
            delete_list.append(temp_cam)

        try:
            delete_list = sorted(set([x for x in delete_list if x and cmds.objExists(x)]))
        except Exception:
            pass

        if delete_list:
            try:
                panel = _adv_get_hover_or_active_model_panel() or _adv_get_active_model_panel()
            except Exception:
                panel = ''
            panel = str(panel or '')
            if panel:
                try:
                    cur_cam = _as_cam_transform(cmds.modelPanel(panel, q=True, camera=True) or '')
                except Exception:
                    cur_cam = ''
                if cur_cam and (cur_cam in delete_list):
                    try:
                        if cmds.objExists('persp'):
                            cmds.lookThru(panel, 'persp')
                        else:
                            repl = _adv_get_best_persp_camera(create_if_missing=True)
                            if repl:
                                cmds.lookThru(panel, repl)
                    except Exception:
                        pass

            for cam in delete_list:
                try:
                    if cmds.objExists(cam):
                        cmds.delete(cam)
                except Exception:
                    pass

        try:
            names = cmds.optionVar(list=True) or []
        except Exception:
            names = []
        for ov in names:
            try:
                ovn = str(ov or '')
            except Exception:
                ovn = ''
            if not ovn:
                continue
            try:
                if ovn.startswith('ADV_ViewCam_'):
                    cmds.optionVar(remove=ovn)
            except Exception:
                pass

        try:
            if cmds.optionVar(exists='ADV_SeamlessViewSwitchTempPerspCamera'):
                cmds.optionVar(remove='ADV_SeamlessViewSwitchTempPerspCamera')
        except Exception:
            pass

        try:
            _ADV_CAMERA_STATUS_CACHE['sig'] = None
        except Exception:
            pass
        try:
            adv_ui_camera_status_refresh(force=True)
        except Exception:
            pass

        try:
            cmds.inViewMessage(
                amg=u'<span style="color:#4a90d9;">%s</span>' % (u'已重置摄影机状态' if LANGUAGE == 'CN' else 'Camera state reset'),
                pos='topCenter',
                fade=True,
                fadeStayTime=1400
            )
        except Exception:
            pass

    try:
        _adv_run_without_undo(_do)
    except Exception:
        _do()
_ADV_HOTKEY_INPUT_GUARD = 0




def _adv_units_grid_ensure_defaults():
    """Seed optionVars from current Maya prefs if missing."""
    # Units
    try:
        if not cmds.optionVar(exists=_ADV_WORK_UNIT_LINEAR_OPTIONVAR):
            try:
                cur_linear = cmds.currentUnit(q=True, linear=True) or 'cm'
            except Exception:
                cur_linear = 'cm'
            cmds.optionVar(sv=(_ADV_WORK_UNIT_LINEAR_OPTIONVAR, str(cur_linear)))
    except Exception:
        pass
    try:
        if not cmds.optionVar(exists=_ADV_WORK_UNIT_ANGLE_OPTIONVAR):
            try:
                cur_angle = cmds.currentUnit(q=True, angle=True) or 'deg'
            except Exception:
                cur_angle = 'deg'
            cmds.optionVar(sv=(_ADV_WORK_UNIT_ANGLE_OPTIONVAR, str(cur_angle)))
    except Exception:
        pass


    # Grid numeric settings
    try:
        if not cmds.optionVar(exists=_ADV_GRID_SIZE_OPTIONVAR):
            try:
                v = float(cmds.grid(q=True, size=True))
            except Exception:
                v = 12.0
            cmds.optionVar(fv=(_ADV_GRID_SIZE_OPTIONVAR, float(v)))
    except Exception:
        pass
    try:
        if not cmds.optionVar(exists=_ADV_GRID_SPACING_OPTIONVAR):
            try:
                v = float(cmds.grid(q=True, spacing=True))
            except Exception:
                v = 5.0
            cmds.optionVar(fv=(_ADV_GRID_SPACING_OPTIONVAR, float(v)))
    except Exception:
        pass
    try:
        if not cmds.optionVar(exists=_ADV_GRID_DIVISIONS_OPTIONVAR):
            try:
                v = int(cmds.grid(q=True, divisions=True))
            except Exception:
                v = 5
            cmds.optionVar(iv=(_ADV_GRID_DIVISIONS_OPTIONVAR, int(v)))
    except Exception:
        pass

    # Viewport grid colors
    # Axis color
    try:
        if (not cmds.optionVar(exists=_ADV_GRID_AXIS_COLOR_R_OPTIONVAR) or
                not cmds.optionVar(exists=_ADV_GRID_AXIS_COLOR_G_OPTIONVAR) or
                not cmds.optionVar(exists=_ADV_GRID_AXIS_COLOR_B_OPTIONVAR)):
            r, g, b = 0.6, 0.6, 0.6
            try:
                c = cmds.grid(q=True, xAxisColor=True) or None
                if c and len(c) >= 3:
                    r, g, b = float(c[0]), float(c[1]), float(c[2])
            except Exception:
                pass
            try:
                cmds.optionVar(fv=(_ADV_GRID_AXIS_COLOR_R_OPTIONVAR, float(r)))
                cmds.optionVar(fv=(_ADV_GRID_AXIS_COLOR_G_OPTIONVAR, float(g)))
                cmds.optionVar(fv=(_ADV_GRID_AXIS_COLOR_B_OPTIONVAR, float(b)))
            except Exception:
                pass
    except Exception:
        pass

    # Major grid lines color
    try:
        if (not cmds.optionVar(exists=_ADV_GRID_COLOR_R_OPTIONVAR) or
                not cmds.optionVar(exists=_ADV_GRID_COLOR_G_OPTIONVAR) or
                not cmds.optionVar(exists=_ADV_GRID_COLOR_B_OPTIONVAR)):
            r, g, b = 0.3, 0.3, 0.3
            try:
                c = cmds.grid(q=True, majorColor=True) or None
                if c and len(c) >= 3:
                    r, g, b = float(c[0]), float(c[1]), float(c[2])
            except Exception:
                pass
            try:
                cmds.optionVar(fv=(_ADV_GRID_COLOR_R_OPTIONVAR, float(r)))
                cmds.optionVar(fv=(_ADV_GRID_COLOR_G_OPTIONVAR, float(g)))
                cmds.optionVar(fv=(_ADV_GRID_COLOR_B_OPTIONVAR, float(b)))
            except Exception:
                pass
    except Exception:
        pass

    # Division/subdiv lines color (minor)
    try:
        if (not cmds.optionVar(exists=_ADV_GRID_SUBDIV_COLOR_R_OPTIONVAR) or
                not cmds.optionVar(exists=_ADV_GRID_SUBDIV_COLOR_G_OPTIONVAR) or
                not cmds.optionVar(exists=_ADV_GRID_SUBDIV_COLOR_B_OPTIONVAR)):
            r, g, b = 0.2, 0.2, 0.2
            try:
                c = cmds.grid(q=True, minorColor=True) or None
                if c and len(c) >= 3:
                    r, g, b = float(c[0]), float(c[1]), float(c[2])
            except Exception:
                pass
            try:
                cmds.optionVar(fv=(_ADV_GRID_SUBDIV_COLOR_R_OPTIONVAR, float(r)))
                cmds.optionVar(fv=(_ADV_GRID_SUBDIV_COLOR_G_OPTIONVAR, float(g)))
                cmds.optionVar(fv=(_ADV_GRID_SUBDIV_COLOR_B_OPTIONVAR, float(b)))
            except Exception:
                pass
    except Exception:
        pass


def _adv_units_grid_get():
    _adv_units_grid_ensure_defaults()
    linear = 'cm'
    angle = 'deg'
    size = 12.0
    spacing = 5.0
    divisions = 5
    r, g, b = 0.3, 0.3, 0.3
    try:
        linear = str(cmds.optionVar(q=_ADV_WORK_UNIT_LINEAR_OPTIONVAR) or 'cm')
    except Exception:
        pass
    try:
        angle = str(cmds.optionVar(q=_ADV_WORK_UNIT_ANGLE_OPTIONVAR) or 'deg')
    except Exception:
        pass
    try:
        size = float(cmds.optionVar(q=_ADV_GRID_SIZE_OPTIONVAR))
    except Exception:
        pass
    try:
        spacing = float(cmds.optionVar(q=_ADV_GRID_SPACING_OPTIONVAR))
    except Exception:
        pass
    try:
        divisions = int(cmds.optionVar(q=_ADV_GRID_DIVISIONS_OPTIONVAR))
    except Exception:
        pass
    try:
        r = float(cmds.optionVar(q=_ADV_GRID_COLOR_R_OPTIONVAR))
        g = float(cmds.optionVar(q=_ADV_GRID_COLOR_G_OPTIONVAR))
        b = float(cmds.optionVar(q=_ADV_GRID_COLOR_B_OPTIONVAR))
    except Exception:
        pass
    return linear, angle, size, spacing, divisions, (r, g, b)


