def _adv_units_grid_set(linear=None, angle=None, size=None, spacing=None, divisions=None, color_rgb=None, axis_color_rgb=None, subdiv_color_rgb=None):
    try:
        if linear is not None:
            cmds.optionVar(sv=(_ADV_WORK_UNIT_LINEAR_OPTIONVAR, str(linear)))
    except Exception:
        pass
    try:
        if angle is not None:
            cmds.optionVar(sv=(_ADV_WORK_UNIT_ANGLE_OPTIONVAR, str(angle)))
    except Exception:
        pass
    try:
        if size is not None:
            cmds.optionVar(fv=(_ADV_GRID_SIZE_OPTIONVAR, float(size)))
    except Exception:
        pass
    try:
        if spacing is not None:
            cmds.optionVar(fv=(_ADV_GRID_SPACING_OPTIONVAR, float(spacing)))
    except Exception:
        pass
    try:
        if divisions is not None:
            cmds.optionVar(iv=(_ADV_GRID_DIVISIONS_OPTIONVAR, int(divisions)))
    except Exception:
        pass
    try:
        if color_rgb is not None and len(color_rgb) >= 3:
            r, g, b = float(color_rgb[0]), float(color_rgb[1]), float(color_rgb[2])
            cmds.optionVar(fv=(_ADV_GRID_COLOR_R_OPTIONVAR, float(r)))
            cmds.optionVar(fv=(_ADV_GRID_COLOR_G_OPTIONVAR, float(g)))
            cmds.optionVar(fv=(_ADV_GRID_COLOR_B_OPTIONVAR, float(b)))
    except Exception:
        pass

    try:
        if axis_color_rgb is not None and len(axis_color_rgb) >= 3:
            r, g, b = float(axis_color_rgb[0]), float(axis_color_rgb[1]), float(axis_color_rgb[2])
            cmds.optionVar(fv=(_ADV_GRID_AXIS_COLOR_R_OPTIONVAR, float(r)))
            cmds.optionVar(fv=(_ADV_GRID_AXIS_COLOR_G_OPTIONVAR, float(g)))
            cmds.optionVar(fv=(_ADV_GRID_AXIS_COLOR_B_OPTIONVAR, float(b)))
    except Exception:
        pass

    try:
        if subdiv_color_rgb is not None and len(subdiv_color_rgb) >= 3:
            r, g, b = float(subdiv_color_rgb[0]), float(subdiv_color_rgb[1]), float(subdiv_color_rgb[2])
            cmds.optionVar(fv=(_ADV_GRID_SUBDIV_COLOR_R_OPTIONVAR, float(r)))
            cmds.optionVar(fv=(_ADV_GRID_SUBDIV_COLOR_G_OPTIONVAR, float(g)))
            cmds.optionVar(fv=(_ADV_GRID_SUBDIV_COLOR_B_OPTIONVAR, float(b)))
    except Exception:
        pass


def _adv_display_rgbcolor_list_entries():
    """Return parsed displayRGBColor(list=True) entries.

    Note: On some Maya builds, `cmds.displayRGBColor(list=True)` returns strings like:
    "background 0.36 0.36 0.36" (name + RGB). On others it may return just names.
    This helper normalizes to (name, rgb_or_None, raw_string).
    """
    try:
        raw = cmds.displayRGBColor(list=True) or []
    except Exception:
        return []

    entries = []
    for item in raw:
        try:
            s = str(item).strip()
        except Exception:
            continue
        if not s:
            continue
        parts = s.split()
        if not parts:
            continue

        name = parts[0]
        rgb = None
        if len(parts) >= 4:
            try:
                rgb = (float(parts[1]), float(parts[2]), float(parts[3]))
            except Exception:
                rgb = None
        entries.append((name, rgb, s))
    return entries


def _adv_set_grid_colors(rgb):
    """Try applying grid-related colors.

    Maya color names vary a bit across versions/locales, so we try a list.
    """
    if not rgb or len(rgb) < 3:
        return
    try:
        r, g, b = float(rgb[0]), float(rgb[1]), float(rgb[2])
    except Exception:
        return

    # Prefer asking Maya for the actual color-name list, then set all grid/axis-related colors.
    entries = _adv_display_rgbcolor_list_entries()
    names = [e[0] for e in (entries or [])]

    targets = []
    try:
        for n in names:
            try:
                nl = str(n).strip().lower()
            except Exception:
                nl = ''
            # Be fuzzy: different Maya builds may use different names.
            if ('grid' in nl) or ('axis' in nl) or ('axes' in nl):
                targets.append(n)
    except Exception:
        targets = []

    # Fallback candidates based on common Maya display color names.
    if not targets:
        targets = [
            'grid',
            'gridHighlight',
            'gridAxis',
            'gridAxes',
            'gridLines',
            'gridLine',
            'gridSubdivisions',
            'gridSubdiv',
            'gridSubdivisionLines',
            'gridSubdivision',
            'gridNumbers',
            'gridText',
            'gridNumeric',
            'axis',
            'axisX',
            'axisY',
            'axisZ',
        ]

    for name in targets:
        try:
            cmds.displayRGBColor(str(name), r, g, b)
        except Exception:
            pass

    try:
        cmds.refresh(f=True)
    except Exception:
        pass


def _adv_set_viewport_grid_colors(axis_rgb, major_rgb, minor_rgb):
    """Apply 3D viewport grid colors (best-effort).

    Try multiple approaches:
    1. cmds.grid color flags (VP2 infinite grid)
    2. displayColor + colorIndex (index color system)
    """
    def _rgba(t):
        try:
            r, g, b = float(t[0]), float(t[1]), float(t[2])
        except Exception:
            r, g, b = 0.3, 0.3, 0.3
        return (r, g, b, 1.0)

    a = _rgba(axis_rgb)
    major = _rgba(major_rgb)
    minor = _rgba(minor_rgb)

    # Method 1: cmds.grid color flags (VP2 infinite grid)
    # Axes
    try:
        cmds.grid(e=True, xAxisColor=a, yAxisColor=a, zAxisColor=a)
    except Exception:
        pass

    # Major/minor lines
    try:
        cmds.grid(e=True, majorColor=major, minorColor=minor)
    except Exception:
        # Some builds may expose only one of these.
        try:
            cmds.grid(e=True, majorColor=major)
        except Exception:
            pass
        try:
            cmds.grid(e=True, minorColor=minor)
        except Exception:
            pass

    # Method 2: Index color system (displayColor + colorIndex)
    # This affects the legacy grid and some VP2 elements
    try:
        # Get the color index used by 'grid'
        grid_idx = cmds.displayColor('grid', q=True, dormant=True)
        if grid_idx is not None and grid_idx > 0:
            # Modify that palette index to our desired RGB
            cmds.colorIndex(grid_idx, major[0], major[1], major[2])
    except Exception:
        pass

    # Best-effort: grid label color (if the Maya build exposes such a flag).
    for flag_name in (
        'labelColor',
        'gridLabelColor',
        'gridTextColor',
        'textColor',
        'numberColor',
        'gridNumberColor',
    ):
        try:
            cmds.grid(e=True, **{flag_name: major})
            break
        except Exception:
            continue

    # Best-effort: if there are any displayRGBColor entries for grid labels/text, set them.
    try:
        entries = _adv_display_rgbcolor_list_entries()
        for name, _rgb, _raw in entries:
            nl = str(name).lower()
            if 'grid' in nl and (('label' in nl) or ('text' in nl) or ('number' in nl)):
                try:
                    cmds.displayRGBColor(name, major[0], major[1], major[2])
                except Exception:
                    pass
    except Exception:
        pass

    try:
        cmds.refresh(f=True)
    except Exception:
        try:
            cmds.refresh()
        except Exception:
            pass


def _adv_debug_grid_colors():
    """Print grid-related display color entries and test apply/query."""
    try:
        print('[ADV] --- Grid Color Diagnostic ---')
    except Exception:
        pass

    entries = _adv_display_rgbcolor_list_entries()
    if not entries:
        try:
            # Still try to report the raw list size if possible.
            raw = cmds.displayRGBColor(list=True) or []
            print('[ADV] displayRGBColor(list=True) returned %d entries, but parsing produced 0.' % (len(raw)))
        except Exception as e:
            try:
                print('[ADV] displayRGBColor(list=True) failed: %s' % str(e))
            except Exception:
                pass
        return

    names = [e[0] for e in entries]
    raw_strings = [e[2] for e in entries]

    try:
        print('[ADV] displayRGBColor list count: %d' % (len(entries)))
    except Exception:
        pass

    # Print a small sample so we can see the naming scheme.
    try:
        sample = []
        for i, s in enumerate(raw_strings):
            if i >= 30:
                break
            try:
                sample.append(str(s))
            except Exception:
                continue
        print('[ADV] sample names (first %d): %s' % (len(sample), ', '.join(sample) if sample else '<none>'))
    except Exception:
        pass

    # Sanity: confirm querying a known entry works.
    try:
        v_bg = cmds.displayRGBColor('background', q=True)
        print('[ADV] sanity query background -> %s' % str(v_bg))
    except Exception as e:
        try:
            print('[ADV] sanity query background failed: %s' % str(e))
        except Exception:
            pass

    # Viewport grid flags sanity (Maya 2022)
    try:
        print('[ADV] viewport grid query:')
    except Exception:
        pass
    for qflag in ('majorColor', 'minorColor', 'xAxisColor', 'yAxisColor', 'zAxisColor', 'displayDivisionLines', 'divisions'):
        try:
            v = cmds.grid(q=True, **{qflag: True})
            print('[ADV]   grid -q %s -> %s' % (qflag, str(v)))
        except Exception as e:
            try:
                print('[ADV]   grid -q %s failed: %s' % (qflag, str(e)))
            except Exception:
                pass

    grid_names = []
    try:
        for n in names:
            try:
                nl = str(n).strip().lower()
                if 'grid' in nl:
                    grid_names.append(str(n).strip())
            except Exception:
                continue
    except Exception:
        grid_names = []

    axis_names = []
    try:
        for n in names:
            try:
                nl = str(n).strip().lower()
                if ('axis' in nl) or ('axes' in nl):
                    axis_names.append(str(n).strip())
            except Exception:
                continue
    except Exception:
        axis_names = []

    try:
        print('[ADV] grid* names (%d): %s' % (len(grid_names), ', '.join(grid_names) if grid_names else '<none>'))
    except Exception:
        pass

    try:
        print('[ADV] axis* names (%d): %s' % (len(axis_names), ', '.join(axis_names) if axis_names else '<none>'))
    except Exception:
        pass

    # Print current values
    for n in grid_names:
        try:
            v = cmds.displayRGBColor(n, q=True)
        except Exception as e:
            v = '<query failed: %s>' % str(e)
        try:
            print('[ADV] %s = %s' % (n, str(v)))
        except Exception:
            pass

    # Probe common candidates even if list has no grid/axis entries.
    candidates = [
        'grid', 'gridHighlight', 'gridAxis', 'gridAxes', 'gridLines', 'gridLine',
        'gridSubdivisions', 'gridSubdiv', 'gridSubdivisionLines', 'gridSubdivision',
        'gridNumbers', 'gridText', 'gridNumeric',
        'axis', 'axisX', 'axisY', 'axisZ'
    ]
    try:
        print('[ADV] candidate probe:')
    except Exception:
        pass
    for c in candidates:
        try:
            v = cmds.displayRGBColor(c, q=True)
            ok = True
        except Exception as e:
            v = '<query failed: %s>' % str(e)
            ok = False
        try:
            print('[ADV]   %s = %s (%s)' % (c, str(v), 'OK' if ok else 'NO'))
        except Exception:
            pass

    # Test set+query on one representative entry
    test_rgb = (0.9, 0.2, 0.2)
    test_name = None
    if grid_names:
        test_name = grid_names[0]
    else:
        for c in candidates:
            try:
                cmds.displayRGBColor(c, q=True)
                test_name = c
                break
            except Exception:
                continue

    if test_name:
        try:
            cmds.displayRGBColor(test_name, *test_rgb)
            v2 = cmds.displayRGBColor(test_name, q=True)
            print('[ADV] TEST set %s -> %s, query back -> %s' % (test_name, str(test_rgb), str(v2)))
        except Exception as e:
            try:
                print('[ADV] TEST set/query failed on %s: %s' % (test_name, str(e)))
            except Exception:
                pass
    else:
        try:
            print('[ADV] No valid grid/axis displayRGBColor entry found to test.')
        except Exception:
            pass

    try:
        cmds.refresh(f=True)
    except Exception:
        pass


def _adv_unit_linear_token_to_label(token):
    t = str(token or 'cm')
    if LANGUAGE == 'CN':
        m = {
            'mm': u'毫米',
            'cm': u'厘米',
            'm': u'米',
            'km': u'公里',
            'in': u'英寸',
            'ft': u'英尺',
            'yd': u'码',
            'mi': u'英里',
        }
        return m.get(t, t)
    return t


