def _adv_units_sync_from_scene_to_optionvars():
    """When opening a scene, read its working units and sync into our optionVars/UI."""
    try:
        cur_linear = cmds.currentUnit(q=True, linear=True) or 'cm'
    except Exception:
        cur_linear = 'cm'
    try:
        cur_angle = cmds.currentUnit(q=True, angle=True) or 'deg'
    except Exception:
        cur_angle = 'deg'

    try:
        cmds.optionVar(sv=(_ADV_WORK_UNIT_LINEAR_OPTIONVAR, str(cur_linear)))
    except Exception:
        pass
    try:
        cmds.optionVar(sv=(_ADV_WORK_UNIT_ANGLE_OPTIONVAR, str(cur_angle)))
    except Exception:
        pass


    # If the UI is open, update dropdowns.
    try:
        if cmds.optionMenu('advUnitLinearOM', exists=True):
            cmds.optionMenu('advUnitLinearOM', e=True, value=_adv_unit_linear_token_to_label(cur_linear))
    except Exception:
        pass
    try:
        if cmds.optionMenu('advUnitAngleOM', exists=True):
            cmds.optionMenu('advUnitAngleOM', e=True, value=_adv_unit_angle_token_to_label(cur_angle))
    except Exception:
        pass


def _adv_units_grid_apply(apply_units=True, apply_grid=True):
    """Apply stored working units + grid settings to Maya.

    Note: on SceneOpened we only apply grid (units are read from the scene).
    """
    linear, angle, size, spacing, divisions, _color_rgb = _adv_units_grid_get()

    if apply_units:
        try:
            cmds.currentUnit(linear=str(linear), angle=str(angle))
        except Exception:
            # Some combinations may fail in certain locales; ignore.
            pass

    if apply_grid:
        try:
            cmds.grid(size=float(size), spacing=float(spacing), divisions=int(divisions))
        except Exception:
            pass

        # Refresh to make sure viewport updates immediately.
        try:
            cmds.refresh()
        except Exception:
            pass


def _adv_units_grid_install_scene_open_scriptjobs(force=False):
    """Install scriptJobs to re-apply units/grid when a scene is opened."""
    global _ADV_UNITS_GRID_SCENEOPEN_SCRIPTJOBS
    if (not force) and _ADV_UNITS_GRID_SCENEOPEN_SCRIPTJOBS:
        return

    try:
        for jid in list(_ADV_UNITS_GRID_SCENEOPEN_SCRIPTJOBS or []):
            try:
                if cmds.scriptJob(exists=jid):
                    cmds.scriptJob(kill=jid, force=True)
            except Exception:
                pass
    except Exception:
        pass
    _ADV_UNITS_GRID_SCENEOPEN_SCRIPTJOBS = []

    def _deferred_apply(*_):
        try:
            _adv_units_sync_from_scene_to_optionvars()
        except Exception:
            pass
        try:
            _adv_units_grid_apply(apply_units=False, apply_grid=True)
        except Exception:
            pass

    for ev in ('SceneOpened', 'NewSceneOpened', 'SceneImported'):
        try:
            jid = cmds.scriptJob(event=[ev, _deferred_apply], protected=True)
            _ADV_UNITS_GRID_SCENEOPEN_SCRIPTJOBS.append(jid)
        except Exception:
            continue




def _adv_units_grid_startup_apply():
    """Best-effort startup apply + install scene-open hooks."""
    try:
        import maya.utils as maya_utils
    except Exception:
        maya_utils = None

    def _do():
        try:
            _adv_units_grid_ensure_defaults()
        except Exception:
            pass
        try:
            _adv_units_sync_from_scene_to_optionvars()
        except Exception:
            pass
        try:
            _adv_units_grid_apply(apply_units=False, apply_grid=True)
        except Exception:
            pass
        try:
            _adv_units_grid_install_scene_open_scriptjobs()
        except Exception:
            pass

    try:
        if maya_utils:
            maya_utils.executeDeferred(_do)
        else:
            _do()
    except Exception:
        try:
            _do()
        except Exception:
            pass


def _adv_remove_usersetup_legacy_blocks():
    """Remove legacy installer blocks from userSetup.py (non-fatal)."""
    import io
    import re

    p = _adv_user_setup_py_path()
    if not p or not os.path.isfile(p):
        return False

    old = ''
    try:
        with io.open(p, 'r', encoding='utf-8') as f:
            old = f.read()
    except Exception:
        try:
            with io.open(p, 'r', encoding='gbk') as f:
                old = f.read()
        except Exception:
            old = ''

    if not old:
        return False

    new = old
    # Legacy marker from adv_fast_select_installer.py
    try:
        b = '# >>> ADV Fast Select Legacy SetKey Fix >>>'
        e = '# <<< ADV Fast Select Legacy SetKey Fix <<<'
        pat = re.compile(re.escape(b) + r".*?" + re.escape(e) + r"\s*", re.S)
        new = re.sub(pat, '', new)
    except Exception:
        pass

    # Our auto-start marker is handled by _adv_update_user_setup_autostart(False),
    # but remove defensively in case of partial writes.
    try:
        pat2 = re.compile(re.escape(_ADV_AUTOSTART_MARK_BEGIN) + r".*?" + re.escape(_ADV_AUTOSTART_MARK_END) + r"\s*", re.S)
        new = re.sub(pat2, '', new)
    except Exception:
        pass

    if new == old:
        return False

    try:
        with io.open(p, 'w', encoding='utf-8') as f:
            f.write(new)
        return True
    except Exception:
        return False


def _adv_remove_adv_optionvars():
    """Remove all optionVars that start with 'ADV_' (best-effort)."""
    removed = 0
    try:
        names = cmds.optionVar(list=True) or []
    except Exception:
        names = []
    for n in names:
        try:
            ns = str(n)
        except Exception:
            continue
        if not ns.startswith('ADV_'):
            continue
        try:
            if cmds.optionVar(exists=ns):
                cmds.optionVar(remove=ns)
                removed += 1
        except Exception:
            pass
    return int(removed)


def _adv_remove_shelf_buttons_for_adv():
    """Remove shelfButton(s) that launch ADV Fast Select (best-effort)."""
    removed = 0
    try:
        if not cmds.control('ShelfLayout', exists=True):
            return 0
    except Exception:
        return 0

    try:
        tabs = cmds.tabLayout('ShelfLayout', q=True, ca=True) or []
    except Exception:
        tabs = []

    needles = (
        'ADV蹇选择夋嫨鐖跺瓙.py',
        'ADV鎺у埗鍣ㄥ眰绾ч€夋嫨工具',
        'ADV Fast Select',
        'ADV蹇选择夋嫨鐖跺瓙',
    )

    for tab in tabs:
        try:
            buttons = cmds.shelfLayout(tab, q=True, ca=True) or []
        except Exception:
            buttons = []
        for b in buttons:
            try:
                cmd = cmds.shelfButton(b, q=True, command=True) or ''
            except Exception:
                cmd = ''
            try:
                ann = cmds.shelfButton(b, q=True, annotation=True) or ''
            except Exception:
                ann = ''
            try:
                lbl = cmds.shelfButton(b, q=True, label=True) or ''
            except Exception:
                lbl = ''
            blob = (str(cmd) + ' ' + str(ann)).lower()
            hit = False
            for n in needles:
                try:
                    if str(n).lower() in blob:
                        hit = True
                        break
                except Exception:
                    pass
            if not hit:
                # common label used by installer
                try:
                    if str(lbl).strip().lower() == 'adv' and '灞傜骇' in str(ann):
                        hit = True
                except Exception:
                    pass
            if not hit:
                continue
            try:
                cmds.deleteUI(b)
                removed += 1
            except Exception:
                pass
    return int(removed)


def _adv_find_installed_dirs_under_user_scripts():
    """Find candidate installed ADV folders under Maya userScriptDir."""
    user_scripts = ''
    try:
        user_scripts = cmds.internalVar(userScriptDir=True) or ''
    except Exception:
        user_scripts = ''
    user_scripts = user_scripts or ''
    if not user_scripts:
        return []
    try:
        user_scripts = os.path.abspath(user_scripts)
    except Exception:
        return []

    candidates = []

    # 1) If we have a persisted path, use its folder.
    try:
        if cmds.optionVar(exists='ADV_FastSelectScriptPath'):
            sp = cmds.optionVar(q='ADV_FastSelectScriptPath') or ''
            if sp:
                d = os.path.dirname(sp)
                if d and os.path.isdir(d):
                    candidates.append(os.path.abspath(d))
    except Exception:
        pass

    # 2) Known folder names used by packages.
    for name in ('ADV Fast select', 'ADV Fast select 2', 'ADV Fast Select', 'ADV_Fast_select'):
        try:
            d = os.path.join(user_scripts, name)
            if os.path.isdir(d):
                candidates.append(os.path.abspath(d))
        except Exception:
            pass

    # 3) Scan user scripts for folders that contain the main file.
    try:
        for entry in os.listdir(user_scripts):
            d = os.path.join(user_scripts, entry)
            if not os.path.isdir(d):
                continue
            main_py = os.path.join(d, u'ADV蹇选择夋嫨鐖跺瓙.py')
            if os.path.isfile(main_py):
                candidates.append(os.path.abspath(d))
    except Exception:
        pass

    # De-dup
    out = []
    seen = set()
    for d in candidates:
        dl = ''
        try:
            dl = os.path.abspath(d).lower()
        except Exception:
            dl = str(d)
        if dl in seen:
            continue
        seen.add(dl)
        out.append(d)
    return out


def _adv_delete_dirs(dirs):
    """Delete directories (best-effort). Returns (removed_paths, failed_paths)."""
    import shutil

    removed = []
    failed = []
    for d in dirs:
        try:
            if not d or not os.path.isdir(d):
                continue
            # Safety: only delete folders under userScriptDir
            base = ''
            try:
                base = os.path.abspath(cmds.internalVar(userScriptDir=True) or '')
            except Exception:
                base = ''
            try:
                if base:
                    if not os.path.abspath(d).lower().startswith(os.path.abspath(base).lower()):
                        continue
            except Exception:
                pass

            shutil.rmtree(d, ignore_errors=False)
            removed.append(d)
        except Exception:
            failed.append(d)
    return removed, failed


def adv_uninstall():
    """Uninstall ADV Fast Select (best-effort cleanup).

    Notes:
    - Deletes only installed folder(s) under Maya userScriptDir.
    - Removes shelf buttons that reference this tool.
    - Clears ADV_* optionVars.
    """
    try:
        r = cmds.confirmDialog(
            title=get_text('uninstall_confirm_title'),
            message=get_text('uninstall_confirm_msg'),
            button=[u'确定' if LANGUAGE == 'CN' else 'OK', u'取消' if LANGUAGE == 'CN' else 'Cancel'],
            defaultButton=(u'确定' if LANGUAGE == 'CN' else 'OK'),
            cancelButton=(u'取消' if LANGUAGE == 'CN' else 'Cancel'),
            dismissString=(u'取消' if LANGUAGE == 'CN' else 'Cancel'),
        )
        if r != (u'确定' if LANGUAGE == 'CN' else 'OK'):
            return
    except Exception:
        # If confirm fails, do nothing.
        return

    removed_items = []
    failed_items = []

    # 1) Turn off runtime features and filters (restore Maya default behavior as much as possible)
    try:
        _adv_remove_time_slider_clear_key_event_filter()
    except Exception:
        pass
    try:
        _adv_remove_hotkey_fallback_filter()
    except Exception:
        pass
    try:
        # disable key repeat and remove its filter
        cmds.optionVar(iv=('ADV_KeyRepeatEnabled', 0))
        _adv_install_key_repeat_filter(force=True)
    except Exception:
        pass
    try:
        _adv_set_axis_popup_enabled(False)
    except Exception:
        pass
    try:
        _adv_set_time_slider_drag_enabled(False)
    except Exception:
        pass
    try:
        _adv_set_autostart_enabled(False)
        removed_items.append('userSetup.py(auto-start)')
    except Exception:
        failed_items.append('userSetup.py(auto-start)')

    # 2) Remove shelf button(s)
    try:
        n = _adv_remove_shelf_buttons_for_adv()
        if n:
            removed_items.append('shelfButton(x%d)' % int(n))
    except Exception:
        pass

    # 3) Remove legacy userSetup blocks (installer snippet)
    try:
        if _adv_remove_usersetup_legacy_blocks():
            removed_items.append('userSetup.py(legacy)')
    except Exception:
        pass

    # 4) Delete installed folder(s) under user scripts
    try:
        dirs = _adv_find_installed_dirs_under_user_scripts()
        rm, fl = _adv_delete_dirs(dirs)
        for p in rm:
            removed_items.append(p)
        for p in fl:
            failed_items.append(p)
    except Exception:
        pass

    # 5) Remove legacy config file in userPrefDir
    try:
        p = _adv_sr_legacy_groups_storage_path()
        if p and os.path.isfile(p):
            try:
                os.remove(p)
                removed_items.append(p)
            except Exception:
                failed_items.append(p)
    except Exception:
        pass

    # 6) Clear ADV_* optionVars
    try:
        n = _adv_remove_adv_optionvars()
        if n:
            removed_items.append('optionVar(ADV_*) x%d' % int(n))
    except Exception:
        pass

    try:
        msg = get_text('uninstall_done') % ("\n".join(removed_items) if removed_items else '-', "\n".join(failed_items) if failed_items else '-')
        cmds.confirmDialog(title=get_text('uninstall_confirm_title'), message=msg, button=[u'确定' if LANGUAGE == 'CN' else 'OK'])
    except Exception as e:
        try:
            cmds.warning(get_text('uninstall_failed') % str(e))
        except Exception:
            pass


def _adv_axis_popup_is_enabled(default=True):
    try:
        if cmds.optionVar(exists=_ADV_AXIS_POPUP_ENABLED_OPTIONVAR):
            return bool(cmds.optionVar(q=_ADV_AXIS_POPUP_ENABLED_OPTIONVAR))
    except Exception:
        pass
    return bool(default)


def _adv_axis_popup_get_trigger_spec(default=_ADV_AXIS_POPUP_TRIGGER_DEFAULT):
    try:
        if cmds.optionVar(exists=_ADV_AXIS_POPUP_TRIGGER_OPTIONVAR):
            v = cmds.optionVar(q=_ADV_AXIS_POPUP_TRIGGER_OPTIONVAR) or ''
            v = str(v).strip()
            if v:
                return v
    except Exception:
        pass
    return str(default or _ADV_AXIS_POPUP_TRIGGER_DEFAULT)


def _adv_axis_popup_set_trigger_spec(spec):
    """Persist axis popup trigger spec to optionVar.

    Empty/None will remove the optionVar and fall back to default.
    """
    try:
        v = ''
        try:
            v = str(spec or '').strip().lower()
        except Exception:
            v = ''

        if not v:
            try:
                if cmds.optionVar(exists=_ADV_AXIS_POPUP_TRIGGER_OPTIONVAR):
                    cmds.optionVar(remove=_ADV_AXIS_POPUP_TRIGGER_OPTIONVAR)
            except Exception:
                pass
            return _adv_axis_popup_get_trigger_spec(default=_ADV_AXIS_POPUP_TRIGGER_DEFAULT)

        # Normalize common separators.
        v = v.replace('|', '+').replace(' ', '')
        try:
            cmds.optionVar(stringValue=(_ADV_AXIS_POPUP_TRIGGER_OPTIONVAR, v))
        except Exception:
            pass
        return v
    except Exception:
        return _adv_axis_popup_get_trigger_spec(default=_ADV_AXIS_POPUP_TRIGGER_DEFAULT)


def _adv_axis_popup_trigger_display(spec=None, lang_cn=None):
    """Return a user-facing display string for the current axis popup trigger."""
    if lang_cn is None:
        try:
            lang_cn = (LANGUAGE == 'CN')
        except Exception:
            lang_cn = True
    try:
        s = str(spec or _adv_axis_popup_get_trigger_spec()).strip().lower()
    except Exception:
        s = _ADV_AXIS_POPUP_TRIGGER_DEFAULT
    s = s.replace('|', '+').replace(' ', '')
    tokens = [t for t in s.split('+') if t]

    mods = []
    btn = None
    for t in tokens:
        if t in ('ctrl', 'control'):
            mods.append('Ctrl')
        elif t == 'alt':
            mods.append('Alt')
        elif t == 'shift':
            mods.append('Shift')
        elif t in ('lmb', 'left', 'mouse1', 'mb1'):
            btn = (u'左键' if lang_cn else 'LMB')
        elif t in ('mmb', 'middle', 'mouse2', 'mb2'):
            btn = (u'中键' if lang_cn else 'MMB')
        elif t in ('rmb', 'right', 'mouse3', 'mb3'):
            btn = (u'右键' if lang_cn else 'RMB')

    if btn is None:
        btn = (u'右键' if lang_cn else 'RMB')

    parts = []
    parts.extend(mods)
    parts.append(btn)
    return '+'.join([p for p in parts if p])


def _adv_axis_popup_remove_stale_filters():
    """Best-effort cleanup for duplicate/stale axis_popup Qt event filters."""
    try:
        import gc
        try:
            from PySide2 import QtWidgets  # type: ignore
        except ImportError:
            from PySide6 import QtWidgets  # type: ignore
        app = QtWidgets.QApplication.instance()
        if not app:
            return 0
    except ImportError:
        return 0

    removed = 0
    for o in gc.get_objects():
        try:
            cls = getattr(o, '__class__', None)
            mod = str(getattr(cls, '__module__', '') or '')
            if getattr(cls, '__name__', '') != 'AltRMBEventFilter' or 'axis_popup.core.event_filter' not in mod:
                continue
            try:
                app.removeEventFilter(o)
                removed += 1
            except Exception:
                pass
            try:
                o.reset()
            except Exception:
                pass
        except Exception:
            continue
    return removed


def _adv_axis_popup_patch_menu_no_shadow():
    """Patch vendored axis_popup menus to avoid Qt shadow artifacts."""
    try:
        try:
            from PySide2 import QtCore  # type: ignore
        except ImportError:
            from PySide6 import QtCore  # type: ignore
    except ImportError:
        return False

    try:
        import axis_popup.core.menu as _ap_menu
    except ImportError:
        return False

    def _patch_class(cls, disable_mask=False):
        if not cls:
            return False
        if getattr(cls, '_adv_no_shadow_patch_applied', False):
            return True
        _orig_init = getattr(cls, '__init__', None)
        if not callable(_orig_init):
            return False

        def _patched_init(self, parent=None, _orig=_orig_init):
            _orig(self, parent)
            try:
                flags = self.windowFlags()
                if hasattr(QtCore.Qt, 'NoDropShadowWindowHint'):
                    flags = flags | QtCore.Qt.NoDropShadowWindowHint
                self.setWindowFlags(flags)
            except Exception:
                pass
            try:
                self.setAttribute(QtCore.Qt.WA_TranslucentBackground, False)
            except Exception:
                pass
            try:
                self.setGraphicsEffect(None)
            except Exception:
                pass
            try:
                self.setStyleSheet("QMenu{border:0px;padding:0px;background:palette(window);}")
            except Exception:
                pass

        try:
            cls.__init__ = _patched_init
        except Exception:
            return False

        if disable_mask and hasattr(cls, '_apply_mask'):
            def _patched_apply_mask(self):
                try:
                    self.clearMask()
                except Exception:
                    pass
            try:
                cls._apply_mask = _patched_apply_mask
            except Exception:
                pass

        cls._adv_no_shadow_patch_applied = True
        return True

    ok = False
    ok = _patch_class(getattr(_ap_menu, 'AxisPopupMenu', None)) or ok
    ok = _patch_class(getattr(_ap_menu, 'AxisPopupTwoColumnMenu', None), disable_mask=False) or ok
    return ok


def _adv_import_vendored_axis_popup():
    """Import vendored axis_popup from this ADV folder.

    If an external axis_popup is already loaded, try to uninstall it and reload
    from the vendored path so enable/disable works reliably.
    """
    try:
        err = ''
        def _patch_menu_no_shadow():
            try:
                _adv_axis_popup_patch_menu_no_shadow()
            except Exception:
                pass

        adv_root = ''
        scripts_root = ''
        try:
            scripts_root = _adv_local_scripts_path() or ''
        except Exception:
            scripts_root = ''
        if scripts_root:
            try:
                adv_root = os.path.dirname(os.path.abspath(str(scripts_root)))
            except Exception:
                adv_root = ''

        if not scripts_root:
            try:
                if cmds.optionVar(exists='ADV_FastSelectLocalScriptsDir'):
                    p = cmds.optionVar(q='ADV_FastSelectLocalScriptsDir') or ''
                    if p and os.path.isdir(p):
                        scripts_root = p
                        try:
                            adv_root = os.path.dirname(os.path.abspath(str(scripts_root)))
                        except Exception:
                            adv_root = ''
            except Exception:
                pass

        try:
            if cmds.optionVar(exists='ADV_FastSelectScriptPath'):
                sp = cmds.optionVar(q='ADV_FastSelectScriptPath') or ''
                if sp and os.path.isfile(sp):
                    adv_root = os.path.dirname(os.path.abspath(sp))
        except Exception:
            adv_root = ''
        if not adv_root:
            try:
                adv_root = os.path.abspath(os.path.dirname(__file__))
            except Exception:
                adv_root = ''
        if not scripts_root:
            scripts_root = os.path.join(adv_root, 'scripts')

        # Prefer scripts/axis_popup (packaging-friendly)
        try:
            scripts_root = os.path.abspath(str(scripts_root))
            adv_root = os.path.abspath(str(adv_root))
            scripts_root = scripts_root.replace('\\', '/')
            adv_root = adv_root.replace('\\', '/')
        except Exception:
            pass

        if scripts_root and scripts_root not in sys.path:
            sys.path.insert(0, scripts_root)
        if adv_root and adv_root not in sys.path:
            sys.path.insert(0, adv_root)

        axis_pkg_dir = os.path.join(scripts_root, 'axis_popup') if scripts_root else ''
        axis_init = os.path.join(axis_pkg_dir, '__init__.py') if axis_pkg_dir else ''

        existing = sys.modules.get('axis_popup')
        if existing is not None:
            try:
                keep = False
                try:
                    ef = getattr(existing, '__file__', '') or ''
                    ef = str(ef).replace('\\', '/')
                    if scripts_root and ('%s/axis_popup' % scripts_root) in ef:
                        keep = True
                except Exception:
                    keep = False
                if not keep:
                    try:
                        if hasattr(existing, 'uninstall'):
                            existing.uninstall()
                    except Exception:
                        pass
                    for k in list(sys.modules.keys()):
                        if k == 'axis_popup' or k.startswith('axis_popup.'):
                            try:
                                del sys.modules[k]
                            except Exception:
                                pass
            except Exception:
                pass

        try:
            import axis_popup
            _patch_menu_no_shadow()
            return axis_popup
        except Exception as e:
            try:
                err = str(e)
            except Exception:
                err = 'import axis_popup failed'

        try:
            if axis_init and os.path.isfile(axis_init):
                try:
                    import importlib.util as iu
                    spec = iu.spec_from_file_location('axis_popup', axis_init, submodule_search_locations=[axis_pkg_dir])
                    if spec and spec.loader:
                        mod = iu.module_from_spec(spec)
                        sys.modules['axis_popup'] = mod
                        spec.loader.exec_module(mod)
                        _patch_menu_no_shadow()
                        return mod
                except Exception:
                    pass
                try:
                    import imp
                    mod = imp.load_source('axis_popup', axis_init)
                    try:
                        mod.__path__ = [axis_pkg_dir]
                    except Exception:
                        pass
                    sys.modules['axis_popup'] = mod
                    _patch_menu_no_shadow()
                    return mod
                except Exception:
                    pass
        except Exception:
            pass
        try:
            if err:
                cmds.optionVar(sv=('ADV_AxisPopupLastError', str(err)))
        except Exception:
            pass
        return None
    except Exception:
        return None


def _adv_apply_axis_popup_enabled_state(enabled=None):
    if enabled is None:
        enabled = _adv_axis_popup_is_enabled(default=True)
    axis_popup = _adv_import_vendored_axis_popup()
    if not axis_popup:
        return False
    try:
        def _reset_axis_popup():
            try:
                if hasattr(axis_popup, 'uninstall'):
                    axis_popup.uninstall()
            except Exception:
                pass
            try:
                _adv_axis_popup_remove_stale_filters()
            except Exception:
                pass

        if enabled:
            _reset_axis_popup()
            ok = bool(axis_popup.install())
            if not ok:
                try:
                    import maya.utils as maya_utils
                    maya_utils.executeDeferred(lambda: axis_popup.install())
                except Exception:
                    pass
        else:
            _reset_axis_popup()
        return True
    except Exception:
        return False


def _adv_set_axis_popup_enabled(enabled):
    try:
        cmds.optionVar(intValue=(_ADV_AXIS_POPUP_ENABLED_OPTIONVAR, 1 if enabled else 0))
    except Exception:
        pass
    _adv_apply_axis_popup_enabled_state(enabled=enabled)


def _adv_ui_capture_mouse_trigger_spec_qt(parent=None, current_spec=None):
    """Capture a modifier+mouse-button trigger spec via a small Qt dialog.

    Returns a normalized spec string like "alt+rmb", or None if cancelled.
    """
    try:
        try:
            from PySide2 import QtCore, QtWidgets  # type: ignore
        except ImportError:
            from PySide6 import QtCore, QtWidgets  # type: ignore
    except ImportError:
        return None

    class _CaptureArea(QtWidgets.QFrame):
        def __init__(self, on_captured, parent=None):
            super(_CaptureArea, self).__init__(parent)
            self._on_captured = on_captured
            self.setFrameShape(QtWidgets.QFrame.StyledPanel)
            self.setMinimumHeight(72)
            lay = QtWidgets.QVBoxLayout(self)
            lay.setContentsMargins(10, 10, 10, 10)
            lab = QtWidgets.QLabel(
                (u"在这里按下新的触发：例如 Alt+右键 / Ctrl+Alt+右键" if LANGUAGE == 'CN' else
                 "Press a new trigger here, e.g. Alt+RMB / Ctrl+Alt+RMB")
            )
            lab.setWordWrap(True)
            lay.addWidget(lab)

        def mousePressEvent(self, event):
            try:
                mods = event.modifiers()
                btn = event.button()
            except Exception:
                return

            parts = []
            try:
                if mods & QtCore.Qt.ControlModifier:
                    parts.append('ctrl')
                if mods & QtCore.Qt.AltModifier:
                    parts.append('alt')
                if mods & QtCore.Qt.ShiftModifier:
                    parts.append('shift')
            except Exception:
                pass

            b = None
            try:
                if btn == QtCore.Qt.LeftButton:
                    b = 'lmb'
                elif btn == QtCore.Qt.MiddleButton:
                    b = 'mmb'
                elif btn == QtCore.Qt.RightButton:
                    b = 'rmb'
            except Exception:
                b = None

            if not b:
                return
            parts.append(b)
            spec = '+'.join(parts)
            try:
                self._on_captured(spec)
            except Exception:
                pass

    dlg = QtWidgets.QDialog(parent)
    dlg.setWindowTitle(get_text('custom_menu_bar'))
    dlg.setModal(True)
    dlg.setMinimumWidth(420)

    outer = QtWidgets.QVBoxLayout(dlg)
    outer.setContentsMargins(10, 10, 10, 10)
    outer.setSpacing(8)

    cur = _adv_axis_popup_trigger_display(current_spec, lang_cn=(LANGUAGE == 'CN'))
    cur_lab = QtWidgets.QLabel((u"当前:?s" % cur) if LANGUAGE == 'CN' else ("Current: %s" % cur))
    outer.addWidget(cur_lab)

    captured = {'spec': None}

    def _on_captured(spec):
        captured['spec'] = spec
        try:
            dlg.accept()
        except Exception:
            pass

    area = _CaptureArea(_on_captured, dlg)
    outer.addWidget(area)

    btn_row = QtWidgets.QHBoxLayout()
    btn_row.addStretch(1)

    reset_btn = QtWidgets.QPushButton((u"閲嶇疆榛樿" if LANGUAGE == 'CN' else 'Reset'))
    cancel_btn = QtWidgets.QPushButton((u"??" if LANGUAGE == 'CN' else 'Cancel'))

    def _on_reset():
        captured['spec'] = _ADV_AXIS_POPUP_TRIGGER_DEFAULT
        try:
            dlg.accept()
        except Exception:
            pass

    def _on_cancel():
        captured['spec'] = None
        try:
            dlg.reject()
        except Exception:
            pass

    reset_btn.clicked.connect(_on_reset)
    cancel_btn.clicked.connect(_on_cancel)

    btn_row.addWidget(reset_btn)
    btn_row.addWidget(cancel_btn)
    outer.addLayout(btn_row)

    try:
        area.setFocus()
    except Exception:
        pass

    # Guard: prevent axis_popup event filter from stealing the capture click.
    try:
        cmds.optionVar(iv=('ADV_AxisPopupCaptureActive', 1))
    except Exception:
        pass

    try:
        exec_fn = getattr(dlg, 'exec_', None)
        if not callable(exec_fn):
            exec_fn = getattr(dlg, 'exec', None)
        if callable(exec_fn):
            exec_fn()
    finally:
        try:
            if cmds.optionVar(exists='ADV_AxisPopupCaptureActive'):
                cmds.optionVar(remove='ADV_AxisPopupCaptureActive')
        except Exception:
            pass

    return captured.get('spec')


def _adv_ui_edit_axis_popup_trigger(parent=None):
    """UI helper to change axis popup trigger. Returns the new spec or None."""
    cur = _adv_axis_popup_get_trigger_spec(default=_ADV_AXIS_POPUP_TRIGGER_DEFAULT)
    spec = _adv_ui_capture_mouse_trigger_spec_qt(parent=parent, current_spec=cur)
    if spec is None:
        # Fallback: text input (for non-Qt environments)
        try:
            txt = cmds.promptDialog(
                title=get_text('custom_menu_bar'),
                message="Enter trigger (e.g. alt+rmb / ctrl+alt+rmb)",
                button=['OK', 'Cancel'],
                defaultButton='OK',
                cancelButton='Cancel',
                dismissString='Cancel',
                text=str(cur or ''),
            )
            if txt != 'OK':
                return None
            spec = cmds.promptDialog(q=True, text=True) or ''
        except Exception:
            return None

    spec = str(spec or '').strip().lower()
    if not spec:
        return None
    _adv_axis_popup_set_trigger_spec(spec)
    return spec


def _adv_ui_edit_axis_popup_trigger_cmds(button_name=None, checkbox_name='axisPopupRowEnableCB'):
    """Cmds UI wrapper: edit trigger then refresh UI labels if controls exist."""
    try:
        # Prefer Maya main window as parent if possible.
        parent = None
        try:
            parent = _adv_get_maya_main_qt_window()
        except Exception:
            parent = None

        new_spec = _adv_ui_edit_axis_popup_trigger(parent=parent)
        if not new_spec:
            return

        disp = _adv_axis_popup_trigger_display(lang_cn=(LANGUAGE == 'CN'))
        try:
            if button_name and cmds.button(button_name, exists=True):
                cmds.button(button_name, e=True, label=disp)
        except Exception:
            pass

        try:
            if checkbox_name and cmds.checkBox(checkbox_name, exists=True):
                hint = u"(%s)" % disp if disp else ''
                cmds.checkBox(
                    checkbox_name,
                    e=True,
                    label=(get_text('custom_menu_bar') + (' ' + hint if hint else '')),
                    annotation=("Enable %s custom menu" % disp),
                )
        except Exception:
            pass
    except Exception:
        pass


