def apply_hotkey(type_name, hotkey_str):
    """Apply hotkey from string (format: 'modifier|key' or 'key')"""
    global CURRENT_PARENT_HOTKEY, CURRENT_CHILD_HOTKEY, CURRENT_ALL_CHILD_HOTKEY, CURRENT_RESET_LAYER_HOTKEY
    global CURRENT_VIEW_LEFT_HOTKEY, CURRENT_VIEW_RIGHT_HOTKEY, CURRENT_VIEW_FRONT_HOTKEY, CURRENT_VIEW_BACK_HOTKEY, CURRENT_VIEW_PERSP_HOTKEY, CURRENT_VIEW_TOP_HOTKEY, CURRENT_PLAY_TOGGLE_HOTKEY, CURRENT_SET_KEY_HOTKEY, CURRENT_FILE_OPEN_HOTKEY, CURRENT_FILE_SAVE_HOTKEY, CURRENT_FILE_SAVE_AS_HOTKEY, CURRENT_TIME_SLIDER_HOTKEY, CURRENT_TIME_SLIDER_CLEARKEY_HOTKEY
    global CURRENT_PREV_FRAME_HOTKEY, CURRENT_NEXT_FRAME_HOTKEY, CURRENT_PREV_KEYFRAME_HOTKEY, CURRENT_NEXT_KEYFRAME_HOTKEY
    global CURRENT_FOCUS_OBJECT_HOTKEY
