    _ADV_UNITS_HOTKEY_SET = 'ADV_TempNoHotkeys'

    def _adv_units_hotkey_block_enter():
        try:
            if _ADV_UNITS_HOTKEY_BLOCK['count'] == 0:
                prev = None
                try:
                    prev = cmds.hotkeySet(q=True, current=True)
                except Exception:
                    prev = None
                _ADV_UNITS_HOTKEY_BLOCK['prev'] = prev

                # Ensure a temp hotkey set exists
                try:
                    if not cmds.hotkeySet(_ADV_UNITS_HOTKEY_SET, exists=True):
                        try:
                            cmds.hotkeySet(_ADV_UNITS_HOTKEY_SET, source=str(prev) if prev else '')
                        except Exception:
                            cmds.hotkeySet(_ADV_UNITS_HOTKEY_SET)
                except Exception:
                    pass

                try:
                    mel.eval('hotkeySet -e -current "%s"' % str(_ADV_UNITS_HOTKEY_SET))
                except Exception:
                    pass

                # Clear common numeric hotkeys on the temp set so typing won't trigger them.
                for k in '0123456789':
                    try:
                        cmds.hotkey(k=k, alt=False, ctl=False, sht=False, name='', releaseName='')
                    except Exception:
                        pass

            _ADV_UNITS_HOTKEY_BLOCK['count'] += 1
            try:
                global _ADV_HOTKEY_INPUT_GUARD
                _ADV_HOTKEY_INPUT_GUARD = max(0, int(_ADV_HOTKEY_INPUT_GUARD)) + 1
            except Exception:
                pass
        except Exception:
            pass

    def _adv_units_hotkey_block_leave():
        try:
            _ADV_UNITS_HOTKEY_BLOCK['count'] = max(0, int(_ADV_UNITS_HOTKEY_BLOCK['count']) - 1)
            if _ADV_UNITS_HOTKEY_BLOCK['count'] == 0:
                prev = _ADV_UNITS_HOTKEY_BLOCK.get('prev')
                if prev:
                    try:
                        mel.eval('hotkeySet -e -current "%s"' % str(prev))
                    except Exception:
                        pass
            try:
                global _ADV_HOTKEY_INPUT_GUARD
                _ADV_HOTKEY_INPUT_GUARD = max(0, int(_ADV_HOTKEY_INPUT_GUARD) - 1)
            except Exception:
                pass
        except Exception:
            pass

    def _adv_units_qt_embed(layout_name):
        """Embed Qt units/grid editor into a cmds layout; return True on success."""
        try:
            from maya import OpenMayaUI as omui
            shiboken = None
            QtWidgets = None
            QtCore = None
            try:
                import shiboken2 as shiboken  # type: ignore
                from PySide2 import QtWidgets, QtCore  # type: ignore
            except ImportError:
                import shiboken6 as shiboken  # type: ignore
                from PySide6 import QtWidgets, QtCore  # type: ignore
        except ImportError:
            return False

        ptr = None
        try:
            ptr = omui.MQtUtil.findLayout(layout_name)
        except Exception:
            ptr = None
        if not ptr:
            return False
        try:
            parent = shiboken.wrapInstance(int(ptr), QtWidgets.QWidget)
        except Exception:
            try:
                parent = shiboken.wrapInstance(long(ptr), QtWidgets.QWidget)  # type: ignore[name-defined]
            except Exception:
                parent = None
        if parent is None:
            return False

        try:
            if _ADV_UNITS_QT_EMBED['w'] is not None:
                try:
                    if getattr(shiboken, 'isValid', lambda *_: True)(_ADV_UNITS_QT_EMBED['w']):
                        _ADV_UNITS_QT_EMBED['w'].deleteLater()
                except Exception:
                    pass
        except Exception:
            pass

        panel = QtWidgets.QWidget(parent)
        lay = QtWidgets.QGridLayout(panel)
        lay.setContentsMargins(0, 0, 0, 0)
        try:
            _qt_factor = float(_adv_get_ui_scale_factor())
        except Exception:
            _qt_factor = 1.0

        def _qt_s(v):
            try:
                return int(round(float(v) * _qt_factor))
            except Exception:
                try:
                    return int(v)
                except Exception:
                    return 0

