def open_macro_menu(*_):
    """Open the controller hierarchy macro menu editor window."""
    try:
        if open_macro_menu_qt():
            return
    except Exception:
        pass
    return open_macro_menu_cmds()


def open_macro_menu_cmds(*_):
    """Open the controller hierarchy macro menu editor window (cmds UI)."""
    window_name = "controllerMacroMenu"

    def _adv_preset_io_default_dir():
        try:
            p = cmds.internalVar(userAppDir=True)
            return p.replace('\\', '/') if p else ''
        except Exception:
            return ''

    def adv_export_presets_to_file(*_):
        # Unified export: Macro + SyncKey groups + SwitchRuntime groups
        return adv_export_all_presets_to_file()


    def adv_import_presets_from_file(*_):
        # Unified import: Macro + SyncKey groups + SwitchRuntime groups
        return adv_import_all_presets_from_file()
    if cmds.window(window_name, exists=True):
        cmds.deleteUI(window_name)
    
    # Create window
    window = cmds.window(window_name,
                        title=get_text("macro_window_title"),
                        widthHeight=(520, 480),
                        resizeToFitChildren=True)
    
    main_layout = cmds.columnLayout(adjustableColumn=True,
                                   columnAttach=('both', 10),
                                   rowSpacing=5)

    # Ensure macro presets exist
    try:
        adv_macro_presets_ensure_defaults()
    except Exception:
        pass

    def _rebuild_macro_preset_menu(select_name=None):
        if not cmds.optionMenu(ADV_MACRO_PRESET_OM, exists=True):
            return
        try:
            cmds.optionMenu(ADV_MACRO_PRESET_OM, e=True, dai=True)
        except Exception:
            items = cmds.optionMenu(ADV_MACRO_PRESET_OM, q=True, ill=True) or []
            for it in items:
                try:
                    cmds.deleteUI(it)
                except Exception:
                    pass

        presets = _adv_macro_presets_load()
        names = [n for n in presets.keys() if n]
        names_sorted = []
        if "ADV" in names:
            names_sorted.append("ADV")
        for n in sorted([x for x in names if x != "ADV"], key=lambda s: s.lower()):
            names_sorted.append(n)
        if not names_sorted:
            names_sorted = ["ADV"]
        for n in names_sorted:
            cmds.menuItem(label=n)

        want = select_name or adv_macro_presets_get_active() or "ADV"
        if want not in names_sorted:
            want = names_sorted[0]
        try:
            cmds.optionMenu(ADV_MACRO_PRESET_OM, e=True, v=want)
        except Exception:
            pass

    def _get_selected_macro_preset():
        try:
            return cmds.optionMenu(ADV_MACRO_PRESET_OM, q=True, v=True) or ""
        except Exception:
            return ""

    def _on_macro_preset_changed(*_):
        name = _get_selected_macro_preset()
        if name:
            _adv_macro_presets_set_active(name)
            # update button label preview
            if cmds.button("macroMenuButton", exists=True):
                try:
                    cmds.button("macroMenuButton", edit=True, label=get_macro_button_label())
                except Exception:
                    pass

    def _macro_load(*_):
        name = _get_selected_macro_preset()
        if name:
            adv_macro_presets_apply(name)
            refresh_mapping_list()

    def _macro_new(*_):
        if cmds.promptDialog(title=get_text("macro_preset_new"),
                             message=get_text("macro_preset_prompt_name"),
                             button=['OK', 'Cancel'],
                             defaultButton='OK',
                             cancelButton='Cancel',
                             dismissString='Cancel',
                             text="") != 'OK':
            return
        name = cmds.promptDialog(q=True, text=True).strip()
        if not name:
            return
        if adv_macro_presets_save_current_as(name):
            _rebuild_macro_preset_menu(select_name=name)

    def _macro_save(*_):
        name = _get_selected_macro_preset()
        if not name:
            return
        if name == "ADV":
            cmds.warning(get_text("macro_preset_protect_adv"))
            return
        msg = get_text("macro_preset_confirm_overwrite") % name
        try:
            ok = (cmds.confirmDialog(title=get_text("macro_preset_save"), message=msg, button=['OK', 'Cancel'], defaultButton='OK', cancelButton='Cancel', dismissString='Cancel') == 'OK')
        except Exception:
            ok = True
        if not ok:
            return
        if adv_macro_presets_overwrite(name):
            _rebuild_macro_preset_menu(select_name=name)

    def _macro_delete(*_):
        name = _get_selected_macro_preset()
        if not name:
            return
        if name == "ADV":
            cmds.warning(get_text("macro_preset_protect_adv"))
            return
        msg = get_text("macro_preset_confirm_delete") % name
        try:
            ok = (cmds.confirmDialog(title=get_text("macro_preset_delete"), message=msg, button=['OK', 'Cancel'], defaultButton='OK', cancelButton='Cancel', dismissString='Cancel') == 'OK')
        except Exception:
            ok = True
        if not ok:
            return
        if adv_macro_presets_delete(name):
            _rebuild_macro_preset_menu(select_name=adv_macro_presets_get_active())
            refresh_mapping_list()

    def _macro_rename(*_):
        old = _get_selected_macro_preset()
        if not old:
            return
        if old == 'ADV':
            cmds.warning(get_text("macro_preset_protect_adv"))
            return

        title = "Rename"
        msg = ("Rename preset %s to:" % old)
        try:
            ok = (cmds.promptDialog(title=title, message=msg, button=['OK', 'Cancel'], defaultButton='OK', cancelButton='Cancel', dismissString='Cancel', text=str(old)) == 'OK')
        except Exception:
            ok = False
        if not ok:
            return
        try:
            new = (cmds.promptDialog(q=True, text=True) or '').strip()
        except Exception:
            new = ''
        if not new or new == old:
            return

        presets = _adv_macro_presets_load() or {}
        if new in presets:
            cmds.warning(get_text("macro_preset_exists") % new)
            return
        if old not in presets:
            return

        presets[new] = presets.get(old)
        try:
            del presets[old]
        except Exception:
            pass
        _adv_macro_presets_save(presets)

        active = adv_macro_presets_get_active() or 'ADV'
        if active == old:
            _adv_macro_presets_set_active(new)
        _rebuild_macro_preset_menu(select_name=new)
        try:
            if cmds.button("macroMenuButton", exists=True):
                cmds.button("macroMenuButton", edit=True, label=get_macro_button_label())
        except Exception:
            pass

    # Preset row (7 cols: +Rename)
    cmds.rowLayout(
        numberOfColumns=7,
        adjustableColumn=2,
        columnWidth=[(1, 42), (2, 150), (3, 50), (4, 50), (5, 50), (6, 60), (7, 60)],
        columnAlign=[(1, 'left'), (2, 'left'), (3, 'left'), (4, 'left'), (5, 'left'), (6, 'left'), (7, 'left')],
        columnAttach=[(1, 'left', 0), (2, 'left', 0), (3, 'left', 0), (4, 'left', 0), (5, 'left', 0), (6, 'left', 0), (7, 'left', 0)],
    )
    cmds.text(label=get_text("macro_preset"), align='left')
    cmds.optionMenu(ADV_MACRO_PRESET_OM, changeCommand=_on_macro_preset_changed)
    cmds.button(label=get_text("macro_preset_load"), height=24,
                backgroundColor=(0.35, 0.55, 0.75),
                command=_macro_load)
    cmds.button(label=get_text("macro_preset_new"), height=24,
                backgroundColor=(0.55, 0.55, 0.65),
                command=_macro_new)
    cmds.button(label=get_text("macro_preset_save"), height=24,
                backgroundColor=(0.55, 0.55, 0.65),
                command=_macro_save)
    cmds.button(label=(u"重命名" if LANGUAGE == 'CN' else "Rename"), height=24,
                backgroundColor=(0.55, 0.55, 0.65),
                command=_macro_rename)
    cmds.button(label=get_text("macro_preset_delete"), height=24,
                backgroundColor=(0.7, 0.35, 0.35),
                command=_macro_delete)

    cmds.setParent('..')

    # Export / Import presets (portable JSON)
    cmds.rowLayout(numberOfColumns=2, columnWidth2=(120, 120), columnAlign2=('left', 'left'), columnAttach2=('left', 'left'))
    cmds.button(label=get_text('preset_export'), height=24, command=adv_export_presets_to_file)
    cmds.button(label=get_text('preset_import'), height=24, command=adv_import_presets_from_file)
    cmds.setParent('..')

    cmds.separator(height=10)
    
    # Add new mapping section
    cmds.text(label=get_text("add_mapping"), font="boldLabelFont", align="left")
    
    
    cmds.rowLayout(numberOfColumns=3, columnWidth3=(100, 280, 120), columnAlign3=('right', 'left', 'left'))
    cmds.text(label=get_text("parent_ctrl") + ":", align="right")
    parent_field = cmds.textField("macroParentField", placeholderText="e.g. FKScapula_L")
    cmds.button(label=u"<< 閫夋嫨鍦烘櫙鐗╀綋", 
               width=115,
               backgroundColor=(0.4, 0.6, 0.5),
               command=lambda x: select_scene_object_to_parent())
    cmds.setParent('..')
    
    
    cmds.rowLayout(numberOfColumns=3, columnWidth3=(100, 280, 120), columnAlign3=('right', 'left', 'left'))
    cmds.text(label=get_text("child_ctrl") + ":", align="right")
    child_field = cmds.textField("macroChildField", placeholderText="e.g. FKShoulder_L")
    cmds.button(label=get_text("select_scene_object"), 
               width=115,
               backgroundColor=(0.4, 0.6, 0.5),
               command=lambda x: select_scene_object_to_child())
    cmds.setParent('..')
    
    # Add button
    cmds.button(label=get_text("add_parent_child"), 
               height=28,
               backgroundColor=(0.4, 0.7, 0.4),
               command=lambda x: add_custom_mapping())
    
    cmds.separator(height=10)
    
    # Mapping list
    cmds.text(label=get_text("current_mappings"), font="boldLabelFont", align="left")
    
    mapping_list = cmds.textScrollList("macroMappingList",
                                      numberOfRows=12,
                                      allowMultiSelection=True,
                                      height=200)
    
    # Control buttons (preset handles save/load; keep delete-only here)
    cmds.rowLayout(numberOfColumns=1, columnWidth1=520)
    cmds.button(label=get_text("delete_multi"),
               backgroundColor=(0.7, 0.3, 0.3),
               command=lambda x: delete_custom_mapping())
    cmds.setParent('..')
    
    cmds.separator(height=10)
    
    # Instructions
    cmds.text(label=get_text("instructions_title"), font="boldLabelFont", align="left")
    cmds.text(label=get_text("macro_inst1"), align="left")
    cmds.text(label=get_text("macro_inst2"), align="left")
    cmds.text(label=get_text("macro_inst3"), align="left")
    cmds.text(label=get_text("macro_inst4"), align="left")
    cmds.text(label=get_text("macro_inst5"), align="left")
    
    # Refresh list
    refresh_mapping_list()

    try:
        _rebuild_macro_preset_menu()
    except Exception:
        pass
    
    cmds.showWindow(window)

def toggle_mapping_mode(use_custom):
    """Switch mapping mode"""
    global USE_CUSTOM_MAPPING
    USE_CUSTOM_MAPPING = use_custom
    status = u"Custom" if use_custom else u"ADV Default"
    _adv_safe_print(u"Mapping mode switched: %s" % status)
    cmds.inViewMessage(amg=u"<hl>Mapping mode: %s</hl>" % status, pos='midCenter', fade=True)
    
    # Update main window button label if exists
    if cmds.button("macroMenuButton", exists=True):
        new_label = get_macro_button_label()
        cmds.button("macroMenuButton", edit=True, label=new_label)


def _adv_macro_legacy_load_from_file():
    """Load legacy single-config file. Returns (use_custom, parent_map, child_map)."""
    import os
    config_dir = cmds.internalVar(userAppDir=True)
    config_file = os.path.join(config_dir, "controller_hierarchy_macro.json")
    if not os.path.exists(config_file):
        return False, {}, {}
    try:
        with open(config_file, 'r') as f:
            config_data = json.load(f)
        use_custom = bool(config_data.get("use_custom", False))
        parent_map = config_data.get("parent_map", {})
        child_map = config_data.get("child_map", {})
        if not isinstance(parent_map, dict):
            parent_map = {}
        if not isinstance(child_map, dict):
            child_map = {}
        return use_custom, parent_map, child_map
    except Exception:
        return False, {}, {}

