def add_custom_mapping():
    """Add a custom parent-child mapping."""
    global CUSTOM_PARENT_MAP, CUSTOM_CHILD_MAP
    
    child_name = cmds.textField("macroChildField", q=True, text=True).strip()
    parent_name = cmds.textField("macroParentField", q=True, text=True).strip()
    
    if not child_name or not parent_name:
        _adv_safe_warning(u"璇疯緭鍏ュ瓙鎺у埗鍣ㄥ拰鐖舵控制器鍚嶇О!")
        return
    
    # Add to mapping
    CUSTOM_PARENT_MAP[child_name] = parent_name
    
    # Also add reverse mapping for child lookup
    if parent_name not in CUSTOM_CHILD_MAP:
        CUSTOM_CHILD_MAP[parent_name] = []
    if child_name not in CUSTOM_CHILD_MAP[parent_name]:
        CUSTOM_CHILD_MAP[parent_name].append(child_name)
    
    # Clear fields
    cmds.textField("macroChildField", e=True, text="")
    cmds.textField("macroParentField", e=True, text="")
    
    # Refresh list
    refresh_mapping_list()
    
    _adv_safe_print(u"Mapping added: %s -> %s" % (child_name, parent_name))

def delete_custom_mapping():
    """Delete selected mapping entries (multi-select supported)."""
    global CUSTOM_PARENT_MAP, CUSTOM_CHILD_MAP
    
    selected = cmds.textScrollList("macroMappingList", q=True, selectItem=True)
    if not selected:
        _adv_safe_warning(u"请先选择要删除的映射!")
        return
    
    delete_count = 0
    
    # Parse all selected lines
    for item in selected:
        
        parts = item.split(u" -> ")
        if len(parts) != 2:
            continue
        
        parent_name = parts[0].strip()
        child_name = parts[1].strip()
        
        # Remove from maps
        if child_name in CUSTOM_PARENT_MAP:
            del CUSTOM_PARENT_MAP[child_name]
            delete_count += 1
        
        if parent_name in CUSTOM_CHILD_MAP:
            if child_name in CUSTOM_CHILD_MAP[parent_name]:
                CUSTOM_CHILD_MAP[parent_name].remove(child_name)
            if not CUSTOM_CHILD_MAP[parent_name]:
                del CUSTOM_CHILD_MAP[parent_name]
    
    refresh_mapping_list()
    _adv_safe_print(u"已删除 %d 个映射" % delete_count)
    cmds.inViewMessage(amg=u"<hl>已删除 %d 个映射</hl>" % delete_count, pos='midCenter', fade=True)

def refresh_mapping_list():
    """Refresh mapping list display (parent -> child)."""
    cmds.textScrollList("macroMappingList", e=True, removeAll=True)
    
    if not CUSTOM_PARENT_MAP:
        cmds.textScrollList("macroMappingList", e=True, 
                          append=[u"(Empty - using ADV default)"])
        return
    
    # Build parent->children display
    display_list = []
    for child_name in sorted(CUSTOM_PARENT_MAP.keys()):
        parent_name = CUSTOM_PARENT_MAP[child_name]
        display_text = u"%s -> %s" % (parent_name, child_name)
        display_list.append(display_text)
    
    # Display sorted by parent name
    display_list.sort()
    for item in display_list:
        cmds.textScrollList("macroMappingList", e=True, append=[item])

def save_macro_config():
    """淇濆瓨瀹忛厤缃埌鏂囦欢"""
    import json
    import os
    
    config_dir = cmds.internalVar(userAppDir=True)
    config_file = os.path.join(config_dir, "controller_hierarchy_macro.json")
    
    config_data = {
        "use_custom": USE_CUSTOM_MAPPING,
        "parent_map": CUSTOM_PARENT_MAP,
        "child_map": CUSTOM_CHILD_MAP
    }
    
    try:
        with open(config_file, 'w') as f:
            json.dump(config_data, f, indent=2)
        _adv_safe_print(u"配置已保存: %s" % config_file)
        cmds.confirmDialog(title=u"成功", message=u"配置已保存", button=["OK"])
    except Exception as e:
        _adv_safe_warning(u"保存失败: %s" % str(e))

def load_macro_config():
    """浠庢枃浠跺姞杞藉畯閰嶇疆"""
    global USE_CUSTOM_MAPPING, CUSTOM_PARENT_MAP, CUSTOM_CHILD_MAP
    import json
    import os
    
    config_dir = cmds.internalVar(userAppDir=True)
    config_file = os.path.join(config_dir, "controller_hierarchy_macro.json")
    
    if not os.path.exists(config_file):
        _adv_safe_warning(u"Config file not found: %s" % config_file)
        return
    
    try:
        with open(config_file, 'r') as f:
            config_data = json.load(f)
        
        USE_CUSTOM_MAPPING = config_data.get("use_custom", False)
        CUSTOM_PARENT_MAP = config_data.get("parent_map", {})
        CUSTOM_CHILD_MAP = config_data.get("child_map", {})
        
        # Update UI if window is open
        if cmds.window("controllerMacroMenu", exists=True):
            refresh_mapping_list()
        
        _adv_safe_print(u"配置已加载: %d 个映射" % len(CUSTOM_PARENT_MAP))
        cmds.confirmDialog(title=u"成功", 
                          message=u"配置已加载\n映射数量: %d" % len(CUSTOM_PARENT_MAP),
                          button=["OK"])
    except Exception as e:
        _adv_safe_warning(u"加载失败: %s" % str(e))

# Auto-load config on script startup
def auto_load_macro_config():
    """Auto-load macro mapping config on script startup."""
    global USE_CUSTOM_MAPPING, CUSTOM_PARENT_MAP, CUSTOM_CHILD_MAP

    # Prefer presets if present; otherwise migrate legacy file once.
    try:
        if cmds.optionVar(exists=ADV_MACRO_PRESETS_OPTIONVAR):
            adv_macro_presets_ensure_defaults()
            adv_macro_presets_apply(adv_macro_presets_get_active())
            return
    except Exception:
        pass

    # Legacy load
    try:
        use_custom, parent_map, child_map = _adv_macro_legacy_load_from_file()
        USE_CUSTOM_MAPPING = bool(use_custom)
        CUSTOM_PARENT_MAP = parent_map if isinstance(parent_map, dict) else {}
        CUSTOM_CHILD_MAP = child_map if isinstance(child_map, dict) else {}
    except Exception:
        USE_CUSTOM_MAPPING = False
        CUSTOM_PARENT_MAP = {}
        CUSTOM_CHILD_MAP = {}

    # Migrate into presets
    presets = {
        "ADV": {"parent_map": {}, "child_map": {}},
        "Bip": {"parent_map": _adv_macro_make_bip_parent_map(), "child_map": {}},
    }
    if CUSTOM_PARENT_MAP:
        presets["Migrated"] = {
            "parent_map": dict(CUSTOM_PARENT_MAP or {}),
            "child_map": dict(CUSTOM_CHILD_MAP or {}),
        }
        _adv_macro_presets_set_active("Migrated" if USE_CUSTOM_MAPPING else "ADV")
    else:
        _adv_macro_presets_set_active("ADV")
    _adv_macro_presets_save(presets)
    try:
        adv_macro_presets_apply(adv_macro_presets_get_active())
    except Exception:
        pass

# Call auto-load
auto_load_macro_config()


# Startup self-heal:
# - Stop legacy "ADV: 鍏抽敭甯у悓姝ユā鍧楁湭娉ㄥ唽..." warning spam caused by old hotkey/runtimeCommand prefs.
# - This runs whenever the tool is launched, so users are not forced to rely on userSetup.py.
def _adv_startup_self_heal_legacy_setkey():
    try:
        import maya.cmds as cmds
        import maya.utils as maya_utils
    except Exception:
        return

    def _do():
        try:
            adv_cleanup_legacy_setkey_hotkey(restore_to_setkey=True)
        except Exception:
            pass

        # Extra safety: patch runtimeCommand even if not bound to S.
        try:
            rt = ADV_SYNC_SETKEY_RUNTIME_COMMAND
            safe_py = (
                "import maya.mel as mel\n"
                "try:\n"
                "    mel.eval('SetKey;')\n"
                "except Exception:\n"
                "    pass\n"
            )
            if rt and _adv_runtime_command_exists(rt):
                try:
                    cmds.runTimeCommand(rt, e=True, commandLanguage='python', command=safe_py,
                                       annotation='ADV Legacy SetKey (no-warning fallback)')
                except Exception:
                    try:
                        cmds.runTimeCommand(rt, edit=True, commandLanguage='python', command=safe_py,
                                           annotation='ADV Legacy SetKey (no-warning fallback)')
                    except Exception:
                        pass
        except Exception:
            pass

    try:
        maya_utils.executeDeferred(_do)
    except Exception:
        _do()


_adv_startup_self_heal_legacy_setkey()

# Apply working units/grid settings and keep them consistent on scene open.
_adv_units_grid_startup_apply()

def _adv_startup_install_seamless_view_switch():
    try:
        _adv_install_seamless_view_switch_event_filter(force=True)
    except Exception:
        try:
            _adv_install_seamless_view_switch_event_filter()
        except Exception:
            pass

try:
    import maya.utils as maya_utils
    maya_utils.executeDeferred(_adv_startup_install_seamless_view_switch)
except Exception:
    _adv_startup_install_seamless_view_switch()

