# ==================== Animation Layer Mark Tool ====================
def open_anim_layer_mark_tool():
    """Open the time_slider_bip tool window (if available)."""
    try:
        import importlib
        import os
        import sys
    except Exception as e:
        cmds.warning("Open anim layer mark tool failed: %s" % str(e))
        return

    try:
        current_dir = os.path.dirname(os.path.abspath(__file__))
        scripts_dir = os.path.join(current_dir, 'scripts')
        if scripts_dir not in sys.path:
            sys.path.insert(0, scripts_dir)

        import time_slider_bip
        try:
            importlib.reload(time_slider_bip)
        except Exception:
            pass
        time_slider_bip.show()
    except ImportError as e:
        cmds.warning("Cannot import time_slider_bip: %s" % str(e))
    except Exception as e:
        cmds.warning("Open anim layer mark tool failed: %s" % str(e))
